INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(1, 'Adana', 'Akdeniz', 'adana.jpg', 'Seyhan Nehri ve tarihi taş köprüsüyle ünlü şehir.', 'Adana denince akla gelen ilk şey Adana Kebap ve Taş Köprü\'dür. Taş Köprü, Roma döneminden kalma ve dünyanın halen kullanılan en eski köprülerinden biridir. Sabancı Merkez Camii, 6 minaresiyle Türkiye\'nin en büyük camilerinden biridir ve mutlaka görülmeli. Şalgam suyu, Bici Bici tatlısı, Karakuş ve Yerliköy höyükleri, Seyhan Nehri üzerindeki Seyhan Barajı ve Çatalan Köprüsü, Varda Köprüsü (Alman Köprüsü) de Adana\'nın meşhur yerleri arasındadır. Ayrıca Adana karpuzu da ülke çapında ünlüdür.', 'Adana\'da yenmesi gereken ilk şey tabii ki Adana Kebap\'tır. Gerçek Adana Kebap, erkek koyun etinin kıyma haline getirilip acı pul biber ve kuyruk yağı ile yoğurulmasıyla yapılır ve şişte pişirilir. Yanında mutlaka sumaklı soğan, roka ve közlenmiş biber-domates gelir. İçecek olarak şalgam suyu vazgeçilmezdir; acılı veya acısız tercih edilebilir. Tatlı olarak Bici Bici (şerbetli nişasta tatlısı) mutlaka denenmeli. Ayrıca ciğer kebabı, kuzu tandır, Adana usulü içli köfte ve batırık da yöresel lezzetler arasındadır. Kahvaltıda ise Çukurova\'ya has biberli, naneli, cevizli \"karaçörek\" önerilir.', 'Adana\'daki en önemli festival Altın Koza Film Festivali\'dir. Her yıl eylül ayında düzenlenen bu festival uluslararası katılımlıdır ve Türk sinemasının en prestijli etkinliklerinden biridir. Mayıs ayında Adana Kebap ve Lezzet Festivali düzenlenir; bu festivalde yöresel lezzetleri tatmak ve kebap yarışmalarını izlemek mümkündür. Nisan başında Portakal Çiçeği Karnavalı yapılır; renkli geçit törenleri ve konserlerle şehir adeta bayram havasına bürünür.', 'Adana\'yı ziyaret etmek için en iyi zaman mart-nisan ve ekim-kasım aylarıdır. Yaz aylarında (haziran-eylül) sıcaklık 40°C\'yi aşabilir, bu nedenle sıcaktan hoşlanmıyorsanız ilkbahar ve sonbahar idealdir. Özellikle nisan ayında portakal çiçeklerinin kokusu tüm şehri sarar ve bu dönemde yapılacak bir gezi unutulmaz olur. Kışlar ılıman geçer ama yağışlı olabilir; aralık-şubat arasında yağmur ihtimaline karşı şemsiye ile gezilmesi önerilir.', 'Adana\'ya hava yoluyla gelmek isterseniz Adana Şakirpaşa Havalimanı tam şehir merkezine sadece 5 km uzaklıktadır. Havalimanından taksi veya belediye otobüsleriyle rahatça şehre ulaşabilirsiniz. Şehirlerarası otobüs terminali (Adana Otogarı) şehir merkezine metro ile bağlıdır; otogardan metroya binerek 10-15 dakikada merkeze varabilirsiniz. Şehir içi ulaşımda metro, belediye otobüsleri, minibüs ve dolmuşlar yaygın olarak kullanılır. Demiryolu ile Mersin, Osmaniye, Gaziantep gibi komşu illere kolayca gidebilirsiniz.', 'Adana, tarihi boyunca Hititler, Persler, Romalılar ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. MÖ 6000 yıllarına uzanan geçmişiyle Çukurova\'nın en eski yerleşim merkezlerinden biridir. Roma döneminde önemli bir eyalet merkezi haline gelmiş, Seyhan Nehri sayesinde tarım ve ticarette parlamıştır. Osmanlı döneminde ise Halep\'e bağlı bir sancak olarak yönetilmiştir. Kurtuluş Savaşı\'nda Fransız işgaline karşı verilen mücadeleyle de ön plana çıkmıştır.', 'Adana', '2026-04-08 23:20:51'),
(2, 'Adıyaman', 'Güneydoğu Anadolu', 'adiyaman.jpg', 'Adıyaman denince akla gelen ilk şey Nemrut Dağı ve Kommagene Krallığı\'na ait dev heykellerdir. Nemrut Dağı\'ndaki dev taş heykeller (Apollo, Zeus, Herakles, Kral Antiochos) gün doğumu ve gün batımında muhteşem görüntü oluşturur. Adıyaman Kalesi, Cendere Köprüsü (Roma döneminden kalma dünyanın en eski kemer köprülerinden), Karakuş Tepesi, Arsemia Antik Kenti (Kommagene\'nin başkenti), Perre Antik Kenti (su kemerleri ve kaya mezarları) de görülmesi gereken yerlerdir. Ayrıca Adıyaman Müzesi\'ndeki eserler de oldukça zengindir.', 'Adıyaman denince akla gelen ilk şey Nemrut Dağı ve Kommagene Krallığı\'na ait dev heykellerdir. Nemrut Dağı\'ndaki dev taş heykeller (Apollo, Zeus, Herakles, Kral Antiochos) gün doğumu ve gün batımında muhteşem görüntü oluşturur. Adıyaman Kalesi, Cendere Köprüsü (Roma döneminden kalma dünyanın en eski kemer köprülerinden), Karakuş Tepesi, Arsemia Antik Kenti (Kommagene\'nin başkenti), Perre Antik Kenti (su kemerleri ve kaya mezarları) de görülmesi gereken yerlerdir. Ayrıca Adıyaman Müzesi\'ndeki eserler de oldukça zengindir.', 'Adıyaman\'da mutlaka denenmesi gereken lezzetlerin başında Adıyaman Çiğ Köftesi gelir. Et kullanılmadan yapılan bu çiğ köfte, ince bulgur, domates, biber salçası ve baharatlarla hazırlanır. İskender Kebap\'ın Adıyaman\'a özgü versiyonu olan Altınözü Tepsi Kebabı da meşhurdur. Ayrıca içli köfte, ekşili köfte, sac kavurma, Adıyaman tutmacı ve cevizli sucuk tatlısı mutlaka tadılmalıdır. Yöresel peynir çeşitleri ve balı da ünlüdür. Kahvaltıda ise \"kıymalı katmer\" sıkça tüketilir.', 'Adıyaman\'daki en önemli etkinlik Nemrut Dağı Kültür ve Turizm Festivali\'dir. Her yıl ağustos ayında düzenlenen bu festivalde konserler, yöresel lezzet tadımları, el sanatları sergileri ve halk oyunları gösterileri yapılır. Ayrıca Nisan ayında Adıyaman Çiğ Köfte Festivali düzenlenir; bu festivalde dünyanın en büyük çiğ köftesi yapılmaya çalışılır. Eylül ayında ise Kahta Kültür ve Sanat Festivali yapılır.', 'Adıyaman\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Yaz aylarında sıcaklık 38-40°C\'ye ulaşabilir, bu nedenle Nemrut Dağı gibi açık alan gezileri için ilkbahar ve sonbahar idealdir. Özellikle nisan ayında hava ılımandır ve doğa canlanır. Kışlar soğuk ve yağışlı geçer, özellikle yüksek kesimlerde kar yağışı görülür; aralık-şubat arasında kalın giyinmek gerekir.', 'Adıyaman\'a en yakın havalimanı Adıyaman Havalimanı\'dır. Havalimanı şehir merkezine yaklaşık 20 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Alternatif olarak Malatya Havalimanı veya Şanlıurfa Havalimanı da kullanılabilir. Şehirlerarası otobüs terminali şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır. Şehir içi ulaşımda minibüs, dolmuş ve belediye otobüsleri kullanılır. Nemrut Dağı gibi uzak yerlere gitmek için turlar veya araç kiralamak önerilir. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Malatya veya Gaziantep\'tedir.', 'Adıyaman, tarihi boyunca Kommagene Krallığı, Roma, Bizans ve Osmanlı gibi birçok medeniyete ev sahipliği yapmıştır. En önemli dönemi, MÖ 1. yüzyılda Kral Antiochos Theos tarafından kurulan Kommagene Krallığı\'dır. Bu dönemden kalan Nemrut Dağı, UNESCO Dünya Mirası Listesi\'ndedir. Osmanlı döneminde önce Malatya\'ya, sonra Maraş\'a bağlanmış, Cumhuriyet döneminde il statüsüne kavuşmuştur. Bölge, tarih boyunca önemli ticaret yolları üzerinde yer almıştır.', 'Adıyaman', '2026-04-08 23:20:51'),
(3, 'Afyonkarahisar', 'Ege', 'afyon.jpg', 'Termal kaynakları ve kaymağı ile ünlü.', 'Afyonkarahisar denince akla ilk gelen şeyler: Afyon Kalesi (şehrin simgesi, tepede yer alır), kaymak, sucuk, pastırma ve haşhaştır. Frig Vadisi\'ndeki kaya mezarları, peri bacaları ve tarihi yerleşimler mutlaka görülmeli. Zafer Müzesi (Başkomutanlık Karargahı), Afyon Müzesi, Kurtuluş Savaşı Müzesi, Mevlevi Camii ve Altıgöz Köprüsü de önemli duraklardır. Ayrıca İscehisar\'daki mermer ocakları ve mermer işlemeciliği de ünlüdür. Termal kaplıcalar (Gazlıgöl, Heybeli, Ömer-Gecek) şehrin önemli sağlık turizmi merkezleridir.', 'Afyonkarahisar, Türk mutfağının en önemli şehirlerinden biridir. Meşhur Afyon kaymağı mutlaka tadılmalı; bal veya pekmezle birlikte yenir. Afyon sucuğu ve pastırması Türkiye\'nin en iyileri arasındadır. Yöresel yemeklerden \"savuş\" (etli, nohutlu, bulgurlu bir yemek), \"ağzaçık\" (içli hamur işi), \"bükme\" (peynirli veya kıymalı börek), \"keşkek\" ve \"patates oturtma\" mutlaka denenmeli. Tatlı olarak \"haşhaşlı revani\", \"kaymaklı ekmek kadayıfı\" ve \"cevizli lokum\" meşhurdur. Ayrıca Afyon ıspanaklı böreği de ünlüdür.', 'Afyonkarahisar\'da her yıl ağustos ayında Uluslararası Afyonkarahisar Kültür ve Sanat Festivali düzenlenir. Bu festivalde konserler, halk oyunları gösterileri, yöresel lezzet yarışmaları ve panayırlar yapılır. Eylül ayında İscehisar Mermer ve Kültür Festivali düzenlenir. Temmuz ayında ise Sandıklı Termal Turizm ve Kültür Festivali yapılır. Ayrıca haşhaş hasadı döneminde düzenlenen Haşhaş Festivali de ilgi çeker.', 'Afyonkarahisar\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Yaz ayları sıcak ve kurak geçer, kışlar ise soğuk ve karlıdır. Kış aylarında termal turizm için ideal bir zamandır çünkü şehir kaplıcalarıyla ünlüdür. Özellikle aralık-şubat arasında termal oteller tercih edilebilir. Tarihi yerleri gezmek için ilkbahar ve sonbahar daha rahattır.', 'Afyonkarahisar\'da her yıl ağustos ayında Uluslararası Afyonkarahisar Kültür ve Sanat Festivali düzenlenir. Bu festivalde konserler, halk oyunları gösterileri, yöresel lezzet yarışmaları ve panayırlar yapılır. Eylül ayında İscehisar Mermer ve Kültür Festivali düzenlenir. Temmuz ayında ise Sandıklı Termal Turizm ve Kültür Festivali yapılır. Ayrıca haşhaş hasadı döneminde düzenlenen Haşhaş Festivali de ilgi çeker.', 'Afyonkarahisar, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Şehrin adı, üzerinde bulunan kalesi nedeniyle \"karahisar\" (kara kale) olarak anılmış, Osmanlı döneminde afyon üretimiyle ünlenince \"Afyonkarahisar\" adını almıştır. Kurtuluş Savaşı\'nda önemli bir direniş merkezi olmuş, Başkomutanlık Meydan Muharebesi bu topraklarda kazanılmıştır. Zafertepe ve Dumlupınar bu nedenle büyük tarihi öneme sahiptir.', 'Afyonkarahisar', '2026-04-08 23:20:51'),
(4, 'Ağrı', 'Doğu Anadolu', 'agri.jpg', 'Ağrı Dağı ile ünlü şehir.', 'Ağrı denince akla gelen ilk şey Ağrı Dağı\'dır (5137 m). Türkiye\'nin en yüksek noktası olan bu dağ, efsanelere göre Hz. Nuh\'un Gemisi\'nin karaya oturduğu yerdir. Dağa tırmanış dünyaca ünlüdür ve her yıl dağcıları ağırlar. İshak Paşa Sarayı (17. yüzyıldan kalma, Osmanlı döneminin en görkemli yapılarından), Doğubayazıt Kalesi, Urartu dönemine ait Meya Mağaraları, Nuh\'un Gemisi Kalıntıları (Tevrat ve Kur\'an\'da adı geçen bölge), Balık Gölü, Meteor Çukuru (dünyanın en büyük ikinci meteor çukuru) ve Ahmed-i Hani Türbesi de mutlaka görülmesi gereken yerlerdir.', 'Ağrı mutfağı, Doğu Anadolu\'nun zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Ağrı köftesi\" (etli ve baharatlı) gelir. \"Abdigör köftesi\" (yarma ve etle yapılan bir yemek), \"keledoş\" (nohutlu, etli, yoğurtlu yemek), \"cılbır\" (yoğurtlu, yağlı yumurta), \"haşıl\" (unlu, tereyağlı bir çorba) ve \"ovmaç çorbası\" yöresel lezzetlerdir. \"Murtuğa\" (etli, bulgurlu, mercimekli yemek) da mutlaka tadılmalı. Tatlı olarak \"şaşak\" (un ve şekerle yapılan bir tatlı) ve \"kaysefe\" (kuru meyveli tatlı) meşhurdur. Ağrı\'nın peynir ve çökelek çeşitleri de oldukça lezzetlidir.', 'Ağrı\'da en önemli etkinlik Ağrı Dağı Uluslararası Dağcılık Festivali\'dir. Her yıl temmuz-ağustos aylarında düzenlenen bu festivalde dünyanın dört bir yanından dağcılar Ağrı Dağı\'na tırmanır. Ayrıca Doğubayazıt Kültür ve Turizm Festivali (ağustos ayında), İshak Paşa Sarayı\'nda konserler ve etkinlikler yapılır. Haziran ayında ise Ahmed-i Hani\'yi Anma ve Kültür Etkinlikleri düzenlenir.', 'Ağrı\'yı ziyaret etmek için en iyi zaman haziran-eylül ayları arasıdır. Yaz ayları ılıman geçer, sıcaklık genelde 25-30°C arasındadır, bu da Ağrı Dağı tırmanışı için idealdir. Kışlar çok sert ve soğuk geçer; sıcaklık -20°C\'nin altına düşebilir, kar yağışı yoğundur. Bu nedenle aralık-şubat arasında seyahat önerilmez. Ağrı Dağı\'na tırmanmak için en uygun zaman temmuz ve ağustos aylarıdır.', 'Ağrı\'ya hava yoluyla gelmek için Ağrı Ahmed-i Hani Havalimanı kullanılır. Havalimanı şehir merkezine yaklaşık 7 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Şehirlerarası otobüs terminali şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı mevcuttur; Kars-Erzurum-İstanbul hattında tren seferleri düzenlenir. Şehir içi ulaşımda minibüs, dolmuş ve belediye otobüsleri kullanılır. Ağrı Dağı ve Doğubayazıt gibi uzak noktalara gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Ağrı, tarihi boyunca Urartular, Medler, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihin en eski yerleşim merkezlerinden biri olarak bilinir. Urartular döneminde önemli bir savunma merkezi haline gelmiştir. Osmanlı döneminde Erzurum\'a bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Ağrı Dağı, Hz. Nuh\'un gemisinin indiğine inanılan yer olarak hem İslam hem de Hristiyan dünyasında kutsal kabul edilir.', 'Ağrı', '2026-04-08 23:20:51'),
(5, 'Aksaray', 'İç Anadolu', 'aksaray.jpg', 'Ihlara Vadisi ile ünlü.', 'Aksaray denince akla gelen ilk şeyler: Ihlara Vadisi (Kapadokya\'nın en etkileyici vadilerinden, içinde kaya kiliseleri olan), Hasan Dağı (Türkiye\'nin en yüksek ikinci dağı, 3253 m), Güzelyurt (tarihi Rum evleri ve kiliseleri), Kızıl Kilise, Eğri Minare (Selçuklu dönemi), Aksaray Müzesi, Zinciriye Medresesi ve Ulu Cami\'dir. Ayrıca Somuncu Baba Türbesi, Selime Katedrali (dünyanın en büyük kaya katedrali) ve Manastır Vadisi de mutlaka görülmesi gereken yerlerdir. Peribacaları ve yer altı şehirleri de bölgenin önemli turistik değerleridir.', 'Aksaray mutfağı, Kapadokya ve Orta Anadolu\'nun zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Aksaray tava\" (kuzu etiyle yapılan bir güveç yemeği) gelir. \"Erişteli yemek\", \"höşmerim\" (un, tereyağı, şekerle yapılan bir tatlı), \"cevizli bükme\", \"sac böreği\", \"patates oturtma\" ve \"nohutlu yarma\" yöresel lezzetlerdir. \"Kuru dolma\" (kurutulmuş biber ve patlıcanın içine bulgur ve et doldurularak yapılır) ve \"höştük çorbası\" da mutlaka tadılmalı. Aksaray\'ın özellikle \"hasan dağı balı\" ve \"cevizli sucuk\" tatlısı meşhurdur.', 'Aksaray\'da en önemli etkinlik Ihlara Vadisi Kültür ve Sanat Festivali\'dir. Her yıl mayıs veya haziran ayında düzenlenen bu festivalde doğa yürüyüşleri, konserler, yöresel lezzet tadımları ve el sanatları sergileri yapılır. Ağustos ayında Hasan Dağı Doğa Sporları ve Dağcılık Festivali düzenlenir. Eylül ayında ise Güzelyurt Kültür ve Turizm Festivali yapılır. Ayrıca Somuncu Baba\'yı Anma Etkinlikleri her yıl düzenlenir.', 'Aksaray\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Yaz aylarında sıcaklık 35-38°C\'ye ulaşabilir, bu nedenle Ihlara Vadisi gibi yürüyüş alanları için ilkbahar ve sonbahar idealdir. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür. Kış aylarında Hasan Dağı\'nın karlı manzarası güzel olsa da geziler için aralık-şubat arası pek uygun değildir.', 'Aksaray\'a en yakın havalimanı Nevşehir Kapadokya Havalimanı\'dır (yaklaşık 70 km). Ayrıca Kayseri Erkilet Havalimanı (140 km) veya Ankara Esenboğa Havalimanı (250 km) da kullanılabilir. Havalimanından havaş otobüsleri veya taksi ile ulaşım sağlanır. Şehirlerarası otobüs terminali şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır. Aksaray, Ankara-Adana demiryolu hattı üzerinde olduğu için trenle de ulaşmak mümkündür. Şehir içi ulaşımda minibüs, dolmuş ve belediye otobüsleri kullanılır. Ihlara Vadisi, Güzelyurt ve Hasan Dağı gibi yerlere gitmek için genellikle araç kiralamak veya turları tercih etmek önerilir.', 'Aksaray, tarihi boyunca Hititler, Frigler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Kapadokya bölgesinin batı girişinde yer alan şehir, tarihi İpek Yolu üzerinde önemli bir durak olmuştur. Selçuklu döneminde Aksaray, \"Karatay\" ve \"Sahip Ata\" gibi ünlü vezirlerin yönetiminde altın çağını yaşamıştır. Cumhuriyet döneminde önce Niğde\'ye bağlanmış, 1989 yılında il statüsü kazanmıştır. Şehir, aynı zamanda bölgenin önemli ticaret ve sanayi merkezlerinden biridir.', 'Aksaray', '2026-04-08 23:20:51'),
(6, 'Amasya', 'Karadeniz', 'amasya.jpg', 'Yeşilırmak kıyısında tarihi evleriyle ünlü.', 'Amasya denince akla gelen ilk şeyler: Amasya Kalesi (Harşena Dağı üzerinde, şehrin simgesi), Kral Kaya Mezarları (Pontus krallarına ait, 2000 yıllık), Yeşilırmak Nehri (şehri ikiye böler, üzerinde tarihi taş köprüler var), Amasya Evleri (Osmanlı döneminden kalma restore edilmiş konaklar), II. Bayezid Külliyesi (Osmanlı dönemi külliye, şimdi müze), Amasya Müzesi, Şehzadeler Müzesi, Ferhat ile Şirin Su Kanalı (efsaneye konu olan su yolu), Gök Medrese (Selçuklu dönemi), Kumbaracılar ve Boyalı köprüleri mutlaka görülmelidir. Ayrıca Borabay Gölü (doğal göl, piknik alanı) ve Terziköy Kaplıcaları da ziyaret edilebilir.', 'Amasya mutfağı, Karadeniz ve Orta Anadolu mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Amasya çöreği\" (cevizli, üzümlü, tarçınlı bir hamur işi) gelir. \"Toyga çorbası\" (yoğurtlu, pirinçli, nane çorbası), \"keşkek\", \"bakla dolması\", \"yuvarlama\" (nohutlu, etli, bulgurlu yemek), \"cızlak\" (mısır unlu hamur işi) ve \"ıhlamur otu kavurması\" yöresel lezzetlerdir. Tatlı olarak \"Amasya kızılcık şerbeti\", \"un helvası\" ve \"cevizli sucuk\" meşhurdur. Amasya\'nın meşhur elması ve kestane balı da mutlaka tadılmalıdır.', 'Amasya\'da en önemli etkinlik Uluslararası Amasya Kültür ve Sanat Festivali\'dir. Her yıl mayıs veya haziran ayında düzenlenen bu festivalde konserler, tiyatro gösterileri, halk oyunları, yöresel lezzet tadımları ve panayırlar yapılır. Eylül ayında Amasya Elma Festivali düzenlenir; bu festivalde dünyanın en büyük elma tatlısı yapılmaya çalışılır. Ağustos ayında ise Kral Kaya Mezarları Işıklı Gösteri ve Müzik Festivali yapılır. Ayrıca Yedikır Gölü\'nde doğa yürüyüşleri ve kuş gözlem etkinlikleri de düzenlenir.', 'Amasya\'yı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, Yeşilırmak kenarında yürüyüş yapmak ve tarihi evleri gezmek çok keyiflidir. Yaz aylarında sıcaklık 30-35°C\'ye ulaşabilir, ancak nem oranı düşük olduğu için katlanılabilir düzeydedir. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür; kış aylarında şehir ayrı bir güzellik kazansa da geziler için aralık-şubat arası pek uygun değildir.', 'Amasya\'ya en yakın havalimanı Amasya Merzifon Havalimanı\'dır. Havalimanı şehir merkezine yaklaşık 40 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Alternatif olarak Samsun Çarşamba Havalimanı (120 km) veya Tokat Havalimanı da kullanılabilir. Şehirlerarası otobüs terminali şehir merkezinin dışında olup belediye otobüsleri veya taksi ile merkeze ulaşılır. Amasya, Samsun-Sivas demiryolu hattı üzerindedir ve şehir merkezinde tren garı bulunur. Şehir içi ulaşımda minibüs, dolmuş ve belediye otobüsleri kullanılır. Tarihi yarımada, kaleler ve kaya mezarları yürüyerek gezilebilir, ancak yokuşlar nedeniyle rahat ayakkabı giyilmesi önerilir.', 'Amasya, tarihi boyunca Hititler, Frigler, Kimmerler, İskitler, Persler, Pontus Krallığı, Romalılar, Bizanslılar, Danişmentliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Pontus Krallığı döneminde başkent olmuş, Roma döneminde ise önemli bir kültür ve yönetim merkezi haline gelmiştir. Amasya, aynı zamanda Osmanlı İmparatorluğu\'nun kuruluş yıllarında şehzadelerin eğitim gördüğü önemli bir merkezdir. Kurtuluş Savaşı\'nın planlarının yapıldığı Amasya Genelgesi burada imzalanmıştır. Şehir, tarihi evleri ve kaya mezarlarıyla adeta bir açık hava müzesidir.', 'Amasya', '2026-04-08 23:20:51'),
(7, 'Ankara', 'İç Anadolu', 'default.jpg', 'Türkiye Cumhuriyetinin başkenti.', 'Ankara denince akla gelen ilk şey Anıtkabir\'dir (Mustafa Kemal Atatürk\'ün anıt mezarı). Bunun dışında Ankara Kalesi (şehrin simgesi, Roma ve Selçuklu döneminden kalma), Anadolu Medeniyetleri Müzesi (dünyanın en iyi arkeoloji müzelerinden), Eski TBMM Binası (Kurtuluş Savaşı Müzesi), Gençlik Parkı, Kuğulu Park, Seğmenler Parkı, Atakule, Kocatepe Camii (Türkiye\'nin en büyük camilerinden), Hacı Bayram Camii (Roma dönemi Augustus Tapınağı yanında), Roma Hamamı, Augustus Tapınağı, Julianus Sütunu ve Gordion Antik Kenti (Midas\'ın başkenti) mutlaka görülmelidir. Beypazarı tarihi evleri, peri bacaları (Kızılcahamam), Eymir ve Mogan gölleri de ziyaret edilebilir.', 'Ankara mutfağı, Orta Anadolu\'nun zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Ankara tava\" (kuzu etiyle yapılan bir güveç yemeği) gelir. \"Çubuk turşusu\", \"Beypazarı kurusu\" (cevizli, üzümlü bir hamur işi), \"Ankara simidi\", \"kızılcık şerbeti\", \"höşmerim\" (un, tereyağı, şekerle yapılan tatlı), \"cevizli bükme\", \"sızgıt böreği\" ve \"oğmaç çorbası\" yöresel lezzetlerdir. Beypazarı\'nda \"baklava\", \"güllaç\", \"macun\" ve \"pestil\" de meşhurdur. Ayrıca Ankara\'nın \"keçi tulum peyniri\" ve \"kavun\"u da ünlüdür.', 'Ankara\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Ankara Müzik Festivali\'dir (nisan-mayıs aylarında, klasik müzik ve caz ağırlıklı). Ankara Uluslararası Film Festivali (kasım ayında, sinema gösterimleri ve yarışmalar). Ankara Caz Festivali (mart ayında). Beypazarı Uluslararası Kültür ve Sanat Festivali (haziran ayında, yöresel lezzetler ve el sanatları). Ankara Kalesi Kültür ve Sanat Festivali (eylül ayında). Ayrıca Çubuk Turşu Festivali, Kalecik Bağ Bozumu Festivali ve Seğmenler Halk Oyunları Festivali de düzenlenir.', 'Ankara\'yı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, şehri gezmek için idealdir. Yaz aylarında sıcaklık 30-35°C\'ye ulaşabilir, ancak nem oranı düşük olduğu için katlanılabilir düzeydedir. Kışlar soğuk ve karlıdır, sıcaklık zaman zaman -10°C\'nin altına düşebilir; aralık-şubat arasında kalın giyinmek gerekir. Ankara\'nın kış aylarında da ayrı bir güzelliği vardır, özellikle kar altında Anıtkabir görülmeye değerdir.', 'Ankara\'ya hava yoluyla gelmek için Esenboğa Havalimanı kullanılır. Havalimanı şehir merkezine yaklaşık 30 km uzaklıkta olup havaş otobüsleri, belediye otobüsleri, taksi ve metro ile ulaşım sağlanır. Şehirlerarası otobüs terminali (AŞTİ) şehir merkezinde olup metro ve otobüslerle her yere bağlantılıdır. Ankara, Türkiye\'nin en önemli demiryolu merkezlerinden biridir; Yüksek Hızlı Tren (YHT) ile İstanbul, Eskişehir, Konya, Sivas gibi birçok ile doğrudan gidilir. Şehir içi ulaşımda metro, ankaray, belediye otobüsleri (EGO), minibüs, dolmuş ve taksi yaygın olarak kullanılır. Ankara\'nın toplu taşıma ağı oldukça gelişmiştir.', 'Ankara, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Galatlar, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Galatlar döneminde başkent olmuş, Roma döneminde \"Ancyra\" adıyla önemli bir merkez haline gelmiştir. Ankara, 23 Nisan 1920\'de Türkiye Büyük Millet Meclisi\'nin açılmasıyla Kurtuluş Savaşı\'nın merkezi olmuş, 13 Ekim 1923\'te ise Türkiye Cumhuriyeti\'nin başkenti ilan edilmiştir. Mustafa Kemal Atatürk\'ün şehre verdiği önemle birlikte Ankara, modern Türkiye\'nin simgesi haline gelmiştir.', 'Ankara', '2026-04-08 23:20:51'),
(8, 'Antalya', 'Akdeniz', 'antalya.jpg', 'Turizmin başkenti.', 'Antalya denince akla gelen ilk şeyler: Konyaaltı ve Lara Plajları, Düden Şelalesi, Kurşunlu Şelalesi, Karpuzkaldıran Şelalesi, Olympos (Yanartaş), Çıralı Plajı (Caretta caretta kaplumbağalarının yuvalama alanı), Phaselis Antik Kenti, Aspendos Antik Tiyatrosu (dünyanın en iyi korunmuş Roma tiyatrolarından), Perge Antik Kenti, Side Antik Kenti, Termessos Antik Kenti, Patara Plajı ve Antik Kenti, Myra Antik Kenti (Kaya Mezarları), Alanya Kalesi, Damlataş Mağarası, Dim Mağarası, Manavgat Şelalesi, Köprülü Kanyon, Saklıkent Kanyonu (sadece Kaş\'ta değil, Antalya\'da da var), Tahtalı Dağı (teleferik), Antalya Akvaryumu, Antalya Müzesi (dünyaca ünlü), Kaleiçi (tarihi marina, Osmanlı evleri), Yivli Minare, Hadrian Kapısı, Atatürk Evi Müzesi ve Karain Mağarası (tarih öncesi yerleşim) mutlaka görülmelidir.', 'Antalya mutfağı, Akdeniz\'in zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Antalya piyazı\" (tahinli, sirke ve sarımsaklı, yumurta ile süslenmiş kuru fasulye salatası) gelir. \"Şiş köfte\", \"taze fasulye kavurması\", \"enginar dolması\", \"Kabak çiçeği dolması\", \"hibeş\" (tahinli, kimyonlu, sarımsaklı ezme), \"çökertme kebabı\", \"tandır kebap\", \"Alanya bohçası\" (peynirli veya kıymalı hamur işi), \"ıspanaklı börek\", \"güveç\" ve \"Elmalı köftesi\" yöresel lezzetlerdir. Tatlı olarak \"portakal tatlısı\", \"incir tatlısı\", \"Kabak tatlısı\" ve \"cevizli sucuk\" meşhurdur. Antalya\'nın \"Finike portakalı\", \"Alanya muzu\", \"Elmalı elması\", \"Kaş peyniri\" ve \"akavita\" (anasonlu içki) da ünlüdür.', 'Antalya\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Antalya Altın Portakal Film Festivali\'dir (ekim ayında, Türkiye\'nin en prestijli film festivallerinden). Aspendos Uluslararası Opera ve Bale Festivali (haziran-eylül ayları arasında, Aspendos Antik Tiyatrosu\'nda düzenlenir). Uluslararası Antalya Piyano Festivali (kasım ayında). Antalya Caz Festivali (mart ayında). Alanya Uluslararası Kültür ve Sanat Festivali (mayıs ayında). Side Kültür ve Sanat Festivali (eylül ayında). Kumluca Portakal Festivali (nisan ayında). Elmalı Kültür ve Elma Festivali (ekim ayında). Kaş Kekova Dalış ve Doğa Festivali (haziran ayında). Ayrıca Caretta caretta kaplumbağaları için Çıralı\'da etkinlikler düzenlenir.', 'Antalya\'yı ziyaret etmek için en iyi zaman ilkbahar (mart-mayıs) ve sonbahar (eylül-kasım) aylarıdır. Bu dönemde hava ılımandır, deniz suyu sıcaklığı yüzmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 35-40°C\'ye ulaşabilir, nem oranı yüksektir, bu nedenle sıcaktan hoşlanmayanlar için ilkbahar ve sonbahar daha uygundur. Kışlar ılıman geçer, sıcaklık genelde 10-15°C arasındadır, yağışlı olabilir. Antalya\'yı yılın her mevsimi ziyaret etmek mümkündür, ancak yaz aylarında turist yoğunluğu en üst seviyededir.', 'Antalya\'ya hava yoluyla gelmek için Antalya Havalimanı kullanılır. Havalimanı şehir merkezine 15 km uzaklıkta olup havaş otobüsleri, belediye otobüsleri, tramvay ve taksi ile ulaşım sağlanır. Alanya Gazipaşa Havalimanı da bölge için alternatiftir. Şehirlerarası otobüs terminali (Antalya Otogarı) şehir merkezine tramvay ve otobüslerle bağlıdır. Antalya, şehir içi ulaşımda tramvay (Antray), otobüs, minibüs, dolmuş ve taksi gibi seçeneklere sahiptir. Antalya\'da yaygın bir deniz otobüsü ve feribot ağı da vardır (örneğin Antalya-Alanya arası). Demiryolu bağlantısı yoktur, ancak şehir içi tramvay hattı mevcuttur. Bölgedeki antik kentler, plajlar ve doğal güzellikler için araç kiralamak en iyi seçenektir.', 'Antalya, tarihi boyunca Likyalılar, Pamfilyalılar, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. MÖ 2. yüzyılda Bergama Kralı II. Attalos tarafından kurulmuş ve \"Attaleia\" adını almıştır. Roma döneminde önemli bir liman kenti haline gelmiştir. Selçuklu döneminde Alâeddin Keykubad tarafından fethedilmiş ve kış başkenti olarak kullanılmıştır. Günümüzde Türkiye\'nin en önemli turizm merkezlerinden biridir ve her yıl milyonlarca turisti ağırlamaktadır.', 'Antalya', '2026-04-08 23:20:51'),
(9, 'Artvin', 'Karadeniz', 'artvin.jpg', 'Yeşilin her tonunu görebileceğiniz şehir.', 'Artvin denince akla gelen ilk şeyler: Karagöl-Sahara Milli Parkı (büyüleyici bir krater gölü ve yaylalar), Borçka Karagölü, Deriner Barajı (Türkiye\'nin en yüksek barajı), Mençuna Şelalesi, Camili Köyü (Macerahevil, Türkiye\'nin ilk biyosfer rezerv alanı), Artvin Kalesi, Livane Kalesi, Cehennem Deresi Kanyonu, Papart Yaylası, Kafkasör Yaylası (boğa güreşleriyle ünlü), Macahel Bölgesi (eski Gürcü köyleri, taş evler), Düzköy (Küçük Kafkasör), Atatepe Gözlem Terası (şehri kuşbakışı görmek için), Şavşat Kalesi, Meydancık ve Uğur Şelalesi, Maral Şelalesi, Efeler Yaylası, Otingo Göleti, Maden Köprüsü (Demirköprü) ve Hatila Vadisi Milli Parkı (özellikle sonbahar renkleriyle ünlü) mutlaka görülmelidir.', 'Artvin mutfağı, Karadeniz ve Gürcü mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Artvin pidesi\" (sandviç şeklinde, peynirli, kıymalı veya kavurmalı) gelir. \"Muhlama\" (kuymak; mısır unu, yağ ve peynirle yapılır), \"laz böreği\" (kremalı baklava), \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı), \"ısırgan otu çorbası\", \"kavurma\", \"etli ekmek\", \"tavalı\", \"kuru fasulye\", \"karabuğday çorbası\", \"mıhlama\", \"haşıl\" ve \"kaygana\" (mısır unlu omlet benzeri) yöresel lezzetlerdir. Artvin\'in balı, \"cevizli sucuk\", \"pestil\" ve \"köme\" (cevizli pestil) tatlıları meşhurdur. Ayrıca \"kızılcık şerbeti\" ve \"kestane\" de ünlüdür.', 'Artvin\'de birçok yayla şenliği ve festival düzenlenmektedir. En önemlilerinden biri Kafkasör Yaylası Boğa Güreşi Festivali\'dir (temmuz ayının 1. haftası, ünlü boğa güreşleri, konserler ve halk oyunları). Borçka Karagöl Kültür ve Sanat Festivali (temmuz-ağustos aylarında). Şavşat Kültür ve Doğa Sporları Festivali (ağustos ayında). Artvin Çoruh Üniversitesi Kültür ve Sanat Festivali (mayıs ayında). Hopa Kültür ve Sanat Festivali (ağustos ayında). Arhavi Kültür ve Çay Festivali (haziran ayında). Macahel Kültür Festivali (temmuz ayında). Ayrıca bal hasadı döneminde Artvin Bal Festivali düzenlenir.', 'Artvin\'i ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, yaylalar yeşildir ve doğa yürüyüşleri için idealdir. Özellikle temmuz ve ağustos aylarında yayla şenlikleri düzenlenir. İlkbahar (nisan-mayıs) yağışlı ve çamurlu olabilir, ancak doğanın canlandığı güzel bir dönemdir. Sonbahar (ekim-kasım) yağışlıdır ve yaprakların döküldüğü hüzünlü bir güzellik sunar. Kışlar çok sert ve karlıdır; aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez.', 'Artvin\'e en yakın havalimanı Hopa veya Arhavi yakınlarındaki yeni yapılan Artvin Hopa Havalimanı\'dır. Havalimanı şehir merkezine yaklaşık 90 km uzaklıktadır. Alternatif olarak Trabzon Havalimanı (180 km) veya Rize-Artvin Havalimanı (120 km) kullanılabilir. Havalimanlarından havaş otobüsleri veya taksi ile ulaşım sağlanır. Şehirlerarası otobüs terminali (Artvin Otogarı) şehir merkezindedir. Artvin\'e karayoluyla ulaşım yaygındır. Şehir içi ulaşımda minibüs, dolmuş ve belediye otobüsleri kullanılır. Artvin\'in yaylaları ve doğal güzelliklerine ulaşmak için araç kiralamak veya turları tercih etmek önerilir. Kış aylarında yollar zaman zaman kapandığı için seyahat planlaması dikkatli yapılmalıdır.', 'Artvin, tarihi boyunca Kolhitler, Urartular, Kimmerler, İskitler, Romalılar, Bizanslılar, Gürcüler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi İpek Yolu üzerinde önemli bir durak olmuştur. Osmanlı döneminde önce Erzurum\'a, daha sonra Trabzon\'a bağlanmıştır. 1877-1878 Osmanlı-Rus Savaşı (93 Harbi) sonrasında Rus işgaline uğramış, 1918\'de geri alınmıştır. Cumhuriyet döneminde il statüsü kazanmıştır. Artvin, doğal güzellikleri, yaylaları ve tarihi yapılarıyla öne çıkan bir Karadeniz ilidir.', 'Artvin', '2026-04-08 23:20:51'),
(10, 'Aydın', 'Ege', 'aydin.jpg', 'Ege Bölgesinin incisi.', 'Aydın denince akla gelen ilk şeyler: Afrodisias Antik Kenti (UNESCO Dünya Mirası, Afrodit Tapınağı ve antik stadyumuyla ünlü), Miletos Antik Kenti (İyonya\'nın en önemli liman kenti, Büyük Tiyatro), Didim Apollon Tapınağı (dünyanın en iyi korunmuş antik tapınaklarından), Priene Antik Kenti (tarihi kent planıyla ünlü), Alinda Antik Kenti, Nysa Antik Kenti, Magnesia Antik Kenti, Dilek Yarımadası-Büyük Menderes Deltası Milli Parkı (vahşi plajlar, yürüyüş parkurları, yaban hayatı), Aydın Kalesi, Güvercinada Kalesi, Kuşadası\'nın plajları (Kadınlar Denizi, Yavansu, Kustur, Sevgi Plajı), Adaland Su Parkı, Kuşadası Marina, Öküz Mehmed Paşa Kervansarayı, Nasuh Paşa Külliyesi, Aydın Arkeoloji Müzesi, Çine ve Söke\'deki tarihi köprüler, Bafa Gölü (Latmos Herakleia Antik Kenti, Kapıkırı köyü, kaya resimleri) ve Karpuzlu\'daki Alabanda Antik Kenti mutlaka görülmelidir.', 'Aydın mutfağı, Ege\'nin zengin ve sağlıklı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Aydın köftesi\" (sadece kıyma, tuz ve kimyonla yapılır, katkısız) gelir. \"Çöp şiş\", \"incir dolması\" (kuru incir içine ceviz konup pişirilir), \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"ot kavurması\" (arapsaçı, ebegümeci, ısırgan gibi otlar), \"cılbır\" (yoğurtlu yumurta), \"çalkama\" (un, yağ, peynirle yapılır), \"kuzu tandır\", \"keşkek\", \"paşa böreği\", \"yuvarlama\", \"kabak çiçeği dolması\", \"söğürmeli köfte\" ve \"Aydın şambalısı\" (tatlı) yöresel lezzetlerdir. Aydın\'ın \"inciri\", \"kestane balı\", \"zeytini\", \"zeytinyağı\", \"Bozdoğan peyniri\", \"Nazilli kumaşı\" (dokuma) ve \"Çine tulum peyniri\" de ünlüdür.', 'Aydın\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Kuşadası Altın Güvercin Müzik Festivali (yaz aylarında, Kuşadası\'nda konserler ve etkinlikler). Aydın Uluslararası Kültür ve Sanat Festivali (eylül ayında). Didap (Didim Kültür ve Turizm Festivali) (eylül ayında). Afrodisias Kültür ve Sanat Festivali (ağustos ayında, antik tiyatroda konserler). Nazilli Kültür ve Turizm Festivali (mayıs ayında). Çine Kültür ve Turizm Festivali (eylül ayında). Söke Pamuk Festivali (ekim ayında). İncir Festivali (ağustos-eylül aylarında). Kuşadası Kaktüs ve Sukulent Festivali (nisan ayında). Ayrıca Kuşadası\'nda Martı Festivali ve yamaç paraşütü etkinlikleri de düzenlenir.', 'Aydın\'ı ziyaret etmek için en iyi zaman ilkbahar (mart-mayıs) ve sonbahar (eylül-kasım) aylarıdır. Bu dönemde hava ılımandır, doğa canlıdır, tarihi yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 35-40°C\'ye ulaşabilir, nem oranı yüksektir, bu nedenle sıcaktan hoşlanmayanlar için ilkbahar ve sonbahar daha uygundur. Kışlar ılıman ve yağışlı geçer, sıcaklık genelde 8-15°C arasındadır. Aydın\'ı yılın her mevsimi ziyaret etmek mümkündür, ancak yaz aylarında turist yoğunluğu fazladır.', 'Aydın\'a hava yoluyla gelmek için İzmir Adnan Menderes Havalimanı (100 km) veya Bodrum-Milas Havalimanı (120 km) kullanılır. Havalimanlarından havaş otobüsleri, otobüsler veya taksi ile ulaşım sağlanır. Aydın\'a şehirlerarası otobüs terminali (Aydın Otogarı) şehir merkezindedir. Aydın, İzmir-Denizli demiryolu hattı üzerindedir ve Yüksek Hızlı Tren (YHT) projeleriyle bağlantılıdır (İzmir-Aydın banliyö hattı mevcuttur). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kuşadası, Didim, Söke, Nazilli gibi ilçelere minibüslerle rahat ulaşım vardır. Antik kentler, milli parklar ve turistik bölgeler için araç kiralamak en iyi seçenektir.', 'Aydın, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, İyonya uygarlığının önemli merkezlerinden biri olmuştur. Adını, Lidyalılar döneminde yaşamış bir hükümdar olan Tralleis\'ten almıştır. Osmanlı döneminde \"Aydın Vilayeti\" olarak önemli bir yönetim merkezi haline gelmiştir. Kurtuluş Savaşı\'nda Yunan işgaline karşı verilen mücadelede önemli bir rol oynamıştır. Günümüzde tarım, turizm ve sanayiyle öne çıkan bir Ege ilidir.', 'Aydın', '2026-04-08 23:20:51'),
(11, 'Ardahan', 'Doğu Anadolu', 'ardahan.jpg', 'Çıldır Gölü ile ünlü.', 'Ardahan denince akla gelen ilk şeyler: Çıldır Gölü (kışın donduğunda üzerinde yürüyüş yapılabilir, atlı kızaklar), Kura Nehri, Ardahan Kalesi (Şeytan Kalesi olarak da bilinir), Şeytan Kalesi (tarihi Gürcü kalesi), Yalnızçam Dağları, Allahuekber Dağları (Sarıkamış Harekatı\'nın geçtiği yer), Göle\'deki tariki kiliseler ve köprüler, Damal\'daki Atatürk silüeti (belirli bir açıdan bakıldığında Atatürk\'ün profili görülür), Aktaş Sınır Kapısı (Gürcistan\'a açılan), Cıncıva Deresi, Posof Bölgesi (yaylalar, kiliseler), İsa Şelalesi, Meşeli Şelalesi, Hasköy Kilisesi, Kılıç Köyü Kilisesi, Balık Gölü ve Ardahan\'ın yüksek yaylaları (Sazlı, Küçük, Göle yaylaları) mutlaka görülmelidir. Kış turizmi için Yalnızçam Kayak Merkezi de ziyaret edilebilir.', 'Ardahan mutfağı, Doğu Anadolu ve Kafkas mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Ardahan etli ekmek\" gelir. \"Kaz eti\" (özellikle kış aylarında, fırında veya tandırda pişirilir), \"keledoş\" (nohutlu, etli, yoğurtlu yemek), \"haşıl\" (unlu, tereyağlı, mısırlı çorba), \"çortan çorbası\" (yoğurtlu, nane, un çorbası), \"kuru kavurma\", \"yayla çorbası\", \"kaymaklı mantı\", \"kıymalı patates oturtma\", \"Ardahan köftesi\", \"etli tava\", \"yumurtalı ekmek\", \"ciğer sarma\" ve \"katmer\" yöresel lezzetlerdir. Ardahan\'ın \"balı\", \"kaymağı\", \"kaşar peyniri\", \"çökelek\", \"kavut\" (kavrulmuş un, şeker, yağ), \"pestil\" ve \"cevizli sucuk\" tatlıları da meşhurdur. Ayrıca Ardahan\'da yetişen \"yabani mantar\" ve \"kuzukulağı\" da tüketilir.', 'Ardahan\'da birçok yayla şenliği ve festival düzenlenmektedir. En önemlilerinden biri Uluslararası Ardahan Kültür ve Sanat Festivali\'dir (ağustos ayında, konserler, halk oyunları, yöresel lezzetler). Çıldır Gölü Kış Festivali (şubat ayında, donmuş gölde kızak çekme, buz hokeyi, at yarışları). Damal Atatürk\'e Sayfa ve Kültür Festivali (temmuz ayında, Atatürk silüetinin görüldüğü alanda etkinlikler). Göle Kültür ve Yayla Şenliği (temmuz ayında). Posof Kültür ve Sanat Festivali (ağustos ayında). Yalnızçam Kayak ve Doğa Sporları Festivali (kış aylarında). Ayrıca Ardahan Bal Festivali (bal hasadı döneminde) düzenlenir.', 'Ardahan\'ı ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, yaylalar yeşildir ve doğa yürüyüşleri için idealdir. Sıcaklık genelde 15-25°C arasındadır. Kışlar çok sert ve karlıdır; sıcaklık -30°C\'nin altına düşebilir, bu nedenle aralık-şubat arasında seyahat önerilmez. Ancak kış sporları için (kayak) kış ayları tercih edilebilir. İlkbahar (nisan-mayıs) yağışlı ve çamurlu, sonbahar (eylül-ekim) ise soğuk ve rüzgarlıdır. Ardahan\'a gitmek için en uygun zaman temmuz ve ağustos aylarıdır.', 'Ardahan\'a en yakın havalimanı Kars Havalimanı\'dır (yaklaşık 100 km). Havalimanından havaş otobüsleri veya taksi ile Ardahan\'a ulaşılır. Ayrıca Erzurum Havalimanı (180 km) da kullanılabilir. Ardahan\'ın kendi havalimanı (Ardahan Göle Havalimanı) yapım aşamasındadır. Şehirlerarası otobüs terminali (Ardahan Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Kars\'tadır. Şehir içi ulaşımda minibüs, dolmuş ve taksi kullanılır. Çıldır Gölü, Yalnızçam, Posof gibi uzak bölgelere gitmek için araç kiralamak veya turları tercih etmek önerilir. Kış aylarında yollar zaman zaman kapandığı için seyahat planlaması dikkatli yapılmalıdır.', 'Ardahan, tarihi boyunca Hurriler, Urartular, İskitler, Persler, Romalılar, Bizanslılar, Gürcüler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi İpek Yolu üzerinde önemli bir durak olmuştur. 1877-1878 Osmanlı-Rus Savaşı (93 Harbi) sonrasında Rus işgaline uğramış, 1918\'de geri alınmış, 1921\'de imzalanan Moskova Antlaşması ile Türkiye sınırları içinde kalmıştır. Cumhuriyet döneminde önce Kars\'a bağlanmış, 1992 yılında il statüsü kazanmıştır. Ardahan, doğal güzellikleri, yaylaları ve kış sporlarıyla öne çıkan bir Doğu Anadolu ilidir.', 'Ardahan', '2026-04-08 23:20:51'),
(12, 'Balıkesir', 'Ege', 'balikesir.jpg', 'Ayvalık ve kazdağlarıyla ünlü.', 'Balıkesir denince akla gelen ilk şeyler: Cunda Adası (Alibey Adası, taş evler, dar sokaklar, Taksiyarhis Kilisesi), Ayvalık (tarihi Rum evleri, saat kulesi, plajlar, Ayvalık Adaları), Sarımsaklı Plajı, Altınoluk Plajı, Akçay, Ören, Güre Plajı, Erdek Plajları, Marmara Adası, Avşa Adası, Ekinlik Adası, Paşalimanı Adası, Kuş Cenneti Milli Parkı (Manyas Kuş Gölü, 250\'den fazla kuş türü), Kaz Dağları (İda Dağı, mitolojide önemli, doğa yürüyüşleri, şelaleler), Hasan Boğuldu Şelalesi, Sütüven Şelalesi, Zeytinli Ada (Bandırma), Balıkesir Kalesi (tarihi surlar), Kuvayı Milliye Müzesi, Balıkesir Arkeoloji Müzesi, Gönen Kaplıcaları, Manyas Kaplıcaları, Edremit Körfezi, Kazdağı Göknarı Milli Parkı, Sarıkız Tepesi, Zeus Sunağı (Kaz Dağları\'nda), Antandros Antik Kenti, Adramytteion Antik Kenti, Kyzikos Antik Kenti (Erdek), Daskyleion Antik Kenti (Bandırma), Parion Antik Kenti (Bigadiç) ve Gönen İkiz Köprüler mutlaka görülmelidir.', 'Balıkesir mutfağı, Marmara ve Ege mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Balıkesir köfte\" gelir. \"Höşmerim\" (un, tereyağı, şekerle yapılan bir tatlı), \"sarımsaklı köfte\", \"bandırma kebabı\", \"kapıdağ peyniri\", \"çanakkale tulum peyniri\", \"güveç\", \"kuzu tandır\", \"ayvalık tostu\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"ot kavurması\", \"keşkek\", \"ekşili köfte\", \"kaymaklı mantı\", \"balıkesir mantısı\", \"höştük çorbası\", \"kağıt kebabı\", \"sütlü çorba\" yöresel lezzetlerdir. Tatlı olarak \"sütlü kadayıf\", \"revani\", \"kalburabastı\", \"kestane şekeri\", \"cevizli sucuk\" ve \"ayvalık çökertme\" meşhurdur. Balıkesir\'in \"zeytini\", \"zeytinyağı\", \"susamı\", \"haşhaşı\", \"balı\", \"Manyas tulum peyniri\", \"Edremit yeşil zeytini\" ve \"Burhaniye kırmızı zeytini\" de ünlüdür.', 'Balıkesir\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Ayvalık Müzik Festivali (temmuz-eylül aylarında, klasik müzik ve caz ağırlıklı). Balıkesir Uluslararası Altın Yumruk Kültür ve Sanat Festivali (eylül ayında). Ayvalık Zeytin Hasadı Festivali (ekim-kasım aylarında). Kazdağları Kültür ve Doğa Sporları Festivali (haziran ayında). Bandırma Kültür ve Turizm Festivali (temmuz ayında). Erdek Kültür ve Turizm Festivali (ağustos ayında). Manyas Kuş Cenneti Festivali (nisan ayında). Gönen Kaplıca ve Termal Turizm Festivali (mart ayında). Susurluk Çay ve Kültür Festivali (mayıs ayında). Balıkesir Gençlik ve Spor Festivali (yaz aylarında). Ayrıca Burhaniye Kırmızı Zeytin Festivali ve Edremit Yeşil Zeytin Festivali düzenlenir.', 'Balıkesir\'i ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, doğa canlıdır, plajlar ve tarihi yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 30-35°C\'ye ulaşabilir, ancak deniz suyu sıcaklığı yüzmek için idealdir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 5-12°C arasındadır. Balıkesir\'i özellikle yaz aylarında Ayvalık, Cunda (Alibey) Adası, Ören, Altınoluk, Akçay, Burhaniye, Erdek, Marmara Adası gibi sahil ilçeleri için ziyaret etmek idealdir. Kış aylarında ise termal turizm (Gönen, Manyas) öne çıkar.', 'Balıkesir\'e hava yoluyla gelmek için Balıkesir Koca Seyit Havalimanı (Edremit Körfezi) kullanılır. Havalimanı, Ayvalık ve Edremit ilçelerine yakındır. Ayrıca Balıkesir Merkez Havalimanı da mevcuttur. Havalimanlarından havaş otobüsleri veya taksi ile ulaşım sağlanır. Balıkesir\'e şehirlerarası otobüs terminali (Balıkesir Otogarı) şehir merkezindedir. Balıkesir, İzmir-Bandırma demiryolu hattı üzerindedir ve Yüksek Hızlı Tren (YHT) ile İstanbul, Ankara, Eskişehir, Konya gibi illere bağlantılıdır. Bandırma-İstanbul feribot seferleri de vardır (İDO). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ayvalık, Cunda, Edremit, Akçay, Altınoluk, Burhaniye, Gömeç, Erdek, Bandırma, Manyas gibi ilçelere minibüslerle rahat ulaşım vardır. Adalara (Marmara, Avşa, Ekinlik) feribot seferleri mevcuttur.', 'Balıkesir, tarihi boyunca Misyalılar, Lidyalılar, Persler, Romalılar, Bizanslılar, Karesioğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, Misya uygarlığının önemli merkezlerinden biri olmuştur. 14. yüzyılda Karesioğulları Beyliği\'nin başkenti olan Balıkesir, daha sonra Osmanlı topraklarına katılmıştır. Kurtuluş Savaşı\'nda Balıkesir Kongresi ile önemli bir direniş merkezi olmuştur. Günümüzde hem Marmara hem de Ege bölgesinde toprakları bulunan, tarım, turizm ve sanayiyle öne çıkan bir ildir.', 'Balıkesir', '2026-04-08 23:20:51'),
(13, 'Bartın', 'Karadeniz', 'bartin.jpg', 'Amasra ile ünlü.', 'Bartın denince akla gelen ilk şeyler: Amasra (tarihi yarımada, kalesi, plajları, limanı, Çekiciler Çarşısı, Fatih Camii, Amasra Müzesi, Kemere Köprüsü, Bedesten, Amasra Evleri, Boztepe, Amasra Kalesi, Ağlayan Ağaç, Çobanlar Koyu), Bartın Kalesi, Bartın Çayı (kano ve tekne turları, yürüyüş yolları), Kuşkayası Yol Anıtı (Roma dönemi, Amasra yolu üzerinde), İnkumu Plajı, Boğaz Plajı, Çakraz Plajı, Güzelcehisar Plajı (Fosil Kumsalı), Kızılkum Plajı, Tekkeönü Plajı, Gümüşlük Plajı, Tavşan Adası (Amasra yakınları), Ahatlar Köyü (yayla evleri, doğa yürüyüşleri), Sakahoca Köyü (yayla), Ulukaya Şelalesi (Arıt köyü yakınları), Kıbrısçık Şelalesi, Sadağ Kanyonu, Kocareis Şelalesi, Çakraz Şelalesi, Değirmen Şelalesi, Göldağı Yaylası, Karagöl (yayla gölü), Bartın Arkeoloji Müzesi, Bartın Kent Ormanı, Çaydıran Şelalesi, Kozcagöz Şelalesi, Hisartepe (Bartın manzarası) ve Kurucaşile ilçesindeki tarihi kiliseler ve kaleler mutlaka görülmelidir.', 'Bartın mutfağı, Karadeniz mutfağının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Bartın köftesi\" gelir. \"Muhlama\" (kuymak; mısır unu, yağ ve peynirle yapılır), \"kaldirik\" (kaldirik otu yemeği), \"ısırgan otu çorbası\", \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı), \"cılbır\" (yoğurtlu yumurta), \"etli ekmek\", \"kavurma\", \"tavalı\", \"kuru fasulye\", \"fasulye tavalı\", \"yumurtalı ekmek\", \"ciğer sarma\", \"hamsi buğulama\", \"hamsi tava\", \"hamsili ekmek\", \"pide\", \"çörek\", \"bezdi\", \"yufka ekmeği\" yöresel lezzetlerdir. Tatlı olarak \"kestane şekeri\", \"cevizli sucuk\", \"pestil\", \"köme\", \"un helvası\", \"sütlü kadayıf\", \"kabak tatlısı\" ve \"hoşaf\" meşhurdur. Bartın\'ın \"balı\", \"cevizi\", \"fındığı\", \"mısır unu\", \"kuyruk yağı\", \"tahin\" ve \"pekmez\"i de ünlüdür.', 'Bartın\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Amasra Kültür ve Sanat Festivali\'dir (temmuz-ağustos aylarında, konserler, halk oyunları, yöresel lezzetler, deniz yarışları). Amasra Balıkçılık ve Deniz Festivali (haziran ayında). Bartın Kültür ve Sanat Festivali (eylül ayında). Kuşkayası Kültür ve Doğa Sporları Festivali (ağustos ayında). Kano ve Nehir Turları Etkinlikleri (bahar ve yaz aylarında). Ulukaya Şelalesi Doğa Yürüyüşü Festivali (mayıs ayında). Bartın Yayla Şenlikleri (temmuz-ağustos aylarında, Göldağı Yaylası ve diğer yaylalar). Ayrıca Bartın Gençlik ve Spor Festivali (yaz aylarında) düzenlenir.', 'Bartın\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, doğa canlıdır ve yemyeşildir. Yaz aylarında (haziran-eylül) sıcaklık 25-30°C arasındadır, nem oranı yüksektir, ancak deniz suyu sıcaklığı yüzmek için idealdir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 3-10°C arasındadır, kar yağışı nadirdir. Bartın\'ı özellikle ilkbahar ve yaz aylarında doğa yürüyüşleri, yayla gezileri, kano ve nehir turları için ziyaret etmek idealdir.', 'Bartın\'a en yakın havalimanı Zonguldak Havalimanı\'dır (Çaycuma ilçesi, yaklaşık 40 km). Havalimanından havaş otobüsleri veya taksi ile Bartın\'a ulaşılır. Ayrıca Ankara Esenboğa Havalimanı (250 km) veya İstanbul Sabiha Gökçen Havalimanı (350 km) da kullanılabilir. Bartın\'a şehirlerarası otobüs terminali (Bartın Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Zonguldak\'tadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Amasra, Kurucaşile, Çakraz, İnkumu gibi ilçe ve plajlara minibüslerle rahat ulaşım vardır. Amasra\'nın tarihi yarımadası yürüyerek gezilebilir, ancak yokuşlar nedeniyle rahat ayakkabı giyilmesi önerilir.', 'Bartın, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, Paflagonya uygarlığının önemli merkezlerinden biri olmuştur. Bartın Çayı\'nın denize döküldüğü noktada kurulan şehir, tarihi boyunca önemli bir liman ve ticaret merkezi olmuştur. Osmanlı döneminde Bolu\'ya bağlı bir kaza olan Bartın, Cumhuriyet döneminde Zonguldak\'a bağlanmış, 1991 yılında il statüsü kazanmıştır. Bartın, Karadeniz\'in en yeşil ve temiz illerinden biridir.', 'Bartın', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(14, 'Batman', 'Güneydoğu Anadolu', 'batman.jpg', 'Hasankeyf ile ünlü.', 'Batman denince akla gelen ilk şeyler: Hasankeyf (12.000 yıllık tarihi, Dicle Nehri kıyısında, Artuklu ve Eyyubi dönemi yapıları, Hasankeyf Kalesi, El Rizk Camii, Sultan Süleyman Camii, Zeynel Bey Türbesi, Küçük Saray, Köprüler, mağara evler, su kemerleri, sarnıçlar, minareler, Hasankeyf Müzesi, Ilısu Barajı nedeniyle taşınan tarihi eserler, yeni Hasankeyf\'te kültür parkı), Malabadi Köprüsü (dünyanın en büyük taş kemer köprülerinden biri, 1147 yılında yapılmış), Batman Çayı, Dicle Nehri, Batman Müzesi (Hasankeyf ve bölge eserleri), Atatürk Parkı, Çamlı Tepe, Raman Dağı (petrol kuleleri), Beşiri\'deki Mor Yakup Kilisesi (Süryani kilisesi), Gercüş ilçesi (doğal güzellikleri, tarihi mağaralar), Sason ilçesi (yaylalar, dağlık alanlar, Küpeli Mağarası, tarihi kiliseler), Kozluk ilçesi (Hızır Bey Cami, Süryani kiliseleri), Zeynel Bey Türbesi (Hasankeyf\'ten taşınan eserler) ve Ilısu Barajı ve Hidroelektrik Santrali (Türkiye\'nin en büyük barajlarından biri, Hasankeyf\'in sular altında kalmasına neden olan proje) mutlaka görülmelidir.', 'Batman mutfağı, Güneydoğu Anadolu\'nun zengin ve baharatlı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Batman burma kadayıf\" (tatlı) gelir. \"Kaburga dolması\" (kuzu kaburgasının içine pirinç, et, baharat doldurularak yapılır), \"Batman tava\", \"içli köfte\", \"kibbe\", \"lahmacun\", \"çiğ köfte\" (etli veya etsiz), \"kuzu tandır\", \"perde pilavı\", \"duvaklı pilav\", \"büryan\" (kuzu etinin tandırda pişirilmesi), \"ekşili köfte\", \"mercimek köftesi\", \"patlıcan kebabı\", \"ciğer kebabı\", \"kuzu şiş\", \"soğan kebabı\", \"sarma\", \"dolma\", \"çorbalar\" (mercimek, ezogelin, yayla) yöresel lezzetlerdir. Tatlı olarak \"kadayıf\", \"baklava\", \"şöbiyet\", \"künefe\", \"Burma kadayıf\" ve \"cevizli sucuk\" meşhurdur. Batman\'ın \"Hasankeyf peyniri\", \"balı\", \"karpuzu\", \"üzümü\" ve \"pestil\"i de ünlüdür.', 'Batman\'da birçok festival düzenlenmektedir. En önemlilerinden biri Hasankeyf Kültür ve Sanat Festivali\'dir (mayıs veya eylül aylarında, tarihi Hasankeyf\'te konserler, halk oyunları, yöresel lezzetler, paneller). Malabadi Kültür ve Turizm Festivali (ağustos ayında, Malabadi Köprüsü yakınlarında). Batman Kültür ve Sanat Festivali (ekim ayında). Batman Petrol ve Sanayi Festivali (eylül ayında). Sason Yayla Şenlikleri (temmuz-ağustos aylarında, Sason ilçesinde). Gercüş Kültür ve Doğa Sporları Festivali (mayıs ayında). Beşiri Kültür ve Sanat Festivali (haziran ayında). Ayrıca Batman\'da düzenlenen \"Hasankeyf Koşusu\" (maraton) ve \"Doğa Yürüyüşleri\" de ilgi çeker.', 'Batman\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 20-30°C arasındadır. Yaz aylarında (haziran-eylül) sıcaklık 40°C\'nin üzerine çıkabilir, bu nedenle sıcaktan hoşlanmayanlar için ilkbahar ve sonbahar idealdir. Kışlar ılıman geçer, sıcaklık genelde 2-10°C arasındadır, yağışlı olabilir. Batman\'ı ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır. Hasankeyf gezi için özellikle ilkbahar ve sonbahar idealdir.', 'Batman\'a hava yoluyla gelmek için Batman Havalimanı kullanılır. Havalimanı şehir merkezine yaklaşık 10 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Ayrıca Diyarbakır Havalimanı (100 km) da kullanılabilir. Batman\'a şehirlerarası otobüs terminali (Batman Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Batman, Kurtalan demiryolu hattının üzerindedir ve trenle de ulaşmak mümkündür (Diyarbakır, Elazığ, Malatya, Ankara bağlantılı). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Hasankeyf, Malabadi Köprüsü, Beşiri, Gercüş, Sason, Kozluk gibi ilçelere minibüslerle rahat ulaşım vardır. Hasankeyf\'e gitmek için özellikle yaz aylarında günübirlik turlar düzenlenir.', 'Batman, tarihi boyunca Hurriler, Mitanniler, Asurlular, Urartular, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Artuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi İpek Yolu üzerinde önemli bir durak olmuştur. 20. yüzyılda petrolün keşfiyle birlikte hızla gelişen Batman, 1950\'lerde Siirt\'e bağlı bir ilçe iken 1990 yılında il statüsü kazanmıştır. Adını, Batman Çayı\'ndan almıştır. Günümüzde Türkiye\'nin önemli petrol merkezlerinden biridir.', 'Batman', '2026-04-08 23:20:51'),
(15, 'Bayburt', 'Karadeniz', 'bayburt.jpg', 'Bayburt Kalesi ile ünlü.', 'Bayburt denince akla gelen ilk şeyler: Bayburt Kalesi (şehrin simgesi, şehre hakim bir tepede, Bizans ve Selçuklu dönemi, surlar, iç kale, zindanlar, sarnıçlar, manzara), Çoruh Nehri (nehir kenarında yürüyüş, piknik), Bayburt Ulu Camii (Selçuklu dönemi, ahşap işlemeleriyle ünlü), Sırakayalar Şelalesi (Kop Dağı eteklerinde, doğal güzellik), Kop Dağı (kış sporları, kayak, doğa yürüyüşleri, manzara), Aydıntepe Yeraltı Şehri (kaya oyma mekanlar, erken Hristiyan dönemi sığınak), Pulur Kanyonu (Kop Dağı yolu üzerinde, derin vadi, yürüyüş parkurları), Sütürgan Yaylası (yayla evleri, yayla şenlikleri), Helva Köyü (tarihi taş evler, doğa), Dede Korkut Türbesi (Dede Korkut\'un mezarı olduğuna inanılır), Korgan Köprüsü (tarihi taş köprü), Bayburt Müzesi (arkeolojik ve etnografik eserler), Baksı Müzesi (modern sanat müzesi, geleneksel el sanatları, halı dokuma, doğa manzarası, dünyaca ünlü), Çatalçeşme Yeraltı Şehri (yeni keşfedilen, kaya oyma), Varzahan Köyü (tarihi kilise kalıntıları), İnceburun Köprüsü, Çatalçeşme Köprüsü, Soğanlı Köyü (tarihi evler) ve Demirözü ilçesindeki tarihi yapılar mutlaka görülmelidir.', 'Bayburt mutfağı, Karadeniz ve Doğu Anadolu mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Bayburt çorbası\" (yöresel çorba) gelir. \"Bayburt kete\" (bir tür börek), \"Bayburt mantısı\" (etli, yoğurtlu, yağlı), \"Bayburt köftesi\", \"etli ekmek\", \"kavurma\", \"kuru kavurma\", \"haşıl\" (un, tereyağ, su), \"oğmaç çorbası\" (un, yumurta, yoğurt), \"herle\" (un, peynir, yağ), \"cılbır\" (yoğurtlu yumurta), \"pide\", \"çörek\", \"tava\", \"keşkek\", \"kurutulmuş sebze yemekleri\", \"yayla çorbası\", \"mercimek çorbası\", \"katmer\", \"gözleme\", \"sütlü çorba\", \"tarhana çorbası\" yöresel lezzetlerdir. Tatlı olarak \"un helvası\", \"kaygana\", \"höşmerim\", \"kadayıf\", \"baklava\", \"kestane şekeri\", \"cevizli sucuk\", \"pestil\" ve \"köme\" meşhurdur. Bayburt\'un \"balı\", \"cevizi\", \"fındığı\", \"keçi peyniri\", \"tulum peyniri\", \"yoğurdu\" ve \"tereyağı\" da ünlüdür.', 'Bayburt\'ta birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Bayburt Kültür ve Sanat Festivali\'dir (ağustos ayında, konserler, halk oyunları, yöresel lezzetler, panayırlar). Kop Dağı Kayak ve Doğa Sporları Festivali (kış aylarında, kayak yarışmaları, doğa yürüyüşleri). Aydıntepe Yeraltı Şehri Kültür ve Turizm Festivali (haziran ayında). Baksı Müzesi Kültür ve Sanat Festivali (yaz aylarında, sergiler, konserler, paneller). Sütürgan Yaylası Şenliği (temmuz ayında). Bayburt Gençlik ve Spor Festivali (yaz aylarında). Ayrıca Bayburt\'ta düzenlenen \"Çoruh Nehri Doğa Yürüyüşleri\" ve \"Bayburt Koşusu\" (maraton) da ilgi çeker.', 'Bayburt\'u ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-28°C arasındadır, yaylalar yeşildir ve doğa yürüyüşleri için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -20°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez. Bayburt\'u ziyaret etmek için en uygun zaman temmuz ve ağustos aylarıdır.', 'Bayburt\'a en yakın havalimanı Erzurum Havalimanı\'dır (yaklaşık 120 km). Havalimanından havaş otobüsleri veya taksi ile Bayburt\'a ulaşılır. Ayrıca Trabzon Havalimanı (150 km) veya Gümüşhane\'deki yeni yapılan havalimanı da kullanılabilir. Bayburt\'a şehirlerarası otobüs terminali (Bayburt Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Erzurum veya Gümüşhane\'deki ilçelerdedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Aydıntepe, Demirözü gibi ilçelere minibüslerle rahat ulaşım vardır. Kop Dağı, Baksı Müzesi, Sırakayalar Şelalesi, Pulur Kanyonu gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Bayburt, tarihi boyunca Hurriler, Hititler, Urartular, İskitler, Persler, Romalılar, Bizanslılar, Saltuklular, Mengücekliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Tarihi İpek Yolu üzerinde önemli bir durak olan Bayburt, stratejik konumu nedeniyle sık sık el değiştirmiştir. 11. yüzyılda Malazgirt Meydan Muharebesi\'nden sonra Türklerin eline geçmiştir. Osmanlı döneminde Erzurum\'a bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmış, 1927\'de Gümüşhane\'ye bağlanmış, 1989 yılında tekrar il olmuştur. Bayburt, doğal güzellikleri ve tarihi dokusuyla öne çıkan bir Doğu Karadeniz ilidir.', 'Bayburt', '2026-04-08 23:20:51'),
(16, 'Bilecik', 'Marmara', 'bilecik.jpg', 'Söğüt ve Osmanlı kuruluş toprakları.', 'Bilecik denince akla gelen ilk şeyler: Söğüt (Osmanlı Devleti\'nin kurulduğu topraklar, Ertuğrul Gazi Türbesi, Osman Gazi Türbesi, Orhan Gazi Cami, Söğüt Müzesi, Söğüt Evleri, Söğüt\'ün tarihi çarşısı, Ertuğrul Gazi\'nin kılıcının sergilendiği alan), Şeyh Edebali Türbesi (Bilecik merkez, Osmanlı Devleti\'nin manevi kurucularından, güzel manzara), Bilecik Kalesi (şehrin simgesi, Bizans dönemi, surlar, manzara), Orhan Gazi Cami (Bilecik merkez, tarihi cami), Pelitözü Göleti (piknik alanı, yürüyüş yolları, kafe, manzara), Osmaneli ilçesi (tarihi Osmaneli evleri, taş köprüler, Tarihi Çeşmeler, Osmaneli Müzesi, Sakarya Nehri kenarı), Gölpazarı ilçesi (tarihi evler, taş evler, Gölpazarı Mağaraları, yaylalar, el sanatları, seramik, çömlek), Pazaryeri ilçesi (yaylalar, şelaleler), Bozüyük ilçesi (İnönü Savaşları\'nın geçtiği topraklar, İnönü Savaşları Müzesi, Bozüyük Saat Kulesi, Metristepe, Bozüyük Kasım Köyü\'ndeki tarihi evler), Vezirhan Köyü (Roma dönemi köprüsü), Küçükelmalı Köyü (tarihi su kemeri), Harmankaya Kanyonu (doğa yürüyüşleri), Gölpazarı Camisi, Bilecik Arkeoloji Müzesi, Atatürk Evi Müzesi, Yağcılar Köyü\'ndeki tarihi kilise kalıntıları, Küçük Yayla Şelalesi ve Dodurga Yaylası mutlaka görülmelidir.', 'Bilecik mutfağı, Marmara, Karadeniz ve İç Anadolu mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Bilecik köftesi\" gelir. \"Güveç\" (etli, sebzeli, çömlekte pişirilir), \"keşkek\", \"yuvarlama\" (nohutlu, etli, bulgurlu yemek), \"erikli et yemeği\", \"nohutlu et\", \"fasulye\", \"etli ekmek\", \"tava\", \"kavurma\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tirit\", \"içli köfte\", \"mercimek köftesi\", \"sarma\", \"dolma\", \"çiğ börek\" yöresel lezzetlerdir. Tatlı olarak \"Bilecik baklavası\", \"cevizli baklava\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"pestil\", \"cevizli sucuk\", \"kabak tatlısı\" ve \"sütlaç\" meşhurdur. Bilecik\'in \"Osmaneli pirinci\", \"Gölpazarı tarhanası\", \"cevizi\", \"balı\", \"üzümü\", \"pekmezi\", \"tahini\" ve \"Söğüt ekmeği\" de ünlüdür.', 'Bilecik\'ta birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Ertuğrul Gazi\'yi Anma ve Söğüt Şenlikleri\'dir (eylül ayının ilk haftası, Söğüt\'te büyük törenler, konserler, halk oyunları, kortej, tarih canlandırmaları, panayır). Bilecik Kültür ve Sanat Festivali (haziran ayında, Bilecik merkez). Gölpazarı Kültür, Sanat ve El Sanatları Festivali (temmuz ayında, Gölpazarı\'nda seramik, çömlek sergileri, konserler). Osmaneli Kültür ve Pirinç Festivali (ağustos ayında, Osmaneli\'nde yöresel lezzetler, pirinç yemek yarışmaları). Pazaryeri Kültür ve Turizm Festivali (ağustos ayında). Bozüyük Kültür ve Sanat Festivali (eylül ayında). Ayrıca Bilecik\'te düzenlenen \"Uluslararası Bisiklet Turu\" ve \"Doğa Yürüyüşleri\" de ilgi çeker.', 'Bilecik\'i ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, doğa canlıdır, tarihi yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 28-33°C arasındadır, nem oranı düşüktür, katlanılabilir düzeydedir. Kışlar soğuk ve yağışlıdır, sıcaklık genelde 0-8°C arasındadır, zaman zaman kar yağışı görülür. Bilecik\'i özellikle ilkbahar ve yaz aylarında Söğüt, Osmaneli, Gölpazarı gibi ilçeleri gezmek için ziyaret etmek idealdir.', 'Bilecik\'e hava yoluyla gelmek için en yakın havalimanı Eskişehir Hasan Polatkan Havalimanı\'dır (yaklaşık 60 km). Havalimanından havaş otobüsleri veya taksi ile Bilecik\'e ulaşılır. Ayrıca İstanbul Sabiha Gökçen Havalimanı (200 km) veya İstanbul Havalimanı (250 km) da kullanılabilir. Bilecik\'e şehirlerarası otobüs terminali (Bilecik Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Bilecik, İstanbul-Ankara Yüksek Hızlı Tren (YHT) hattı üzerindedir. Bilecik tren garı şehir merkezine yakın olup YHT ile İstanbul, Ankara, Eskişehir, Konya gibi illere kolayca ulaşılır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Söğüt, Osmaneli, Gölpazarı, Bozüyük, Pazaryeri gibi ilçelere minibüslerle rahat ulaşım vardır.', 'Bilecik, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Osmanlı İmparatorluğu\'nun kuruluş yıllarında büyük önem taşıyan Bilecik, Osman Gazi\'nin fethettiği topraklar arasındadır. Şeyh Edebali\'nin türbesi burada bulunur ve Osmanlı Devleti\'nin temelleri bu topraklarda atılmıştır. Cumhuriyet döneminde il statüsü kazanmıştır. Bilecik, Marmara ve Karadeniz bölgeleri arasında geçiş noktasında yer alan, tarihi ve doğal güzellikleriyle öne çıkan bir ildir.', 'Bilecik', '2026-04-08 23:20:51'),
(17, 'Bingöl', 'Doğu Anadolu', 'bingol.jpg', 'Bingöl Dağları ile ünlü.', 'Bingöl denince akla gelen ilk şeyler: Bingöl Dağları (Türkiye\'nin en yüksek dağlarından, doğa yürüyüşleri, kamp), Yüzen Adalar (Sazlıca köyü yakınlarındaki Turna Gölü\'nde, bitki köklerinin oluşturduğu doğal adacıklar, dünyada nadir görülen bir doğa olayı), Turna Gölü (kuş cenneti, göçmen kuşlar, doğa manzarası, piknik), Çır Şelalesi (Bingöl\'ün en büyük şelalesi, doğal havuzlar), Oklavalı Şelalesi, Gayt Şelalesi, Kalkanlı Şelalesi, Ilıcalar Kaplıcası (termal su), Aya Yorgi Kilisesi (tarihi kilise), Çapakçur Vadisi (Bingöl Çayı boyunca, yürüyüş parkurları), Şeyh Abdullah Zaviyesi, Cemalettin Cami (tarihi cami), Bingöl Kalesi (şehir merkezinde, tarihi sur kalıntıları), Bingöl Müzesi (arkeolojik ve etnografik eserler), Kervansaray (tarihi yapı), Kuşköy (yaylalar, yayla evleri), Solhan ilçesi (yaylalar, doğa), Karşıyaka Yaylası, Şerafettin Yaylası, Zazaca köyler (kültürel zenginlik), Güveçli Köyü (tarihi taş evler), Sütlüce Köyü (doğal güzellikler) ve Akdağ Tabiat Parkı (ormanlık alan, piknik, yürüyüş) mutlaka görülmelidir.', 'Bingöl mutfağı, Doğu Anadolu\'nun zengin ve doğal lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Bingöl köftesi\" gelir. \"Bingöl tava\" (etli, sebzeli güveç), \"keledoş\" (nohutlu, etli, yoğurtlu yemek), \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"kuru kavurma\", \"yumurtalı ekmek\", \"ciğer sarma\", \"içli köfte\", \"mercimek köftesi\", \"sarma\", \"dolma\", \"yayla çorbası\", \"mercimek çorbası\", \"tarhana çorbası\", \"oğmaç çorbası\", \"keşkek\", \"haşıl\", \"herle\", \"gözleme\", \"katmer\", \"sac böreği\" yöresel lezzetlerdir. Tatlı olarak \"un helvası\", \"höşmerim\", \"kadayıf\", \"baklava\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\" ve \"sütlaç\" meşhurdur. Bingöl\'ün \"balı\" (Bingöl balı dünyaca ünlü), \"cevizi\", \"kavutu\", \"kurutulmuş sebzeleri\", \"keçi peyniri\", \"tulum peyniri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\" ve \"karabuğday unu\" da ünlüdür.', 'Bingöl\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Bingöl Kültür ve Sanat Festivali\'dir (ağustos ayında, konserler, halk oyunları, yöresel lezzetler, panayır, yayla şenlikleri). Yüzen Adalar Kültür ve Doğa Festivali (haziran veya temmuz ayında, Turna Gölü ve Yüzen Adalar çevresinde doğa yürüyüşleri, kuş gözlem, konserler). Çır Şelalesi Kültür ve Turizm Festivali (temmuz ayında, şelale çevresinde doğa yürüyüşleri, piknik, konserler). Solhan Yayla Şenlikleri (temmuz-ağustos aylarında, Solhan ilçesinde yayla şenlikleri, boğa güreşleri, at yarışları). Genç Kültür ve Sanat Festivali (ağustos ayında, Genç ilçesinde). Karlıova Kültür ve Doğa Sporları Festivali (temmuz ayında, Karlıova ilçesinde). Ayrıca Bingöl\'de düzenlenen \"Doğa Yürüyüşleri\", \"Kuş Gözlem Festivali\" ve \"Bingöl Koşusu\" (maraton) da ilgi çeker.', 'Bingöl\'ü ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-30°C arasındadır, yaylalar yeşildir ve doğa yürüyüşleri için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -20°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez. Bingöl\'ü ziyaret etmek için en uygun zaman temmuz ve ağustos aylarıdır. Bingöl\'ün soğuk kaynak suları yaz aylarında daha keyiflidir.', 'Bingöl\'e hava yoluyla gelmek için Bingöl Havalimanı kullanılır. Havalimanı şehir merkezine yaklaşık 8 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Ayrıca Diyarbakır Havalimanı (180 km) veya Elazığ Havalimanı (150 km) da kullanılabilir. Bingöl\'e şehirlerarası otobüs terminali (Bingöl Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Elazığ veya Muş\'tadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Solhan, Genç, Karlıova, Yayladere, Kiğı, Adaklı gibi ilçelere minibüslerle rahat ulaşım vardır. Yüzen Adalar, Çır Şelalesi, Turna Gölü, Ilıcalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Bingöl, tarihi boyunca Hurriler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi İpek Yolu üzerinde önemli bir durak olmuştur. Osmanlı döneminde Diyarbakır ve Bitlis eyaletlerine bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde 1936 yılında il statüsü kazanmıştır. Adını, bölgede bulunan ve \"bin göl\" anlamına gelen çok sayıdaki göl ve kaynak sulardan almıştır. Bingöl, doğal güzellikleri, yaylaları ve soğuk kaynak sularıyla öne çıkan bir Doğu Anadolu ilidir.', 'Bingöl', '2026-04-08 23:20:51'),
(18, 'Bitlis', 'Doğu Anadolu', 'bitlis.jpg', 'Nemrut Krater Gölü ile ünlü.', 'Bitlis denince akla gelen ilk şeyler: Bitlis Kalesi (şehrin simgesi, şehre hakim tepede, Bizans dönemi, surlar, iç kale, zindanlar, sarnıçlar, manzara), Selçuklu Meydan Mezarlığı (Ahlat\'ta, dünyanın en büyük Türk İslam mezarlığı, UNESCO Dünya Mirası Geçici Listesi\'nde, tarihi mezar taşları, kümbetler), Ahlat (tarihi ilçe, Selçuklu dönemi eserleri, Emir Bayındır Kümbeti, Ulu Cami, Çifte Kümbetler, Ahlat Müzesi, Ahlat Evleri, Nemrut Krater Gölü yakınları), Nemrut Krater Gölü (Bitlis-Tatvan yakınlarında, dünyanın en büyük ikinci krater gölü, volkanik dağ, doğa harikası, kamp, yürüyüş, manzara), Tatvan (ilçe, Van Gölü kenarında, feribotla Van\'a geçiş, Sahil Parkı, Tatvan Kalesi, Kireçtaşı Mağaraları, Serin Şelalesi), Van Gölü (Türkiye\'nin en büyük gölü, Tatvan sahili, feribot seferleri), Güroymak ilçesi (Ilıcalar, kaplıcalar), Mutki ilçesi (yaylalar, doğa), Hizan ilçesi (tarihi yapılar, kiliseler, kaleler), Adilcevaz ilçesi (Van Gölü kenarı, Adilcevaz Kalesi, Kef Kalesi, tarihi camiler), Rahva Yaylası (Tatvan yakınlarında, yayla şenlikleri, doğa), Esenkıyı Köyü (tarihi Ermeni kilisesi), Bitlis Evleri (tarihi taş evler, restore edilmiş konaklar), Bitlis Müzesi (arkeolojik ve etnografik eserler), Ulu Cami (Bitlis merkez, tarihi cami), Gök Meydan Medresesi (Selçuklu dönemi), Şerefiye Cami, Kalealtı Cami, Molla Halil Cami, Saklı Şelale, Kömüş Yaylası ve Ziyaret Dağı mutlaka görülmelidir.', 'Bitlis mutfağı, Doğu Anadolu\'nun zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Bitlis köftesi\" (etli, bulgurlu, baharatlı) gelir. \"Büryan kebabı\" (kuzu etinin tandırda pişirilmesi, Bitlis\'in meşhur lezzeti), \"perde pilavı\" (etli, bademli, kuş üzümlü pilav, ince yufkayla kaplanır), \"içli köfte\", \"kibbe\", \"ekşili köfte\", \"yayla çorbası\", \"mercimek çorbası\", \"tarhana çorbası\", \"oğmaç çorbası\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"kuru kavurma\", \"ciğer sarma\", \"sarma\", \"dolma\", \"keşkek\", \"haşıl\", \"herle\", \"katmer\", \"gözleme\", \"sac böreği\", \"Bitlis böreği\" yöresel lezzetlerdir. Tatlı olarak \"Büryan tatlısı\", \"un helvası\", \"höşmerim\", \"kadayıf\", \"baklava\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\" ve \"sütlaç\" meşhurdur. Bitlis\'in \"balı\", \"cevizi\", \"kurutulmuş sebzeleri\", \"Bitlis peyniri\" (tulum), \"otlu peynir\", \"yoğurdu\", \"tereyağı\", \"çökeleği\" ve \"kavutu\" da ünlüdür.', 'Bitlis\'te birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Ahlat Kültür ve Sanat Festivali\'dir (ağustos ayında, Ahlat\'ta Selçuklu Meydan Mezarlığı çevresinde konserler, halk oyunları, yöresel lezzetler, paneller, tarihi canlandırmalar). Nemrut Krater Gölü Kültür ve Doğa Sporları Festivali (temmuz-ağustos aylarında, krater gölü çevresinde doğa yürüyüşleri, kamp, dağcılık, yamaç paraşütü, konserler). Bitlis Kültür ve Sanat Festivali (eylül ayında, Bitlis merkez, konserler, yöresel lezzetler, halk oyunları). Tatvan Kültür ve Turizm Festivali (temmuz ayında, Tatvan\'da Van Gölü kenarında konserler, yüzme yarışları, doğa sporları). Rahva Yaylası Şenliği (ağustos ayında, Tatvan yakınlarında yayla şenlikleri, at yarışları, boğa güreşleri, konserler). Güroymak Ilıca ve Termal Turizm Festivali (haziran ayında). Adilcevaz Kültür ve Sanat Festivali (ağustos ayında). Ayrıca Bitlis\'te düzenlenen \"Van Gölü Yüzme Maratonu\" (Tatvan-Van arası) ve \"Nemrut Dağı Doğa Yürüyüşü\" de ilgi çeker.', 'Bitlis\'i ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-30°C arasındadır, tarihi yerleri gezmek ve doğa yürüyüşleri için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -20°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez. Bitlis\'i ziyaret etmek için en uygun zaman temmuz ve ağustos aylarıdır. Ahlat\'a gitmek için de yaz ayları idealdir.', 'Bitlis\'e en yakın havalimanı Muş Havalimanı\'dır (yaklaşık 80 km). Havalimanından havaş otobüsleri veya taksi ile Bitlis\'e ulaşılır. Ayrıca Van Ferit Melen Havalimanı (120 km) veya Batman Havalimanı (150 km) da kullanılabilir. Bitlis\'e şehirlerarası otobüs terminali (Bitlis Otogarı) şehir merkezindedir; birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Muş veya Batman\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Tatvan, Ahlat, Adilcevaz, Güroymak, Mutki, Hizan gibi ilçelere minibüslerle rahat ulaşım vardır. Tatvan\'dan Van Gölü üzerinde feribot seferleri ile Van\'a geçiş mümkündür. Nemrut Krater Gölü, Ahlat mezarlığı, Rahva Yaylası gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Bitlis, tarihi boyunca Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Artuklular, Eyyubiler, İlhanlılar, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Şehrin adı, Büyük İskender\'in komutanlarından Bedlis\'ten gelmektedir. Tarihi İpek Yolu üzerinde önemli bir durak olan Bitlis, stratejik konumu nedeniyle sık sık el değiştirmiştir. Osmanlı döneminde Bitlis Eyaleti\'nin merkezi olmuş, Kürt emirleri tarafından yönetilmiştir. Cumhuriyet döneminde il statüsünü korumuştur. Bitlis, tarihi taş evleri, kaleleri ve doğal güzellikleriyle öne çıkan bir Doğu Anadolu ilidir.', 'Bitlis', '2026-04-08 23:20:51'),
(19, 'Bolu', 'Karadeniz', 'bolu.jpg', 'Abant Gölü ile ünlü.', 'Bolu denince akla gelen ilk şeyler: Abant Gölü (Türkiye\'nin en popüler doğa harikalarından, krater gölü, yürüyüş yolları, fayton turları, at binme, piknik, manzara, çam ormanları, Abant\'ta konaklama), Yedigöller Milli Parkı (yedi göl, yürüyüş parkurları, kamp alanları, şelaleler, zengin bitki örtüsü, sonbahar renkleri), Gölcük Gölü (Bolu merkeze yakın, krater gölü, yürüyüş yolu, kafe, manzara), Kartalkaya Kayak Merkezi (Türkiye\'nin en önemli kayak merkezlerinden, kış sporları, oteller, teleferik), Mengen (aşçılar diyarı, Mengen Pilavı, Mengen Böreği, aşçılık okulları, Mengen Evleri, Mengen Müzesi, yaylalar), Mudurnu (tarihi Mudurnu evleri, Osmanlı dönemi konakları, dar sokaklar, Mudurnu Tarhanası, Mudurnu Müzesi, yaylalar), Göynük (tarihi Göynük evleri, Osmanlı dönemi konakları, Akşemseddin Türbesi, Göynük Kanyonu, yürüyüş parkurları, Göynük Şelalesi), Seben (yaylalar, doğa), Kıbrısçık (yaylalar, şelaleler), Dörtdivan (yaylalar), Bolu Kalesi (şehir merkezinde, tarihi sur kalıntıları), Bolu Müzesi (arkeolojik ve etnografik eserler), Akşemseddin Türbesi (Göynük), Sarıalan Yaylası, Bakacak Yaylası, Eğriova Yaylası, Yedigöller\'deki Kapankaya manzarası, Sülüklügöl, Tabaklar Yaylası, Kartalkaya\'dan manzara, Olukpınar Şelalesi, Kadıdağı Yaylası, Kığı Yaylası, Kireçli Yaylası, Avdan Yaylası ve Bolu Kent Ormanı mutlaka görülmelidir.', 'Bolu mutfağı, Karadeniz ve Batı Karadeniz mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Bolu köftesi\" gelir. \"Mengen pilavı\" (Mengen ilçesinin meşhur pilavı, etli, nohutlu, baharatlı), \"Mengen böreği\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"etli ekmek\", \"kavurma\", \"sac kavurma\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"çörek\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\" yöresel lezzetlerdir. Tatlı olarak \"Bolu baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Mengen lokumu\" meşhurdur. Bolu\'nun \"Mengen yayla peyniri\", \"Mudurnu tarhanası\", \"Gerede balı\", \"cevizi\", \"fındığı\", \"kurutulmuş sebzeleri\", \"keçi peyniri\", \"tulum peyniri\", \"yoğurdu\" ve \"tereyağı\" da ünlüdür.', 'Bolu\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Mengen Aşçılar ve Lezzet Festivali\'dir (ağustos ayında, Mengen\'de aşçılık yarışmaları, yöresel lezzetler, konserler, paneller). Uluslararası Abant Kültür ve Sanat Festivali (temmuz-ağustos aylarında, Abant Gölü çevresinde konserler, halk oyunları, doğa yürüyüşleri). Bolu Uluslararası Turizm ve Kültür Festivali (eylül ayında, Bolu merkez, yöresel lezzetler, konserler, panayır). Yedigöller Doğa ve Fotoğraf Festivali (ekim ayında, Yedigöller\'de sonbahar renklerinde fotoğraf yarışması, doğa yürüyüşleri). Kartalkaya Kış Sporları ve Kayak Festivali (şubat ayında, kayak yarışmaları, konserler). Göynük Kültür ve Sanat Festivali (temmuz ayında, Göynük\'te tarihi evler önünde konserler, yöresel lezzetler). Mudurnu Tarihi Evler ve Kültür Festivali (haziran ayında). Ayrıca Bolu\'da düzenlenen \"Abant Bisiklet Turu\" ve \"Uluslararası Bolu Maratonu\" da ilgi çeker.', 'Bolu\'yu ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-28°C arasındadır, doğa yemyeşildir, göller ve yaylalar gezmek için idealdir. Sonbahar (eylül-ekim) da güzeldir, yaprakların renklendiği dönemdir. Kışlar soğuk ve karlıdır; sıcaklık -10°C\'nin altına düşebilir, ancak kış aylarında Kartalkaya kayak merkezi için idealdir. Bolu\'yu yılın her mevsimi ziyaret etmek mümkündür: ilkbahar ve yaz doğa için, kış kayak için, sonbahar ise fotoğraf için idealdir.', 'Bolu\'ya hava yoluyla gelmek için en yakın havalimanı Zonguldak Havalimanı\'dır (Çaycuma, yaklaşık 120 km). Havalimanından havaş otobüsleri veya taksi ile Bolu\'ya ulaşılır. Ayrıca Ankara Esenboğa Havalimanı (180 km) veya İstanbul Sabiha Gökçen Havalimanı (250 km) da kullanılabilir. Bolu\'ya şehirlerarası otobüs terminali (Bolu Otogarı) şehir merkezine yaklaşık 3 km uzaklıkta olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır. Bolu, İstanbul-Ankara karayolu (TEM otoyolu) üzerinde olduğu için özel araçla ulaşım çok kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Bilecik veya Ankara\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Mengen, Mudurnu, Göynük, Gerede, Seben, Kıbrısçık, Dörtdivan, Yeniçağa gibi ilçelere minibüslerle rahat ulaşım vardır. Abant, Yedigöller, Kartalkaya, Gölcük gibi turistik yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Bolu, tarihi boyunca Bitinler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, Bitinya uygarlığının önemli merkezlerinden biri olmuştur. Roma döneminde \"Claudiopolis\" adıyla anılmıştır. Osmanlı döneminde Bolu Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Bolu, yemyeşil ormanları, gölleri, yaylaları ve kaplıcalarıyla ünlü bir Karadeniz ilidir. Aynı zamanda Türkiye\'nin önemli eğitim merkezlerinden biri olan Bolu, Abant İzzet Baysal Üniversitesi ile tanınır.', 'Bolu', '2026-04-08 23:20:51'),
(20, 'Burdur', 'Akdeniz', 'burdur.jpg', 'Salda Gölü ile ünlü.', 'Burdur denince akla gelen ilk şeyler: Salda Gölü (Türkiye\'nin Maldivleri olarak bilinir, beyaz kumsalı, turkuaz rengi suyu, manyezit yatakları, doğa harikası, yüzme, piknik, kamp, manzara, Salda Gölü\'nün bembeyaz kumsalı dünyada nadir görülen bir oluşumdur), Burdur Gölü (kuş cenneti, flamingolar, göçmen kuşlar, doğa manzarası, ancak son yıllarda su seviyesi düşmüştür), İnsuyu Mağarası (traverten oluşumları, sarkıt ve dikitler, yürüyüş yolları, aydınlatma, mağara içi dere), Sagalassos Antik Kenti (UNESCO Dünya Mirası Geçici Listesi\'nde, Pisidya bölgesinin en önemli antik kenti, Roma dönemi yapıları, tiyatro, Antoninler Çeşmesi, heroon, meclis binası, agora, sütunlu cadde, kral yolu, mozaikler, muhteşem manzara), Kibyra Antik Kenti (medusa mozaiği, stadyumu, tiyatrosu, odeonu, agora, su kemerleri), Kremna Antik Kenti, Ariassos Antik Kenti, Burdur Müzesi (dünyaca ünlü Burdur eserleri, Sagalassos ve Kibyra\'dan çıkarılan heykeller, lahitler, mozaikler, altın takılar, Likya lahitleri, \"Burdur Kadını\" heykeli), Burdur Kalesi (şehir merkezinde, tarihi sur kalıntıları, manzara), Ulu Cami (Burdur merkez, tarihi cami), Taşoda Medresesi (Selçuklu dönemi), Çeşmeli Cami, Ağlasun ilçesi (Sagalassos\'a giden yol, doğa), Bucak ilçesi (Kibyra Antik Kenti, İnsuyu Mağarası), Gölhisar ilçesi (Kibyra, göl), Yeşilova ilçesi (Salda Gölü, doğa), Karamanlı ilçesi (tarihi yapılar), Çeltikçi ilçesi (yaylalar), Burdur Evleri (tarihi taş evler, restore edilmiş konaklar) mutlaka görülmelidir.', 'Burdur mutfağı, Akdeniz ve Göller Yöresi mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Burdur köftesi\" gelir. \"Burdur şiş\" (kuşbaşı et, yağ, biber, soğan şişte pişirilir), \"Burdur tava\", \"etli ekmek\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"kavurma\", \"sac kavurma\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"çörek\", \"katmer\", \"gözleme\", \"içli köfte\", \"mercimek köftesi\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"oğmaç çorbası\", \"tava ciğer\", \"Burdur yoğurdu\", \"Burdur peyniri\" yöresel lezzetlerdir. Tatlı olarak \"Burdur baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Burdur lokumu\" meşhurdur. Burdur\'un \"Salda ekmeği\", \"balı\", \"cevizi\", \"bademi\", \"elması\", \"üzümü\", \"pekmezi\", \"kurutulmuş sebzeleri\", \"keçi peyniri\", \"tulum peyniri\" ve \"tereyağı\" da ünlüdür.', 'Burdur\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Salda Gölü Kültür ve Doğa Festivali\'dir (temmuz ayında, Salda Gölü çevresinde doğa yürüyüşleri, konserler, yüzme yarışları, plaj voleybolu, yöresel lezzetler). Uluslararası Sagalassos Kültür ve Sanat Festivali (ağustos ayında, Sagalassos Antik Tiyatrosu\'nda konserler, tiyatro gösterileri, tarihi canlandırmalar). Burdur Kültür ve Sanat Festivali (eylül ayında, Burdur merkez, konserler, halk oyunları, yöresel lezzetler, panayır). Kibyra Kültür ve Sanat Festivali (temmuz ayında, Kibyra Antik Kenti\'nde konserler, gösteriler). İnsuyu Mağarası Kültür ve Turizm Festivali (haziran ayında, mağara çevresinde doğa yürüyüşleri, konserler). Ağlasun Kültür ve Sanat Festivali (ağustos ayında, Ağlasun ilçesinde). Gölhisar Kültür ve Turizm Festivali (eylül ayında). Ayrıca Burdur\'da düzenlenen \"Salda Gölü Bisiklet Turu\" ve \"Uluslararası Salda Gölü Maratonu\" da ilgi çeker.', 'Burdur\'u ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, Salda Gölü ve tarihi yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 30-35°C\'ye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve yağışlıdır, sıcaklık genelde 0-8°C arasındadır, zaman zaman kar yağışı görülür. Burdur\'u ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır. Salda Gölü için yaz ayları da güzeldir, ancak çok sıcak olabilir.', 'Burdur\'a hava yoluyla gelmek için en yakın havalimanı Isparta Süleyman Demirel Havalimanı\'dır (yaklaşık 50 km). Havalimanından havaş otobüsleri veya taksi ile Burdur\'a ulaşılır. Ayrıca Denizli Çardak Havalimanı (70 km) veya Antalya Havalimanı (150 km) da kullanılabilir. Burdur\'a şehirlerarası otobüs terminali (Burdur Otogarı) şehir merkezine yakın olup birçok ilden direkt otobüs seferleri vardır. Burdur, Isparta-Antalya demiryolu hattı üzerindedir, ancak yolcu tren seferleri sınırlıdır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Bucak, Gölhisar, Yeşilova, Ağlasun, Karamanlı, Çeltikçi gibi ilçelere minibüslerle rahat ulaşım vardır. Salda Gölü, Sagalassos, Kibyra, İnsuyu Mağarası gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Burdur, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Hamitoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, Pisidya uygarlığının önemli merkezlerinden biri olmuştur. Roma döneminde önemli bir yerleşim merkezi haline gelmiştir. Osmanlı döneminde Konya ve Anadolu eyaletlerine bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Burdur, gölleri, termal kaynakları, tarihi yapıları ve el sanatlarıyla öne çıkan bir Akdeniz ilidir.', 'Burdur', '2026-04-08 23:20:51'),
(21, 'Bursa', 'Marmara', 'bursa.jpg', 'Yeşil Bursa, Osmanlının ilk başkenti.', 'Bursa denince akla gelen ilk şeyler: Uludağ (Türkiye\'nin en önemli kayak merkezlerinden, kış sporları, teleferik, doğa yürüyüşleri, kamp, manzara, Uludağ milli parkı, Uludağ eteklerinde yaylalar), Yeşil Bursa (Bursa\'nın yeşil dokusu, parkları, bahçeleri), Yeşil Cami ve Yeşil Türbe (Çelebi Sultan Mehmet dönemi, Bursa\'nın simgelerinden, İznik çinileri), Ulu Cami (Bursa\'nın en büyük camisi, Osmanlı dönemi, 20 kubbesi, hat levhaları), Emir Sultan Cami ve Türbesi, Muradiye Külliyesi (Osmanlı şehzadelerinin türbeleri), Koza Han (ipek çarşısı, tarihi han, alışveriş, ipek kumaşlar, kafe), Cumalıkızık (Osmanlı döneminden kalma tarihi köy, taş evler, dar sokaklar, Cumalıkızık evleri, pancar turşusu, Osmanlı kıyafetleri canlandırmaları), İznik (tarihi ilçe, İznik çinileri, İznik Müzesi, Ayasofya Müzesi, İznik surları, Roma tiyatrosu, göl, doğa), Gölyazı (Uluabat Gölü kenarında tarihi köy, yürüyüş yolları, kuş gözlem, göl manzarası, tarihi evler), Mudanya (Mütareke Evi, Mudanya evleri, sahil, balıkçılar, zeytinyağlı kahvaltı), Trilye (Zeytinbağı, tarihi Rum evleri, kiliseler, deniz manzarası), Bursa Kalesi (Hisar, Osmangazi ve Orhangazi türbeleri, manzara), Bursa Arkeoloji Müzesi, Bursa Kent Müzesi, Atatürk Evi Müzesi, Tofaş Anadolu Arabaları Müzesi, Merinos Parkı (eski tekstil fabrikası, park, müze), Hayvanat Bahçesi, Botanik Parkı, Soğanlı Botanik Parkı, Reşat Oyal Kültür Parkı, Çekirge (termal kaplıcalar, oteller), Oylat Kaplıcaları (İnegöl), İnegöl\'de İnegöl Köftesi, Mustafakemalpaşa\'da Kemalpaşa Tatlısı, Orhaneli\'nde bal, Karacabey\'de uzun plajı, Karacabey Boğazı, Karacabey Subasar Ormanı (Kızılcahamam benzeri), Apolyont Gölü (Uluabat Gölü), Kapalı Çarşı, Çarşı Hamamı, Tarihi Irgandı Köprüsü (üzerinde çarşı olan tarihi köprü), Setbaşı Köprüsü, Tatarlar Köprüsü, Bursa Teleferik (Uludağ\'a çıkar), Uludağ\'daki oteller, kayak pistleri, Bursa Merinos Parkı\'ndaki koyun heykelleri, Bursa Hayvanat Bahçesi, Hüdavendigar Parkı, Bursa\'nın tüm tarihi hanları, bedestenleri, çarşıları mutlaka görülmelidir.', 'Bursa mutfağı, Osmanlı mutfağının en zengin örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"İskender Kebap\" (Bursa\'nın dünyaca ünlü lezzeti, yufka ekmek üzerine doğranmış döner eti, üzerine domates sosu ve sıcak tereyağı, yanında yoğurt) gelir. \"Kemalpaşa tatlısı\" (peynirli, şerbetli tatlı), \"pideli köfte\", \"İnegöl köftesi\" (sadece kıyma, tuz ve baharat, katkısız), \"Bursa cantık\" (pide benzeri, kıymalı, peynirli), \"tahinli pide\", \"kestane şekeri\", \"Bursa kebabı\" (beyti kebabı), \"ciğer şiş\", \"kuzu şiş\", \"tavuk şiş\", \"etli ekmek\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"zeytinyağlılar\", \"Bursa mantısı\", \"yoğurtlu mantı\", \"çılbır\", \"mıhlama\", \"karalahana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tarhana çorbası\", \"içli köfte\", \"mercimek köftesi\", \"Bursa simidi\", \"Bursa peyniri\", \"Bursa yoğurdu\" yöresel lezzetlerdir. Tatlı olarak \"Bursa baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Bursa lokumu\" meşhurdur. Bursa\'nın \"İnegöl köftesi\", \"Kemalpaşa tatlısı\", \"kestane şekeri\", \"Tahir sofrası\", \"Mudanya zeytinyağı\", \"Gemlik zeytini\" (siyah, çizik), \"Orhaneli balı\", \"İznik elması\", \"Bursa şeftalisi\", \"Bursa ayvası\" ve \"Bursa ipeği\" de ünlüdür.', 'Bursa\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Bursa Festivali (kültür ve sanat festivali, mayıs-eylül ayları arasında, konserler, tiyatro, bale, sergiler, uluslararası sanatçılar). Uluslararası Bursa Merinos Yün ve Yöresel Ürünler Festivali (ekim ayında, yün, ipek, yöresel ürünler sergisi). Uluslararası İznik Çini ve Kültür Festivali (temmuz ayında, İznik\'te çini sergileri, atölyeler, konserler). Uluslararası Karagöz ve Gölge Oyunları Festivali (ağustos ayında, Karagöz-Hacivat gösterileri, gölge oyunu). Cumalıkızık Kültür ve Doğa Festivali (haziran ayında, Cumalıkızık\'ta tarihi canlandırmalar, pancar turşusu yarışmaları, yöresel lezzetler). Uludağ Kış Sporları ve Kayak Festivali (şubat ayında, kayak yarışmaları, konserler). Mudanya Zeytin Hasadı Festivali (kasım ayında, zeytin hasadı, zeytinyağı tadımı). İnegöl Köfte ve Kültür Festivali (eylül ayında, İnegöl\'de köfte yarışmaları, yöresel lezzetler). Ayrıca Bursa\'da düzenlenen \"Uludağ Bisiklet Turu\" ve \"Uluslararası Bursa Maratonu\" da ilgi çeker.', 'Bursa\'yı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, tarihi yerleri ve doğayı gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 30-35°C\'ye ulaşabilir, nem oranı yüksektir. Kışlar soğuk ve karlıdır, sıcaklık genelde 0-8°C arasındadır, zaman zaman kar yağışı görülür. Kış aylarında Uludağ kayak merkezi için idealdir. Bursa\'yı yılın her mevsimi ziyaret etmek mümkündür: ilkbahar ve sonbahar şehir gezisi için, kış kayak için, yaz termal kaplıcalar için uygundur.', 'Bursa\'ya hava yoluyla gelmek için Bursa Yenişehir Havalimanı (YEI) kullanılır. Havalimanı şehir merkezine yaklaşık 50 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Ayrıca İstanbul Sabiha Gökçen Havalimanı (100 km) veya İstanbul Havalimanı (150 km) da kullanılabilir; bu havalimanlarından Bursa\'ya otobüs ve araç kiralama seçenekleri vardır. Bursa\'ya şehirlerarası otobüs terminali (Bursa Otogarı) şehir merkezinin dışında olup metro ve otobüslerle merkeze bağlıdır; birçok ilden direkt otobüs seferleri vardır. Bursa, İstanbul-Ankara karayolu üzerinde olduğu için özel araçla ulaşım çok kolaydır. Bursa\'da şehir içi ulaşımda metro (Bursaray), tramvay, belediye otobüsleri (Burulaş), minibüs, dolmuş, taksi ve deniz otobüsü (İDO, BUDO) kullanılır. Bursa\'dan İstanbul\'a deniz otobüsü ve feribot seferleri vardır (Mudanya\'dan, Güzelyalı\'dan). Bursa\'da ayrıca teleferik (Bursa Teleferik) ile Uludağ\'a çıkılır. İnegöl, İznik, Gemlik, Mudanya, Mustafakemalpaşa, Karacabey, Orhaneli, Keles, Yenişehir gibi ilçelere minibüs ve otobüslerle rahat ulaşım vardır. Uludağ, Cumalıkızık, Gölyazı, Trilye gibi turistik yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Bursa, tarihi boyunca Bitinler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Prusa\" adıyla anılmıştır. Bursa, Osmanlı İmparatorluğu\'nun ilk başkenti olma özelliğini taşır (1326-1365). Osmanlı\'nın kuruluş yıllarında önemli bir merkez olan Bursa, ilk külliye, ilk medrese, ilk darphane gibi birçok ilke ev sahipliği yapmıştır. Cumhuriyet döneminde il statüsünü korumuştur. Bursa, tarihi yapıları, termal kaynakları, dağları ve sanayisiyle öne çıkan bir Marmara ilidir. Günümüzde otomotiv, tekstil ve makine sanayisinde Türkiye\'nin önemli merkezlerinden biridir.', 'Bursa', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(22, 'Çanakkale', 'Marmara', 'canakkale.jpg', 'Troya ile ünlü.', 'Çanakkale denince akla gelen ilk şeyler: Truva Antik Kenti (Troya, Homeros\'un İlyada\'sında geçen Truva Savaşı\'nın geçtiği yer, Truva Atı, UNESCO Dünya Mirası Listesi, kazı alanı, surlar, rampalar, kazı evi, müze), Çanakkale Savaşı ve Gelibolu Yarımadası Tarihi Milli Parkı (Şehitlikler, anıtlar, müzeler: Conkbayırı, Arıburnu, Anzak Koyu, Kanlısırt, Kilitbahir Kalesi, Çimenlik Kalesi, Namazgah Tabyası, Mecidiye Tabyası, 57. Alay Şehitliği, Mehmetçik Anıtı, Çanakkale Şehitler Abidesi, Gelibolu\'daki şehitlikler, Anzak tören alanları, Seyit Onbaşı Heykeli, Yahya Çavuş Şehitliği, Rumeli Mecidiye Tabyası, Anadolu Hamidiye Tabyası, Morto Koyu, Seddülbahir Kalesi, Ertuğrul Tabyası, Eceabat, Kabatepe), Gelibolu ilçesi (tarihi Gelibolu, Gelibolu Kalesi, Piri Reis Müzesi, Gelibolu Mevlevihanesi), Bozcaada (Türkiye\'nin en batıdaki ilçesi, üzüm bağları, şarap evleri, Bozcaada Kalesi, plajlar: Ayazma Plajı, Habbele Plajı, Sulubahçe Koyu, Tuzburnu, Akvaryum Koyu, yel değirmenleri, taş evler, Bozcaada merkez, Bozcaada Müzesi, Bozcaada\'nın gün batımı), Gökçeada (Türkiye\'nin en büyük adası, Aydıncık Plajı, Kefalos Plajı, Yıldız Koyu, Kapıkaya Koyu, Laz Koyu, Mavi Koy, Gökçeada Kalesi, tarihi Rum evleri, Yeni Bademli köyü, Zeytinli köyü, Gökçeada\'nın şarapları), Assos Antik Kenti (Behramkale, Atatürk Heykeli, Athena Tapınağı, tiyatro, surlar, taş evler, Assos Limanı, Behramkale Köyü), Apollon Smintheion Tapınağı (Gülpınar köyü), Parion Antik Kenti (Bigalı köyü), Adatepe köyü (taş evler, zeytinyağı fabrikası), Küçükkuyu (sahil, balıkçılar), Ayvacık (el sanatları, kilim, heybe), Bayramiç (Bayramiç Beyazı elma, Kaz Dağları etekleri, doğa), Çanakkale Kalesi (Çimenlik Kalesi, Piri Reis Müzesi), Çanakkale Deniz Müzesi, Çanakkale Arkeoloji Müzesi, Troya Müzesi (yeni müze, etkileyici mimari, Truva eserleri), Kaz Dağları (İda Dağı, mitolojide önemli, doğa yürüyüşleri, şelaleler: Hasan Boğuldu Şelalesi, Sütüven Şelalesi, Mıhlı Şelalesi), Adalar (Bozcaada, Gökçeada), Tavşan Adaları (Adacıklar), Eceabat, Kilitbahir, Çanakkale Köprüsü (1915 Çanakkale Köprüsü, dünyanın en uzun orta açıklıklı asma köprüsü, Çanakkale Boğazı\'nı geçer), Çanakkale Sahil Şeridi, Çanakkale Saat Kulesi, Kordon, Truva Atı (Çanakkale sahilinde büyük Truva Atı heykeli), Aynalı Çarşı, Bedesten, Yalı Hanı, Kayserili Ahmet Paşa Camii, İskele Meydanı, Morto Koyu, Kabatepe, Büyük Anzak Koyu, Conkbayırı, Arıburnu, Kanlısırt, Mehmetçik Anıtı, Çanakkale Şehitler Abidesi\'ne giden yol, Kilitbahir\'den manzara, Eceabat\'tan gün batımı mutlaka görülmelidir.', 'Çanakkale mutfağı, Marmara ve Ege mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Çanakkale peyniri\" (Ezine peyniri) gelir. \"Ezine peyniri\" (tulum, beyaz peynir, dünyaca ünlü), \"Çanakkale köftesi\", \"gelibolu köftesi\", \"tava ciğer\", \"etli ekmek\", \"güveç\", \"kuzu tandır\", \"keşkek\", \"yaprak sarma\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"ot kavurması\", \"çılbır\", \"mıhlama\", \"karalahana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tarhana çorbası\", \"içli köfte\", \"mercimek köftesi\", \"midye dolma\", \"midye tava\", \"hamsi tava\", \"hamsi buğulama\", \"çinekop\", \"levrek\", \"çipura\", \"kalamar\", \"ahtapot\", \"balık ekmek\" yöresel lezzetlerdir. Tatlı olarak \"Çanakkale baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Ayvalık çökertme\", \"kestane şekeri\" meşhurdur. Çanakkale\'nin \"Ezine peyniri\", \"Bayramiç beyazı\" (elma), \"Çanakkale elması\", \"zeytini\", \"zeytinyağı\", \"balı\", \"pekmezi\", \"kurutulmuş sebzeleri\", \"kuzu eti\", \"dağ kekiği\", \"lavantası\", \"Ayvacık kekiği\", \"Bozcaada şarabı\", \"Gökçeada şarabı\", \"Bozcaada ada şarabı\", \"Gökçeada ada şarabı\" da ünlüdür.', 'Çanakkale\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Çanakkale Troya Festivali (ağustos ayında, Truva Antik Kenti\'nde konserler, tiyatro gösterileri, tarihi canlandırmalar). Uluslararası Çanakkale Bienali (sonbahar aylarında, çağdaş sanat sergileri). Çanakkale Şehitlerini Anma ve Gelibolu Yarımadası Tarihi Yürüyüşü (18 Mart ve 25 Nisan tarihlerinde, şehitlikler ziyaret, anma törenleri, yürüyüşler, konserler). Bozcaada Şarap Festivali (temmuz-ağustos aylarında, şarap tadımı, bağ bozumu, konserler, panayır). Gökçeada Kültür ve Doğa Festivali (ağustos ayında, şarap tadımı, doğa yürüyüşleri, konserler). Assos Kültür ve Sanat Festivali (eylül ayında, Assos Athena Tapınağı\'nda konserler, tiyatro). Kaz Dağları Kültür ve Doğa Sporları Festivali (haziran ayında, doğa yürüyüşleri, yamaç paraşütü, konserler). Çanakkale Uluslararası Caz Festivali (mayıs ayında). Ezine Peynir ve Kültür Festivali (eylül ayında, Ezine\'de peynir tadımı, yarışmalar). Bayramiç Elma Festivali (ekim ayında, Bayramiç Beyazı elma hasadı, elma yarışmaları). Ayrıca Çanakkale\'de düzenlenen \"Uluslararası Çanakkale Boğazı Yüzme Maratonu\" (yaz aylarında, Asya\'dan Avrupa\'ya yüzme yarışı), \"Truva Maratonu\" ve \"Gelibolu Bisiklet Turu\" da ilgi çeker.', 'Çanakkale\'yi ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, tarihi savaş alanları, şehitlikler ve antik kentleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 28-33°C\'ye ulaşabilir, nem oranı yüksektir, ancak deniz suyu sıcaklığı yüzmek için idealdir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 5-12°C arasındadır, zaman zaman kar yağışı görülmez. Çanakkale\'yi özellikle nisan ayında (Çanakkale Zaferi anma törenleri) ve yaz aylarında (adalara geziler) ziyaret etmek idealdir.', 'Çanakkale\'ye hava yoluyla gelmek için Çanakkale Havalimanı (CKZ) kullanılır. Havalimanı şehir merkezine yaklaşık 3 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Ayrıca Balıkesir Koca Seyit Havalimanı (Edremit Körfezi) da kullanılabilir. Çanakkale\'ye şehirlerarası otobüs terminali (Çanakkale Otogarı) şehir merkezine yakın olup birçok ilden direkt otobüs seferleri vardır. Çanakkale\'ye özel araçla İstanbul\'dan TEM otoyolu, Tekirdağ üzerinden veya Bursa-Çanakkale yoluyla ulaşılır. Çanakkale\'de şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Çanakkale\'den Gelibolu, Eceabat, Ezine, Ayvacık, Bayramiç, Biga, Yenice, Çan, Lapseki, Gökçeada, Bozcaada gibi ilçelere minibüslerle rahat ulaşım vardır. Çanakkale\'den Bozcaada ve Gökçeada\'ya feribot seferleri düzenlenir (Yükyolu, Geyikli\'den Bozcaada\'ya feribot, Kabatepe\'den Gökçeada\'ya feribot). Ayrıca Çanakkale\'den Gelibolu\'ya (Kilitbahir-Eceabat) feribot seferleri vardır. Truva, Assos, Kaz Dağları, Gelibolu Yarımadası, Bozcaada, Gökçeada gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n', 'Çanakkale, tarihi boyunca Truva (Troya), Lidyalılar, Persler, Romalılar, Bizanslılar, Cenevizliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, antik dönemde Truva Savaşı ile ünlenmiştir. 1915 yılında Çanakkale Savaşı (Gelibolu Muharebesi) bu topraklarda gerçekleşmiş, Mustafa Kemal Atatürk\'ün askeri dehasıyla zafer kazanılmıştır. Cumhuriyet döneminde il statüsü kazanmıştır. Çanakkale, tarihi savaş alanları, şehitlikleri, antik kentleri ve doğal güzellikleriyle öne çıkan bir Marmara ilidir.', 'Çanakkale', '2026-04-08 23:20:51'),
(23, 'Çankırı', 'İç Anadolu', 'cankiri.jpg', 'Ilgaz Dağı ile ünlü.', 'Çankırı denince akla gelen ilk şeyler: Ilgaz Dağı (Ilgaz Dağı Milli Parkı, kayak merkezi, doğa yürüyüşleri, kamp, yaylalar, manzara, Ilgaz Dağı\'nın zirvesi, Ilgaz şelalesi, Ilgaz ormanları), Ilgaz ilçesi (Ilgaz Dağı eteklerinde, yaylalar), Çankırı Kalesi (şehrin simgesi, tarihi kale, surlar, iç kale, manzara), Çankırı Müzesi (arkeolojik ve etnografik eserler, tuz lambaları), Tuz Mağarası (Sofular Mahallesi, Türkiye\'nin en büyük tuz mağarası, astım hastalığına iyi gelir, tuz lambaları, yürüyüş yolları), Yaran Kültürü (Çankırı\'ya özgü yaren kültürü, yaren oturmaları, yaren çorbası, yaren geceleri), Taş Mescit (Selçuklu dönemi, küçük mescit), Ulu Cami (Çankırı merkez, tarihi cami), Kurşunlu Cami (Osmanlı dönemi), Çerkeş ilçesi (Çerkeş peyniri, Çerkeş ormanları, yaylalar), Korgun ilçesi (Korgun balı, yaylalar), Şabanözü ilçesi (tarihi evler, doğa), Eldivan ilçesi (Eldivan yaylası, yayla şenlikleri), Orta ilçesi (Ilıca kaplıcaları, termal su), Bayramören ilçesi (yaylalar), Yapraklı ilçesi (Yapraklı yaylası, doğa), Kızılırmak ilçesi (Kızılırmak nehri kenarı, doğa), Çankırı\'nın tuz üretimi, Çankırı evleri (tarihi Çankırı evleri, restore edilmiş konaklar), Atatürk Evi Müzesi, Çankırı Arkeoloji Müzesi, Çankırı\'nın dar sokakları, Çankırı\'nın yaren müzesi, Ilgaz Dağı\'nın eteklerindeki yaylalar, Çankırı\'nın termal kaplıcaları (Ilıca, Taşdibek), Sofular Köyü (tuz mağarası), Budakpınar Şelalesi, Eski Çankırı evleri, İstiklal Yolu (Kurtuluş Savaşı\'nda cephane taşınan yol, tarihi önemi) mutlaka görülmelidir.', 'Çankırı mutfağı, İç Anadolu ve Karadeniz mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Çankırı ekmeği\" (yufka ekmeği, sac ekmeği) gelir. \"Çankırı mantısı\" (etli, yoğurtlu, yağlı), \"Çankırı köftesi\", \"etli ekmek\", \"kavurma\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"sirkeli yaprak sarma\", \"banduma\", \"haşıl\", \"herle\", \"kurutulmuş sebze yemekleri\" yöresel lezzetlerdir. Tatlı olarak \"Çankırı baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Çankırı lokumu\", \"Çankırı pidesi\" meşhurdur. Çankırı\'nın \"Çankırı tarhanası\", \"Korgun balı\", \"Çerkeş peyniri\", \"Ilgaz kaşar peyniri\", \"Kurşunlu peyniri\", \"kavutu\", \"kurutulmuş sebzeleri\", \"cevizi\", \"üzümü\", \"pekmezi\", \"tahini\" ve \"Çankırı elması\" da ünlüdür.', 'Çankırı\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Ilgaz Dağı Kış Sporları ve Kayak Festivali (şubat ayında, Ilgaz Dağı Kayak Merkezi\'nde kayak yarışmaları, konserler). Uluslararası Çankırı Yaran Kültürü ve Yemek Festivali (ağustos ayında, Çankırı merkez, yaran geceleri canlandırmaları, yöresel lezzetler, konserler, halk oyunları). Çankırı Kültür ve Sanat Festivali (eylül ayında, Çankırı merkez, konserler, sergiler, panayır). Çankırı Tuz Festivali (ekim ayında, Tuz Mağarası\'nda tuz lambası yapım atölyeleri, tuz temalı sergiler, konserler). Ilgaz Doğa Yürüyüşü ve Kültür Festivali (haziran ayında, Ilgaz Dağı\'nda doğa yürüyüşleri, kamp, konserler). Çerkeş Peynir ve Kültür Festivali (eylül ayında, Çerkeş ilçesinde peynir tadımı, yöresel lezzetler). Korgun Bal ve Kültür Festivali (ağustos ayında, Korgun ilçesinde bal tadımı, yarışmalar). Kurşunlu Kültür ve Sanat Festivali (temmuz ayında). Ayrıca Çankırı\'da düzenlenen \"Ilgaz Dağı Bisiklet Turu\" ve \"Çankırı Yürüyüş Günleri\" de ilgi çeker.', 'Çankırı\'yı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır, doğa yürüyüşleri ve tarihi yerleri gezmek için idealdir. Sonbahar (eylül-ekim) da güzeldir, yaprakların renklendiği dönemdir. Kışlar soğuk ve karlıdır; sıcaklık -10°C\'nin altına düşebilir, ancak kış aylarında Ilgaz Dağı kayak merkezi için idealdir. Çankırı\'yı yılın her mevsimi ziyaret etmek mümkündür: ilkbahar ve yaz doğa için, kış kayak için idealdir.', 'Çankırı\'ya en yakın havalimanı Ankara Esenboğa Havalimanı\'dır (yaklaşık 120 km). Havalimanından havaş otobüsleri, şehirlerarası otobüsler veya taksi ile Çankırı\'ya ulaşılır. Çankırı\'ya şehirlerarası otobüs terminali (Çankırı Otogarı) şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır (özellikle Ankara\'dan sık seferler). Çankırı, Ankara-Çankırı karayolu üzerinde olduğu için özel araçla ulaşım kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Ankara veya Kırıkkale\'dedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ilgaz, Çerkeş, Korgun, Kurşunlu, Orta, Şabanözü, Yapraklı, Eldivan, Bayramören, Kızılırmak gibi ilçelere minibüslerle rahat ulaşım vardır. Ilgaz Dağı, Tuz Mağarası, Yaran Kültürü alanları, Ilıca Kaplıcaları gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n', 'Çankırı, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Gangra\" adıyla anılmıştır. Roma döneminde Paflagonya bölgesinin önemli merkezlerinden biri olmuştur. Osmanlı döneminde Çankırı Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Çankırı, doğal güzellikleri, termal kaynakları, tarihi yapıları ve yöresel ürünleriyle öne çıkan bir İç Anadolu ilidir.', 'Çankırı', '2026-04-08 23:20:51'),
(24, 'Çorum', 'Karadeniz', 'corum.jpg', 'Hititlerin başkenti.', 'Çorum denince akla gelen ilk şeyler: Hattuşaş (Hitit İmparatorluğu\'nun başkenti, UNESCO Dünya Mirası Listesi, kazı alanı, Kral Kapısı, Aslanlı Kapı, Yerkapı, tüneller, Büyük Tapınak, Hitit surları, kral mezarları, yazıtlar, Hattuşaş Müzesi), Yazılıkaya (Hitit kaya tapınağı, açık hava tapınağı, kaya kabartmaları, tanrı ve tanrıça figürleri, dünyaca ünlü), Alacahöyük (Hitit dönemi, Sfenksli Kapı, kral mezarları, altın eserler, güneş kursları, Alacahöyük Müzesi, höyük), Şapinuva (Hitit dönemi, tabletler, arşiv, kazı alanı, Ortaköy ilçesi), Çorum Müzesi (Hitit eserleri, arkeolojik eserler, etnografik eserler, leblebi tarihi), Çorum Kalesi (şehrin simgesi, tarihi kale, surlar, manzara), İskilip ilçesi (tarihi İskilip evleri, İskilip Kalesi, İskilip Peyniri, İskilip leblebisi, İskilip tarhanası, tarihi çarşı, dar sokaklar, İskilip Müzesi, Ulu Cami, İskilip\'in yokuşları), Osmancık ilçesi (Osmancık Kalesi, Kızılırmak kenarı, Osmancık pirinci, Osmancık leblebisi), Sungurlu ilçesi (tarihi evler, doğa), Boğazkale ilçesi (Hattuşaş\'ın bulunduğu ilçe), Mecitözü ilçesi (Mecitözü balı, yaylalar), Uğurludağ ilçesi (yaylalar), Oğuzlar ilçesi (Oğuzlar peyniri), Dodurga ilçesi (doğa), Çorum Evleri (tarihi Çorum evleri, restore edilmiş konaklar), Atatürk Evi Müzesi, Saat Kulesi, Ulu Cami (Çorum merkez), Kubbeli Cami, Kargı Han (tarihi han), Bedesten, İskilip\'te Kaya Mezarları, İskilip\'te Roma dönemi su kemerleri, Alacahöyük\'te güneş kursları replikaları, Çorum leblebisi fabrikaları, Hattuşaş\'taki Hitit surları üzerinde yürüyüş, Yazılıkaya\'daki kaya kabartmalarının yakından görülmesi mutlaka yapılmalıdır.', 'Çorum mutfağı, İç Anadolu\'nun zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Çorum leblebisi\" (dünyaca ünlü, rosto, sarı, beyaz leblebi) gelir. \"Çorum mantısı\" (etli, yoğurtlu, yağlı, salçalı), \"Çorum köftesi\", \"etli ekmek\", \"kavurma\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"sirkeli yaprak sarma\", \"banduma\", \"haşıl\", \"herle\", \"kurutulmuş sebze yemekleri\" yöresel lezzetlerdir. Tatlı olarak \"Çorum baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Çorum lokumu\" meşhurdur. Çorum\'un \"Çorum leblebisi\", \"Çorum mantısı\", \"Çorum tarhanası\", \"İskilip peyniri\", \"Oğuzlar peyniri\", \"Mecitözü balı\", \"kavutu\", \"kurutulmuş sebzeleri\", \"cevizi\", \"üzümü\", \"pekmezi\", \"tahini\", \"Çorum elması\", \"Çorum kızılcığı\" ve \"Çorum üzümü\" de ünlüdür.', 'Çorum\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Hattuşaş Hitit Kültür ve Sanat Festivali (ağustos ayında, Hattuşaş Antik Kenti\'nde konserler, tiyatro gösterileri, Hitit yemekleri, tarihi canlandırmalar, panel). Uluslararası Çorum Leblebi Festivali (eylül ayında, Çorum merkez, leblebi yapım atölyeleri, leblebi yarışmaları, konserler, yöresel lezzetler). Çorum Kültür ve Sanat Festivali (temmuz ayında, Çorum merkez, konserler, halk oyunları, panayır). İskilip Kültür ve Lezzet Festivali (ağustos ayında, İskilip\'te tarihi evler önünde konserler, İskilip peyniri, leblebi, tarhana yarışmaları). Osmancık Kültür ve Pirinç Festivali (eylül ayında, Osmancık\'ta pirinç yemek yarışmaları, konserler). Alacahöyük Kültür ve Sanat Festivali (temmuz ayında, Alacahöyük ören yerinde konserler, halk oyunları). Boğazkale Kültür ve Turizm Festivali (ağustos ayında). Ayrıca Çorum\'da düzenlenen \"Hitit Yolu Yürüyüşü\" (Hattuşaş-Yazılıkaya-Alacahöyük arası) ve \"Uluslararası Çorum Bisiklet Turu\" da ilgi çeker.', 'Çorum\'u ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, Hitit başkenti Hattuşaş gibi tarihi yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 28-33°C\'ye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve karlıdır, sıcaklık genelde -5 ile 5°C arasındadır, zaman zaman kar yağışı görülür. Çorum\'u ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Çorum\'a en yakın havalimanı Amasya Merzifon Havalimanı\'dır (yaklaşık 80 km). Havalimanından havaş otobüsleri veya taksi ile Çorum\'a ulaşılır. Ayrıca Ankara Esenboğa Havalimanı (230 km) veya Samsun Çarşamba Havalimanı (150 km) da kullanılabilir. Çorum\'a şehirlerarası otobüs terminali (Çorum Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır. Çorum, Ankara-Samsun karayolu üzerinde olduğu için özel araçla ulaşım kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Amasya veya Kırıkkale\'dedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. İskilip, Osmancık, Sungurlu, Boğazkale, Alacahöyük (Alaca ilçesi), Mecitözü, Uğurludağ, Oğuzlar, Dodurga gibi ilçelere minibüslerle rahat ulaşım vardır. Hattuşaş, Yazılıkaya, Alacahöyük, Şapinuva gibi Hitit merkezlerine gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Çorum, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Çorum, Hitit İmparatorluğu\'nun başkenti Hattuşaş\'a ev sahipliği yapmasıyla dünya çapında ünlüdür. Hitit döneminde bölge, önemli bir siyasi ve kültürel merkez olmuştur. Osmanlı döneminde Çorum Sancağı olarak yönetilmiştir. Kurtuluş Savaşı\'nda önemli bir direniş merkezi olmuştur. Cumhuriyet döneminde il statüsü kazanmıştır. Çorum, tarihi ve arkeolojik zenginlikleri, leblebisi ve el sanatlarıyla öne çıkan bir İç Anadolu ilidir.', 'Çorum', '2026-04-08 23:20:51'),
(25, 'Denizli', 'Ege', 'denizli.jpg', 'Pamukkale ile ünlü.', 'Denizli denince akla gelen ilk şeyler: Pamukkale (dünyaca ünlü beyaz travertenler, sıcak su kaynakları, pamuk görünümlü kalsiyum terasları, UNESCO Dünya Mirası Listesi, travertenlerde yürüyüş, termal havuzlar, antik havuz (Kleopatra Havuzu), manzara), Hierapolis Antik Kenti (Pamukkale\'nin tepesinde, antik kent, tiyatro, nekropol, Roma hamamları, Apollo Tapınağı, kutsal alan, Hierapolis Arkeoloji Müzesi), Laodikeia Antik Kenti (Denizli\'nin 6 km kuzeyinde, Roma dönemi, tiyatro, stadyum, hamamlar, su kemerleri, tapınaklar, laodikeia kilisesi, freskler, mozaikler), Tripolis Antik Kenti (Buldan ilçesi yakınlarında), Colossae Antik Kenti (Honaz ilçesi yakınlarında, antik kent höyüğü, kilise kalıntıları), Kaklık Mağarası (Honaz ilçesi, traverten oluşumları, sarkıt ve dikitler, yürüyüş yolları), Denizli Kalesi (şehir merkezinde, tarihi sur kalıntıları, manzara), Denizli Arkeoloji Müzesi (Hierapolis ve Laodikeia eserleri), Atatürk Etiyoloji Müzesi, Güney ilçesi (Güney köftesi), Buldan ilçesi (Buldan bez dokumacılığı, Buldan evleri, yaylalar), Çal ilçesi (Çal üzümü, Çal şarabı, bağ bozumu, şarap evleri), Honaz ilçesi (Honaz Dağı, Honaz Peyniri, Honaz cevizi, doğa yürüyüşleri), Acıpayam ilçesi (Acıpayam cevizi, yaylalar), Tavas ilçesi (Tavas tarhanası, Tavas halıları, yaylalar), Serinhisar ilçesi (Serinhisar elması), Babadağ ilçesi (Babadağ alıcı, yaylalar), Bekilli ilçesi (şarap üretimi), Çivril ilçesi (Işıklı Gölü, kuş cenneti), Beyağaç ilçesi (Kartal Gölü, yaylalar), Bozkurt ilçesi (yaylalar), Cardak ilçesi (Cardak Havalimanı), Akköy ilçesi (termal kaplıcalar), Pamukkale ilçesi (Pamukkale travertenleri, Hierapolis), Karahayıt (kırmızı su termal kaynağı, kırmızı travertenler), Honaz Dağı Milli Parkı (doğa yürüyüşleri, kamp, manzara), Işıklı Gölü (kuş gözlem, piknik), Kartal Gölü (krater gölü, doğa), Denizli\'nin dar sokakları, tarihi çarşısı, Denizli horozu (Denizli\'nin sembolü, ötüşü ünlü), Denizli\'nin pamuk tarlaları, tekstil fabrikaları mutlaka görülmelidir.', 'Denizli mutfağı, Ege ve İç Anadolu mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Denizli kebabı\" gelir. \"Denizli şiş\", \"Denizli köftesi\", \"etli ekmek\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"ot kavurması\", \"çılbır\", \"mıhlama\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"içli köfte\", \"mercimek köftesi\", \"cızlama\", \"katmer\", \"gözleme\", \"pide\", \"kete\", \"Buldur\", \"hamur işleri\" yöresel lezzetlerdir. Tatlı olarak \"Denizli baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Denizli lokumu\", \"şambalı\" meşhurdur. Denizli\'nin \"pamuklu kumaşı\" (tekstil), \"Honaz peyniri\", \"Çal üzümü\", \"Çal şarabı\", \"Güney köftesi\", \"Acıpayam cevizi\", \"Tavas tarhanası\", \"Babadağ alıcı\", \"Serinhisar elması\", \"bekmez\", \"tahin\", \"balı\", \"kurutulmuş sebzeleri\", \"zeytini\", \"zeytinyağı\" da ünlüdür.', 'Denizli\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Pamukkale Kültür ve Sanat Festivali (temmuz-ağustos aylarında, Pamukkale travertenleri ve Hierapolis Antik Tiyatrosu\'nda konserler, tiyatro gösterileri, bale). Uluslararası Denizli Horozu ve Kültür Festivali (eylül ayında, Denizli merkez, horoz yarışmaları, konserler, yöresel lezzetler, sergiler, panayır). Uluslararası Laodikeia Kültür ve Sanat Festivali (ekim ayında, Laodikeia Antik Kenti\'nde konserler, gösteriler). Denizli Kültür ve Turizm Festivali (mayıs ayında, Denizli merkez, konserler, halk oyunları). Çal Üzüm ve Şarap Festivali (eylül ayında, Çal ilçesinde bağ bozumu, şarap tadımı, yöresel lezzetler, konserler). Buldan Bezi ve Kültür Festivali (ağustos ayında, Buldan ilçesinde Buldan bezi dokuma sergileri, atölyeler, defile, konserler). Acıpayam Ceviz ve Kültür Festivali (ekim ayında, Acıpayam\'da ceviz hasadı, ceviz yarışmaları, yöresel lezzetler). Honaz Kültür ve Sanat Festivali (temmuz ayında). Tavas Kültür ve Tarhana Festivali (ağustos ayında). Ayrıca Denizli\'de düzenlenen \"Pamukkale Maratonu\", \"Denizli Bisiklet Turu\" ve \"Honaz Dağı Doğa Yürüyüşü\" de ilgi çeker.', 'Denizli\'yi ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır, Pamukkale travertenleri ve antik kentleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 35-40°C\'ye ulaşabilir, çok sıcak ve kuraktır, bu nedenle sıcaktan hoşlanmayanlar için ilkbahar ve sonbahar daha uygundur. Kışlar ılımandır, sıcaklık genelde 5-12°C arasındadır, yağışlı olabilir, zaman zaman kar yağışı görülür (Pamukkale\'de kış ayrı güzeldir). Denizli\'yi yılın her mevsimi ziyaret etmek mümkündür, ancak en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Denizli\'ye hava yoluyla gelmek için Denizli Çardak Havalimanı (DNZ) kullanılır. Havalimanı şehir merkezine yaklaşık 65 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Denizli\'ye şehirlerarası otobüs terminali (Denizli Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır. Denizli, İzmir-Aydın-Denizli karayolu üzerinde olduğu için özel araçla ulaşım kolaydır. Denizli, İzmir-Denizli demiryolu hattı üzerindedir ve Yüksek Hızlı Tren (YHT) projeleriyle bağlantılıdır (şehir içinde tren garı mevcuttur, İzmir, Ankara, Eskişehir bağlantılı). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri, taksi ve teleferik (Pamukkale\'ye çıkan) kullanılır. Pamukkale, Honaz, Buldan, Çal, Acıpayam, Tavas, Serinhisar, Babadağ, Bekilli, Çivril, Beyağaç, Bozkurt, Cardak, Akköy, Güney gibi ilçelere minibüslerle rahat ulaşım vardır. Pamukkale, Hierapolis, Laodikeia, Kaklık Mağarası, Honaz Dağı, Işıklı Gölü, Kartal Gölü gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n', 'Denizli, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, Frigya uygarlığının önemli merkezlerinden biri olmuştur. Roma döneminde Laodikeia ve Hierapolis gibi önemli kentler kurulmuştur. Osmanlı döneminde Denizli Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Denizli, pamuklu dokuma sanayisi, tekstil ürünleri, termal kaynakları ve doğal güzellikleriyle öne çıkan bir Ege ilidir. Dünyaca ünlü Pamukkale travertenleri de buradadır.', 'Denizli', '2026-04-08 23:20:51'),
(26, 'Diyarbakır', 'Güneydoğu Anadolu', 'diyarbakir.jpg', 'Surları ile ünlü.', 'Diyarbakır denince akla gelen ilk şeyler: Diyarbakır Surları (dünyanın en uzun ve en sağlam surları, 5.5 km uzunluğunda, 16-22 metre yüksekliğinde, 82 burç, tarihi kapılar: Dağ Kapı, Mardin Kapı, Urfa Kapı, Yeni Kapı, Oğrun Kapı, İçkale, sur üzerinde yürüyüş, manzara), İçkale (Diyarbakır\'ın iç kalesi, Artuklu Sarayı, Viranşehir Kapısı, Evli Beden Burcu, Yedi Kardeş Burcu), Ulu Cami (Diyarbakır\'ın en büyük camisi, İslam dünyasının en eski camilerinden biri, 639 yılında inşa edilmiş, avlusu, minaresi, tarihi önemi), Dört Ayaklı Minare (Şeyh Mutahhar Cami, efsaneye göre dört ayağına çıkan dilekler kabul olur), Hevsel Bahçeleri (Dicle Nehri kıyısında, UNESCO Dünya Mirası Listesi, 8.000 yıllık tarım alanları, doğa yürüyüşleri, kuş gözlem), Dicle Nehri (Diyarbakır\'ın doğusundan akar, On Gözlü Köprü (Malabadi Köprüsü de denir, 12. yüzyıl, Artuklu dönemi), Dicle Köprüsü (On Gözlü Köprü), kenarında yürüyüş, balıkçılar, manzara), Meryem Ana Kilisesi (Süryani Kadim Kilisesi, 3. yüzyıl, Diyarbakır\'ın en eski kilisesi, mozaikler, freskler), Mar Petyun Kilisesi (Keldani Kilisesi), Aziz George Kilisesi, Hasan Paşa Hanı (tarihi han, avlusu, kafeler, alışveriş), Çarşı Hamamı (tarihi hamam), Sülüklü Han (tarihi han), Cahit Sıtkı Tarancı Evi (müze, şairin evi), Diyarbakır Arkeoloji Müzesi (arkeolojik eserler, Artuklu eserleri, etnografik eserler), Ziya Gökalp Müzesi, Atatürk Evi Müzesi, Dicle Vadisi, Eğil ilçesi (Eğil Kalesi, Eğil Mağaraları, Hz. Zülkifl Makamı, tarihi kiliseler, Dicle Nehri kenarı), Çermik ilçesi (termal kaplıcalar, Çermik Kaplıcası), Çüngüş ilçesi (yaylalar), Ergani ilçesi (Çayönü Höyüğü (Çayönü Kazıları, Neolitik dönem, dünyanın en eski yerleşimlerinden biri), tarihi yapılar), Kulp ilçesi (yaylalar), Lice ilçesi (yaylalar), Silvan ilçesi (Malabadi Köprüsü, Silvan Kalesi), Hazro ilçesi (tarihi evler), Bismil ilçesi (Dicle Nehri kenarı, doğa), Hani ilçesi (yaylalar), Diyarbakır Karpuz Tarlaları, Karpuz Festivali alanı, Diyarbakır Evleri (tarihi taş evler, dar sokaklar, süslemeler), Diyarbakır\'ın bakırcılar çarşısı, Diyarbakır\'ın taş işlemeciliği, Diyarbakır\'ın el sanatları, Diyarbakır\'ın tiftik keçisi mutlaka görülmelidir.', 'Diyarbakır mutfağı, Güneydoğu Anadolu\'nun en zengin ve en baharatlı mutfaklarından biridir. Mutlaka denenmesi gerekenlerin başında \"Diyarbakır ciğer kebabı\" (kuzu ciğeri, kuyruk yağı, pul biber, şişte pişirilir) gelir. \"Diyarbakır tava\", \"içli köfte\", \"kibbe\" (içli köftenin farklı versiyonu), \"kuzu tandır\", \"büryan kebabı\" (tandırda pişmiş kuzu), \"perde pilavı\" (etli, bademli, kuş üzümlü pilav, ince yufkayla kaplanır), \"lahmacun\", \"çiğ köfte\" (etli, baharatlı), \"mercimek köftesi\", \"sarma\", \"dolma\", \"ekşili köfte\", \"yayla çorbası\", \"mercimek çorbası\", \"tarhana çorbası\", \"patlıcan kebabı\", \"soğan kebabı\", \"kuzu şiş\", \"tavuk şiş\", \"etli ekmek\", \"katmer\", \"gözleme\", \"Bumbar\" (kuzu bağırsağına et, pirinç, baharat doldurulur), \"meftune\" (etli, sebzeli güveç), \"kaburga dolması\", \"kuzu dolması\", \"kibe\" (etli, bulgurlu, fırında) yöresel lezzetlerdir. Tatlı olarak \"Diyarbakır kadayıfı\", \"burma kadayıf\", \"baklava\", \"künefe\", \"şöbiyet\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"kabak tatlısı\", \"sütlaç\", \"Diyarbakır lokumu\", \"Karpuz tatlısı\" (karpuz kabuğundan yapılır) meşhurdur. Diyarbakır\'ın \"karpuzu\" (Diyarbakır karpuzu dünyaca ünlü, iri ve tatlı), \"pekmezi\", \"tahini\", \"balı\", \"cevizi\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"peyniri\", \"otlu peyniri\", \"Diyarbakır şalgamı\", \"Diyarbakır narı\", \"Diyarbakır üzümü\", \"Diyarbakır elması\" da ünlüdür.', 'Diyarbakır\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Diyarbakır Kültür ve Sanat Festivali (ekim ayında, Diyarbakır merkez, surlar önünde konserler, halk oyunları, yöresel lezzetler, panayır, sergiler, panel). Uluslararası Diyarbakır Karpuz Festivali (ağustos ayında, Diyarbakır merkez, karpuz yarışmaları, dünyanın en büyük karpuzu, karpuz oymacılığı, konserler, yöresel lezzetler). Dicle Kültür ve Doğa Festivali (mayıs ayında, Dicle Nehri kenarında doğa yürüyüşleri, konserler). Hevsel Bahçeleri Kültür ve Tarım Festivali (eylül ayında, Hevsel Bahçeleri\'nde tarım sergileri, yöresel ürünler, doğa yürüyüşleri). Eğil Kültür ve Turizm Festivali (temmuz ayında, Eğil ilçesinde konserler, tarihi alanların tanıtımı). Çermik Kaplıca ve Termal Turizm Festivali (haziran ayında, Çermik ilçesinde termal su tanıtımı, konserler). Ergani Kültür ve Sanat Festivali (ağustos ayında, Ergani ilçesinde). Ayrıca Diyarbakır\'da düzenlenen \"Dicle Köprüsü Yürüyüşü\", \"Diyarbakır Maratonu\" ve \"Diyarbakır Bisiklet Turu\" da ilgi çeker.', 'Diyarbakır\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır, tarihi surları ve antik kentleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 40°C\'nin üzerine çıkabilir, çok sıcak ve kuraktır, bu nedenle sıcaktan hoşlanmayanlar için ilkbahar ve sonbahar daha uygundur. Kışlar soğuktur, sıcaklık genelde 0-8°C arasındadır, yağışlı ve zaman zaman karlıdır. Diyarbakır\'ı ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Diyarbakır\'a hava yoluyla gelmek için Diyarbakır Havalimanı (DIY) kullanılır. Havalimanı şehir merkezine yaklaşık 5 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Diyarbakır\'a şehirlerarası otobüs terminali (Diyarbakır Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır. Diyarbakır, Doğu Ekspresi\'nin güzergahında olup demiryolu ile Ankara, Kayseri, Sivas, Malatya, Elazığ, Batman, Kurtalan gibi illere bağlıdır. Diyarbakır Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kayapınar, Bağlar, Yenişehir, Sur, Bismil, Çermik, Ergani, Silvan, Kulp, Lice, Eğil, Hani, Hazro, Çüngüş, Dicle gibi ilçelere minibüslerle rahat ulaşım vardır. Diyarbakır surları, Ulu Cami, Hevsel Bahçeleri, Dicle Nehri, On Gözlü Köprü, Eğil, Çayönü Höyüğü gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Diyarbakır, tarihi boyunca Hurriler, Mitanniler, Asurlular, Urartular, İskitler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Mervaniler, Selçuklular, Artuklular, Eyyubiler, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Amid\" adıyla anılmıştır. Roma döneminde önemli bir askeri ve idari merkez haline gelmiştir. Diyarbakır surları, dünyanın en uzun ve en sağlam surları arasında gösterilmektedir. Osmanlı döneminde Diyarbakır Eyaleti\'nin merkezi olmuştur. Cumhuriyet döneminde il statüsünü korumuştur. Diyarbakır, tarihi yapıları, surları, karpuzu, yöresel yemekleri ve kültürel zenginliğiyle öne çıkan bir Güneydoğu Anadolu ilidir.', 'Diyarbakır', '2026-04-08 23:20:51'),
(27, 'Düzce', 'Karadeniz', 'duzce.jpg', 'Akçakoca ile ünlü.', 'Düzce denince akla gelen ilk şeyler: Samandere Şelalesi (Düzce\'nin en ünlü şelalesi, Samandere Köyü\'nde, doğa yürüyüşü, ahşap yürüyüş yolları, şelale manzarası, piknik alanı, mesire yeri), Güzeldere Şelalesi (Güzeldere Köyü, yüksekten dökülen şelale, doğa harikası), Kurugöl Şelalesi (Kurugöl Köyü, şelale ve göl bir arada), Ceneviz Şelalesi (Ceneviz Köyü), Koca Şelale, Sultaniye Şelalesi, Efteni Gölü (Efteni Kuş Cenneti, göçmen kuşlar, flamingolar, pelikanlar, doğa yürüyüşleri, kuş gözlem, piknik), Büyük Melen Çayı (Melen Nehri, rafting, kano, doğa yürüyüşleri, balık tutma), Gölyaka ilçesi (Gölyaka Gölü, doğa), Yığılca ilçesi (Yığılca ormanları, yaylalar, Yığılca balı, Yığılca evleri, tarihi camiler), Akçakoca ilçesi (Karadeniz sahili, Akçakoca Kalesı (Ceneviz Kalesi), Akçakoca Plajı, Akçakoca Feneri, Akçakoca Limanı, balıkçılar, deniz ürünleri, tarihi evler, Orhan Gazi Cami, Akçakoca Müzesi), Akçakoca Yaylası (Ceneviz Yaylası, Güzeldere Yaylası, doğa yürüyüşleri), Çilimli ilçesi (Çilimli Şelalesi, doğa), Cumayeri ilçesi (Cumayeri Kaplıcaları, termal su), Kaynaşlı ilçesi (Kaynaşlı Yaylası), Gümüşova ilçesi (Gümüşova Şelalesi), Düzce Kalesi (Konuralp ilçesinde, tarihi kale kalıntıları), Konuralp Müzesi (Konuralp ilçesi, arkeolojik eserler, mozaikler, Prusias ad Hypium antik kenti, tiyatro kalıntıları, su kemerleri), Prusias ad Hypium Antik Kenti (Konuralp, Roma dönemi, tiyatro, hamamlar, su kemerleri, surlar), Düzce Arkeoloji Müzesi (Düzce merkez, Konuralp ve çevre kazı eserleri), Düzce Fındık Bahçeleri (Düzce\'nin her yerinde fındık bahçeleri, fındık hasadı ağustos-eylül aylarında), Düzce Ormanları (gür ormanlar, yürüyüş parkurları, kamp alanları), Düzce Yaylaları (Kardüz Yaylası, Sırakayalar Yaylası, Topuk Yaylası, Abaza Yaylası, Ceneviz Yaylası, doğa yürüyüşleri, yayla şenlikleri), Düzce\'nin tarihi evleri (Konuralp ve Akçakoca\'da restore edilmiş evler), Düzce\'nin el sanatları (Düzce bezi, ahşap oymacılığı), Düzce\'nin bakır işlemeciliği mutlaka görülmelidir.', 'Düzce mutfağı, Karadeniz ve Batı Karadeniz mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Düzce fındığı\" (Türkiye\'nin en kaliteli fındıkları burada yetişir) gelir. \"Düzce mantısı\" (etli, yoğurtlu, yağlı), \"Düzce köftesi\", \"etli ekmek\", \"kavurma\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"hamsi tava\", \"hamsi buğulama\" yöresel lezzetlerdir. Tatlı olarak \"Düzce baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Düzce lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı helva\" meşhurdur. Düzce\'nin \"fındığı\", \"Düzce balı\", \"cevizi\", \"elması\", \"üzümü\", \"kestanesi\", \"kurutulmuş sebzeleri\", \"keçi peyniri\", \"tulum peyniri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\", \"tahini\", \"pekmezi\", \"Düzce pidesi\" de ünlüdür.', 'Düzce\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Düzce Fındık Festivali (ağustos ayında, Düzce merkez, fındık hasadı, fındık yarışmaları, fındık kırmaca, fındık tadımı, konserler, yöresel lezzetler, halk oyunları, panayır). Uluslararası Akçakoca Kültür ve Sanat Festivali (temmuz ayında, Akçakoca ilçesinde, Akçakoca Kalesi önünde konserler, halk oyunları, deniz yarışları, yöresel lezzetler). Samandere Şelalesi Doğa ve Kültür Festivali (mayıs ayında, Samandere Şelalesi\'nde doğa yürüyüşleri, konserler, piknik). Efteni Gölü Kuş Cenneti ve Doğa Festivali (nisan ayında, Efteni Gölü\'nde kuş gözlem, doğa yürüyüşleri, fotoğraf yarışması). Yığılca Bal ve Kültür Festivali (ağustos ayında, Yığılca ilçesinde bal tadımı, bal yarışmaları, yöresel lezzetler, konserler). Konuralp Kültür ve Tarih Festivali (eylül ayında, Konuralp\'te Prusias ad Hypium Antik Kenti\'nde tarihi canlandırmalar, konserler). Gölyaka Kültür ve Doğa Festivali (temmuz ayında, Gölyaka\'da doğa yürüyüşleri, konserler). Ayrıca Düzce\'de düzenlenen \"Melen Nehri Rafting Festivali\", \"Düzce Bisiklet Turu\" ve \"Düzce Doğa Yürüyüşleri\" de ilgi çeker.', 'Düzce\'yi ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 18-28°C arasındadır, yaylalar yeşildir, şelaleler coşkun akar, doğa yürüyüşleri için idealdir. Sonbahar (eylül-ekim) da güzeldir, yaprakların renklendiği dönemdir. Kışlar ılıman geçer, sıcaklık genelde 0-8°C arasındadır, zaman zaman kar yağışı görülür, ancak kış ayları da doğa için ayrı bir güzellik sunar. Düzce\'yi yılın her mevsimi ziyaret etmek mümkündür, ancak en uygun zaman nisan-mayıs ve haziran-eylül aylarıdır.', 'Düzce\'ye en yakın havalimanı Zonguldak Havalimanı\'dır (Çaycuma, yaklaşık 100 km). Havalimanından havaş otobüsleri veya taksi ile Düzce\'ye ulaşılır. Ayrıca İstanbul Sabiha Gökçen Havalimanı (200 km) veya Ankara Esenboğa Havalimanı (220 km) da kullanılabilir. Düzce\'ye şehirlerarası otobüs terminali (Düzce Otogarı) şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır (özellikle İstanbul, Ankara, Bursa, İzmir, Adapazarı, Bolu, Zonguldak, Bartın). Düzce, İstanbul-Ankara karayolu (TEM otoyolu) üzerinde olduğu için özel araçla ulaşım çok kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Adapazarı veya Zonguldak\'tadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Akçakoca, Yığılca, Gölyaka, Çilimli, Cumayeri, Kaynaşlı, Gümüşova, Konuralp gibi ilçelere minibüslerle rahat ulaşım vardır. Samandere Şelalesi, Güzeldere Şelalesi, Efteni Gölü, Akçakoca, Prusias ad Hypium, Yığılca yaylaları gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Düzce, tarihi boyunca Bitinler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde bölge, Bitinya uygarlığının önemli merkezlerinden biri olmuştur. Osmanlı döneminde Bolu Sancağı\'na bağlı bir kaza olarak yönetilmiştir. Cumhuriyet döneminde önce Bolu\'ya bağlanan Düzce, 1999 yılında meydana gelen büyük depremin ardından 9 Aralık 1999 tarihinde il statüsü kazanmıştır. Türkiye\'nin en genç illerinden biridir. Düzce, ormanları, yaylaları, şelaleleri ve fındık bahçeleriyle öne çıkan bir Karadeniz ilidir.', 'Düzce', '2026-04-08 23:20:51'),
(28, 'Edirne', 'Marmara', 'edirne.jpg', 'Selimiye Camii ile ünlü.', 'Edirne denince akla gelen ilk şeyler: Selimiye Camii (Mimar Sinan\'ın usta eseri, UNESCO Dünya Mirası Listesi, dünyanın en güzel camilerinden biri, 4 minaresi, devasa kubbesi, iç mekan çinileri, mermer işçiliği, akustiği, Edirne\'nin simgesi), Eski Cami (Ulu Cami, Osmanlı dönemi, büyük avlusu, 9 kubbeli, duvarlarında hat yazıları), Üç Şerefeli Cami (Osmanlı dönemi, 4 minaresi, 3 şerefeli minare, taş işçiliği), Muradiye Cami (Osmanlı dönemi, çinileri meşhur), Edirne Sarayı (Osmanlı dönemi saray kalıntıları, saray mutfağı, cihannüma kasrı, adalet kasrı, manzara), Edirne Kalesi (surlar, tarihi sur kalıntıları, kaleler), Kırkpınar Yağlı Güreşleri (dünyanın en eski spor organizasyonu, her yıl temmuz ayında düzenlenir, yağlı güreşler, pehlivanlar, altın kemer, Edirne\'nin sembolü), Meriç Nehri, Tunca Nehri, Arda Nehri (Edirne\'yi çevreleyen nehirler, üzerinde tarihi köprüler), Meriç Köprüsü (Mimar Sinan köprüsü), Tunca Köprüsü, Gazi Mihal Köprüsü, Kanuni Köprüsü, Fatih Köprüsü (tarihi taş köprüler), Edirne Müzesi (arkeolojik ve etnografik eserler, Türk İslam eserleri), II. Bayezid Külliyesi (Sağlık Müzesi, Osmanlı dönemi hastanesi, müze, manzara), Edirne Arkeoloji Müzesi, Türk İslam Eserleri Müzesi, Atatürk Evi Müzesi (Atatürk\'ün Edirne\'de kaldığı ev), Balkan Savaşı Müzesi, Lozan Anıtı, Karagöz ve Hacivat (gölge oyunu, Edirne\'de doğmuşlardır), Edirne Evleri (tarihi Osmanlı evleri, dar sokaklar, restorasyon), Edirne Kapalı Çarşı (tarihi çarşı, badem ezmesi alışverişi), Edirne Bedesteni, Arasta Çarşısı, Edirne\'nin el sanatları (bakır işlemeciliği, Edirne bezi, Edirne kilimi), Edirne\'nin yaylaları, Edirne\'nin köyleri, Karaağaç (Edirne\'nin bir mahallesi, Meriç Nehri kenarı, tren istasyonu, Edirne\'nin yeşil alanı), Bosna Köyü (tarihi evleri), Süloğlu, Lalapaşa, Havsa, Uzunköprü ilçesi (Uzunköprü, dünyanın en uzun taş köprüsü, 1392 yılında yapılmış, 1.392 metre uzunluğunda, 174 kemerli), İpsala ilçesi (İpsala Sınır Kapısı, Yunanistan\'a açılan kapı), Keşan ilçesi (Keşan\'ın elması, Keşan\'ın peyniri), Enez ilçesi (Enez Kalesı, Enez Sahili, Meriç Deltası, kuş cenneti, Enez Plajı, Enez Antik Kenti), Meriç Deltası (Enez\'de, kuş cenneti, doğa harikası), Gala Gölü (Enez\'de, doğa, kuş gözlem), Enez Evleri (tarihi taş evler), Edirne\'nin nehir kenarındaki çay bahçeleri, Edirne\'nin kahvaltıcıları (Edirne kahvaltısı, Edirne böreği, Edirne peyniri, Edirne yoğurdu, Edirne sucuğu ile meşhur) mutlaka görülmelidir.', 'Edirne mutfağı, Osmanlı mutfağının en zengin örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"Edirne ciğeri\" (kuzu ciğerinin unlanıp kızartılması, yanında patates ve soğan) gelir. \"Edirne tava\", \"Edirne köftesi\", \"tava ciğer\", \"börek\" (Edirne böreği, peynirli, kıymalı), \"Edirne mantısı\", \"yaprak sarma\", \"dolma\", \"güveç\", \"keşkek\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"çılbır\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"içli köfte\", \"mercimek köftesi\", \"Edirne peyniri\", \"Edirne yoğurdu\", \"Edirne pastırması\", \"Edirne sucuğu\", \"badem ezmesi\", \"Edirne şekeri\", \"Edirne lokumu\" yöresel lezzetlerdir. Tatlı olarak \"Edirne baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"badem ezmesi\", \"Edirne şekeri\", \"Edirne lokumu\", \"hanımgöbeği\" meşhurdur. Edirne\'nin \"badem ezmesi\", \"Edirne peyniri\", \"Edirne yoğurdu\", \"Edirne pastırması\", \"Edirne sucuğu\", \"Edirne şekeri\", \"Edirne lokumu\", \"Edirne kırmızı biberi\", \"Edirne ayvası\", \"Edirne elması\", \"Edirne üzümü\", \"Edirne balı\", \"Edirne zeytini\", \"Edirne zeytinyağı\" da ünlüdür.', 'Edirne\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Kırkpınar Yağlı Güreşleri Festivali (temmuz ayının ilk haftası, Kırkpınar Er Meydanı\'nda, yağlı güreşler, pehlivanlar, altın kemer, konserler, panayır, yöresel lezzetler, Edirne\'nin en büyük etkinliği). Uluslararası Edirne Kültür ve Sanat Festivali (mayıs ayında, Edirne merkez, Selimiye Camii önünde konserler, halk oyunları, sergiler). Uluslararası Edirne Ciğer Festivali (eylül ayında, Edirne merkez, ciğer yarışmaları, ciğer tadımı, konserler, yöresel lezzetler). Edirne Badem Ezmesi Festivali (ekim ayında, Edirne merkez, badem ezmesi yapım atölyeleri, badem ezmesi yarışmaları, konserler). Enez Kültür ve Doğa Festivali (ağustos ayında, Enez ilçesinde, Enez Plajı\'nda konserler, deniz yarışları, doğa yürüyüşleri). Uzunköprü Kültür ve Sanat Festivali (eylül ayında, Uzunköprü ilçesinde, Uzunköprü\'de konserler, yöresel lezzetler). Keşan Kültür ve Elma Festivali (ekim ayında, Keşan ilçesinde, elma yarışmaları, elma tadımı, konserler). Ayrıca Edirne\'de düzenlenen \"Edirne Bisiklet Turu\", \"Edirne Maratonu\" ve \"Meriç Nehri Yüzme Yarışı\" da ilgi çeker.', 'Edirne\'yi ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, tarihi camiler, köprüler ve müzeleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 30-35°C\'ye ulaşabilir, nem oranı yüksektir, ancak temmuz ayında düzenlenen Kırkpınar Yağlı Güreşleri için yaz ayları tercih edilir. Kışlar soğuk ve yağışlıdır, sıcaklık genelde 0-8°C arasındadır, zaman zaman kar yağışı görülür. Edirne\'yi ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır, ancak güreşleri görmek için temmuz ayı idealdir.', 'Edirne\'ye hava yoluyla gelmek için en yakın havalimanı İstanbul Havalimanı (220 km) veya Tekirdağ Çorlu Havalimanı (120 km) kullanılır. Havalimanlarından havaş otobüsleri, şehirlerarası otobüsler veya taksi ile Edirne\'ye ulaşılır. Edirne\'ye şehirlerarası otobüs terminali (Edirne Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (İstanbul, Ankara, İzmir, Bursa, Tekirdağ, Kırklareli, Çanakkale). Edirne, İstanbul-Edirne karayolu (TEM otoyolu) üzerinde olduğu için özel araçla ulaşım çok kolaydır. Edirne, İstanbul-Edirne demiryolu hattı üzerindedir (İstanbul\'dan kalkan trenlerle ulaşılır). Edirne Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Uzunköprü, Keşan, İpsala, Enez, Havsa, Lalapaşa, Süloğlu, Meriç gibi ilçelere minibüslerle rahat ulaşım vardır. Selimiye Camii, Eski Cami, Üç Şerefeli Cami, Edirne Müzesi, II. Bayezid Külliyesi, Uzunköprü, Enez Antik Kenti, Meriç Deltası, Gala Gölü, Kırkpınar Er Meydanı gibi yerlere gitmek için araç kiralamak veya turları tercif etmek önerilir.', 'Edirne, tarihi boyunca Traklar, Persler, Romalılar, Bizanslılar ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Hadrianopolis\" adıyla anılmıştır. Edirne, 1365 yılında Osmanlı İmparatorluğu\'nun başkenti olmuş ve İstanbul\'un fethine kadar (1453) bu özelliğini korumuştur. Osmanlı döneminde birçok önemli eser inşa edilmiştir. Cumhuriyet döneminde il statüsünü korumuştur. Edirne, tarihi yapıları, köprüleri, camileri, sınır kapısı ve ünlü yağlı güreşleriyle öne çıkan bir Marmara ilidir.', 'Edirne', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(29, 'Elazığ', 'Doğu Anadolu', 'elazig.jpg', 'Hazar Gölü ile ünlü.', 'Elazığ denince akla gelen ilk şeyler: Harput (Eski Elazığ, tarihi yarımada, Harput Kalesi, Ulu Cami (Harput Ulu Cami, Anadolu\'nun en eski camilerinden biri, 1157 yılında yapılmış), Sarahatun Cami, Kurşunlu Cami, Meryem Ana Kilisesi (Harput\'ta), Harput Evleri (tarihi taş evler, dar sokaklar, restore edilmiş evler), Harput Müzesi (Elazığ Arkeoloji Müzesi, Harput eserleri), Harput Konağı, Harput Mahallesi), Harput Kalesi (Elazığ\'ın simgesi, şehre hakim tepede, Urartu dönemi, surlar, iç kale, zindanlar, sarnıçlar, manzara), Hazar Gölü (Gölcük, Elazığ\'ın güneyinde, krater gölü, doğal güzellik, yüzme, piknik, kamp, balık tutma, sandal gezisi, çay bahçeleri, manzara), Keban Barajı (Fırat Nehri üzerinde, Türkiye\'nin ilk büyük barajı, 1974 yılında tamamlandı, baraj gölü, doğa, balıkçılık, su sporları), Fırat Nehri (Elazığ\'dan doğar, Keban Barajı ve Karakaya Barajı ile çevrilidir), Karakaya Barajı, Elazığ Müzesi (arkeolojik ve etnografik eserler), Atatürk Evi Müzesi, Buzluk Mağarası (Harput\'ta, doğal mağara, yazın serin, kışın buz tutar), Ağa Camii, Alacalı Cami, PTT Cami, Çarşı Hamamı (tarihi hamam), Kurşunlu Han (tarihi han), Ağabeyler Konağı (tarihi konak), Baskil ilçesi (Baskil peyniri, yaylalar), Karakoçan ilçesi (yaylalar, doğa), Kovancılar ilçesi (yaylalar), Maden ilçesi (Maden ilçesinin bakır madeni, tarihi yapılar), Palu ilçesi (Palu Kalesi, Palu Çayı, tarihi evler), Sivrice ilçesi (Hazar Gölü kenarında, Sivrice ilçe merkezi, doğa), Elazığ\'ın tarihi çarşısı, Elazığ\'ın bakırcılar çarşısı, Elazığ\'ın el sanatları (bakır işlemeciliği, halıcılık, kilim dokumacılığı), Elazığ\'ın mağaraları (Buzluk Mağarası, Diyadin Mağarası), Elazığ\'ın mesire alanları, Elazığ\'ın yaylaları (Ziyaret Yaylası, Çaydaçıra Yaylası, Sarıçiçek Yaylası), Elazığ\'ın tarihi evleri (Harput\'taki taş evler) mutlaka görülmelidir.', 'Elazığ mutfağı, Doğu Anadolu\'nun zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Elazığ köftesi\" gelir. \"Harput köftesi\" (içli köfte), \"elazığ tava\", \"etli ekmek\", \"kavurma\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"hamsi tava\", \"hamsi buğulama\", \"Elazığ usulü etli ekmek\", \"Elazığ usulü içli köfte\" yöresel lezzetlerdir. Tatlı olarak \"Elazığ baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Elazığ lokumu\", \"Elazığ orcik\" (cevizli sucuk) meşhurdur. Elazığ\'ın \"Harput peyniri\", \"Elazığ balı\", \"Elazığ üzümü\", \"Elazığ cevizi\", \"Elazığ karpuzu\", \"Elazığ elması\", \"Elazığ kavunu\", \"Elazığ dutu\", \"Elazığ pekmezi\", \"Elazığ tahini\", \"Elazığ tarhanası\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\" da ünlüdür.', 'Elazığ\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Harput Kültür ve Sanat Festivali (ağustos ayında, Harput\'ta, Harput Kalesi ve Ulu Cami önünde konserler, halk oyunları, yöresel lezzetler, panayır, sergiler, panel). Uluslararası Hazar Gölü Kültür ve Doğa Festivali (temmuz ayında, Hazar Gölü çevresinde doğa yürüyüşleri, yüzme yarışları, konserler, yöresel lezzetler). Elazığ Kültür ve Sanat Festivali (eylül ayında, Elazığ merkez, konserler, halk oyunları, panayır). Keban Barajı Kültür ve Su Sporları Festivali (haziran ayında, Keban Baraj Gölü\'nde su sporları yarışları, konserler). Baskil Kültür ve Peynir Festivali (ağustos ayında, Baskil ilçesinde peynir tadımı, peynir yarışmaları, yöresel lezzetler). Palu Kültür ve Sanat Festivali (eylül ayında, Palu ilçesinde konserler, tarihi alanların tanıtımı). Ayrıca Elazığ\'da düzenlenen \"Hazar Gölü Maratonu\", \"Keban Barajı Bisiklet Turu\" ve \"Harput Yürüyüş Günleri\" de ilgi çeker.', 'Elazığ\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, Harput Kalesi, Hazar Gölü ve tarihi yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 35-40°C\'ye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve karlıdır, sıcaklık genelde -5 ile 5°C arasındadır, zaman zaman kar yağışı görülür. Elazığ\'ı ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Elazığ\'a hava yoluyla gelmek için Elazığ Havalimanı kullanılır. Havalimanı şehir merkezine yaklaşık 15 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Elazığ\'a şehirlerarası otobüs terminali (Elazığ Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Diyarbakır, Malatya, Gaziantep, Adana, Kayseri, Sivas, Erzurum). Elazığ, Doğu Ekspresi\'nin güzergahında olup demiryolu ile Ankara, Kayseri, Sivas, Malatya, Diyarbakır, Batman, Kurtalan gibi illere bağlıdır. Elazığ Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Baskil, Karakoçan, Kovancılar, Maden, Palu, Sivrice, Arıcak, Keban, Alacakaya, Ağın gibi ilçelere minibüslerle rahat ulaşım vardır. Harput, Hazar Gölü, Keban Barajı, Buzluk Mağarası, Palu Kalesi gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n', 'Elazığ, tarihi boyunca Hurriler, Hititler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Artuklular, Beylikler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Harput (Eski Elazığ) bölgesi, tarihi ve kültürel zenginlikleriyle öne çıkmaktadır. Osmanlı döneminde Harput Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmış, adını \"elazık\" (bol yiyecek) kelimesinden almıştır. Elazığ, tarihi Harput Kalesi, Keban Barajı ve yöresel yemekleriyle öne çıkan bir Doğu Anadolu ilidir.', 'Elazığ', '2026-04-08 23:20:51'),
(30, 'Erzincan', 'Doğu Anadolu', 'erzincan.jpg', 'Kemaliye ile ünlü.', 'Erzincan denince akla gelen ilk şeyler: Erzincan Ovası (verimli ova, tarım alanları, bağlar, bahçeler), Karasu Nehri (Fırat\'ın kolu, Erzincan\'ın kuzeyinden akar), Girlevik Şelalesi (Erzincan\'ın en ünlü şelalesi, Çağlayan beldesi, yüksekten dökülen şelale, doğa harikası, yürüyüş yolları, piknik alanı, mesire yeri, buz tutmuş şelale kışın ayrı güzel), Ergan Dağı (kış sporları, kayak merkezi, yaylalar, doğa yürüyüşleri), Munzur Dağları (Munzur Vadisi Milli Parkı, doğa harikası, yaylalar, şelaleler, yürüyüş parkurları, kamp, Munzur Çayı), Kemah (tarihi Kemah Kalesı (Kemah Kalesi, Eğin Kalesi), Kemah Evleri (tarihi taş evler), Kemah Ulu Cami, Kemah Çayı, Kemah\'ın tarihi köprüleri, Kemah\'ın peyniri), Kemaliye (Eğin) ilçesi (tarihi Kemaliye Evleri (taş evler, ahşap işlemeleriyle ünlü), Kemaliye Kalesi, Kemaliye Müzesi, Dilli Vadisi (Karanlık Kanyon, doğa yürüyüşleri, kaya tırmanışı, kamp), Kemaliye Taş Köprüsü (Eğin Köprüsü), Kemaliye\'nin dar sokakları, Kemaliye\'nin el sanatları), İliç ilçesi (İliç Kaplıcaları, termal su, İliç Altın Madeni), Tercan ilçesi (Tercan Kalesi, Tercan Ulu Cami, Tercan Kaplıcaları), Üzümlü ilçesi (Üzümlü Yaylası), Refahiye ilçesi (Refahiye\'nin peyniri, yaylalar), Çayırlı ilçesi (yaylalar), Erzincan Kalesi (şehir merkezinde, tarihi sur kalıntıları, manzara), Erzincan Müzesi (arkeolojik ve etnografik eserler), Terzibaba Türbesi (Mengüceli dönemi), Melik Gazi Türbesi, Atatürk Evi Müzesi, Güzelyayla (Erzincan\'ın yaylası, doğa), Erzincan\'ın tarihi camileri (Ulu Cami, Kurşunlu Cami, Askeri Cami), Erzincan\'ın hamamları, Erzincan\'ın çarşıları, Erzincan\'ın bakırcılar çarşısı, Erzincan\'ın el sanatları (bakır işlemeciliği, halıcılık, kilim dokumacılığı), Erzincan\'ın yaylaları (Kartallı Yaylası, Kılıçkaya Yaylası, Meryemana Yaylası, Çadırkaya Yaylası, doğa yürüyüşleri, yayla şenlikleri), Erzincan\'ın termal kaynakları (Tercan Kaplıcaları, İliç Kaplıcaları, Ekşisu (Erzincan\'ın güneyinde, maden suyu kaynağı, ekşi su, şifalı su)), Erzincan\'ın mesire alanları (Yalnızbağ, Akyazı, Çağlayan), Erzincan\'ın bağ evleri, Erzincan\'ın üzüm bağları (Erzincan üzümü meşhur), Ekşisu (maden suyu), Otlukbeli Gölü, Munzur Çayı, Karasu Nehri, Fırat Nehri, Erzincan Ovası\'nın manzarası mutlaka görülmelidir.', 'Erzincan mutfağı, Doğu Anadolu\'nun zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Erzincan tava\" gelir. \"Erzincan köftesi\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Erzincan usulü etli ekmek\", \"Erzincan usulü içli köfte\", \"cevizli erişte\", \"kesme aşı\", \"su böreği\", \"Tulum peyniri\" yöresel lezzetlerdir. Tatlı olarak \"Erzincan baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Erzincan lokumu\", \"Erzincan orcik\" (cevizli sucuk), \"kesme aşı tatlısı\" meşhurdur. Erzincan\'ın \"Tulum peyniri\" (Erzincan tulum peyniri dünyaca ünlü), \"Erzincan balı\", \"cevizi\", \"üzümü\", \"elması\", \"kavunu\", \"karpuzu\", \"dutu\", \"pekmezi\", \"tahini\", \"tarhanası\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\" de ünlüdür.', 'Erzincan\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Erzincan Kültür ve Sanat Festivali (ağustos ayında, Erzincan merkez, konserler, halk oyunları, yöresel lezzetler, panayır, sergiler). Uluslararası Kemaliye Kültür ve Doğa Festivali (temmuz ayında, Kemaliye (Eğin) ilçesinde, Kemaliye Evleri önünde konserler, doğa yürüyüşleri (Dilli Vadisi), kaya tırmanışı, yöresel lezzetler). Girlevik Şelalesi Kültür ve Doğa Festivali (haziran ayında, Girlevik Şelalesi\'nde doğa yürüyüşleri, konserler, piknik). Erzincan Tulum Peyniri ve Kültür Festivali (eylül ayında, Erzincan merkez, tulum peyniri tadımı, tulum peyniri yarışmaları, yöresel lezzetler, konserler). Munzur Vadisi Kültür ve Doğa Sporları Festivali (temmuz ayında, Munzur Vadisi\'nde doğa yürüyüşleri, kamp, dağcılık, yamaç paraşütü). Kemah Kültür ve Sanat Festivali (ağustos ayında, Kemah ilçesinde, Kemah Kalesi önünde konserler, halk oyunları). Tercan Kültür ve Kaplıca Festivali (haziran ayında, Tercan ilçesinde termal su tanıtımı, konserler). Ayrıca Erzincan\'da düzenlenen \"Ergan Dağı Kayak Festivali\" (kış aylarında), \"Munzur Dağı Doğa Yürüyüşü\" ve \"Erzincan Bisiklet Turu\" da ilgi çeker.', 'Erzincan\'ı ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-30°C arasındadır, yaylalar yeşildir, doğa yürüyüşleri ve tarihi yerleri gezmek için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -20°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez. Erzincan\'ı ziyaret etmek için en uygun zaman temmuz ve ağustos aylarıdır.', 'Erzincan\'a hava yoluyla gelmek için Erzincan Havalimanı (ERC) kullanılır. Havalimanı şehir merkezine yaklaşık 7 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Erzincan\'a şehirlerarası otobüs terminali (Erzincan Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Sivas, Erzurum, Malatya, Elazığ, Diyarbakır, Gaziantep, Kayseri). Erzincan, Doğu Ekspresi\'nin güzergahında olup demiryolu ile Ankara, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Batman, Kurtalan, Erzurum, Kars gibi illere bağlıdır. Erzincan Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kemah, Kemaliye (Eğin), Tercan, İliç, Üzümlü, Refahiye, Çayırlı, Otlukbeli gibi ilçelere minibüslerle rahat ulaşım vardır. Girlevik Şelalesi, Munzur Vadisi, Kemaliye (Eğin), Kemah Kalesi, Ergan Dağı, Ekşisu, Tercan Kaplıcaları, İliç Kaplıcaları, Yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Erzincan, tarihi boyunca Hurriler, Hititler, Kimmerler, İskitler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Selçuklular, İlhanlılar, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Tarihi İpek Yolu üzerinde önemli bir durak olan Erzincan, stratejik konumu nedeniyle sık sık el değiştirmiştir. Osmanlı döneminde Erzurum\'a bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. 1939 yılında büyük bir deprem geçiren şehir, neredeyse tamamen yıkılmış ve yeniden inşa edilmiştir. Erzincan, doğal güzellikleri, yaylaları, termal kaynakları ve yöresel lezzetleriyle öne çıkan bir Doğu Anadolu ilidir.', 'Erzincan', '2026-04-08 23:20:51'),
(31, 'Erzurum', 'Doğu Anadolu', 'erzurum.jpg', 'Kış sporları ile ünlü.', 'Erzurum denince akla gelen ilk şeyler: Palandöken Dağı ve Kayak Merkezi (Türkiye\'nin en önemli kayak merkezlerinden, uzun pistleri, Ejder 3200 pisti (dünyanın en uzun pistlerinden), kayak okulları, oteller, teleferik, manzara, kış sporları), Çifte Minareli Medrese (Erzurum\'un simgesi, Selçuklu dönemi, taç kapısı, iki minaresi, mozaik çinileri, taş işçiliği, günümüzde müze), Yakutiye Medresesi (Selçuklu dönemi, taş işçiliği, mozaik, günümüzde Türk İslam Eserleri Müzesi), Erzurum Kalesi (iç kale, dış kale, saat kulesi, manzara), Üç Kümbetler (Saltuklu dönemi, üç türbe), Lala Paşa Cami, Ulu Cami (Saltuklu dönemi), Murat Paşa Cami, Rüstem Paşa Kervansarayı (tarihi kervansaray, günümüzde otel, restoran), Erzurum Müzesi (arkeolojik ve etnografik eserler), Atatürk Evi Müzesi (Erzurum Kongresi\'nin yapıldığı ev), Erzurum Kongresi Binası, Azerbaycan Parkı, Tortum Şelalesi (Tortum ilçesinde, doğal şelale, yüksekten dökülen su, muhteşem manzara, yürüyüş yolları, piknik alanı, Tortum Gölü), Tortum Gölü (heyelan set gölü, doğal güzellik), Narman Peri Bacaları (Narman ilçesinde, kaya oluşumları, peri bacaları, Kapadokya benzeri, doğa harikası, fotoğraf, yürüyüş), Oltu (Oltu taşı işlemeciliği, Oltu Kalesi, Oltu Çayı, Oltu Kaplıcaları, Oltu\'nun yaylaları), Oltu Taşı (kehribar benzeri, tesbih, kolye, küpe, yüzük, Erzurum\'a özgü), Oltu Taşı Müzesi (Oltu ilçesinde), İspir (İspir Kalesi, İspir Çayı, İspir Yaylaları, İspir Kaplıcaları, İspir\'in tarihi evleri), Pasinler (Pasinler Kalesi, Pasinler Sazlığı (kuş cenneti), Pasinler Kaplıcaları), Karayazı (yaylalar), Şenkaya (Şenkaya Kalesi, yaylalar), Tortum (Tortum Şelalesi, Tortum Gölü, Tortum Kalesi), Aziziye Tabyaları (93 Harbi\'nde Osmanlı-Rus Savaşı\'nın geçtiği tabyalar, tarihi önemi, manzara), Mecidiye Tabyası, Erzurum Evleri (tarihi taş evler, restore edilmiş konaklar), Erzurum\'un çarşıları (Taşhan, Rüstem Paşa Kervansarayı, Bakırcılar Çarşısı, Kazım Karabekir Çarşısı), Erzurum\'un el sanatları (Oltu taşı işlemeciliği, bakır işlemeciliği, halıcılık, kilim dokumacılığı), Erzurum\'un yaylaları (Ağdağ Yaylası, Demirkapı Yaylası, Dökmetaş Yaylası, Kırkdeğirmen Yaylası, Palandöken Yaylası, doğa yürüyüşleri, yayla şenlikleri), Erzurum\'un termal kaynakları (Pasinler Kaplıcaları, Ilıca Kaplıcaları, Köprüköy Kaplıcaları, İspir Kaplıcaları, Oltu Kaplıcaları, şifalı sular), Erzurum\'un kış sporları (Palandöken Kayak Merkezi, Konaklı Kayak Merkezi, Kandilli Kayak Merkezi), Erzurum\'un tarihi köprüleri (Çobandede Köprüsü, Irgandı Köprüsü), Erzurum\'un mesire alanları (Dumlu, Çobandede, Gez Mahallesi), Erzurum\'un bağ evleri, Erzurum\'un üzüm bağları, Tortum Şelalesi\'nin kışın donmuş hali, Narman Peri Bacaları\'nın gün batımı, Palandöken\'den Erzurum ovası manzarası mutlaka görülmelidir.', 'Erzurum mutfağı, Doğu Anadolu\'nun en zengin ve en meşhur mutfaklarından biridir. Mutlaka denenmesi gerekenlerin başında \"Cağ kebabı\" (kuzu etinin yatay bir şişe geçirilerek tandırda veya odun ateşinde pişirilmesi, Erzurum\'un dünyaca ünlü lezzeti) gelir. \"Erzurum köftesi\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Erzurum usulü etli ekmek\", \"Erzurum usulü içli köfte\", \"su böreği\", \"ayran aşı çorbası\", \"paspatur\" yöresel lezzetlerdir. Tatlı olarak \"Erzurum baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Erzurum lokumu\", \"kete\", \"şekerpare\", \"kalburabastı\", \"hanımgöbeği\", \"kadayıf dolması\" meşhurdur. Erzurum\'un \"cağ kebabı\", \"Oltu peyniri\", \"Göğermiş peyniri\", \"Civil peyniri\" (civil, taze peynir), \"Erzurum balı\", \"Erzurum elması\", \"Erzurum üzümü\", \"Erzurum cevizi\", \"Erzurum dutu\", \"Erzurum pekmezi\", \"Erzurum tahini\", \"Erzurum tarhanası\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\" de ünlüdür.', 'Erzurum\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Erzurum Kültür ve Sanat Festivali (ağustos ayında, Erzurum merkez, Çifte Minareli Medrese önünde konserler, halk oyunları, yöresel lezzetler, panayır, sergiler). Uluslararası Palandöken Kış Sporları ve Kayak Festivali (şubat ayında, Palandöken Kayak Merkezi\'nde kayak yarışmaları, konserler, kış sporları gösterileri). Tortum Şelalesi Kültür ve Doğa Festivali (temmuz ayında, Tortum Şelalesi\'nde doğa yürüyüşleri, konserler, piknik). Narman Peri Bacaları Kültür ve Doğa Festivali (haziran ayında, Narman Peri Bacaları\'nda doğa yürüyüşleri, fotoğraf yarışması, konserler). Oltu Taşı ve Kültür Festivali (eylül ayında, Oltu ilçesinde Oltu taşı sergileri, Oltu taşı işleme atölyeleri, konserler). Erzurum Cağ Kebabı Festivali (ekim ayında, Erzurum merkez, cağ kebabı yarışmaları, cağ kebabı tadımı, yöresel lezzetler, konserler). Ayrıca Erzurum\'da düzenlenen \"Palandöken Dağı Maratonu\" (yaz aylarında), \"Erzurum Bisiklet Turu\" ve \"Erzurum Doğa Yürüyüşleri\" de ilgi çeker.', 'Erzurum\'u ziyaret etmek için en iyi zaman kış ayları (aralık-şubat) ve yaz aylarıdır (haziran-eylül). Kış aylarında Palandöken Kayak Merkezi için idealdir, sıcaklık -15°C ile -5°C arasındadır, yoğun kar yağışı olur. Yaz aylarında hava ılımandır, sıcaklık 15-25°C arasındadır, tarihi yerleri gezmek ve yaylaları ziyaret etmek için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Erzurum\'u ziyaret etmek için kış aylarında kayak, yaz aylarında kültür ve doğa turları yapılabilir.', 'Erzurum\'a hava yoluyla gelmek için Erzurum Havalimanı (ERZ) kullanılır. Havalimanı şehir merkezine yaklaşık 12 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Erzurum\'a şehirlerarası otobüs terminali (Erzurum Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Sivas, Kayseri, Malatya, Elazığ, Diyarbakır, Gaziantep, Trabzon, Rize, Artvin, Kars, Ardahan, Ağrı, Muş, Bingöl). Erzurum, Doğu Ekspresi\'nin güzergahında olup demiryolu ile Ankara, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Batman, Kurtalan, Erzincan, Kars, Ardahan gibi illere bağlıdır. Erzurum Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri, taksi ve teleferik (Palandöken Teleferiği) kullanılır. Aziziye, Palandöken, Köprüköy, Tortum, Narman, Oltu, Olur, İspir, Pasinler, Karayazı, Şenkaya, Tekman, Hınıs, Karaçoban gibi ilçelere minibüslerle rahat ulaşım vardır. Palandöken Kayak Merkezi, Çifte Minareli Medrese, Yakutiye Medresesi, Tortum Şelalesi, Narman Peri Bacaları, Oltu Taşı Müzesi, Aziziye Tabyaları, Yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n', 'Erzurum, tarihi boyunca Hurriler, Urartular, İskitler, Medler, Persler, Romalılar, Bizanslılar, Selçuklular, Saltuklular, İlhanlılar, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Theodosiopolis\" adıyla anılmıştır. Malazgirt Meydan Muharebesi\'nden (1071) sonra Türklerin eline geçmiştir. Osmanlı döneminde Erzurum Eyaleti\'nin merkezi olmuş, önemli bir askeri ve ticari merkez haline gelmiştir. Kurtuluş Savaşı\'nda Erzurum Kongresi (23 Temmuz - 7 Ağustos 1919) burada toplanmıştır. Cumhuriyet döneminde il statüsünü korumuştur. Erzurum, tarihi yapıları, kış sporları, yöresel yemekleri ve Oltu taşı işlemeciliğiyle öne çıkan bir Doğu Anadolu ilidir.', 'Erzurum', '2026-04-08 23:20:51'),
(32, 'Eskişehir', 'İç Anadolu', 'eskisehir.jpg', 'Öğrenci şehri.', 'Eskişehir denince akla gelen ilk şeyler: Odunpazarı (tarihi Odunpazarı evleri, restore edilmiş Osmanlı dönemi evleri, dar sokaklar, taş evler, ahşap işlemeleri, Odunpazarı Müzesi (Eskişehir Odunpazarı Modern Müze - OMM, dünyaca ünlü müzelerden, Japon mimar Kengo Kuma\'nın tasarımı, modern sanat eserleri, ahşap ve cam tasarım), Kurşunlu Cami, Külliyesi ve Kervansarayı (Kurşunlu Külliyesi, Osmanlı dönemi, avlu, çeşme, hamam, restoran), Lületaşı Müzesi (Eskişehir Lületaşı Müzesi, lületaşı işlemeciliği, pipolar, takılar, süs eşyaları), Eskişehir Lületaşı Atölyeleri (alışveriş, lületaşı ürünleri), Porsuk Çayı (şehrin içinden geçen nehir, gondol turları (Venedik benzeri), yürüyüş yolları, çay bahçeleri, kafeler, restoranlar, ışıklandırmalar, Porsuk Barajı), Sazova Parkı (Sazova Bilim Kültür ve Sanat Parkı, Masal Şatosu, Eskişehir Bilim Deney Merkezi (ESBİL), Sualtı Dünyası, Hayvanat Bahçesi, Japonya Bahçesi, Çin Bahçesi, korsan gemisi, mini tren, gölet, yürüyüş yolları, piknik alanları), Eskişehir Hayvanat Bahçesi, Eskişehir Bilim Deney Merkezi (Türkiye\'nin en büyük bilim merkezlerinden), Eskişehir Büyükşehir Belediyesi Parkları, Kentpark (alışveriş merkezi, park, gölet), Anadolu Üniversitesi Havacılık Parkı (uçaklar, helikopterler, füze sergileri), Eskişehir Arkeoloji Müzesi (arkeolojik eserler, Frig dönemi eserleri), Eskişehir Etnoğrafya Müzesi, Cumhuriyet Tarihi Müzesi (Eskişehir Kurtuluş Müzesi), Tayfun Talipoğlu Müzesi (cam eserler), Tülomsaş Demiryolu Müzesi (lokomotifler, trenler), Eskişehir Spor Tesisleri (Eskişehirspor), Atatürk Kültür Merkezi, Çağdaş Cam Sanatları Müzesi (cam eserler, cam üfleme atölyeleri), Yılmaz Büyükerşen Balmumu Heykeller Müzesi (ünlü kişilerin balmumu heykelleri), Şelale Park (yapay şelale, yürüyüş yolları), Eskişehir\'in köprüleri (Yunus Emre Köprüsü, İsmet İnönü Köprüsü), Eskişehir Saat Kulesi, Hamamyolu (yaya bölgesi, heykeller, kafeler, restoranlar, tarihi hamam), Adalar (Porsuk Çayı üzerinde yapay adalar, kafeler, restoranlar), Eskişehir\'in meydanları (Vilayet Meydanı, Özdilek Meydanı), Eskişehir\'in parkları (Kanlıpınar Parkı, Sazova Parkı, Kentpark, Çamlıca Parkı, Gökmeydan Parkı, Ertuğrul Gazi Parkı), Eskişehir\'in tarihi hamamları (Kurşunlu Hamamı, Taşbaşı Hamamı), Eskişehir\'in camileri (Kurşunlu Cami, Alaaddin Cami, Akarbaşı Cami, Poyraklı Cami), Eskişehir\'in çarşıları (Odunpazarı Çarşısı, Eskişehir Kapalı Çarşı, Bakırcılar Çarşısı), Eskişehir\'in el sanatları (lületaşı işlemeciliği, bakır işlemeciliği, halıcılık, kilim dokumacılığı, çömlekçilik), Sivrihisar ilçesi (Sivrihisar Ulu Cami (Kılıçarslan Cami), Sivrihisar Kalesi, Nasreddin Hoca Türbesi, Sivrihisar Evleri, Sivrihisar\'ın yaylaları), Çifteler ilçesi (Çifteler Kaplıcaları, termal su), Mihalıççık ilçesi (Mihalıççık peyniri, yaylalar), Beylikova ilçesi (tarihi evler), Seyitgazi ilçesi (Seyit Battal Gazi Külliyesi, Seyit Battal Gazi Türbesi, Seyitgazi ilçesi tarihi), Han ilçesi (Han ilçesinin yaylaları), Günyüzü ilçesi (yaylalar), Alpu ilçesi (yaylalar), Mahmudiye ilçesi (yaylalar), Sarıcakaya ilçesi (Sarıcakaya Kaplıcaları, termal su), Eskişehir\'in mesire alanları (Mihalıççık Yaylası, Sivrihisar Yaylası, Çifteler Yaylası), Eskişehir\'in bağ evleri, Porsuk Çayı üzerinde gondol turu, Odunpazarı evlerinde yürüyüş, Sazova Parkı\'nda masal şatosu, lületaşı atölyelerini ziyaret, Bilim Deney Merkezi\'nde deneyler yapmak, Eskişehir\'de bisiklet turu yapmak (şehirde bisiklet yolları var), Eskişehir\'deki köprülerden Porsuk manzarası izlemek mutlaka yapılmalıdır.', 'Eskişehir mutfağı, İç Anadolu ve Göller Yöresi mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Çibörek\" (kıymalı, soğanlı, yağda kızartılmış hamur işi, Kırım Tatar mutfağından Eskişehir\'e özgü) gelir. \"Eskişehir köftesi\", \"etli ekmek\", \"kavurma\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"yufka ekmeği\", \"Eskişehir usulü etli ekmek\", \"Eskişehir usulü içli köfte\", \"su böreği\", \"Beyşehir usulü etli ekmek\", \"Sivrihisar usulü keşkek\", \"Kırım Tatar mantısı\" yöresel lezzetlerdir. Tatlı olarak \"Eskişehir baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Eskişehir lokumu\", \"met helvası\", \"badem ezmesi\", \"Eskişehir macunu\", \"Eskişehir şekeri\" meşhurdur. Eskişehir\'in \"Lületaşı\" (dünyaca ünlü, tütün piposu, takı, süs eşyası), \"Eskişehir tarhanası\", \"Sivrihisar peyniri\", \"Mihalıççık peyniri\", \"Eskişehir balı\", \"Eskişehir üzümü\", \"Eskişehir elması\", \"Eskişehir cevizi\", \"Eskişehir pekmezi\", \"Eskişehir tahini\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\" de ünlüdür.', 'Eskişehir\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Eskişehir Festivali (kültür ve sanat festivali, haziran-eylül ayları arasında, Odunpazarı, Porsuk Çayı ve Sazova Parkı\'nda konserler, tiyatro gösterileri, sergiler, atölyeler, panayır). Uluslararası Çibörek Festivali (mayıs ayında, Eskişehir merkez, çibörek yapım atölyeleri, çibörek yarışmaları, çibörek tadımı, konserler, yöresel lezzetler). Uluslararası Lületaşı Festivali (ekim ayında, Eskişehir merkez, lületaşı sergileri, lületaşı işleme atölyeleri, lületaşı yarışmaları, konserler). Eskişehir Uluslararası Film Festivali (kasım ayında, sinema gösterimleri, paneller, ödül töreni). Sivrihisar Nasreddin Hoca Kültür ve Sanat Festivali (temmuz ayında, Sivrihisar ilçesinde, Nasreddin Hoca Türbesi önünde fıkra anlatma yarışmaları, konserler, halk oyunları, yöresel lezzetler). Eskişehir Caz Festivali (nisan ayında, Eskişehir merkez, yerli ve yabancı caz sanatçıları). Ayrıca Eskişehir\'de düzenlenen \"Porsuk Çayı Gondol Şenliği\", \"Eskişehir Bisiklet Turu\", \"Eskişehir Maratonu\" ve \"Sazova Parkı Çocuk Şenliği\" de ilgi çeker.', 'Eskişehir\'i ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-25°C arasındadır, Odunpazarı evleri, Porsuk Çayı ve diğer turistik yerleri gezmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 28-33°C\'ye ulaşabilir, kurak ve sıcaktır, ancak şehirdeki çay bahçeleri ve nehir kenarı keyiflidir. Kışlar soğuk ve karlıdır, sıcaklık genelde -5 ile 5°C arasındadır, zaman zaman kar yağışı görülür, kış aylarında Sazova Parkı ve Bilim Merkezi gibi kapalı alanlar tercih edilebilir. Eskişehir\'i ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Eskişehir\'e hava yoluyla gelmek için Eskişehir Hasan Polatkan Havalimanı (AOS) kullanılır. Havalimanı şehir merkezine yaklaşık 10 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Eskişehir\'e şehirlerarası otobüs terminali (Eskişehir Otogarı) şehir merkezinin dışında olup belediye otobüsleri, tramvay ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Bursa, Konya, Kütahya, Afyonkarahisar, Denizli, Antalya, Adana, Mersin, Kayseri, Sivas, Bolu, Düzce, Sakarya, Kocaeli, Zonguldak, Bartın, Karabük, Kastamonu, Sinop, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin, Erzincan, Erzurum, Kars, Malatya, Elazığ, Diyarbakır, Gaziantep, Şanlıurfa, Adıyaman, Batman, Siirt, Şırnak, Mardin, Van, Muş, Bingöl, Bitlis, Ağrı, Ardahan, Iğdır, Tunceli, Elazığ). Eskişehir, Yüksek Hızlı Tren (YHT) hattı üzerinde olup demiryolu ile Ankara (1.5 saat), İstanbul (2.5-3 saat), Konya (1.5 saat), Sivas (3 saat) gibi illere hızlı tren bağlantısı vardır. Eskişehir Tren Garı şehir merkezindedir. Şehir içi ulaşımda tramvay (Eskişehir tramvay ağı çok gelişmiştir), minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Odunpazarı, Sivrihisar, Çifteler, Mihalıççık, Beylikova, Seyitgazi, Han, Günyüzü, Alpu, Mahmudiye, Sarıcakaya gibi ilçelere minibüslerle rahat ulaşım vardır. Odunpazarı evleri, Sazova Parkı, Porsuk Çayı, Bilim Deney Merkezi, Lületaşı Müzesi, Kurşunlu Cami, Sivrihisar Ulu Cami, Seyit Battal Gazi Külliyesi, Çifteler Kaplıcaları, Sarıcakaya Kaplıcaları, Yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir. Eskişehir\'de tramvay ile her yere gidilebilir.', 'Eskişehir, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Dorylaion\" adıyla anılmıştır. Frigler döneminde önemli bir merkez olmuştur. Osmanlı döneminde Eskişehir Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Eskişehir, Türkiye\'nin en modern ve öğrenci dostu şehirlerinden biridir. Lületaşı, çibörek, havagazı, şehir içi tramvay ağı, Odunpazarı evleri ve üniversiteleriyle öne çıkan bir İç Anadolu ilidir.', 'Eskişehir', '2026-04-08 23:20:51'),
(33, 'Gaziantep', 'Güneydoğu Anadolu', 'gaziantep.jpg', 'Lezzetin başkenti.', 'Gaziantep denince akla gelen ilk şeyler: Gaziantep Kalesi (şehrin simgesi, şehir merkezinde, tarihi kale, surlar, manzara, içinde Gaziantep Savunması Müzesi), Zeugma Mozaik Müzesi (dünyanın en büyük mozaik müzesi, Roma dönemi Zeugma Antik Kenti\'nden çıkarılan mozaikler, Çingene Kızı Mozaiği (dünyaca ünlü), Mars Mozaiği, Poseidon Mozaiği, Akhilleus Mozaiği, Eros Mozaiği, mozaikler, heykeller, çeşmeler, Zeugma Antik Kenti\'ni tanıtan alan), Zeugma Antik Kenti (Belkıs Köyü, Fırat Nehri kenarında, Roma dönemi, mozaikler, villalar, su kemerleri, tiyatro, surlar, kazı alanı, Birecik Barajı suları altında kalan antik kent), Bakırcılar Çarşısı (tarihi çarşı, bakır işlemeciliği, bakır tencere, tava, cezve, ibrik, kazan, sini, bakır el sanatları, alışveriş, atölyeler), Zincirli Bedesten (tarihi bedesten, kapalı çarşı, altın, gümüş, takı, halı, kilim, yöresel ürünler), Antep Çarşısı (tarihi çarşılar, Kurşunlu Han, Şire Hanı, Hışvahan, Emir Han, tüccarlar, baharatçılar, yemeniciler, bakırcılar, keçeciler, kalaycılar), Tahmis Kahvesi (tarihi kahvehane, 1635 yılında yapılmış, menengiç kahvesi, Türk kahvesi, sıcak süt, Antep fıstıklı kahve), Şire Hanı (tarihi han, günümüzde restoran, kafe), Kurşunlu Han (tarihi han), Gaziantep Arkeoloji Müzesi (arkeolojik eserler, heykeller, mozaikler, sikke koleksiyonu), Gaziantep Emine Göğüş Mutfak Müzesi (Gaziantep mutfağı, yemek kültürü, mutfak eşyaları, yemek modelleri), Gaziantep Hamam Müzesi (tarihi hamam, hamam kültürü), Gaziantep Atatürk Evi Müzesi, Bayazhan Gaziantep Kent Müzesi, Hasan Süzer Etnografya Müzesi, Medusa Cam Eserler Müzesi (cam eserler, cam işlemeciliği), Oyun ve Oyuncak Müzesi, Gaziantep Hayvanat Bahçesi, Gaziantep Botanik Bahçesi, Dülük (Doliche) Antik Kenti (Gaziantep\'in 10 km kuzeyinde, Roma dönemi, Zeus tapınağı, kaya mezarları, su kemerleri), Rumkale (Yavuzeli ilçesi, Fırat Nehri kenarında, Ortaçağ kalesi, surlar, kiliseler, manastır, muhteşem manzara, tekne turu), Yesemek Açık Hava Müzesi (İslahiye ilçesi, Hitit dönemi heykel atölyesi, taş ocakları, bitmemiş heykeller, aslan heykelleri, kabartmalar), Karkamış (Kargamış) Antik Kenti (Nizip ilçesi, Hitit dönemi, kabartmalar, surlar, kazı alanı, Fırat Nehri kenarı), Belkıs Köyü (Zeugma Antik Kenti\'nin yanındaki köy), Nizip ilçesi (Nizip ilçesi, Nizip Müzesi, Nizip Evleri, Nizip fıstığı), İslahiye ilçesi (Yesemek Açık Hava Müzesi, İslahiye fıstığı, yaylalar), Yavuzeli ilçesi (Rumkale, Yavuzeli fıstığı), Oğuzeli ilçesi (Oğuzeli ilçesi, Oğuzeli fıstığı), Şahinbey ilçesi (Şahinbey\'in tarihi evleri), Şehitkamil ilçesi (Şehitkamil\'in yaylaları), Gaziantep fıstık bahçeleri (fıstık hasadı eylül ayında), Gaziantep bağları (Antep üzümü), Gaziantep\'in tarihi evleri (Bey Mahallesi, Şahinbey Mahallesi, restore edilmiş evler), Gaziantep\'in surları, Gaziantep\'in hamamları (Kadı Hamamı, Paşa Hamamı, Şehir Hamamı), Gaziantep\'in camileri (Ulu Cami, Boyacı Cami, Şirvani Cami, Ömeriye Cami, Ali Dede Cami, Ahmet Çelebi Cami), Gaziantep\'in kiliseleri (Kurtuluş Cami (eski kilise), Aziz Bedros Kilisesi, Meryem Ana Kilisesi), Gaziantep\'in yaylaları (Sof Dağı, Kartal Dağı, Dülük Dağı, Barak Ovası), Gaziantep\'in mesire alanları (Dülük Mesire Alanı, 100. Yıl Parkı, Gaziantep Ormanı), Gaziantep\'in yöresel ürünleri (Antep fıstığı, baklava, bakır işlemeciliği, yemeni, ipekli dokuma), Antep fıstıklı kahve, menengiç kahvesi, Gaziantep mutfağı yemek atölyeleri, Zeugma Mozaik Müzesi\'nde Çingene Kızı Mozaiği\'ni görmek, Bakırcılar Çarşısı\'nda bakır döverek yapılan eşyaları izlemek, Tahmis Kahvesi\'nde menengiç kahvesi içmek, Rumkale\'de Fırat Nehri manzarası, Yesemek\'te Hitit heykelleri, Karkamış\'ta kabartmalar, Gaziantep Kalesi\'nden şehir manzarası mutlaka yapılmalıdır.', 'Gaziantep mutfağı, dünyanın en zengin ve en ünlü mutfaklarından biridir. UNESCO Yaratıcı Şehirler Ağı\'na \"Gastronomi Şehri\" olarak kabul edilmiştir. Mutlaka denenmesi gerekenlerin başında \"Gaziantep baklavası\" (ince yufkalı, antep fıstıklı, şerbetli, dünyaca ünlü) gelir. \"Antep fıstığı\" (dünyanın en kaliteli fıstığı), \"kebap çeşitleri\" (simit kebabı, patlıcan kebabı, ciğer kebabı, soğan kebabı, kuşbaşı kebabı, kağıt kebabı, tava ciğer, oruk kebabı), \"içli köfte\" (oruk), \"kibbe\", \"lahmacun\", \"çiğ köfte\" (etli, baharatlı), \"mercimek köftesi\", \"sarma\", \"dolma\", \"ekşili köfte\", \"yayla çorbası\", \"mercimek çorbası\", \"tarhana çorbası\", \"beyran çorbası\" (etli, yağlı, acılı), \"kuzu tandır\", \"etli ekmek\", \"katmer\", \"gözleme\", \"Beyran\", \"Ali Nazik kebabı\", \"küşleme\", \"kuzu şiş\", \"tavuk şiş\", \"patlıcanlı kebap\", \"fıstıklı kebap\", \"kırmızı mercimek köftesi\", \"yaprak sarma\", \"zeytinyağlı enginar\", \"Bulgur pilavı\", \"Antep salatası\", \"Antep turşusu\", \"Antep peyniri\", \"Antep yoğurdu\", \"Antep şalgamı\", \"Antep ayranı\", \"Antep bozası\" yöresel lezzetlerdir. Tatlı olarak \"baklava\" (çeşitleri: fıstıklı, cevizli, şöbiyet, sütlü nuriye, kuru baklava, havuc dilimi), \"kadayıf\" (kadayıf dolması, tel kadayıf, burma kadayıf), \"künefe\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Antep lokumu\", \"Antep macunu\", \"Antep şekeri\", \"fıstıklı sucuk\", \"fıstıklı helva\", \"fıstıklı sütlaç\", \"fıstıklı dondurma\", \"Antep fıstıklı çikolata\" meşhurdur. Gaziantep\'in \"Antep fıstığı\", \"Antep baklavası\", \"Antep ipeği\", \"bakır işlemeciliği\", \"yemenicilik\", \"Antep elması\", \"Antep üzümü\", \"Antep narı\", \"Antep cevizi\", \"Antep bademi\", \"Antep pekmezi\", \"Antep tahini\", \"Antep tarhanası\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\", \"sucuğu\", \"pastırması\", \"zeytini\", \"zeytinyağı\" da ünlüdür.', 'Gaziantep\'te birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Gaziantep Baklava ve Lezzet Festivali (eylül ayında, Gaziantep merkez, baklava yapım atölyeleri, baklava yarışmaları, baklava tadımı, yöresel lezzetler, konserler, panayır). Uluslararası Gaziantep Fıstık Festivali (ekim ayında, Gaziantep merkez, fıstık hasadı, fıstık kırma yarışmaları, fıstık tadımı, fıstıklı ürünler sergisi, konserler). Uluslararası Zeugma Mozaik Festivali (mayıs ayında, Zeugma Mozaik Müzesi\'nde mozaik sergileri, mozaik yapım atölyeleri, konserler, panel). Uluslararası Gaziantep Kültür ve Sanat Festivali (temmuz ayında, Gaziantep merkez, konserler, halk oyunları, sergiler, panayır). Uluslararası Rumkale Kültür ve Doğa Festivali (ağustos ayında, Rumkale\'de doğa yürüyüşleri, tekne turları, konserler). Uluslararası Yesemek Kültür ve Sanat Festivali (haziran ayında, Yesemek Açık Hava Müzesi\'nde konserler, heykel atölyeleri). Ayrıca Gaziantep\'te düzenlenen \"Gaziantep Maratonu\", \"Gaziantep Bisiklet Turu\" ve \"Zeugma Yürüyüş Günleri\" de ilgi çeker.', 'Gaziantep\'i ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır, tarihi çarşıları, bakırcıları, müzeleri ve yemekleri için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 40°C\'nin üzerine çıkabilir, çok sıcak ve kuraktır, bu nedenle sıcaktan hoşlanmayanlar için ilkbahar ve sonbahar daha uygundur. Kışlar soğuktur, sıcaklık genelde 0-10°C arasındadır, yağışlı ve zaman zaman karlıdır. Gaziantep\'i ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Gaziantep\'e hava yoluyla gelmek için Gaziantep Havalimanı (GZT) kullanılır. Havalimanı şehir merkezine yaklaşık 20 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Gaziantep\'e şehirlerarası otobüs terminali (Gaziantep Otogarı) şehir merkezinin dışında olup belediye otobüsleri, tramvay ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Adana, Mersin, Konya, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Şanlıurfa, Adıyaman, Kahramanmaraş, Hatay, Osmaniye, Kilis, Nizip). Gaziantep, demiryolu ile Adana, Kayseri, Malatya, Elazığ, Diyarbakır, Batman, Kurtalan, Mersin, Ankara, İstanbul gibi illere bağlıdır (Gaziantep Tren Garı şehir merkezindedir). Şehir içi ulaşımda tramvay (Gaziantep tramvay ağı), minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Şahinbey, Şehitkamil, Oğuzeli, Nizip, İslahiye, Yavuzeli, Araban, Nurdağı, Karkamış gibi ilçelere minibüslerle rahat ulaşım vardır. Zeugma Mozaik Müzesi, Gaziantep Kalesi, Bakırcılar Çarşısı, Zincirli Bedesten, Rumkale, Yesemek Açık Hava Müzesi, Karkamış Antik Kenti, Zeugma Antik Kenti, Dülük Antik Kenti, Gaziantep mutfağı restoranları, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Gaziantep, tarihi boyunca Hititler, Asurlular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Memluklular, Dulkadiroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Antep\" adıyla anılmıştır. Kurtuluş Savaşı\'nda Fransız işgaline karşı kahramanca direnişi nedeniyle 1921 yılında TBMM tarafından \"Gazi\" unvanı verilmiş ve şehrin adı \"Gaziantep\" olmuştur. Cumhuriyet döneminde il statüsünü korumuştur. Gaziantep, dünyaca ünlü mutfağı, bakırcılığı, mozaikleri, fıstığı ve tarihi dokusuyla öne çıkan bir Güneydoğu Anadolu ilidir.', 'Gaziantep', '2026-04-08 23:20:51'),
(34, 'Giresun', 'Karadeniz', 'giresun.jpg', 'Fındığı ile ünlü.', 'Giresun denince akla gelen ilk şeyler: Giresun Adası (Ares Adası, Karadeniz\'in tek adası, Giresun şehir merkezinin açığında, Argonotlar efsanesinde geçer, adada Ares Tapınağı kalıntıları, surlar, manastır, zindan, sarnıç, fener, doğa yürüyüşleri, piknik alanı, manzara, tekne turları, ada çevresinde tekne gezisi), Giresun Kalesi (şehrin simgesi, şehre hakim tepede, Bizans dönemi, surlar, iç kale, manzara, saat kulesi), Giresun Müzesi (Giresun Kalesi içinde, arkeolojik ve etnografik eserler, sikke koleksiyonu), Zeytinlik (Giresun\'un tarihi mahallesi, restore edilmiş Rum evleri, taş evler, dar sokaklar, manzara, kafeler, restoranlar), Giresun Plajları (Giresun Sahili, yürüyüş yolu, bisiklet yolu, çay bahçeleri, restoranlar, şehir plajı, piknik alanı), Giresun\'un yaylaları (Kümbet Yaylası (Giresun\'un en ünlü yaylası, yayla evleri, yayla şenlikleri, doğa yürüyüşleri, piknik, kamp, manzara), Kulakkaya Yaylası (Kulakkaya Kayalıkları, şelale, yürüyüş yolları), Bektaş Yaylası (yayla evleri, yayla şenlikleri), Mıhçak Şelalesi, Çakrak Yaylası, Karagöl Yaylası (krater gölü), Tamdere Yaylası, Ayıbeli Yaylası, Sis Dağı Yaylaları (Sis Dağı, doğa yürüyüşleri, kamp, manzara), Balaban Yaylası, Kırkharman Yaylası, Yağlıdere Yaylaları, Çamoluk Yaylaları, Şebinkarahisar Yaylaları), Sis Dağı (Giresun\'un doğusunda, kış sporları, kayak, doğa yürüyüşleri, yaylalar, manzara), Kümbet Yaylası (Giresun\'un en meşhur yaylası, her yıl temmuz-ağustos aylarında yayla şenliği düzenlenir, at yarışları, güreşler, konserler, halk oyunları, yöresel lezzetler), Kulakkaya (Kulakkaya Kayalıkları, doğa harikası, şelale, yürüyüş yolları, manzara), Karagöl (krater gölü, doğa harikası, yürüyüş yolları, piknik, manzara), Tamdere Yaylası (yayla evleri, yayla şenlikleri), Giresun Fındık Bahçeleri (Giresun\'un her yerinde fındık bahçeleri, fındık hasadı ağustos-eylül aylarında, fındık toplama, fındık kırma), Giresun\'un tarihi camileri (Ulu Cami, Hacı Miktad Cami, Eski Cami, Cami Kebir), Giresun\'un kiliseleri (Santa Harabeleri (Dumanlı Köyü, Rum kilisesi, manastır, taş evler), Krom (Güce ilçesi, Rum kiliseleri), Kadırga (Rum kilisesi), Yavuzkemal (Rum kilisesi), Taşlı Kilise (Meryem Ana Kilisesi), Çakırkaya Kilisesi, Zeytinlik\'te Rum kilisesi), Şebinkarahisar ilçesi (Şebinkarahisar Kalesi, Şebinkarahisar\'ın tarihi evleri, Şebinkarahisar yaylaları, Şebinkarahisar\'ın peyniri, Şebinkarahisar\'ın balı), Bulancak ilçesi (Bulancak Sahili, Bulancak Plajı, Bulancak fındığı, Bulancak yaylaları), Espiye ilçesi (Espiye fındığı, Espiye yaylaları, Espiye Kalesi), Görele ilçesi (Görele fındığı, Görele yaylaları, Görele Kemençesi (Görele kemençe yapımı, kemençe sanatçıları), Görele sahil), Tirebolu ilçesi (Tirebolu Kalesı (Ceneviz Kalesi), Tirebolu fındığı, Tirebolu yaylaları, Tirebolu Sahili), Dereli ilçesi (Dereli yaylaları, Dereli şelalesi), Güce ilçesi (Güce yaylaları, Güce kiliseleri), Yağlıdere ilçesi (Yağlıdere yaylaları, Yağlıdere şelalesi), Çamoluk ilçesi (Çamoluk yaylaları), Eynesil ilçesi (Eynesil Sahili, Eynesil Plajı, Eynesil fındığı), Piraziz ilçesi (Piraziz Sahili, Piraziz fındığı), Keşap ilçesi (Keşap Sahili, Keşap fındığı), Giresun\'un el sanatları (bakır işlemeciliği, halıcılık, kilim dokumacılığı, keçecilik, yemenicilik), Giresun\'un bakırcılar çarşısı, Giresun\'un tarihi çarşıları, Giresun\'un hamamları, Giresun\'un yayla evleri, Giresun\'un ahşap işlemeciliği, Giresun\'un Orta Mahallesi, Giresun\'un feneri, Giresun\'un iskelesi, Giresun\'un limanı, Giresun sahil yolu, Giresun adasına tekne turu, Kümbet Yaylası\'nda yayla şenliği, Kulakkaya\'da şelale manzarası, Sis Dağı\'nda kayak, Karagöl\'de piknik, Giresun kalesinden şehir ve deniz manzarası, Zeytinlik\'te tarihi evler ve manzara, fındık bahçelerinde fındık hasadı mutlaka yapılmalıdır.', 'Giresun mutfağı, Karadeniz mutfağının en zengin örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"Giresun fındığı\" (dünyanın en kaliteli fındığı, Giresun fındığı, yağlı fındık, tombul fındık, çakıldak fındık, kara fındık, Giresun\'un her yerinde fındık bahçeleri) gelir. \"Giresun kebabı\" (etli, patatesli, biberli, domatesli, tencere kebabı), \"Giresun mantısı\", \"etli ekmek\", \"kavurma\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"hamsili börek\", \"çiroz\" (tuzlanmış hamsi), \"kalkan balığı\", \"çinekop\", \"levrek\", \"mezgit\", \"kefal\", \"palamut\", \"lüfer\", \"kalamar\", \"midye\", \"karides\", \"yengeç\", \"kuzu tandır\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Giresun usulü etli ekmek\", \"Giresun usulü içli köfte\", \"sırık köftesi\" (palamut köftesi), \"ısırgan otu yemeği\", \"kaldirik otu yemeği\", \"kuzukulağı yemeği\", \"kırmızı pancar yemeği\", \"fasulye tavalı\", \"kuru fasulye\", \"Giresun usulü fasulye\", \"Giresun usulü lahana sarması\" yöresel lezzetlerdir. Tatlı olarak \"Giresun baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Giresun lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı helva\", \"fındıklı dondurma\", \"fındıklı çikolata\", \"kestane şekeri\", \"kestane tatlısı\", \"fındıklı sucuk\", \"Giresun macunu\" meşhurdur. Giresun\'un \"fındığı\", \"Giresun balı\", \"Giresun elması\", \"Giresun kestanesi\", \"Giresun üzümü\", \"Giresun cevizi\", \"Giresun dutu\", \"Giresun pekmezi\", \"Giresun tahini\", \"Giresun tarhanası\", \"kurutulmuş sebzeleri\", \"yoğurdu\", \"tereyağı\", \"çökeleği\", \"keçi peyniri\", \"tulum peyniri\", \"Giresun peyniri\" de ünlüdür.', 'Giresun\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Giresun Kümbet Yaylası Kültür ve Turizm Festivali (temmuz-ağustos aylarında, Kümbet Yaylası\'nda yayla şenliği, at yarışları, güreşler, kızak çekme, yöresel lezzetler, konserler, halk oyunları). Uluslararası Giresun Kültür ve Sanat Festivali (eylül ayında, Giresun merkez, konserler, halk oyunları, sergiler, panayır). Uluslararası Giresun Fındık Festivali (ağustos ayında, Giresun merkez, fındık hasadı, fındık kırma yarışmaları, fındık tadımı, fındıklı ürünler sergisi, konserler). Giresun Adası Kültür ve Sanat Festivali (haziran ayında, Giresun Adası\'nda konserler, tiyatro gösterileri, efsane anlatımları). Kulakkaya Şelalesi ve Doğa Festivali (temmuz ayında, Kulakkaya\'da doğa yürüyüşleri, şelale altında piknik, konserler). Karagöl Doğa ve Kültür Festivali (ağustos ayında, Karagöl\'de doğa yürüyüşleri, kamp, konserler). Ayrıca Giresun\'da düzenlenen \"Giresun Adası Yüzme Maratonu\", \"Giresun Bisiklet Turu\" ve \"Sis Dağı Kayak Festivali\" (kış aylarında) de ilgi çeker.', 'Giresun\'u ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 18-28°C arasındadır, yaylalar yeşildir, doğa yürüyüşleri, ada gezisi ve yayla şenlikleri için idealdir. Sonbahar (eylül-ekim) da güzeldir, yaprakların renklendiği ve fındık hasadının yapıldığı dönemdir (fındık hasadı ağustos-eylül aylarında). Kışlar ılıman ve yağışlıdır, sıcaklık genelde 3-10°C arasındadır, zaman zaman kar yağışı görülür (özellikle yüksek yaylalarda). Giresun\'u ziyaret etmek için en uygun zaman nisan-mayıs ve haziran-eylül aylarıdır, fındık hasadını görmek için ağustos-eylül idealdir.', 'Giresun\'a hava yoluyla gelmek için Ordu-Giresun Havalimanı (OGU) kullanılır. Havalimanı Giresun merkeze yaklaşık 40 km, Ordu merkeze ise 20 km uzaklıkta olup havaş otobüsleri ve taksi ile Giresun\'a ulaşılır. Giresun\'a şehirlerarası otobüs terminali (Giresun Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Bursa, Samsun, Trabzon, Rize, Artvin, Ordu, Gümüşhane, Bayburt, Erzurum, Sivas, Kayseri, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ). Giresun, Trabzon-Samsun karayolu üzerindedir, özel araçla ulaşım kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Samsun veya Erzincan\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Bulancak, Espiye, Görele, Tirebolu, Dereli, Güce, Yağlıdere, Çamoluk, Eynesil, Piraziz, Keşap, Şebinkarahisar, Alucra gibi ilçelere minibüslerle rahat ulaşım vardır. Giresun Adası\'na şehir merkezinden tekne turları düzenlenir (yaz aylarında). Kümbet Yaylası, Kulakkaya, Karagöl, Tamdere Yaylası, Sis Dağı, Şebinkarahisar Kalesi, Giresun Kalesi, Zeytinlik, Giresun Müzesi, yaylalar, fındık bahçeleri gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Giresun, tarihi boyunca Kolhitler, Kimmerler, İskitler, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Kerasus\" (kiraz) adıyla anılmıştır. Giresun Adası, Argonotlar efsanesinde geçen Ares Adası (Savaş Tanrısı Ares\'in adası) olduğuna inanılan tarihi bir adadır. Osmanlı döneminde Trabzon\'a bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Giresun, fındığı, yaylaları, adası, tarihi kaleleri ve yeşil doğasıyla öne çıkan bir Karadeniz ilidir.', 'Giresun', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(35, 'Gümüşhane', 'Karadeniz', 'gumushane.jpg', 'Süleymaniye Camii ile ünlü.', 'Gümüşhane denince akla gelen ilk şeyler: Zigana Dağı ve Zigana Kayak Merkezi (kış sporları, kayak, doğa yürüyüşleri, yaylalar, manzara, Zigana Tüneli (Türkiye\'nin ilk tüneli, 1963), Zigana Dağı eteklerinde yaylalar), Limni Gölü (krater gölü, doğa harikası, Gümüşhane\'nin en ünlü gölü, yürüyüş yolları, piknik alanı, kamp, manzara, çadır kurma alanları), Karaca Mağarası (Cebeli Mağarası, Türkiye\'nin en güzel mağaralarından biri, sarkıt ve dikitler, traverten havuzları, yürüyüş yolu, aydınlatma, mağara içi dere, doğa harikası, mağara içi sıcaklık 16°C, yazın serin, kışın ılık), Tomara Şelalesi (Gümüşhane\'nin en büyük şelalesi, doğa harikası, yürüyüş yolları, piknik alanı, manzara), Çakırkaya Mağarası, Dörtkonak Şelalesi, Kürtün Şelalesi, Krom Şelalesi, Gümüşhane Kalesi (şehir merkezinde, tarihi kale kalıntıları, manzara), Gümüşhane Müzesi (arkeolojik ve etnografik eserler, Gümüşhane tarihi, gümüş madenleri), Süleymaniye Cami (Osmanlı dönemi, tarihi cami), Taşköprü (tarihi taş köprü, Krom Vadisi\'nde), Krom Vadisi (doğa yürüyüşleri, vadi, şelaleler, kamp), Şiran ilçesi (Şiran\'ın yaylaları, Şiran\'ın peyniri, Şiran\'ın balı, Şiran Kalesi, Karaca Mağarası Şiran sınırları içinde), Kelkit ilçesi (Kelkit Çayı, Kelkit Kalesi, Kelkit\'in yaylaları, Kelkit\'in elması, Kelkit\'in peyniri, Kelkit\'in balı, Kelkit\'in cevizi), Kürtün ilçesi (Kürtün Kalesi, Kürtün yaylaları, Kürtün şelalesi, Kürtün baraj gölü), Torul ilçesi (Torul Kalesi (Zigana Kalesi), Torul yaylaları, Torul\'un peyniri, Torul\'un balı, Zigana Dağı\'nın Torul tarafı), Yağlıdere (Yağlıdere yaylaları, Yağlıdere şelalesi), Köse ilçesi (Köse yaylaları, Köse\'nin peyniri), Gümüşhane\'nin yaylaları (Kadırga Yaylası (en ünlü yayla, yayla şenlikleri, at yarışları, güreşler, konserler, yöresel lezzetler, doğa yürüyüşleri, kamp), Artabel Yaylası (Artabel Gölleri, Artabel Şelalesi, yürüyüş parkurları, kamp, doğa harikası), Çakırgöl Yaylası (göl, doğa), Erikbeli Yaylası, Soğukpınar Yaylası, Kazıkbeli Yaylası, Sis Dağı Yaylaları, Taşköprü Yaylası, Beşköy Yaylaları, Sırakayalar Yaylası, Çiçekli Yaylası, Gümüşhane\'nin yüksek yaylaları (1900-2600 metre rakım), yayla evleri, yayla şenlikleri), Artabel Gölleri (Artabel Yaylası\'nda, doğal göller, yürüyüş, kamp, manzara), Kadırga Yaylası Şenliği (her yıl temmuz ayının 3. haftası, at yarışları, güreşler, konserler, halk oyunları, yöresel lezzetler, Gümüşhane\'nin en büyük yayla şenliği), Gümüşhane Evleri (tarihi Gümüşhane evleri, taş evler, ahşap işlemeleri, restore edilmiş evler, özellikle Süleymaniye Mahallesi\'nde), Gümüşhane\'nin tarihi camileri (Süleymaniye Cami, Kurşunlu Cami, Kale Cami, Ulu Cami, Çit Cami, Hıdırnebi Cami), Gümüşhane\'nin hamamları (Kurşunlu Hamamı, Süleymaniye Hamamı), Gümüşhane\'nin el sanatları (bakır işlemeciliği, halıcılık, kilim dokumacılığı, keçecilik, yemenicilik), Gümüşhane\'nin yöresel kıyafetleri, Gümüşhane\'nin bakırcılar çarşısı, Gümüşhane\'nin tarihi çarşıları, Gümüşhane\'nin gümüş madenleri (tarihi gümüş madenleri, gümüş işlemeciliği), Gümüşhane\'nin maden galerileri, Gümüşhane\'nin tarihi su kemerleri, Gümüşhane\'nin tarihi çeşmeleri, Limni Gölü\'nde yürüyüş, Karaca Mağarası\'nda mağara içi gezinti, Tomara Şelalesi\'nde piknik, Zigana Dağı\'nda kayak, Kadırga Yaylası\'nda yayla şenliği, Artabel Yaylası\'nda kamp ve göl manzarası, Gümüşhane Kalesi\'nden şehir manzarası mutlaka yapılmalıdır.', 'Gümüşhane mutfağı, Karadeniz ve Doğu Anadolu mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Gümüşhane köftesi\" gelir. \"Gümüşhane mantısı\" (etli, yoğurtlu, yağlı), \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kızılcık şerbeti\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Gümüşhane usulü etli ekmek\", \"Gümüşhane usulü içli köfte\", \"sırık köftesi\", \"ısırgan otu yemeği\", \"kaldirik otu yemeği\", \"kuzukulağı yemeği\", \"fasulye tavalı\", \"Gümüşhane tava\", \"Gümüşhane kebabı\", \"Gümüşhane turşusu\", \"Gümüşhane yoğurdu\", \"Gümüşhane peyniri\" yöresel lezzetlerdir. Tatlı olarak \"Gümüşhane baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Gümüşhane lokumu\", \"Gümüşhane kete\" (ayçöreği benzeri, cevizli, üzümlü), \"Gümüşhane zülbiyesi\", \"Gümüşhane sucuk\", \"Gümüşhane pekmezi\", \"Gümüşhane tahini\" meşhurdur. Gümüşhane\'nin \"Gümüşhane balı\" (yayla balı), \"Gümüşhane peyniri\" (tulum peyniri, küp peyniri), \"Gümüşhane yoğurdu\", \"Gümüşhane cevizi\", \"Gümüşhane elması\", \"Gümüşhane üzümü\", \"Gümüşhane dutu\", \"Gümüşhane kestanesi\", \"Gümüşhane tarhanası\", \"kurutulmuş sebzeleri\", \"tereyağı\", \"çökeleği\", \"keçi peyniri\", \"kavutu\" da ünlüdür.', 'Gümüşhane\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Kadırga Yaylası Kültür ve Turizm Festivali (temmuz ayının 3. haftası, Kadırga Yaylası\'nda at yarışları, güreşler, konserler, halk oyunları, yöresel lezzetler, yayla şenliği, Gümüşhane\'nin en büyük festivali). Uluslararası Limni Gölü Kültür ve Doğa Festivali (ağustos ayında, Limni Gölü çevresinde doğa yürüyüşleri, kamp, konserler, piknik). Uluslararası Karaca Mağarası Kültür ve Turizm Festivali (eylül ayında, Karaca Mağarası çevresinde mağara gezileri, doğa yürüyüşleri, konserler). Gümüşhane Kültür ve Sanat Festivali (ağustos ayında, Gümüşhane merkez, konserler, halk oyunları, sergiler, panayır). Artabel Yaylası Doğa Sporları ve Kamp Festivali (temmuz ayında, Artabel Yaylası\'nda doğa yürüyüşleri, kamp, dağcılık, yamaç paraşütü, konserler). Torul Kültür ve Sanat Festivali (ağustos ayında, Torul ilçesinde konserler, yayla şenlikleri). Ayrıca Gümüşhane\'de düzenlenen \"Zigana Dağı Kayak Festivali\" (kış aylarında), \"Limni Gölü Yürüyüş Günleri\" ve \"Gümüşhane Bisiklet Turu\" da ilgi çeker.', 'Gümüşhane\'yi ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 18-28°C arasındadır, yaylalar yeşildir, doğa yürüyüşleri, yayla şenlikleri ve tarihi yerleri gezmek için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -15°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez (ancak Zigana Kayak Merkezi için kış ayları idealdir). Gümüşhane\'yi ziyaret etmek için en uygun zaman temmuz ve ağustos aylarıdır.', 'Gümüşhane\'ye hava yoluyla gelmek için en yakın havalimanı Trabzon Havalimanı (TZX) (120 km) veya Erzincan Havalimanı (ERC) (150 km) kullanılır. Havalimanlarından havaş otobüsleri ve taksi ile Gümüşhane\'ye ulaşılır. Gümüşhane\'ye şehirlerarası otobüs terminali (Gümüşhane Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Bursa, Trabzon, Rize, Artvin, Samsun, Ordu, Giresun, Erzincan, Erzurum, Bayburt, Sivas, Kayseri, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ). Gümüşhane, Trabzon-Erzincan karayolu üzerindedir, özel araçla ulaşım kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Erzincan\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kelkit, Şiran, Kürtün, Torul, Köse, Yağlıdere, Kürtün, Köse gibi ilçelere minibüslerle rahat ulaşım vardır. Karaca Mağarası, Limni Gölü, Tomara Şelalesi, Kadırga Yaylası, Artabel Yaylası, Zigana Kayak Merkezi, Gümüşhane Kalesi, Gümüşhane Müzesi, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Gümüşhane, tarihi boyunca Hurriler, Hititler, Kimmerler, İskitler, Urartular, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, Trabzon İmparatorluğu ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Tarihi İpek Yolu üzerinde önemli bir durak olan Gümüşhane, adını Osmanlı döneminde işletilen gümüş madenlerinden almıştır. Osmanlı döneminde Trabzon\'a bağlı bir sancak olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Gümüşhane, yaylaları, doğal güzellikleri, tarihi kiliseleri, kaleleri ve yöresel lezzetleriyle öne çıkan bir Doğu Karadeniz ilidir.', 'Gümüşhane', '2026-04-08 23:20:51'),
(36, 'Hakkari', 'Doğu Anadolu', 'hakkari.jpg', 'Cilo Dağları ile ünlü.', 'Hakkâri denince akla gelen ilk şeyler: Cilo Dağı ve Cilo-Sat Dağları (Türkiye\'nin en yüksek dağlarından, Cilo Dağı 4116 m, Uludoruk Zirvesi 4135 m, Türkiye\'nin en yüksek ikinci zirvesi, dağcılık, tırmanış, buzul gölleri, doğa yürüyüşleri, kamp, manzara, Cilo Dağı Milli Parkı), Cilo Buzulları (Cilo Dağı\'nın zirvesinde, Türkiye\'nin en büyük buzulları, yaz aylarında bile karlar erimez, doğa harikası), Sat Dağları (Sat Dağları, Cilo Dağı\'nın devamı, dağcılık, doğa yürüyüşleri), Cilo Dağı Buzul Gölleri (Cilo Dağı\'nın eteklerinde buzul gölleri, krater gölleri, doğal güzellik, doğa yürüyüşü), Zap Suyu (Büyük Zap Suyu, rafting, kano, doğa yürüyüşleri, balık tutma, vadi, manzara), Zap Vadisi (doğa yürüyüşleri, kamp, manzara), Hakkâri Kalesi (şehir merkezinde, tarihi kale kalıntıları, manzara), Hakkâri Müzesi (arkeolojik ve etnografik eserler, Hakkâri tarihi, yöresel kıyafetler, el sanatları), Merzan Mahallesi (tarihi taş evler, restore edilmiş evler, dar sokaklar), Meydan Medresesi (tarihi medrese, Osmanlı dönemi), Hakkâri Ulu Cami (tarihi cami), Düzenli Mağarası (doğal mağara, sarkıt ve dikitler), Berçelan Yaylası (Hakkâri\'nin en ünlü yaylalarından, yayla evleri, yayla şenlikleri, doğa yürüyüşleri, piknik, kamp, manzara, Berçelan Yaylası Şenliği her yıl ağustos ayında düzenlenir), Buzul Gölü (Berçelan Yaylası\'nda buzul gölü), Kuşluk Yaylası, Çukurca Yaylası, Şemdinli Yaylası, Yüksekova Yaylası, Oğul Yaylası, Kaval Yaylası, Yaylalar (Hakkâri\'nin yaylaları 2000-3000 metre rakımda, yayla evleri, yayla şenlikleri, at yarışları, güreşler, yöresel lezzetler, konserler, halk oyunları), Yüksekova ilçesi (Yüksekova Ovası, Yüksekova Kalesi, Yüksekova\'nın yaylaları, Yüksekova\'nın balı, Yüksekova\'nın peyniri, Yüksekova\'nın el sanatları, Yüksekova\'nın halı ve kilimleri dünyaca ünlü), Şemdinli ilçesi (Şemdinli Kalesi, Şemdinli\'nin yaylaları, Şemdinli\'nin balı, Şemdinli\'nin peyniri), Çukurca ilçesi (Çukurca Kalesi, Çukurca\'nın yaylaları, Çukurca\'nın balı), Derecik ilçesi (Derecik\'in yaylaları), Hakkâri\'nin yayla evleri (taş evler, ahşap işlemeleri), Hakkâri\'nin halı ve kilim dokumacılığı (Hakkâri halıları ve kilimleri dünyaca ünlü, el dokuması, doğal boyalar, yün, motifler, Hakkâri Müzesi\'nde sergilenir), Hakkâri\'nin bakır işlemeciliği, Hakkâri\'nin keçeciliği, Hakkâri\'nin yöresel kıyafetleri (renkli, işlemeli), Hakkâri\'nin tarihi çarşıları, Hakkâri\'nin bakırcılar çarşısı, Hakkâri\'nin el sanatları (halı, kilim, bakır, keçe, yemeni), Hakkâri\'nin mesire alanları, Hakkâri\'nin su kaynakları, Hakkâri\'nin köprüleri, Hakkâri\'nin çeşmeleri, Cilo Dağı\'na tırmanış (profesyonel dağcılar için), Zap Suyu\'nda rafting, Berçelan Yaylası\'nda yayla şenliği, Cilo Buzulları\'nı izlemek, Yüksekova halılarını incelemek, Hakkâri Kalesi\'nden şehir manzarası mutlaka yapılmalıdır.', 'Hakkâri mutfağı, Doğu Anadolu\'nun zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Hakkâri köftesi\" (etli, baharatlı, şişte pişirilir) gelir. \"Hakkâri tava\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Hakkâri usulü etli ekmek\", \"Hakkâri usulü içli köfte\", \"kırma\", \"keledoş\", \"köme\", \"Hakkâri peyniri\", \"Hakkâri yoğurdu\", \"Hakkâri balı\", \"Hakkâri kavutu\" yöresel lezzetlerdir. Tatlı olarak \"Hakkâri baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Hakkâri lokumu\", \"kaysefe\" (kuru meyveli tatlı) meşhurdur. Hakkâri\'nin \"Hakkâri balı\" (yüksek rakımlı yayla balı, dünyaca ünlü), \"Hakkâri peyniri\" (tulum peyniri, küp peyniri), \"Hakkâri yoğurdu\", \"Hakkâri cevizi\", \"Hakkâri dutu\", \"Hakkâri üzümü\", \"Hakkâri elması\", \"Hakkâri kavunu\", \"Hakkâri karpuzu\", \"Hakkâri tarhanası\", \"kurutulmuş sebzeleri\", \"tereyağı\", \"çökeleği\", \"keçi peyniri\", \"kavutu\" da ünlüdür.', 'Hakkâri\'de birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Hakkâri Kültür ve Sanat Festivali (ağustos ayında, Hakkâri merkez, konserler, halk oyunları, yöresel lezzetler, panayır, sergiler). Uluslararası Berçelan Yaylası Kültür ve Turizm Festivali (ağustos ayında, Berçelan Yaylası\'nda at yarışları, güreşler, konserler, halk oyunları, yöresel lezzetler, yayla şenliği). Uluslararası Cilo Dağı Dağcılık ve Doğa Sporları Festivali (temmuz ayında, Cilo Dağı\'nda dağcılık tırmanışları, doğa yürüyüşleri, kamp, yamaç paraşütü, konserler). Yüksekova Kültür ve Sanat Festivali (eylül ayında, Yüksekova ilçesinde konserler, halk oyunları, halı sergileri). Şemdinli Kültür ve Bal Festivali (ağustos ayında, Şemdinli ilçesinde bal tadımı, bal yarışmaları, yöresel lezzetler, konserler). Çukurca Kültür ve Doğa Festivali (temmuz ayında, Çukurca ilçesinde doğa yürüyüşleri, konserler). Ayrıca Hakkâri\'de düzenlenen \"Zap Suyu Rafting Festivali\", \"Cilo Dağı Maratonu\" ve \"Hakkâri Bisiklet Turu\" da ilgi çeker.', 'Hakkâri\'yi ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır, yaylalar yeşildir, doğa yürüyüşleri, dağcılık, yayla şenlikleri için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -25°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez (ancak dağcılık için haziran-eylül idealdir). Hakkâri\'yi ziyaret etmek için en uygun zaman temmuz ve ağustos aylarıdır.', 'Hakkâri\'ye hava yoluyla gelmek için Hakkâri Yüksekova Selahaddin Eyyubi Havalimanı (YKO) kullanılır. Havalimanı Yüksekova ilçesine yaklaşık 20 km, Hakkâri merkeze ise 70 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Hakkâri\'ye şehirlerarası otobüs terminali (Hakkâri Otogarı) şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Van, Diyarbakır, Gaziantep, Adana, Mersin, Konya, Kayseri, Sivas, Malatya, Elazığ). Hakkâri, Van-Hakkâri karayolu üzerindedir, özel araçla ulaşım sağlanır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Van\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Yüksekova, Şemdinli, Çukurca, Derecik gibi ilçelere minibüslerle rahat ulaşım vardır. Cilo Dağı, Sat Dağları, Berçelan Yaylası, Zap Suyu, Zap Vadisi, Hakkâri Kalesi, Yüksekova halı atölyeleri, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir. Dağcılık turları için profesyonel rehber eşliğinde gitmek gereklidir.', 'Hakkâri, tarihi boyunca Asurlular, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi boyunca stratejik konumu nedeniyle sık sık el değiştirmiştir. Osmanlı döneminde Hakkâri Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Hakkâri, doğal güzellikleri, yaylaları, dağları, Cilo Dağı ve Zap Suyu vadisiyle öne çıkan bir Doğu Anadolu ilidir. Bölge, dağcılık ve doğa sporları için Türkiye\'nin en önemli merkezlerinden biridir.', 'Hakkari', '2026-04-08 23:20:51'),
(37, 'Hatay', 'Akdeniz', 'hatay.jpg', 'Mozaikleri ile ünlü.', 'Hatay denince akla gelen ilk şeyler: Antakya (tarihi şehir merkezi, uzun çarşısı, dar sokakları, tarihi evleri, camileri, kiliseleri, sinagogları, hanları, hamamları, müzeleri), St. Pierre Kilisesi (Hristiyanlık tarihinin en önemli kiliselerinden, kaya kilisesi, Aziz Petrus\'un ilk vaaz verdiği yer, Hristiyanlığın ilk kilisesi, 1983 yılında Papa tarafından hac yeri ilan edilmiştir, mağara içinde kilise, mozaikler, heykeller), Hatay Arkeoloji Müzesi (dünyanın en büyük mozaik müzelerinden biri, Roma ve Bizans dönemi mozaikleri, heykeller, lahitler, sikke koleksiyonu, Büyük Mozaik (4. yüzyıl), Kıbrıs Mozaiği, Orpheus Mozaiği, Atlantis Mozaiği, heykeller, Arkeoloji Müzesi), Antakya Kalesi (şehrin simgesi, şehre hakim tepede, tarihi kale, surlar, manzara), Habib-i Neccar Cami (Anadolu\'nun ilk camilerinden, Hz. Habib-i Neccar\'ın türbesi, tarihi cami), Ulu Cami (Antakya Ulu Cami, tarihi cami), Vakıflı Köyü (Türkiye\'nin tek Ermeni köyü, taş evler, dar sokaklar, kilise, bahçeler, doğa, el sanatları, yöresel ürünler, Vakıflı Köyü\'nde Ermeni mutfağı, Vakıflı Köyü\'nde kahvaltı meşhur), Samandağ (Seleucia Pieria Antik Kenti, Titus Tüneli, Beşikli Mağara, Samandağ sahili, plaj, deniz, balıkçılar, deniz ürünleri), Titus Tüneli (Roma dönemi su kanalı, tünel, 1.4 km uzunluğunda, dünyanın en büyük tüneli, Vespasianus ve Titus dönemi), Seleucia Pieria Antik Kenti (Samandağ\'da, Roma dönemi liman kenti, tiyatro, hamam, su kemerleri, surlar, kaya mezarları), Beşikli Mağara (Samandağ\'da, kaya mezarları, mağara içinde beşik şeklinde oyma mezarlar), Harbiye (Daphne, Antakya\'nın 8 km güneyinde, şelaleler, mesire alanı, doğa, piknik, yürüyüş, restoranlar, Harbiye şelaleleri, Harbiye\'de defineli tepeler, Harbiye\'nin asmalı restoranları, Harbiye\'nin çay bahçeleri, Harbiye\'nin yörük çadırları), Defne ilçesi (Harbiye\'nin bağlı olduğu ilçe, Defne kaplıcaları, termal su), Arsuz ilçesi (Arsuz Plajı, Arsuz sahili, deniz, balıkçılar, Arsuz Kalesı (Ceneviz Kalesi), Arsuz\'un tarihi evleri, Arsuz\'un narenciye bahçeleri, Arsuz\'un portakalı, limonu, mandalini), İskenderun (İskenderun limanı, İskenderun sahil şeridi, İskenderun Kalesı (Ceneviz Kalesi), İskenderun Arkeoloji Müzesi, İskenderun Deniz Müzesi, İskenderun\'un tarihi evleri, İskenderun\'un restoranları (deniz ürünleri), İskenderun\'un balıkçıları, İskenderun\'un çarşıları, İskenderun\'un bakırcıları, İskenderun\'un lezzetleri), İskenderun\'un plajları (Karaağaç Plajı, Mersin Plajı, Konacık Plajı), Dörtyol (Dörtyol\'un tarihi evleri, Dörtyol\'un yaylaları, Dörtyol\'un portakal bahçeleri), Hassa (Hassa Kalesi, Hassa\'nın yaylaları), Kırıkhan (Kırıkhan Kalesi, Kırıkhan\'ın yaylaları), Reyhanlı (Reyhanlı\'nın yaylaları, Reyhanlı\'nın ovaları), Altınözü (Altınözü\'nün yaylaları, Altınözü\'nün tarihi evleri), Yayladağı (Yayladağı\'nın yaylaları, Yayladağı\'nın doğası), Hatay\'ın yaylaları (Sokuluk Yaylası, Ziyaret Yaylası, Daz Yaylası, Ballıgöl Yaylası, Karbeyaz Yaylası, Yayladağı yaylaları, doğa yürüyüşleri, yayla şenlikleri), Hatay\'ın plajları (Samandağ Plajı, Çevlik Plajı, Arsuz Plajı, Konacık Plajı, Karaağaç Plajı, Mersin Plajı, İskenderun sahil şeridi, yüzme, deniz, güneş), Hatay\'ın mağaraları (Beşikli Mağara, Kaya Mağaraları, Mağaracık Mağarası), Hatay\'ın antik kentleri (Antiokheia (Antakya), Seleucia Pieria (Samandağ), İskenderun Antik Kenti, Bakras Antik Kenti), Hatay\'ın camileri (Habib-i Neccar Cami, Ulu Cami, Hacı Veli Cami, Karsu Cami), Hatay\'ın kiliseleri (St. Pierre Kilisesi, St. Paul Kilisesi, Vakıflı Köyü Kilisesi, İskenderun Meryem Ana Kilisesi, Antakya Latin Katolik Kilisesi, Antakya Ortodoks Kilisesi), Hatay\'ın sinagogları (Antakya Sinagogu), Hatay\'ın hanları (Kurşunlu Han, Zincirli Han, Büyük Han, Küçük Han, Hacı Veli Han), Hatay\'ın hamamları (Büyük Hamam, Küçük Hamam, Paşa Hamamı, Yeni Hamam), Hatay\'ın çarşıları (Uzun Çarşı, Kapalı Çarşı, Bakırcılar Çarşısı, Kunduracılar Çarşısı, Saraçlar Çarşısı), Hatay\'ın el sanatları (bakır işlemeciliği, sedef kakmacılığı, taş işlemeciliği, halıcılık, kilim dokumacılığı, ipek dokumacılığı, defne sabunu yapımı), Hatay\'ın defne sabunu (Antakya defne sabunu, doğal defne sabunu, zeytinyağlı defne sabunu, Hatay\'a özgü, el yapımı, doğal, tarihi sabun), Hatay\'ın bakır işlemeciliği (bakır tencere, tava, cezve, ibrik, sini, kazan, bakır işleme atölyeleri, Uzun Çarşı\'da bakırcılar), Hatay\'ın sedef kakmacılığı (sedef kakmalı aynalar, kutular, sehpalar, tablolar, hatıra eşyası), Hatay\'ın taş işlemeciliği (Antakya taşı, taş işleme, tarihi yapılar), Hatay\'ın yöresel kıyafetleri (renkli, işlemeli, bindallı), Hatay\'ın mesire alanları (Harbiye Şelaleleri, Ballıgöl, Sokuluk, Daz Yaylası, Habib-i Neccar Parkı, Atatürk Parkı, İskenderun Sahil Parkı, Arsuz Sahil Parkı), Hatay\'ın yöresel ürünleri (künefe, içli köfte, humus, muhammara, babağannuş, beyran çorbası, defne sabunu, Antakya peyniri, Antakya yoğurdu, Antakya zeytini, Antakya zeytinyağı, Antakya baharatı, nar ekşisi, üzüm sirkesi, pekmez, tahin, isot, kekik, sumak, kimyon), St. Pierre Kilisesi\'nde kilise ziyareti, Hatay Arkeoloji Müzesi\'nde mozaikleri görmek, Uzun Çarşı\'da alışveriş ve künefe yemek, Harbiye Şelaleleri\'nde piknik, Samandağ\'da Titus Tüneli\'ni gezmek, Vakıflı Köyü\'nde kahvaltı yapmak, İskenderun\'da deniz ürünleri yemek, Arsuz\'da denize girmek, defne sabunu almak, Antakya evleri ve dar sokaklarında yürüyüş yapmak, Hatay Kalesi\'nden şehir manzarası izlemek mutlaka yapılmalıdır.', 'Hatay mutfağı, dünyanın en zengin ve ünlü mutfaklarından biridir. UNESCO Yaratıcı Şehirler Ağı Gastronomi Şehri\'dir. Mutlaka denenmesi gerekenlerin başında \"Hatay künefesi\" (tel kadayıf arasında taze peynir, şerbetli, sıcak servis edilir, dünyaca ünlü) gelir. \"Hatay usulü kebap çeşitleri\" (oruk kebabı, simit kebabı, kağıt kebabı, tepsi kebabı, sıkma kebabı, ciğer kebabı, soğan kebabı, kuşbaşı kebabı, patlıcan kebabı, ekşili kebap, taş kebabı, şiş kebabı), \"Hatay içli köfte\" (oruk), \"Hatay çiğ köftesi\" (etli, baharatlı, maydanozlu), \"mercimek köftesi\", \"lahmacun\", \"sarma\", \"dolma\", \"ekşili köfte\", \"yayla çorbası\", \"mercimek çorbası\", \"tarhana çorbası\", \"beyran çorbası\" (etli, yağlı, acılı, Antakya\'ya özgü), \"kuzu tandır\", \"etli ekmek\", \"katmer\", \"gözleme\", \"kırma\", \"batırık\", \"humus\", \"muhammara\" (cevizli, biberli, ekmek üstüne sürülür), \"babağannuş\" (patlıcanlı mezze), \"kısır\", \"şakşuka\", \"acılı ezme\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"zeytinyağlı yaprak sarma\", \"zeytinyağlı kereviz\", \"zeytinyağlı pırasa\", \"otlu börek\", \"pide\", \"Antakya peyniri\", \"Antakya yoğurdu\", \"Antakya şalgamı\", \"Antakya bozası\", \"sirkesi\", \"pekmezi\", \"tahini\", \"zeytini\", \"zeytinyağı\" yöresel lezzetlerdir. Tatlı olarak \"künefe\", \"baklava\", \"kadayıf\", \"şöbiyet\", \"burma kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Hatay lokumu\", \"fıstıklı sucuk\", \"katmer tatlısı\", \"ağzıaçık\", \"Antakya macunu\", \"Antakya şekeri\" meşhurdur. Hatay\'ın \"künefesi\", \"Antakya peyniri\", \"Antakya yoğurdu\", \"Antakya zeytini\", \"Antakya zeytinyağı\", \"Antakya defne sabunu\", \"Antakya baharatı\" (isot, kimyon, sumak, pul biber, kekik, nane), \"Hatay narı\", \"Hatay üzümü\", \"Hatay elması\", \"Hatay portakalı\", \"Hatay limonu\", \"Hatay mandalini\", \"Hatay karpuzu\", \"Hatay kavunu\", \"Hatay inciri\", \"Hatay cevizi\", \"Hatay bademi\", \"Hatay balı\", \"Hatay tarhanası\", \"kurutulmuş sebzeleri\" de ünlüdür.', 'Hatay\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Hatay Kültür ve Sanat Festivali (eylül ayında, Antakya merkez, konserler, halk oyunları, yöresel lezzetler, panayır, sergiler, panel). Uluslararası Hatay Gastronomi Festivali (ekim ayında, Hatay merkez, yemek yarışmaları, künefe yapım atölyeleri, yöresel lezzet tadımları, konserler). Uluslararası St. Pierre Kültür ve Sanat Festivali (haziran ayında, St. Pierre Kilisesi\'nde konserler, tiyatro gösterileri). Harbiye Şelaleleri Kültür ve Doğa Festivali (temmuz ayında, Harbiye\'de doğa yürüyüşleri, şelale altında piknik, konserler). Vakıflı Köyü Kültür ve Sanat Festivali (ağustos ayında, Vakıflı Köyü\'nde konserler, el sanatları sergileri, yöresel lezzetler). Samandağ Kültür ve Turizm Festivali (ağustos ayında, Samandağ\'da konserler, deniz yarışları, yöresel lezzetler). Arsuz Kültür ve Turizm Festivali (temmuz ayında, Arsuz\'da konserler, plaj voleybolu, deniz yarışları). Ayrıca Hatay\'da düzenlenen \"Hatay Maratonu\", \"İskenderun Bisiklet Turu\" ve \"Samandağ Plaj Voleybolu Turnuvası\" da ilgi çeker.', 'Hatay\'ı ziyaret etmek için en iyi zaman ilkbahar (mart-mayıs) ve sonbahar (eylül-kasım) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır, tarihi yerleri, müzeleri ve mutfağı keşfetmek için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 35-40°C\'ye ulaşabilir, sıcak ve nemlidir, ancak Samandağ ve Arsuz sahilleri için yaz ayları tercih edilebilir. Kışlar ılımandır, sıcaklık genelde 5-15°C arasındadır, yağışlı olabilir. Hatay\'ı ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Hatay\'a hava yoluyla gelmek için Hatay Havalimanı (HTY) kullanılır. Havalimanı Antakya\'ya 25 km, İskenderun\'a 60 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Hatay\'a şehirlerarası otobüs terminali (Antakya Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Adana, Mersin, Gaziantep, Şanlıurfa, Diyarbakır, Konya, Kayseri, Sivas, Malatya, Elazığ, Maraş, Osmaniye, Kilis). Hatay, Adana-İskenderun karayolu üzerindedir, özel araçla ulaşım kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Adana veya Osmaniye\'dedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Antakya, İskenderun, Samandağ, Arsuz, Dörtyol, Hassa, Kırıkhan, Reyhanlı, Altınözü, Yayladağı, Defne, Payas, Erzin gibi ilçelere minibüslerle rahat ulaşım vardır. St. Pierre Kilisesi, Hatay Arkeoloji Müzesi, Uzun Çarşı, Harbiye Şelaleleri, Titus Tüneli, Samandağ Plajı, Arsuz Plajı, İskenderun Kalesi, Vakıflı Köyü, Defne Kaplıcaları, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Hatay, tarihi boyunca Hititler, Asurlular, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Memluklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Antakya\" (Antioch) adıyla anılmıştır. Roma döneminde Doğu\'nun en önemli şehirlerinden biri olan Antakya, Hristiyanlık tarihinde de büyük öneme sahiptir. 1939 yılında Hatay Devleti\'nin Türkiye\'ye katılmasıyla il statüsü kazanmıştır. Hatay, tarihi zenginlikleri, mozaikleri, eşsiz mutfağı, kültürel çeşitliliği ve Akdeniz sahiliyle öne çıkan bir ilimizdir. UNESCO Yaratıcı Şehirler Ağı\'na \"Gastronomi Şehri\" olarak kabul edilmiştir.', 'Hatay', '2026-04-08 23:20:51'),
(38, 'Iğdır', 'Doğu Anadolu', 'igdir.jpg', 'Ağrı Dağı manzarası ile ünlü.', 'Iğdır denince akla gelen ilk şeyler: Ağrı Dağı (Türkiye\'nin en yüksek dağı, 5137 m, efsanelere göre Hz. Nuh\'un Gemisi\'nin indiğine inanılan dağ, Iğdır\'dan Ağrı Dağı\'nın eşsiz manzarası, dağcılık, tırmanış (profesyonel dağcılar için), doğa yürüyüşleri, kamp, manzara, Ağrı Dağı\'nın zirvesi, Ağrı Dağı eteklerinde yürüyüş, Ağrı Dağı Milli Parkı), Iğdır Kalesi (şehir merkezinde, tarihi kale kalıntıları, manzara), Iğdır Müzesi (arkeolojik ve etnografik eserler, Iğdır tarihi, yöresel kıyafetler, el sanatları), Iğdır Kayısı Bahçeleri (Iğdır\'ın her yerinde kayısı bahçeleri, kayısı hasadı haziran-temmuz aylarında, kayısı toplama, kayısı kurutma, taze kayısı yeme, kayısı bahçelerinde gezinti), Iğdır\'ın yaylaları (Suluçem Yaylası, Güllüce Yaylası, Melekli Yaylası, Koçbaşı Yaylası, Hacet Yaylası, Yellibel Yaylası, doğa yürüyüşleri, yayla şenlikleri, piknik, kamp, yayla evleri), Aras Nehri (Iğdır\'ın doğusundan akar, Aras Vadisi, kuş cenneti, göçmen kuşlar, flamingolar, doğa yürüyüşleri, balık tutma, piknik, manzara), Aras Kuş Cenneti (Aras Nehri kenarında, göçmen kuşlar, flamingolar, pelikanlar, leylekler, kartallar, kuş gözlem, doğa fotoğrafçılığı), Tuzluca (Tuzluca ilçesi, Tuz Mağarası, tuz madeni, astım hastalığına iyi gelir, tuz lambaları, doğal tuz oluşumları, mağara içi yürüyüş), Karakoyunlu (Karakoyunlu ilçesi, Karakoyunlu Kalesi, Karakoyunlu\'nun tarihi evleri), Aralık (Aralık ilçesi, Aralık\'ın yaylaları, Aralık\'ın tarım alanları), Halfeli (Halfeli ilçesi, Halfeli Kalesi), Iğdır\'ın köprüleri (Aras Nehri üzerinde tarihi köprüler), Iğdır\'ın tarihi camileri (Ulu Cami, Çarşı Cami, Fatih Cami, Kurşunlu Cami), Iğdır\'ın hamamları (Kurşunlu Hamamı, Yeni Hamam), Iğdır\'ın çarşıları (Kapalı Çarşı, Bakırcılar Çarşısı, Saraçlar Çarşısı), Iğdır\'ın el sanatları (bakır işlemeciliği, halıcılık, kilim dokumacılığı, keçecilik, yemenicilik), Iğdır\'ın halı ve kilimleri (Iğdır halıları, el dokuması, doğal boyalar, yün, motifler), Iğdır\'ın yöresel kıyafetleri, Iğdır\'ın mesire alanları (Iğdır Parkı, Atatürk Parkı, Yayla Mesire Alanı), Iğdır\'ın Ağrı Dağı manzarası (Iğdır\'dan Ağrı Dağı\'nın gün doğumu ve gün batımı manzarası, eşsiz görüntü), Iğdır\'da kayısı kurutma tesisleri, Tuzluca Tuz Mağarası\'nda tuz terapi, Aras Kuş Cenneti\'nde kuş gözlem, Ağrı Dağı eteklerinde doğa yürüyüşü, Iğdır Kalesi\'nden şehir manzarası mutlaka yapılmalıdır.', 'Iğdır mutfağı, Doğu Anadolu ve Kafkas mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Iğdır kayısısı\" (dünyaca ünlü, Iğdır kayısısı, güneşte kurutulmuş, tatlı, aromatik) gelir. \"Iğdır kebabı\", \"Iğdır köftesi\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Iğdır usulü etli ekmek\", \"Iğdır usulü içli köfte\", \"keledoş\", \"ayran aşı\", \"kaymaklı mantı\", \"Iğdır peyniri\", \"Iğdır yoğurdu\", \"Iğdır balı\" yöresel lezzetlerdir. Tatlı olarak \"Iğdır baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Iğdır lokumu\", \"kayısı tatlısı\", \"kayısı hoşafı\", \"kayısı reçeli\", \"kayısı marmelatı\", \"kayısı pestili\", \"kayısı kömesi\" meşhurdur. Iğdır\'ın \"kayısısı\" (dünyaca ünlü), \"Iğdır balı\" (yayla balı), \"Iğdır peyniri\" (tulum peyniri), \"Iğdır yoğurdu\", \"Iğdır cevizi\", \"Iğdır elması\", \"Iğdır üzümü\", \"Iğdır dutu\", \"Iğdır karpuzu\", \"Iğdır kavunu\", \"Iğdır tarhanası\", \"kurutulmuş sebzeleri\", \"tereyağı\", \"çökeleği\", \"kavutu\", \"keçi peyniri\" de ünlüdür.', 'Iğdır\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Iğdır Kayısı Festivali (temmuz ayında, Iğdır merkez, kayısı hasadı, kayısı yarışmaları, kayısı tadımı, kayısılı ürünler sergisi, konserler, yöresel lezzetler, panayır, halk oyunları). Uluslararası Iğdır Kültür ve Sanat Festivali (ağustos ayında, Iğdır merkez, konserler, halk oyunları, sergiler, panayır). Aras Kuş Cenneti ve Doğa Festivali (mayıs ayında, Aras Kuş Cenneti\'nde kuş gözlem, doğa yürüyüşleri, fotoğraf yarışması). Tuzluca Tuz Mağarası Kültür ve Turizm Festivali (ağustos ayında, Tuzluca ilçesinde tuz mağarası gezileri, tuz terapi, konserler). Ağrı Dağı Doğa Sporları ve Dağcılık Festivali (temmuz ayında, Ağrı Dağı eteklerinde doğa yürüyüşleri, dağcılık tırmanışları (profesyoneller için), kamp). Ayrıca Iğdır\'da düzenlenen \"Aras Nehri Bisiklet Turu\", \"Ağrı Dağı Maratonu\" ve \"Iğdır Yayla Şenlikleri\" de ilgi çeker.', 'Iğdır\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 15-30°C arasındadır, Ağrı Dağı\'nı görmek, yaylaları gezmek ve doğa yürüyüşleri için idealdir. Kayısı hasadı haziran-temmuz aylarında yapılır. Yaz aylarında sıcaklık 35°C\'yi bulabilir, ancak kurak geçer. İlkbahar ve sonbahar serin ve yağışlıdır. Kışlar çok sert ve karlıdır; sıcaklık -20°C\'nin altına düşebilir, aralık-şubat arasında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez. Iğdır\'ı ziyaret etmek için en uygun zaman nisan-mayıs ve haziran-eylül aylarıdır.', 'Iğdır\'a hava yoluyla gelmek için Iğdır Şehit Bülent Aydın Havalimanı (IGD) kullanılır. Havalimanı şehir merkezine yaklaşık 15 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Iğdır\'a şehirlerarası otobüs terminali (Iğdır Otogarı) şehir merkezinde olup birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Kars, Ardahan, Ağrı, Van, Erzurum, Erzincan, Malatya, Elazığ, Diyarbakır, Gaziantep). Iğdır, Kars-Iğdır-Ağrı karayolu üzerindedir, özel araçla ulaşım sağlanır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Kars\'tadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Tuzluca, Karakoyunlu, Aralık, Halfeli gibi ilçelere minibüslerle rahat ulaşım vardır. Ağrı Dağı Milli Parkı, Aras Kuş Cenneti, Tuzluca Tuz Mağarası, Iğdır Kalesi, Iğdır Müzesi, kayısı bahçeleri, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir. Ağrı Dağı\'na tırmanış için profesyonel rehber eşliğinde izin almak gereklidir.', 'Iğdır, tarihi boyunca Hurriler, Hititler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Selçuklular, İlhanlılar, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Tarihi İpek Yolu üzerinde önemli bir durak olan Iğdır, stratejik konumu nedeniyle sık sık el değiştirmiştir. 1920 yılında Türkiye sınırlarına katılmış, 1992 yılında il statüsü kazanmıştır. Iğdır, Türkiye\'nin en doğudaki illerinden biridir. Ağrı Dağı\'nın eteklerinde kurulan Iğdır, tarım alanları, kayısı bahçeleri ve yaylalarıyla öne çıkan bir Doğu Anadolu ilidir.', 'Iğdır', '2026-04-08 23:20:51'),
(39, 'Isparta', 'Akdeniz', 'isparta.jpg', 'Gülleri ile ünlü.', 'Isparta denince akla gelen ilk şeyler: Gül Bahçeleri ve Gül Hasadı (Isparta\'nın gül bahçeleri, mayıs sonu haziran başı gül hasadı, gül toplama, gül yağı üretimi, gül suyu üretimi, gül bahçeleri gezisi, gül fotoğrafçılığı, gül kokusu, Isparta\'nın her yerinde gül tarlaları, gül işleme tesisleri, Güneykent Gül Parkı, Gül Müzesi, Gül Kültürü), Gül Müzesi (Isparta Gül Müzesi, gül yetiştiriciliği, gül yağı üretimi, gül suyu üretimi, gülün tarihi, gül ürünleri sergisi, gül kozmetiği, gül lokumu, gül reçeli), Lavanta Bahçeleri (Isparta\'nın Kuyucak köyü, lavanta bahçeleri, haziran-temmuz aylarında lavanta hasadı, lavanta yağı, lavanta suyu, lavanta kozmetiği, lavanta bahçeleri gezisi, lavanta fotoğrafçılığı, lavanta kokusu, lavanta bahçelerinde yürüyüş, Kuyucak Lavanta Bahçeleri), Eğirdir Gölü (Isparta\'nın en büyük gölü, Türkiye\'nin 4. büyük gölü, doğal güzellik, yüzme, piknik, kamp, balık tutma, sandal gezisi, yürüyüş, kuş gözlem, Eğirdir Gölü manzarası, Eğirdir ilçesi, göl kenarında yürüyüş yolu, çay bahçeleri, restoranlar), Eğirdir ilçesi (Eğirdir Kalesı, Eğirdir Evleri (tarihi taş evler, restore edilmiş konaklar), Eğirdir Müzesi, Eğirdir Adası (Can Ada, Yeşil Ada), Eğirdir Gölü\'nde adalar, Eğirdir\'in çarşısı, Eğirdir\'in el sanatları), Davraz Dağı (Davraz Kayak Merkezi, kış sporları, kayak, doğa yürüyüşleri, yaylalar, manzara, Davraz Dağı eteklerinde yürüyüş), Kovada Gölü Milli Parkı (Eğirdir Gölü\'nün güneyinde, doğal güzellik, yürüyüş yolları, piknik alanı, kamp, kuş gözlem, doğa fotoğrafçılığı), Kovada Kanyonu (Kovada Gölü\'nden başlar, doğa yürüyüşleri, vadi, şelale, kamp), Yılanlı Kilise (Eğirdir ilçesinde, tarihi kilise, kaya oyma, freskler), Kızıl Kilise (tarihi kilise, freskler), Isparta Müzesi (arkeolojik ve etnografik eserler, gül ürünleri sergisi, halı sergisi), Isparta Kalesi (şehir merkezinde, tarihi kale kalıntıları, manzara), Isparta Ulu Cami (tarihi cami), Kutlu Cami, Bedesten (tarihi bedesten, kapalı çarşı), Halıcılar Çarşısı (Isparta halıları, el dokuması halılar, kilimler, yöresel el sanatları), Isparta Halıları (dünyaca ünlü, Isparta halısı, el dokuması, doğal boyalar, yün, ipek, motifler, halıcılık atölyeleri), Yalvaç ilçesi (Yalvaç ilçesi, Antiokheia (Pisidia Antiokheiası) Antik Kenti (Pisidia Antiokheia, Roma dönemi, tiyatro, hamam, su kemerleri, kaya mezarları, sütunlu cadde, agora, mozaikler, kazı alanı, müze), Yalvaç Müzesi (arkeolojik eserler, mozaikler, heykeller), Yalvaç Evleri (tarihi taş evler), Yalvaç\'ın yaylaları), Şarkikaraağaç ilçesi (Şarkikaraağaç ilçesi, Beyşehir Gölü kenarı, Beyşehir Gölü Milli Parkı, Şarkikaraağaç\'ın elması, Şarkikaraağaç\'ın yaylaları), Gelendost ilçesi (Gelendost ilçesi, Eğirdir Gölü kenarı, Gelendost\'un elması), Senirkent ilçesi (Senirkent ilçesi, Senirkent\'in elması, yaylalar), Uluborlu ilçesi (Uluborlu ilçesi, Uluborlu Kalesi, Uluborlu\'nun yaylaları), Keçiborlu ilçesi (Keçiborlu ilçesi, Keçiborlu\'nun yaylaları), Atabey ilçesi (Atabey ilçesi, Atabey\'in yaylaları), Gönen ilçesi (Gönen ilçesi, Gönen Kaplıcaları, termal su), Aksu ilçesi (Aksu ilçesi, Aksu\'nun yaylaları), Yenişarbademli ilçesi (Yenişarbademli ilçesi, yaylalar), Isparta\'nın yaylaları (Sultan Dağları Yaylaları, Davraz Yaylası, Barla Yaylası, Gelincik Yaylası, doğa yürüyüşleri, yayla şenlikleri), Isparta\'nın mesire alanları (Güneykent Parkı, Gül Parkı, Atatürk Parkı, Millet Bahçesi), Isparta\'nın elma bahçeleri (Isparta elması, elma hasadı eylül-ekim aylarında, elma toplama, taze elma yeme, elma bahçelerinde gezinti), Isparta\'nın gül bahçeleri (gül toplama mayıs sonu haziran başı, gül yağı üretimi izleme, gül suyu üretimi izleme, gül bahçeleri gezisi), Kuyucak Lavanta Bahçeleri\'nde lavanta hasadı izleme (haziran-temmuz aylarında), Eğirdir Gölü\'nde yüzme ve göl manzarası, Davraz Dağı\'nda kayak (kış aylarında), Pisidia Antiokheia Antik Kenti\'ni gezme, Isparta Halıları alışverişi, Gül Müzesi ziyareti mutlaka yapılmalıdır.', 'Isparta mutfağı, Akdeniz ve Göller Yöresi mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Isparta gülü\" (gül yağı, gül suyu, gül reçeli, gül lokumu, gül şekeri, gül şerbeti, gül sirkesi, gül kozmetiği) gelir. \"Isparta köftesi\", \"Isparta tava\", \"etli ekmek\", \"kavurma\", \"kuzu tandır\", \"güveç\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"otlu börek\", \"pide\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"tava ciğer\", \"içli köfte\", \"mercimek köftesi\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"keşli çorba\", \"yufka ekmeği\", \"Isparta usulü etli ekmek\", \"Isparta usulü içli köfte\", \"Isparta peyniri\", \"Isparta yoğurdu\", \"Isparta balı\", \"Isparta elması\" yöresel lezzetlerdir. Tatlı olarak \"Isparta baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Isparta lokumu\", \"gül lokumu\", \"gül reçeli\", \"gül şekeri\", \"gül şerbeti\", \"gül tatlısı\", \"güllü aşure\", \"güllü sütlaç\", \"güllü dondurma\", \"güllü baklava\", \"güllü kadayıf\", \"elma tatlısı\", \"elma reçeli\", \"elma sirkesi\" meşhurdur. Isparta\'nın \"gülü\" (dünyaca ünlü, Isparta gülü, Rosa Damascena), \"gül yağı\", \"gül suyu\", \"gül kozmetiği\", \"gül lokumu\", \"gül reçeli\", \"gül şekeri\", \"gül sirkesi\", \"gül kolonyası\", \"gül sabunu\", \"gül kremi\", \"Isparta elması\" (Starking, Golden, Amasya, Isparta elması, Türkiye\'nin en kaliteli elmaları), \"Isparta lavantası\" (lavanta yağı, lavanta suyu, lavanta kozmetiği, lavanta bahçeleri), \"Isparta balı\", \"Isparta peyniri\" (tulum peyniri, küp peyniri), \"Isparta yoğurdu\", \"Isparta cevizi\", \"Isparta üzümü\", \"Isparta dutu\", \"Isparta kestanesi\", \"Isparta tarhanası\", \"kurutulmuş sebzeleri\", \"tereyağı\", \"çökeleği\" de ünlüdür.', 'Isparta\'da birçok festival düzenlenmektedir. En önemlilerinden biri Uluslararası Isparta Gül Festivali (mayıs sonu-haziran başı, Isparta merkez, gül hasadı, gül toplama yarışmaları, gül yağı üretimi gösterileri, gül ürünleri sergisi, gül lokumu tadımı, gül reçeli tadımı, gül şerbeti tadımı, konserler, halk oyunları, panayır). Uluslararası Isparta Lavanta Festivali (temmuz ayında, Kuyucak Lavanta Bahçeleri\'nde lavanta hasadı, lavanta yağı üretimi gösterileri, lavanta ürünleri sergisi, konserler, doğa yürüyüşleri). Uluslararası Isparta Elma Festivali (ekim ayında, Isparta merkez, elma hasadı, elma yarışmaları, elma tadımı, elmalı ürünler sergisi, konserler, yöresel lezzetler). Uluslararası Eğirdir Gölü Kültür ve Doğa Festivali (ağustos ayında, Eğirdir ilçesinde, Eğirdir Gölü\'nde yüzme yarışları, doğa yürüyüşleri, konserler, halk oyunları, yöresel lezzetler). Uluslararası Yalvaç Pisidia Antiokheia Kültür ve Sanat Festivali (eylül ayında, Yalvaç ilçesinde, Pisidia Antiokheia Antik Kenti\'nde konserler, tiyatro gösterileri, tarihi canlandırmalar). Davraz Dağı Kış Sporları ve Kayak Festivali (şubat ayında, Davraz Kayak Merkezi\'nde kayak yarışmaları, konserler). Ayrıca Isparta\'da düzenlenen \"Eğirdir Gölü Yüzme Maratonu\", \"Isparta Bisiklet Turu\" ve \"Davraz Dağı Doğa Yürüyüşleri\" de ilgi çeker.', 'Isparta\'yı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 18-30°C arasındadır, gül bahçeleri mayıs-haziran aylarında çiçek açar (gül hasadı mayıs sonu haziran başı), lavanta bahçeleri haziran-temmuz aylarında çiçek açar, doğa yürüyüşleri, göller ve yaylalar için idealdir. Sonbahar (eylül-ekim) da güzeldir, elma hasadı eylül-ekim aylarında yapılır. Kışlar soğuk ve karlıdır, sıcaklık genelde -5 ile 5°C arasındadır, zaman zaman kar yağışı görülür, kış aylarında Davraz Dağı Kayak Merkezi için idealdir. Isparta\'yı ziyaret etmek için en uygun zaman nisan-mayıs (gül için), haziran-temmuz (lavanta için) ve eylül-ekim (elma için) aylarıdır.', 'Isparta\'ya hava yoluyla gelmek için Isparta Süleyman Demirel Havalimanı (ISE) kullanılır. Havalimanı şehir merkezine yaklaşık 20 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşım sağlanır. Isparta\'ya şehirlerarası otobüs terminali (Isparta Otogarı) şehir merkezinin dışında olup belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır (Ankara, İstanbul, İzmir, Antalya, Burdur, Denizli, Konya, Afyonkarahisar, Kütahya, Eskişehir, Bursa, Adana, Mersin, Gaziantep, Diyarbakır). Isparta, Antalya-Burdur-Isparta karayolu üzerindedir, özel araçla ulaşım kolaydır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Burdur veya Afyonkarahisar\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Eğirdir, Yalvaç, Şarkikaraağaç, Gelendost, Senirkent, Uluborlu, Keçiborlu, Gönen, Atabey, Aksu, Yenişarbademli gibi ilçelere minibüslerle rahat ulaşım vardır. Gül Bahçeleri, Lavanta Bahçeleri, Eğirdir Gölü, Davraz Dağı, Kovada Gölü Milli Parkı, Pisidia Antiokheia Antik Kenti, Isparta Müzesi, Yalvaç Müzesi, Gül Müzesi, halıcılar çarşısı, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Isparta, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Hamitoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Pisidya bölgesinin önemli merkezlerinden biri olan Isparta, Roma döneminde \"Baris\" adıyla anılmıştır. Osmanlı döneminde Isparta Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanmıştır. Isparta, gülü (Isparta gülü, gül yağı, gül suyu), elması, lavantası, halıcılığı, termal kaynakları ve gölleriyle öne çıkan bir Akdeniz ilidir. Türkiye\'nin gül ve lavanta üretim merkezidir.', 'Isparta', '2026-04-08 23:20:51'),
(40, 'İstanbul', 'Marmara', 'istanbul.jpg', 'Tarihi ve kültürel zenginlikleriyle Türkiyenin incisi.', 'İstanbul\'un simgesi, 537 yılında inşa edilen ve Bizans ile Osmanlı\'nın izlerini taşıyan **Ayasofya** ile 6 minareli **Sultanahmet Camii\'dir (Mavi Cami)**. Bu iki dev eser, tarihi yarımadanın kalbi Sultanahmet Meydanı\'nda yan yana durur. Osmanlı\'nın 400 yıllık ana sarayı **Topkapı Sarayı**, kutsal emanetleri ve mücevher bölümüyle mutlaka görülmelidir. Bizans dönemine ait **Yerebatan Sarnıcı** ve dünyanın en eski kapalı çarşılarından **Kapalıçarşı** (1461) tarihi atmosferleriyle etkileyicidir. Boğazın iki yakasını birleştiren **Boğaziçi Köprüsü**, **Rumeli Hisarı**, **Galata Kulesi**, **Kız Kulesi** ve **İstiklal Caddesi** şehrin diğer simgeleridir. Adalar (Büyükada, Heybeliada), Balat\'ın renkli evleri, Pierre Loti Tepesi, Çamlıca Tepesi ve boğazın kıyı semtleri (Bebek, Ortaköy, Arnavutköy, Kuzguncuk) da İstanbul\'un vazgeçilmez duraklarıdır.', 'İstanbul mutfağı, Osmanlı saray mutfağının mirasçısıdır. Mutlaka denenmesi gerekenlerin başında Eminönü\'nde \"balık ekmek\", Ortaköy\'de \"kumpir\", Beyoğlu\'nda \"midye dolma\" ve \"İskender kebap\" gelir. Sokak lezzetlerinden simit, kestane kebap, mısır, ıslak hamburger ve tavuklu pilav ünlüdür. Restoranlarda \"beyti kebabı\", \"döner\", \"lahmacun\", \"pide\", \"içli köfte\", \"mercimek köftesi\", \"yaprak sarma\", \"zeytinyağlılar\" ve \"meze çeşitleri\" yaygındır. Tatlı olarak \"baklava\", \"kadayıf\", \"künefe\", \"sütlaç\", \"kazandibi\", \"güllaç\", \"tavuk göğsü\", \"aşure\", \"lokma\" ve \"dondurma\" öne çıkar. İstanbul\'a özgü \"Vefa Bozası\", \"sahlep\", \"Türk kahvesi\" ve \"çay\" da mutlaka tadılmalıdır.', 'İstanbul\'da yıl boyunca sayısız festival düzenlenir. En önemlileri Uluslararası İstanbul Müzik Festivali (haziran), İstanbul Film Festivali (nisan), İstanbul Tiyatro Festivali (ekim-kasım) ve İstanbul Caz Festivali (temmuz)\'dir. İstanbul Bienali (eylül-kasım, iki yılda bir) güncel sanatın önemli buluşma noktasıdır. İstanbul Lale Festivali (nisan) ve İstanbul Boğazı Kıtalararası Yüzme Yarışı (temmuz) da ilgi çeker.', 'İstanbul\'u ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılıman, sıcaklık 15-25°C arasındadır; tarihi yarımadayı, boğazı ve adaları gezmek için idealdir. Yaz aylarında sıcaklık 30-35°C\'ye çıkar ve nem yüksektir, ancak şehir en hareketli dönemini yaşar. Kışlar serin ve yağışlıdır, zaman zaman kar yağışı görülür. İstanbul yılın her mevsimi ziyaret edilebilir, ancak bahar ve sonbahar en rahat dönemlerdir.', 'İstanbul\'a iki havalimanı hizmet verir: İstanbul Havalimanı (Avrupa) ve Sabiha Gökçen Havalimanı (Anadolu). Şehir içi ulaşımda metro, metrobüs, tramvay, füniküler, teleferik, şehir hatları vapurları, deniz otobüsleri (İDO, BUDO) ve otobüsler kullanılır. Trafik yoğun olduğu için toplu taşıma önerilir. İstanbul\'dan İzmit, Bursa, Yalova, Adapazarı gibi yakın illere feribot ve hızlı otobüs seferleri vardır.\r\n', 'İstanbul, dünyanın en eski ve en önemli şehirlerinden biridir. MÖ 660 yılında Megaralılar tarafından \"Bizantion\" adıyla kurulmuştur. MÖ 196\'da Roma İmparatorluğu egemenliğine giren şehir, MS 330 yılında İmparator Konstantin tarafından başkent yapılmış ve \"Konstantinopolis\" adını almıştır. Bizans İmparatorluğu\'nun bin yılı aşkın başkenti olan İstanbul, Ayasofya, Hipodrom ve Theodosius Surları gibi devasa yapılarla donatılmıştır. 1204 yılında IV. Haçlı Seferi sırasında Latinler tarafından yağmalanan şehir, 1261\'de Bizans tarafından geri alınmıştır. 29 Mayıs 1453\'te Fatih Sultan Mehmet tarafından fethedilerek Osmanlı İmparatorluğu\'nun başkenti yapılmıştır. Osmanlı döneminde Topkapı Sarayı, Süleymaniye Camii, Kapalıçarşı gibi eserler kazanan İstanbul, üç dinin bir arada yaşadığı kozmopolit bir merkez haline gelmiştir. 1923\'te Cumhuriyet\'in ilanıyla başkent Ankara\'ya taşınmış olsa da İstanbul, Türkiye\'nin ekonomik, kültürel ve tarihi başkenti olmaya devam etmektedir. Günümüzde 15 milyonu aşkın nüfusuyla Avrupa\'nın en büyük metropollerinden biridir.', 'İstanbul', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(41, 'İzmir', 'Ege', 'izmir.jpg', 'Egenin incisi.', 'İzmir denince akla gelen ilk şeyler: Saat Kulesi (İzmir\'in simgesi, Konak Meydanı\'nda, 1901 yılında yapılmış, Osmanlı dönemi, saat kulesi, manzara, etrafı güvercinler), Konak Meydanı (İzmir\'in kalbi, Saat Kulesi, Konak Camii (Yalı Camii, 18. yüzyıl), Kemeraltı Çarşısı girişi, deniz kenarı, vapur iskelesi), Kemeraltı Çarşısı (tarihi çarşı, 17. yüzyıldan kalma, dar sokaklar, hanlar, bedestenler, dükkanlar, kuyumcular, bakırcılar, aktarlar, tekstil, deri, halı, kilim, antika, baharat, kuruyemiş, lokum, tatlı, kahve, Kızlarağası Hanı (18. yüzyıl), Hisarönü Camii, Başdurak Camii, Şadırvanlı Han, Çakaloğlu Han, Gümrük Han, Hacı Beşir Ağa Han, Kervansaray, Kemeraltı\'nda tarihi restoranlar, kafeler, kahvehaneler, kuyumcular çarşısı, bakırcılar çarşısı, kunduracılar çarşısı, saraçlar çarşısı, Kemeraltı\'nın dar sokaklarında yürüyüş, alışveriş), Kızlarağası Hanı (Kemeraltı Çarşısı içinde, 1744 yılında yapılmış, Osmanlı dönemi kervansaray, avlusu, dükkanlar, kafeler, restoranlar, hanın ortasında çeşme), Agora (Smyrna Agorası, İzmir\'in antik dönem çarşısı, Roma dönemi, sütunlu galeriler, kemerler, tonozlar, heykeller, yazıtlar, ticaret merkezi, kazı alanı, müze), Kadifekale (Pagos Dağı, İzmir Kalesi, Büyük İskender dönemi, Helenistik dönem, Roma dönemi, Bizans dönemi, Osmanlı dönemi, surlar, burçlar, manzara (İzmir Körfezi, şehir manzarası)), Asansör (Tarihi Asansör, Karataş semtinde, 1907 yılında yapılmış, Fransız mimar, yukarı Karataş ile aşağı Karataş arasında ulaşım, asansör çıkışında restoran, kafe, manzara (İzmir Körfezi, saat kulesi, Kemeraltı, Kadifekale)), Hisar Camii (Kemeraltı Çarşısı içinde, 1598 yılında yapılmış, Osmanlı dönemi, minaresi, avlusu, çinileri), Konak Camii (Yalı Camii, 1755 yılında yapılmış, Konak Meydanı\'nda, deniz kenarında, sekizgen planlı, kubbeli, mavi çinileri, küçük cami), Şadırvanlı Han (Kemeraltı Çarşısı içinde, tarihi han, avlu, çeşme, dükkanlar), Kordon (Birinci Kordon, İzmir\'in deniz kenarı yürüyüş yolu, Alsancak ile Karataş arası, palmiye ağaçları, deniz manzarası, kafeler, restoranlar, oteller, balıkçılar, gün batımı, yürüyüş, bisiklet, paten), Alsancak (İzmir\'in en hareketli semtlerinden, Kordon boyu, Kıbrıs Şehitleri Caddesi (mağazalar, butikler, kafeler, restoranlar, barlar, meyhaneler, sanat galerileri), Alsancak Garı (tren istasyonu, Atatürk Evi Müzesi (Atatürk\'ün İzmir\'de kaldığı ev, iki katlı, müze)), Passaport (Pasaport İskelesi, Pasaport Feribot İskelesi, pasaport binaları, deniz manzarası, Kordon boyu başlangıcı), Cumhuriyet Meydanı (Atatürk Anıtı (1929), Atatürk Heykeli, çevresi resmi binalar, oteller, bankalar), Lozan Meydanı (Lozan Anıtı, hükümet binaları), Gündoğdu Meydanı (Kordon boyunda, miting alanı, konserler, etkinlikler), Alsancak Garı (tren istasyonu, İzmir\'in ilk tren istasyonu, 1858 yılında yapılmış, İzmir-Aydın demiryolu hattı), Basmane Garı (tren istasyonu, Basmane semtinde, İzmir\'e gelen trenlerin ana durağı), Basmane (Basmane semti, tarihi binalar, dar sokaklar, oteller, restoranlar, kafeler), Kemeraltı (Kemeraltı Çarşısı, tarihi çarşı, hanlar, camiler, restoranlar, kafeler, dükkanlar, dar sokaklar), Kültürpark (İzmir Kültürpark, 1936 yılında kurulmuş, fuar alanı, park, göller, yürüyüş yolları, çay bahçeleri, restoranlar, lunapark, konser alanı, sergi salonları, İzmir Enternasyonal Fuarı (İEF) her yıl ağustos-eylül aylarında), İzmir Enternasyonal Fuarı (İEF, her yıl ağustos-eylül aylarında Kültürpark\'ta düzenlenir, konserler, sergiler, panayır, yemek stantları, teknoloji, tarım, sanayi, otomotiv, fuar, İzmir\'in en büyük etkinliği), Karşıyaka (İzmir\'in karşı yakası, İzmir Körfezi\'nin kuzeyinde, Karşıyaka Meydanı, Karşıyaka İskelesi, Karşıyaka Çarşısı, Karşıyaka Kordon (deniz kenarı, yürüyüş yolu, manzara (Alsancak, Konak, Kadifekale), Karşıyaka Evleri (tarihi evler, restore edilmiş konaklar), Bostanlı (Bostanlı Sahili, Bostanlı Gün Batımı İzleme Terası, manzara, yürüyüş yolu, restoranlar, kafeler), Karşıyaka\'da balıkçılar, Karşıyaka\'da çarşı), Göztepe (Göztepe semti, Göztepe Sahili, Göztepe Parkı, Göztepe Tepesi (manzara)), Balçova (Balçova Kaplıcaları (termal su, şifalı su, Agamemnon Kaplıcaları, Roma döneminden beri kullanılan kaplıcalar, fizik tedavi, termal otel), İnciraltı (Balçova\'da, deniz kenarı, çay bahçeleri, restoranlar, park), Narlıdere (Narlıdere Sahili), Güzelbahçe (Güzelbahçe\'nin çiçekleri, yaylalar), Urla (Urla ilçesi, Urla\'nın şarap bağları (Üzüm üretimi, şarap evleri, şarap tadımı), Urla\'nın sanat sokakları (Urla Sanat Sokağı, atölyeler, galeriler), Urla\'nın tarihi evleri (Urla Evleri, restore edilmiş konaklar), Urla\'nın plajları (Urla Plajı, Demircili Plajı), Urla\'nın restoranları (deniz ürünleri, zeytinyağlılar, ot yemekleri), Urla\'nın doğası), Çeşme (Çeşme ilçesi, Çeşme Plajları (İlica Plajı (sıcak su kaynakları, kum), Altınkum Plajı, Pırlanta Plajı, Boyalık Plajı, Ayayorgi Plajı (Ayıorgi, Mavi Bayrak plaj), Dalyan Plajı (kum), Yalıçiftlik Plajı), Çeşme Kalesi (15. yüzyıl, Cenevizliler, Osmanlı, kale, müze, manzara), Alaçatı (Çeşme\'nin mahallesi, Alaçatı taş evleri, dar sokaklar, Alaçatı Rüzgar Değirmenleri, Alaçatı Plajı (kum, sörf, rüzgar sörfü, dünyaca ünlü rüzgar sörfü merkezi), Alaçatı Çarşısı (butikler, kafeler, restoranlar, meyhaneler), Alaçatı Otları (Alaçatı otu, Alaçatı enginarı), Alaçatı\'da yemek (Ege mutfağı, zeytinyağlılar, ot yemekleri), Alaçatı\'da gece hayatı (barlar, meyhaneler)), Ilıca (Çeşme\'de, Ilıca Plajı (sıcak su kaynakları, kum, sığ deniz, termal otel), Ilıca Kaplıcaları (termal su)), Şifne (Çeşme\'de, Şifne Plajı), Karaburun (Karaburun ilçesi, Karaburun Sahili, Karaburun Plajları (Ardıç Plajı, Mimoza Plajı, Kocakum Plajı, Büyük Plaj, Sarpıncık Plajı), Karaburun Doğası (Karaburun Yarımadası, yürüyüş, doğa), Karaburun Köyleri), Foça (Foça ilçesi, Eski Foça (tarihi Foça, Foça Kalesı (Ceneviz Kalesi), Foça Evleri (tarihi taş evler, restore edilmiş konaklar), Foça Plajları (Yenifoça Plajı, Sazlıca Plajı, Mersinli Plajı, Değirmenburnu Plajı, Taşlıburun Plajı), Foça\'da balıkçılar (Foça balığı, deniz ürünleri), Foça\'da yürüyüş, Foça\'da manastır kalıntıları), Seferihisar (Seferihisar ilçesi, Sığacık (Sığacık Kalesi, Sığacık Çarşısı, Sığacık Limanı, Sığacık Plajları (Akarca Plajı, Sığacık Plajı), Sığacık\'ta balıkçılar, Sığacık\'ta restoranlar), Seferihisar\'ın mandalinası (Seferihisar mandalini, Seferihisar üzümü), Teos Antik Kenti (Seferihisar\'da, antik kent, tiyatro, agora, tapınak, kazı alanı), Seferihisar yaylaları), Selçuk (Selçuk ilçesi, Efes Antik Kenti (Efes, UNESCO Dünya Mirası Listesi, Roma dönemi, Celsus Kütüphanesi, Büyük Tiyatro (25.000 kişilik), Artemis Tapınağı (Dünyanın Yedi Harikası\'ndan biri), Meryem Ana Evi (Meryem Ana\'nın son günlerini geçirdiğine inanılan ev, Vatikan tarafından hac yeri ilan edilmiş), St. Jean Kilisesi (Aziz Yuhanna, Havari Yuhanna), Selçuk Kalesi (Ayasuluk Tepesi), İsa Bey Camii (14. yüzyıl, Selçuklu), Efes Müzesi (Selçuk\'ta, Efes kazıları eserleri, heykeller, mozaikler, Artemis heykeli), Şirince (Selçuk\'a bağlı köy, Şirince Evleri (tarihi Rum evleri, restore edilmiş taş evler), Şirince Dar Sokakları, Şirince\'nin Şarabı (Şirince şarabı, meyve şarapları), Şirince\'nin Zeytinyağı, Şirince\'nin Pekmezi, Şirince\'nin Doğası, Şirince\'nin Manzarası, Şirince\'de alışveriş, Şirince\'de kahvaltı), Pamucak Plajı (Selçuk\'ta, kum plaj, deniz), Kuşadası (Kuşadası ilçesi (İzmir değil, Aydın, ancak yakın), Kuşadası Plajları, Kuşadası Marina, Kuşadası Limanı, Kuşadası Kale İçi, Kuşadası Çarşısı), Bergama (Bergama ilçesi, Bergama Antik Kenti (Pergamon, UNESCO Dünya Mirası Listesi, Akropolis (Zeus Sunağı (Bergama Sunağı), Kütüphane (200.000 cilt), Tiyatro (10.000 kişilik), Tapınaklar, Saraylar, Surlar), Asklepion (Tıp merkezi, antik hastane, Galenos\'un yetiştiği yer), Kızıl Avlu (Serapis Tapınağı, Mısır tanrılarına adanmış), Bergama Müzesi (Pergamon eserleri, heykeller, mozaikler, Bergama Sunağı\'nın parçaları), Bergama Evleri (tarihi Bergama evleri), Bergama\'nın ipeği (Bergama ipeği, Bergama kilimi, Bergama halısı), Bergama\'nın doğası), Dikili (Dikili ilçesi, Dikili Plajları (Bademli Plajı, Kabakum Plajı, Denizköy Plajı, Dikili Plajı), Dikili Kalesı, Dikili Limanı, Dikili Çarşısı, Dikili\'nin Zeytini), Kınık (Kınık ilçesi, Kınık\'ın yaylaları), Bayındır (Bayındır ilçesi, Bayındır\'ın elması, Bayındır\'ın yaylaları), Ödemiş (Ödemiş ilçesi, Ödemiş Kalesi, Ödemiş Evleri (tarihi evler), Ödemiş\'in peyniri (Tulum peyniri), Ödemiş\'in cevizi, Ödemiş\'in elması, Ödemiş\'in yaylaları (Birgi Yaylası, Bozdağlar (Bozdağ Kayak Merkezi)), Birgi (Ödemiş\'te, tarihi Birgi Evleri (Çakıroğlu Konağı, restore edilmiş konak), Birgi Ulu Cami (Aydınoğulları dönemi), Birgi Çarşısı, Birgi\'nin dar sokakları), Tire (Tire ilçesi, Tire Kalesi, Tire Evleri (tarihi evler), Tire\'nin köftesi (Tire köftesi), Tire\'nin peyniri, Tire\'nin balı, Tire\'nin pidesi (Tire pidesi), Tire\'nin çarşısı (Tire Çarşısı, Tire Pazarı), Tire\'nin doğası), Beydağ (Beydağ ilçesi, Beydağ\'ın yaylaları), Kemalpaşa (Kemalpaşa ilçesi, Kemalpaşa\'nın kirazı (Kemalpaşa kirazı), Kemalpaşa\'nın yaylaları), Torbalı (Torbalı ilçesi, Torbalı\'nın inciri, Torbalı\'nın pamuğu, Torbalı\'nın yaylaları), Menderes (Menderes ilçesi, Menderes\'in inciri (Menderes inciri), Menderes\'in pamuğu, Menderes\'in yaylaları), Gaziemir (Gaziemir ilçesi, Gaziemir\'in çarşısı), Buca (Buca ilçesi, Buca\'nın tarihi evleri, Buca\'nın meyhaneleri, Buca\'nın restoranları), Bornova (Bornova ilçesi, Bornova\'nın lokması (Bornova lokması, şerbetli tatlı), Bornova\'nın çarşısı, Bornova\'nın meyhaneleri), Çiğli (Çiğli ilçesi, Çiğli\'nin sahil şeridi), Menemen (Menemen ilçesi, Menemen\'in pidesi (Menemen pidesi), Menemen\'in yaylaları), Aliağa (Aliağa ilçesi, Aliağa\'nın sahil şeridi, Aliağa\'nın yaylaları), Bergama, Dikili, Foça, Karaburun, Urla, Çeşme, Seferihisar, Selçuk, Ödemiş, Tire, Kemalpaşa, Torbalı, Menderes, Bayındır, Kınık, Beydağ, Ödemiş, Tire, Kemalpaşa, Torbalı, Menderes, Bayındır, Kınık, Beydağ ilçeleri, İzmir\'in tüm ilçeleri, İzmir\'in tarihi yerleri, İzmir\'in doğal güzellikleri, İzmir\'in plajları, İzmir\'in yaylaları, İzmir\'in kaplıcaları, İzmir\'in şarap bağları, İzmir\'in el sanatları, İzmir\'in bakır işlemeciliği, İzmir\'in halıcılığı, İzmir\'in kilim dokumacılığı, İzmir\'in yemeniciliği, İzmir\'in keçeciliği, İzmir\'in taş işlemeciliği, İzmir\'in kuyumculuğu, İzmir\'in seramikçiliği, İzmir\'in çömlekçiliği, İzmir\'in zeytinciliği, İzmir\'in bağcılığı, İzmir\'in incir bahçeleri, İzmir\'in üzüm bağları, İzmir\'in pamuk tarlaları, İzmir\'in tütün tarlaları, İzmir\'in kiraz bahçeleri, İzmir\'in şeftali bahçeleri, İzmir\'in elma bahçeleri, İzmir\'in armut bahçeleri, İzmir\'in ayva bahçeleri, İzmir\'in nar bahçeleri, İzmir\'in portakal bahçeleri, İzmir\'in mandalin bahçeleri, İzmir\'in limon bahçeleri, İzmir\'in greyfurt bahçeleri, İzmir\'in badem bahçeleri, İzmir\'in ceviz bahçeleri, İzmir\'in fındık bahçeleri, İzmir\'in kestane bahçeleri, İzmir\'in enginar tarlaları, İzmir\'in börülce tarlaları, İzmir\'in bakla tarlaları, İzmir\'in bezelye tarlaları, İzmir\'in fasulye tarlaları, İzmir\'in patates tarlaları, İzmir\'in domates tarlaları, İzmir\'in biber tarlaları, İzmir\'in patlıcan tarlaları, İzmir\'in kabak tarlaları, İzmir\'in salatalık tarlaları, İzmir\'in karpuz tarlaları, İzmir\'in kavun tarlaları, İzmir\'in otları, İzmir\'in denizi, İzmir\'in güneşi, İzmir\'in kordonu, İzmir\'in saati, İzmir\'in asansörü, İzmir\'in agorası, İzmir\'in kaleleri, İzmir\'in camileri, İzmir\'in kiliseleri, İzmir\'in sinagogları, İzmir\'in hanları, İzmir\'in bedestenleri, İzmir\'in çarşıları, İzmir\'in hamamları, İzmir\'in müzeleri, İzmir\'in otelleri, İzmir\'in restoranları, İzmir\'in kafeleri, İzmir\'in meyhaneleri, İzmir\'in barları, İzmir\'in gece hayatı, İzmir\'in fuarı, İzmir\'in festivalleri, İzmir\'in konserleri, İzmir\'in tiyatroları, İzmir\'in sinemaları, İzmir\'in sanat galerileri, İzmir\'in kütüphaneleri, İzmir\'in üniversiteleri (Ege Üniversitesi, İzmir Yüksek Teknoloji Enstitüsü, Dokuz Eylül Üniversitesi, İzmir Demokrasi Üniversitesi, İzmir Kâtip Çelebi Üniversitesi, İzmir Ekonomi Üniversitesi, Yaşar Üniversitesi), İzmir\'in hastaneleri, İzmir\'in alışveriş merkezleri (İzmir Optimum, Mavibahçe, Hilltown, Agora AVM, Forum Bornova, Park Bornova, Point Bornova, Ege Park, Palladium, Carrefour, Real, Kipa), İzmir\'in sağlık turizmi, İzmir\'in termal turizmi, İzmir\'in kış sporları (Bozdağ Kayak Merkezi), İzmir\'in yaz sporları (rüzgar sörfü, yelken, yüzme, plaj voleybolu), İzmir\'in her şeyi, güzel İzmir, İzmir\'in güzellikleri mutlaka görülmelidir.', 'İzmir mutfağı, Ege mutfağının en zengin ve en sağlıklı örneklerini taşır. Zeytinyağlılar, ot yemekleri ve deniz ürünleri ağırlıklıdır. Mutlaka denenmesi gerekenlerin başında \"İzmir köftesi\" (patatesli, biberli, domates soslu, fırın tepsisinde) gelir. \"Boyoz\" (İzmir\'e özgü, susamlı, yufka kat kat, fırınlanmış hamur işi, kahvaltıda veya çay saatinde), \"gevrek\" (İzmir simidi, susamlı, çıtır), \"kumru\" (İzmir\'e özgü sandviç, özel ekmek arası sucuk, kaşar peyniri, domates, biber, turşu), \"lokma\" (şerbetli hamur tatlısı, özellikle Bornova\'da), \"söğüş\" (kelle, paça, dil, işkembe, tuz, karabiber, maydanoz, sumak, servis), \"tulum peyniri\" (İzmir tulumu, Ege tulumu), \"çiğ köfte\" (etsiz, bulgurlu, baharatlı, İzmir usulü), \"midye dolma\" (sokak lezzeti, midye içi pirinçli, soğanlı, baharatlı, limonlu), \"midye tava\", \"hamsi tava\", \"hamsi buğulama\", \"çinekop\", \"levrek\", \"çipura\", \"palamut\", \"lüfer\", \"kalkan\", \"kalamar\", \"ahtapot\", \"karides\", \"istakoz\", \"yengeç\", \"meze çeşitleri\" (humus, haydari, acılı ezme, şakşuka, fava, tarama, lakerda, zeytinyağlı enginar, zeytinyağlı yaprak sarma, zeytinyağlı taze fasulye, zeytinyağlı kereviz, zeytinyağlı pırasa, zeytinyağlı enginar), \"ot kavurması\" (arapsaçı, ebegümeci, ısırgan, radika, hindiba, tarla sarmaşığı, deniz börülcesi, çıtlık, sirken, gelincik, yabani pazı, labada, kuzukulağı, zeytinyağlı, yumurtalı), \"şevketi bostan yemeği\" (Ege otu, zeytinyağlı, yumurtalı), \"cacık\", \"haydari\", \"antep fıstıklı ezme\", \"atom\", \"şakşuka\", \"babağannuş\", \"humus\", \"muhammara\", \"kısır\", \"acılı ezme\", \"sarma\", \"dolma\", \"yayla çorbası\", \"mercimek çorbası\", \"tarhana çorbası\", \"İzmir usulü enginar\", \"zeytinyağlı taze fasulye\", \"zeytinyağlı pırasa\", \"zeytinyağlı kereviz\", \"zeytinyağlı patlıcan\", \"zeytinyağlı kabak\", \"zeytinyağlı bamya\", \"zeytinyağlı bakla\", \"zeytinyağlı bezelye\", \"zeytinyağlı barbunya\", \"zeytinyağlı türlü\", \"zeytinyağlı sarma\", \"zeytinyağlı dolma\", \"İzmir usulü kuzu tandır\", \"güveç\", \"keşkek\", \"etli ekmek\", \"pide\", \"lahmacun\", \"katmer\", \"gözleme\", \"İzmir peyniri\", \"İzmir yoğurdu\", \"İzmir balı\" yöresel lezzetlerdir. Tatlı olarak \"İzmir baklavası\", \"kadayıf\", \"künefe\", \"şöbiyet\", \"burma kadayıf\", \"dilber dudağı\", \"hanımgöbeği\", \"tulumba tatlısı\", \"kemalpaşa tatlısı\", \"şekerpare\", \"kalburabastı\", \"revani\", \"irmik helvası\", \"un helvası\", \"kabak tatlısı\", \"incir tatlısı\", \"ayva tatlısı\", \"cevizli sucuk\", \"pestil\", \"köme\", \"dondurma\", \"lokma\", \"boyoz (tatlı değil tuzlu)\", \"gevrek\", \"kumru\", \"sütlaç\", \"güllaç\", \"aşure\", \"helva\", \"pişmaniye\", \"akide şekeri\", \"İzmir lokumu\", \"İzmir macunu\" meşhurdur. İzmir\'in \"boyozu\", \"gevreği\", \"kumrusu\", \"tulum peyniri\", \"zeytini\", \"zeytinyağı\", \"inciri\" (Sarıbey inciri), \"üzümü\" (Çeşme üzümü, Menderes üzümü), \"tütünü\" (Ege tütünü), \"pamuğu\", \"enginarı\", \"narı\", \"portakalı\", \"mandalini\", \"limonu\", \"elması\", \"şeftalisi\", \"kayısısı\", \"karpuzu\", \"kavunu\", \"bademi\", \"cevizi\", \"balı\", \"tarhanası\", \"sirkesi\", \"pekmezi\", \"tahini\" de ünlüdür.', 'İzmir\'de birçok festival düzenlenmektedir. En önemlilerinden biri İzmir Enternasyonal Fuarı (İEF) (ağustos-eylül aylarında, Kültürpark\'ta, konserler, sergiler, panayır, yemek stantları, teknoloji, tarım, sanayi, otomotiv, fuar, İzmir\'in en büyük etkinliği). Uluslararası İzmir Festivali (haziran-temmuz aylarında, İKSV, klasik müzik, caz, dünya müziği, bale, tiyatro, Efes Antik Tiyatrosu, Çeşme Kalesi, Kadifekale, Agora, tarihi mekanlarda). Uluslararası İzmir Film Festivali (kasım ayında, sinema gösterimleri, yarışmalar, ödül töreni). Uluslararası Çeşme Rüzgar Sörfü Festivali (ağustos ayında, Alaçatı Plajı\'nda rüzgar sörfü yarışmaları, konserler). Uluslararası Foça Kültür ve Sanat Festivali (temmuz ayında, Foça\'da konserler, halk oyunları, deniz yarışları, yöresel lezzetler). Uluslararası Urla Şarap Festivali (eylül ayında, Urla\'da bağ bozumu, şarap tadımı, konserler). Uluslararası Bergama Kültür ve Sanat Festivali (ağustos ayında, Bergama\'da konserler, tiyatro gösterileri (Pergamon Antik Tiyatrosu), halk oyunları). Uluslararası Selçuk Efes Festivali (mayıs ayında, Efes Antik Tiyatrosu\'nda konserler, tarihi canlandırmalar). İzmir Caz Festivali (mart ayında). İzmir Kısa Film Festivali (yaz aylarında). Ayrıca İzmir\'de düzenlenen \"İzmir Maratonu\", \"İzmir Bisiklet Turu\" ve \"Çeşme Alaçatı Rüzgar Sörfü Yarışları\" da ilgi çeker.', 'İzmir\'i ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 18-28°C arasındadır, kordon boyunda yürüyüş, saat kulesi, agoralar, asansör, çeşmeler, tarihi yerler ve doğa için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 30-38°C\'ye ulaşabilir, nem oranı yüksektir, ancak İzmir\'in en hareketli dönemidir, deniz, plaj, festivaller, konserler, açık hava etkinlikleri için idealdir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 5-15°C arasındadır, zaman zaman kar yağışı görülmez (nadiren). İzmir\'i yılın her mevsimi ziyaret etmek mümkündür, ancak en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'İzmir\'e hava yoluyla gelmek için İzmir Adnan Menderes Havalimanı (ADB) kullanılır. Havalimanı şehir merkezine yaklaşık 18 km uzaklıkta olup havaş otobüsleri, belediye otobüsleri, İZBAN (banliyö treni), taksi ve özel araç kiralama ile ulaşım sağlanır. İzmir\'e şehirlerarası otobüs terminali (İzmir Otogarı) (Yeni Otogar, Pınarbaşı, Bornova) şehir merkezinin dışında olup metro, İZBAN, belediye otobüsleri ve taksi ile merkeze ulaşılır; birçok ilden direkt otobüs seferleri vardır. İzmir, İzmir-Ankara, İzmir-İstanbul, İzmir-İzmir çevre yolları ve otoyollar (İzmir-Çeşme Otoyolu, İzmir-Aydın Otoyolu, İzmir-Ankara Otoyolu) üzerindedir, özel araçla ulaşım kolaydır. İzmir\'de şehir içi ulaşım çok gelişmiştir: Metro (İzmir Metrosu, M1, M2, M3 hatları, Bornova, Konak, Karşıyaka, Balçova, Fahrettin Altay, Evka-3), İZBAN (banliyö treni, Aliağa-Menderes arası, Menemen, Çiğli, Karşıyaka, Alsancak, Basmane, Gaziemir, Adnan Menderes Havalimanı, Torbalı, Selçuk), Tramvay (Konak Tramvayı, Karşıyaka Tramvayı), Otobüs (ESHOT, belediye otobüsleri), Minibüs, Dolmuş, Taksi, İskele (Şehir Hatları Vapurları (Alsancak-Karşıyaka, Alsancak-Bostanlı, Konak-Karşıyaka, Konak-Bostanlı, Karşıyaka-Pasaport, Pasaport-Bostanlı, Üçkuyular-Bostanlı, Üçkuyular-Karşıyaka), İDO (Deniz otobüsü), BUDO (Bursa-İzmir deniz otobüsü)), Bisiklet (İZBİSİM), Elektrikli Scooter (Martı, Togg, Pal), Yürüyüş. İzmir\'de her ilçeye, her bölgeye ulaşım mümkündür. Konak, Karşıyaka, Alsancak, Bornova, Buca, Balçova, Gaziemir, Çiğli, Menemen, Bergama, Dikili, Foça, Karaburun, Urla, Çeşme, Seferihisar, Selçuk, Kuşadası (Aydın), Ödemiş, Tire, Kemalpaşa, Torbalı, Menderes, Bayındır, Kınık, Beydağ ilçelerine minibüslerle rahat ulaşım vardır. Efes Antik Kenti, Şirince, Çeşme, Alaçatı, Foça, Karaburun, Urla, Bergama, Kadifekale, Agora, Asansör, Saat Kulesi, Kemeraltı, Kültürpark, Kordon, Karşıyaka, Bostanlı, İnciraltı, Balçova Kaplıcaları, Bozdağ Kayak Merkezi, yaylalar, plajlar, şarap evleri gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'İzmir, tarihi boyunca birçok medeniyete ev sahipliği yapmış, yaklaşık 8.500 yıllık bir geçmişe sahiptir. Bölgedeki ilk yerleşimler Neolitik döneme kadar uzanır. Antik dönemde \"Smyrna\" olarak bilinen şehir, MÖ 3. binyılda Troya, MÖ 2. binyılda Hititler, MÖ 1. binyılda Frigler, Lidyalılar ve Perslerin egemenliği altında kalmıştır. MÖ 334 yılında Büyük İskender tarafından fethedilmiş ve İskender\'in komutanlarından Lysimakhos, şehri bugünkü Kadifekale (Pagos) eteklerine taşıyarak yeniden kurmuştur. Roma İmparatorluğu döneminde Smyrna, Asya Eyaleti\'nin en önemli şehirlerinden biri olmuş ve \"İzmir\'in ilk altın çağı\" yaşanmıştır. Roma döneminde agora, tiyatro, stadyum, hamamlar, su kemerleri gibi birçok eser inşa edilmiştir. Bizans döneminde şehir, Arap akınlarına ve depremlere maruz kalmış, ancak önemini korumuştur. 1076 yılında Selçukluların eline geçen İzmir, 1098\'de Bizans tarafından geri alınmış, 14. yüzyılda Cenevizliler, Aydınoğulları ve ardından Osmanlılar tarafından fethedilmiştir. 1402 yılında Timur\'un saldırısına uğrayan şehir büyük tahribat görmüştür. 15. yüzyıldan itibaren Osmanlı yönetiminde yeniden canlanan İzmir, özellikle 17. ve 18. yüzyıllarda Avrupalı tüccarların yerleşmesiyle uluslararası bir liman kenti haline gelmiştir. Levantenler (Fransız, İtalyan, İngiliz, Hollandalı tüccarlar) İzmir\'e yerleşmiş, şehirde konsolosluklar, kiliseler, okullar, hastaneler ve ticaret evleri açılmıştır. 19. yüzyılda demiryolunun gelmesiyle İzmir\'in hinterlandı (İç Batı Anadolu) tarım ürünleri (incir, üzüm, tütün, pamuk, zeytin) ihracatında patlama yaşanmıştır. 15 Mayıs 1919\'da Yunan işgaline uğrayan İzmir, 9 Eylül 1922\'de Mustafa Kemal Atatürk komutasındaki Türk ordusu tarafından kurtarılmıştır. Kurtuluş Savaşı\'nın sona erdiği şehir olan İzmir, Cumhuriyet döneminde Türkiye\'nin en önemli liman ve ticaret kenti olmuştur. 2005 yılında düzenlenen Akdeniz Oyunları ile uluslararası arenada adından söz ettiren İzmir, günümüzde Türkiye\'nin üçüncü büyük şehri ve Ege Bölgesi\'nin en önemli merkezidir. Tarihi dokusu, kordon boyu, saat kulesi, agorası, asansörü, çeşmeleri ve zengin mutfağıyla \"güzel İzmir\" olarak anılmaktadır.', 'İzmir', '2026-04-08 23:20:51'),
(42, 'Kahramanmaraş', 'Akdeniz', 'kahramanmaras.jpg', 'Dondurması ile ünlü.', 'Kahramanmaraş\'ın en ünlü simgesi hiç şüphesiz dondurmasıdır, ancak şehir tarihi yapılarıyla da dikkat çeker. Kahramanmaraş Kalesi, şehir merkezinde yükselen ve Roma, Bizans ve Osmanlı dönemlerinden izler taşıyan etkileyici bir yapıdır. Ulu Cami, Dulkadiroğlu Beyliği döneminden kalma taç kapısı ve taş işçiliğiyle görülmeye değerdir. Taş Medrese, Hatuniye Camii ve Eshab-ı Kehf (Yedi Uyuyanlar Mağarası) şehrin diğer önemli tarihi noktalarıdır. Şehrin kuzeyindeki Tekir Yaylası ve Bağrıbütün Yaylası doğa severler için kaçış noktasıdır. Ayrıca Kahramanmaraş, bakır işlemeciliği ve yemeni (el dokuması başörtüsü) ile de ünlüdür. Kapalı Çarşı ve Bakırcılar Çarşısı, bu el sanatlarını görmek ve alışveriş yapmak için ideal yerlerdir.', 'Kahramanmaraş denince akla gelen ilk lezzet dondurmadır. \"Maraş dondurması\" (sahlep, keçi sütü, şeker, orkide kökü, uzun kıvamlı, bıçakla kesilir, kaşıkla yenir, dünyaca ünlü) mutlaka tadılmalıdır. Yöresel yemeklerden \"Maraş tava\" (etli, nohutlu, bulgurlu), \"ekşili köfte\", \"içli köfte\" (oruk), \"kaymaklı köfte\", \"simit kebabı\", \"patlıcan kebabı\", \"ciğer kebabı\", \"katıklı ekmek\", \"tirit\", \"yaprak sarma\", \"dolma\", \"mercimek köftesi\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"Maraş peyniri\" (tulum), \"Maraş yoğurdu\", \"Maraş balı\", \"Maraş sucuğu\" ve \"Maraş pastırması\" da meşhurdur. Tatlı olarak \"dondurma\" dışında \"Maraş baklavası\", \"kadayıf\", \"un helvası\", \"pestil\", \"cevizli sucuk\" (köme) ve \"Maraş lokumu\" öne çıkar.', 'Kahramanmaraş\'ta en önemli etkinlik Uluslararası Kahramanmaraş Dondurma ve Kültür Festivali\'dir (ağustos ayında). Festivalde dondurma yapım gösterileri, konserler, halk oyunları ve yöresel lezzet tadımları yapılır. Ayrıca Uluslararası Tekir Yaylası Kültür ve Sanat Festivali (temmuz) ve Kahramanmaraş Kültür ve Sanat Festivali (eylül) düzenlenmektedir.', 'Kahramanmaraş\'ı ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılımandır, sıcaklık 15-28°C arasındadır. Yaz aylarında sıcaklık 38°C\'yi bulabilir, kışlar ise soğuk ve yağışlıdır. Kış aylarında yakın çevredeki kış sporları merkezleri (Tekir Yaylası) için de ziyaret yapılabilir.', 'Kahramanmaraş\'a hava yoluyla Kahramanmaraş Havalimanı (KCM) ile ulaşılır. Havalimanı şehir merkezine 5 km uzaklıktadır. Şehirlerarası otobüs terminali şehir merkezindedir ve birçok ilden direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Gaziantep veya Adana\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır.\r\n', 'Kahramanmaraş, tarihi boyunca Hititler, Asurlular, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Dulkadiroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Maraş\" adıyla anılan şehir, Hitit döneminde önemli bir merkez olan Gurgum Krallığı\'nın başkentidir. MÖ 12. yüzyılda Asur egemenliğine giren şehir, daha sonra Pers, Roma ve Bizans yönetiminde kalmıştır. 7. yüzyılda Emeviler tarafından fethedilen Maraş, İslam dünyasının önemli bir uç merkezi haline gelmiştir. 11. yüzyılda Selçukluların eline geçen şehir, 13. yüzyılda Dulkadiroğulları Beyliği\'nin başkenti olmuştur. 1515 yılında Osmanlı topraklarına katılan Kahramanmaraş, Osmanlı döneminde sancak statüsünde yönetilmiştir. Kurtuluş Savaşı\'nda Fransız işgaline karşı gösterdiği kahramanlık nedeniyle 1925 yılında TBMM tarafından \"Kahraman\" unvanı verilmiş ve şehrin adı \"Kahramanmaraş\" olmuştur. Günümüzde Kahramanmaraş, dondurması, bakır işlemeciliği, tekstili ve tarihi dokusuyla öne çıkan bir Akdeniz ilidir.', 'Kahramanmaraş', '2026-04-08 23:20:51'),
(43, 'Karabük', 'Karadeniz', 'karabuk.jpg', 'Safranbolu evleri ile ünlü.', 'Karabük denince akla gelen ilk yer, UNESCO Dünya Mirası Listesi\'ndeki **Safranbolu** ilçesidir. Safranbolu, 18. ve 19. yüzyıldan kalma geleneksel Türk evleri, dar taş sokakları, tarihi hamamları, camileri, çeşmeleri ve konaçlarıyla adeta bir açık hava müzesidir. **Cinci Hanı** ve **Cinci Hamamı** (17. yüzyıl), **Köprülü Mehmet Paşa Camii**, **Kazdağlıoğlu Camii** ve **Safranbolu Evleri** mutlaka görülmelidir. **Karabük Kalesi** (Bostancı Kalesi) şehir merkezinde manzarasıyla dikkat çeker. **Bulak Mağarası** (Mencilis Mağarası) ve **Derebucak Mağarası** doğa severler için ilgi çekicidir. **Hıdırlık Tepesi** ise Safranbolu\'nun kuşbakışı manzarasını izlemek için en iyi noktadır. Karabük, adını safran bitkisinden alan Safranbolu ile özdeşleşmiştir.', 'Karabük mutfağı, Batı Karadeniz mutfağının izlerini taşır. En meşhur lezzeti, ince yufka arasına peynir, kıyma veya patates konularak yapılan \"Safranbolu bükmesi\"dir. \"Karabük köftesi\", \"etli ekmek\", \"yaprak sarma\", \"dolma\", \"keşkek\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mıhlama\" (kuymak), \"sac böreği\" ve \"katmer\" yöresel yemeklerdendir. Tatlı olarak \"Safranbolu lokumu\", \"cevizli sucuk\", \"pestil\", \"köme\", \"un helvası\" ve \"kabak tatlısı\" meşhurdur. Safranbolu\'da \"safranlı pilav\" ve \"safranlı lokum\" da tadılmalıdır.', 'Karabük\'te en önemli etkinlik Uluslararası Safranbolu Kültür ve Sanat Festivali\'dir (haziran-temmuz). Festivalde Safranbolu evlerinde sergiler, konserler, halk oyunları, yöresel lezzet tadımları ve panayır düzenlenir. Ayrıca Safranbolu Evleri fotoğraf yarışması ve Safranbolu Safran Festivali (ekim) de ilgi çeker.', 'Karabük\'ü ziyaret etmek için en iyi zaman ilkbahar (nisan-mayıs) ve sonbahar (eylül-ekim) aylarıdır. Bu dönemde hava ılıman, sıcaklık 15-25°C arasındadır; Safranbolu\'nun tarihi sokaklarında yürümek için idealdir. Yaz aylarında sıcaklık 28-32°C\'ye çıkar, kışlar soğuk ve yağışlıdır. Kış aylarında Safranbolu\'nun karla kaplı görüntüsü ayrı bir güzellik sunar.', 'Karabük\'e en yakın havalimanı Zonguldak Havalimanı (Çaycuma, 90 km) veya Ankara Esenboğa Havalimanı (220 km) kullanılır. Karabük\'e şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Bursa, Zonguldak, Kastamonu, Çankırı gibi illere direkt otobüs seferleri vardır. Demiryolu ile Ankara, Zonguldak, Çankırı gibi illere bağlantı vardır (Karabük Tren Garı şehir merkezindedir). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Safranbolu ilçesine şehir merkezinden sık sık minibüs seferleri vardır.', 'Karabük, Türkiye\'nin en genç illerinden biridir. Antik dönemde Paflagonya bölgesi sınırları içinde kalan bölge, sırasıyla Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Candaroğulları Beyliği ve Osmanlıların egemenliğinde kalmıştır. Bölge, uzun yıllar boyunca tarım ve hayvancılıkla geçinen küçük bir yerleşim yeri olmuştur. 1937 yılında Karabük Demir Çelik Fabrikaları\'nın (KARDEMİR) kurulmasıyla birlikte hızlı bir sanayileşme sürecine girmiş ve Türkiye\'nin ağır sanayi merkezlerinden biri haline gelmiştir. Fabrikanın çevresinde oluşan yerleşim, önce Zonguldak\'a bağlı bir bucak, 1953\'te ilçe ve nihayet 1995 yılında il statüsü kazanmıştır. Karabük, demir-çelik sanayisinin yanı sıra tarihi Safranbolu evleriyle de dünya çapında üne sahiptir.', 'Karabük', '2026-04-08 23:20:51'),
(44, 'Karaman', 'İç Anadolu', 'karaman.jpg', 'Karaman peyniri ile ünlü.', 'Karaman denince akla gelen ilk eser, şehrin simgesi haline gelmiş Karaman Kalesi\'dir. Şehir merkezinde yükselen bu kale, Bizans, Selçuklu ve Karamanoğulları dönemlerinden izler taşır. Karamanoğlu Mehmet Bey Anıtı ve türbesi, Türk dilinin resmi dil ilan edilmesinin anısına önemli bir duraktır. Aktekke Camii (Mader-i Mevlana), Mevlana Celaleddin-i Rumi\'nin annesinin türbesinin bulunduğu yerdir ve manevi önemi büyüktür. İnce Minareli Medrese, Hatuniye Medresesi, İbrahim Bey İmareti ve Nefise Sultan Medresesi Karamanoğulları döneminden kalan önemli eserlerdir. Binbir Kilise (Karadağ Bölgesi), Ortaçağ\'da önemli bir Hristiyan hac merkezi olan çok sayıda kilise ve manastır kalıntısını barındırır. Manazan Mağaraları (Taşkale), 5 katlı kaya oyma yerleşimiyle dikkat çeker. Taşkale ve Yeşildere Köyü\'ndeki yeraltı şehirleri ve kaya oyma evler bölgenin tarihi dokusunu yansıtır. Derkuyu Yeraltı Şehri ve Görmeli Köyü\'ndeki kiliseler de görülmeye değerdir. Karaman, ayrıca et ve süt verimi yüksek olan Karaman koyunu ile de ünlüdür.', 'Karaman mutfağı, İç Anadolu\'nun doyurucu ve lezzetli yemekleriyle ünlüdür. Mutlaka denenmesi gerekenlerin başında etli, nohutlu ve patatesli güveç yemeği olan Karaman tava gelir. Karaman köftesi, etli ekmek, yaprak sarma, dolma, keşkek, oğmaç çorbası, tarhana çorbası, mercimek çorbası, yayla çorbası, sac böreği, katmer, gözleme, kuru fasulye, sac kavurma, haşıl ve herle yöresel yemeklerdendir. Karaman peyniri (tulum), Karaman yoğurdu, Karaman balı ve Karaman sucuğu da meşhurdur. Tatlı olarak Karaman baklavası, kadayıf, un helvası, höşmerim, cevizli sucuk, pestil, köme, kabak tatlısı, sütlaç, güllaç ve Karaman lokumu öne çıkar. Karaman\'a özgü yoğurt, ceviz, sarımsak ve nane karışımı olan batırık ile bulgur aşı da tadılmalıdır.', 'Karaman\'da en önemli etkinlik, her yıl mayıs ayında düzenlenen Uluslararası Karaman Türk Dili ve Kültürü Festivali\'dir. Festivalde Karamanoğlu Mehmet Bey\'in Türkçeyi resmi dil ilan edişinin yıldönümü kutlanır, konserler, paneller, şiir dinletileri, halk oyunları ve yöresel lezzet tadımları yapılır. Ayrıca Karaman Kültür ve Sanat Festivali (ağustos), Taşkale Kültür ve Doğa Festivali (temmuz) ve Karaman Yayla Şenlikleri (yaz aylarında) düzenlenmektedir.', 'Karaman\'ı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, kaleleri ve yeraltı şehirlerini gezmek için idealdir. Yaz aylarında sıcaklık 30-35 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür, sıcaklık sıfırın altına düşebilir.', 'Karaman\'a hava yoluyla ulaşmak için en yakın havalimanı Konya Havalimanı\'dır. Havalimanı şehir merkezine yaklaşık 100 km uzaklıkta olup havaş otobüsleri veya taksi ile Karaman\'a ulaşılabilir. Karaman\'a şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Konya, Adana, Mersin, Antalya, Kayseri, Nevşehir ve Aksaray gibi birçok ile direkt otobüs seferleri vardır. Karaman, Konya-Adana demiryolu hattı üzerinde olup trenle de ulaşmak mümkündür; Karaman Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Taşkale, Yeşildere, Görmeli ve Karadağ gibi ilçe ve köylere minibüslerle ulaşım sağlanır. Karaman Kalesi, Aktekke Camii, Manazan Mağaraları ve Binbir Kilise gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Karaman, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Laranda adıyla anılan şehir, Roma ve Bizans dönemlerinde önemli bir piskoposluk merkezi olmuştur. 11. yüzyılda Malazgirt Meydan Muharebesi\'nden sonra Türklerin eline geçen bölge, 13. yüzyılda Karamanoğulları Beyliği\'nin başkenti olmuştur. Karamanoğulları, Anadolu\'da Türk dilinin resmi dil olarak kabul edildiği ilk beylik olarak tarihe geçmiştir. 1277 yılında Mehmet Bey, Karaman\'da Türkçeyi resmi dil ilan eden fermanı yayımlamıştır. 1468 yılında Fatih Sultan Mehmet tarafından Osmanlı topraklarına katılan Karaman, uzun yıllar Karaman Eyaleti\'nin merkezi olmuştur. Cumhuriyet döneminde il statüsü kazanmıştır. Karaman, tarihi yapıları, yeraltı şehirleri ve yöresel ürünleriyle öne çıkan bir İç Anadolu ilidir.', 'Karaman', '2026-04-08 23:20:51'),
(45, 'Kars', 'Doğu Anadolu', 'kars.jpg', 'Ani Harabeleri ile ünlü.', 'Kars denince akla gelen ilk yer, UNESCO Dünya Mirası Listesi\'nde yer alan Ani Antik Kenti\'dir. 1001 Kilise Şehri olarak da bilinen Ani, Ortaçağ\'da Ermeni, Bizans, Selçuklu ve Gürcü medeniyetlerinin buluşma noktası olmuş, katedralleri, kiliseleri, camileri ve saray kalıntılarıyla büyüleyicidir. Kars Kalesi (İç Kale), şehre hakim bir tepede yer alır ve Selçuklu döneminden kalma surları, manastır ve camisiyle dikkat çeker. Fethiye Camii (eski Rus kilisesi), Evliya Camii, Kümbet Cami ve Havariler Kilisesi (12 Havariler Kilisesi) şehrin önemli tarihi yapılarıdır. Kars\'a Rus döneminde kazandırılan Baltık mimarili Sarıkamış Beyaz Ormanları, Kars Evleri (taş konaklar), Kars Müzesi ve Atatürk Evi Müzesi görülmelidir. Kars\'ın simgelerinden Çıldır Gölü (kışın donduğunda üzerinde atlı kızaklar) ve Sarıkamış Kayak Merkezi doğa sporları için idealdir. Kars, ayrıca Kars gravyeri, Kars kazı ve Kars balı ile gastronomide de ünlüdür.', 'Kars mutfağı, Doğu Anadolu ve Kafkas mutfaklarının izlerini taşır. En meşhur lezzeti, tulum peyniri, tereyağı ve özel ekmekle yapılan Kars gravyeri (Kars kaşarı) ve Kars tulum peyniridir. Kars kazı (ördek benzeri kümes hayvanı) fırında, tandırda veya pilavla birlikte pişirilerek yenir. Kars usulü bozbaş (etli nohut yemeği), etli ekmek, kavurma, keşkek, oğmaç çorbası, tarhana çorbası, yayla çorbası, içli köfte, mercimek köftesi, yaprak sarma, dolma, kurutulmuş sebze yemekleri yöresel lezzetlerdir. Tatlı olarak kadayıf, un helvası, cevizli sucuk (köme), pestil, sütlaç ve Kars lokumu meşhurdur. Kars\'ta ayrıca Rus döneminden kalan fırınlarda yapılan Kars ekmeği (Kars somunu) ve çörekler de ünlüdür.', 'Kars\'ta en önemli etkinlik, her yıl eylül ayında düzenlenen Uluslararası Kars Kafkas Kültür Festivali\'dir. Festivalde Kafkas halk oyunları, konserler, yöresel lezzet tadımları, Kars peyniri ve Kars kazı yemek yarışmaları yapılır. Ayrıca Ani Antik Kenti Kültür ve Sanat Festivali (ağustos), Kars Boğa Güreşi Festivali (temmuz), Sarıkamış Kış Sporları ve Kayak Festivali (şubat) ve Çıldır Gölü Kış Festivali (ocak-şubat) düzenlenmektedir.', 'Kars\'ı ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 15-25 derece arasındadır, tarihi yapıları, Ani Harabeleri ve yaylaları gezmek için idealdir. Kışlar çok sert ve karlıdır; sıcaklık -20 derecenin altına düşebilir, aralık-şubat ayları arasında yollar zaman zaman kapanabilir. Kış aylarında Sarıkamış Kayak Merkezi için seyahat yapılabilir, ancak şehir merkezi ziyareti için yaz ayları önerilir.', 'Kars\'a hava yoluyla Kars Harakani Havalimanı ile ulaşılır. Havalimanı şehir merkezine 6 km uzaklıktadır. Kars\'a şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Erzurum, Ardahan, Ağrı, Muş, Van, Trabzon, Samsun, Bursa, Kocaeli gibi illere otobüs seferleri vardır. Kars, Doğu Ekspresi\'nin (Turistik Doğu Ekspresi) son duraklarından biridir; Ankara\'dan trenle Kars\'a ulaşmak popüler bir turistik rotadır. Kars Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ani Antik Kenti, Çıldır Gölü, Sarıkamış, Kağızman ve Selim ilçelerine minibüslerle ulaşım vardır. Ani Harabeleri, Kars Kalesi, Sarıkamış Kayak Merkezi gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n\r\n', 'Kars, tarihi boyunca Urartular, İskitler, Persler, Romalılar, Bizanslılar, Selçuklular, Gürcüler, Moğollar, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde önemli bir kale kenti olan Kars, 928-961 yılları arasında Ermeni Bagratuni Krallığı\'nın başkenti olmuştur. 1064 yılında Selçuklu Sultanı Alp Arslan tarafından fethedilmiş, 13. yüzyılda Gürcü atabeyleri tarafından yönetilmiştir. 1534 yılında Kanuni Sultan Süleyman tarafından Osmanlı topraklarına katılan Kars, 1877-1878 Osmanlı-Rus Savaşı (93 Harbi) sonrasında 40 yıl süreyle Rus işgalinde kalmıştır. Bu dönemde Ruslar tarafından şehir yeniden inşa edilmiş, Baltık mimarisinden etkilenen taş binalar, kiliseler ve konaklar yapılmıştır. 1918\'de geri alınan Kars, 1921\'de imzalanan Moskova Antlaşması ile Türkiye sınırları içinde kalmıştır. Cumhuriyet döneminde il statüsü kazanan Kars, tarihi yapıları, kümes hayvancılığı (Kars kazı) ve peyniriyle ünlüdür.', 'Kars', '2026-04-08 23:20:51'),
(46, 'Kastamonu', 'Karadeniz', 'kastamonu.jpg', 'Ilgaz Dağı ile ünlü.', 'Kastamonu denince akla gelen ilk şey, Osmanlı döneminden kalma tarihi Kastamonu Evleri\'dir. Özellikle kentin simgesi haline gelmiş olan Nasrullah Meydanı çevresindeki konaklar, restore edilmiş ahşap evleriyle ziyaretçileri büyüler. Kastamonu Kalesi (Komnenos Kalesi), şehre hakim bir tepede yer alır ve Bizans ile Candaroğulları döneminden kalma surları, iç kalesi ve manzarasıyla dikkat çeker. Şehir merkezindeki Nasrullah Camii, Atabey Camii ve İsmail Bey Külliyesi önemli Osmanlı eserleridir. Mahmut Bey Camii (Kasaba Köyü), ahşap işçiliği ve tarihi dokusuyla UNESCO Dünya Mirası Geçici Listesi\'ndedir. Küre Dağları Milli Parkı, Ilgaz Dağı Milli Parkı ve Horma Kanyonu doğa severler için eşsiz güzellikler sunar. Valla Kanyonu (Azdavay) ve Çatak Kanyonu (Pınarbaşı) yürüyüş ve kamp için idealdir. Ilgaz Dağı Kayak Merkezi kış sporları, Ilıca Şelalesi ve Elekdağ Şelalesi ise serinlemek için popüler duraklardır. Kastamonu, ayrıca bakır işlemeciliği (Kastamonu bakırı), kendir (kenevir) ürünleri (çanta, ip, bebek) ve yöresel el dokuması ürünleriyle ünlüdür.', 'Kastamonu mutfağı, Karadeniz ve İç Anadolu mutfaklarının izlerini taşır. En meşhur lezzeti, hamuru yoğrulup özel kalıplarda şekillendirilen ve odun ateşinde pişirilen \"Kastamonu simidi\" (kendir simidi) ile \"kendir ekmeği\"dir. \"Kastamonu mantısı\" (etli, yoğurtlu, yağlı), \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\" ve \"herle\" yöresel yemeklerdendir. \"Kastamonu pastırması\" ve \"Kastamonu sucuğu\" oldukça meşhurdur. Tatlı olarak \"Kastamonu baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kastamonu lokumu\" öne çıkar. Kastamonu\'ya özgü \"banduma\" (mısır unlu hamur) ve \"kızılcık şerbeti\" de tadılmalıdır.', 'Kastamonu\'da en önemli etkinlik, her yıl temmuz ayında düzenlenen Uluslararası Kastamonu Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, bakır işlemeciliği sergileri ve panayır düzenlenir. Ayrıca Ilgaz Dağı Kış Sporları ve Kayak Festivali (şubat), Küre Dağları Doğa Yürüyüşü Festivali (haziran), Kastamonu Simit Festivali (eylül), İnebolu Kültür ve Turizm Festivali (ağustos) ve Tosya Pirinç Festivali (ekim) düzenlenmektedir.', 'Kastamonu\'yu ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; tarihi konakları, yaylaları ve doğa yürüyüşleri için idealdir. Sonbahar aylarında yaprakların renklendiği dönem de güzeldir. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşer, ancak Ilgaz Dağı Kayak Merkezi için kış ayları tercih edilebilir.', 'Kastamonu\'ya hava yoluyla ulaşmak için en yakın havalimanı Kastamonu Havalimanı\'dır (Uzunyazı). Havalimanı şehir merkezine yaklaşık 15 km uzaklıkta olup havaş otobüsleri ve taksi ile ulaşılır. Ayrıca Ankara Esenboğa Havalimanı (230 km) da alternatiftir. Kastamonu\'ya şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Bursa, Samsun, Zonguldak, Karabük, Çankırı, Sinop, Bartın gibi birçok ile direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Karabük veya Çankırı\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Tosya, Taşköprü, İnebolu, Cide, Araç, Daday, Devrekani, Azdavay, Pınarbaşı, Küre, Bozkurt, Abana, Çatalzeytin, Hanönü, Şenpazar, Ağlı, Seydiler gibi ilçelere minibüslerle rahat ulaşım vardır. Ilgaz Dağı, Küre Dağları Milli Parkı, Horma Kanyonu, Valla Kanyonu, Mahmut Bey Camii, Kastamonu Evleri, Kastamonu Kalesi gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Kastamonu, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Paflagonya bölgesinin önemli merkezlerinden biri olan Kastamonu, Roma döneminde \"Castamonu\" adıyla anılmıştır. 13. yüzyılda Candaroğulları Beyliği\'nin başkenti olan şehir, bu dönemde önemli bir kültür ve ticaret merkezi haline gelmiştir. 1461 yılında Fatih Sultan Mehmet tarafından Osmanlı topraklarına katılan Kastamonu, Osmanlı döneminde Kastamonu Eyaleti\'nin merkezi olmuştur. Kurtuluş Savaşı\'nda Kastamonu, İnebolu üzerinden cepheye silah ve cephane taşınan İstiklal Yolu\'nun en önemli duraklarından biri olarak tarihe geçmiştir. Cumhuriyet döneminde il statüsünü koruyan Kastamonu, tarihi konakları, bakır işlemeciliği, kendir (kenevir) üretimi ve yöresel lezzetleriyle öne çıkan bir Batı Karadeniz ilidir.', 'Kastamonu', '2026-04-08 23:20:51'),
(47, 'Kayseri', 'İç Anadolu', 'kayseri.jpg', 'Pastırması ile ünlü.', 'Kayseri denince akla gelen ilk simge, Türkiye\'nin en önemli kış sporları merkezlerinden biri olan Erciyes Dağı\'dır (3917 m). Erciyes Kayak Merkezi, modern tesisleri, uzun pistleri ve teleferiğiyle her yıl binlerce yerli ve yabancı turisti ağırlamaktadır. Kayseri\'nin merkezindeki Kayseri Kalesi, Roma, Bizans, Selçuklu ve Osmanlı dönemlerinden izler taşıyan surları ve iç kalesiyle şehrin simgesidir. Saat Kulesi ve Cumhuriyet Meydanı şehrin buluşma noktasıdır. Kapadokya bölgesinin bir parçası olan Kültepe-Kaniş Karumu, dünyanın en eski yazılı belgelerinin bulunduğu arkeolojik alandır. Hunat Hatun Külliyesi (1238), Selçuklu döneminden kalma cami, medrese, hamam ve türbeden oluşan önemli bir eserdir. Sahabiye Medresesi, Çifte Medrese, Kurşunlu Cami, Gülük Camii ve Kayseri Arkeoloji Müzesi (eserler arasında Gevher Nesibe Müzesi de bulunur) diğer tarihi duraklardır. Sultan Sazlığı Milli Parkı (kuş cenneti), Koramaz Vadisi (peri bacaları ve kaya oyma kiliseleri) ve Soğanlı Vadisi (kaya kiliseleri) doğa ve tarih severler için eşsiz güzellikler sunar. Kayseri, ayrıca pastırması ve sucuğu ile gastronomide Türkiye\'nin en önde gelen illerindendir.', 'Kayseri mutfağı, İç Anadolu\'nun en zengin ve en ünlü mutfaklarından biridir. Mutlaka denenmesi gerekenlerin başında \"Kayseri mantısı\" (küçük hamur karelerinin içine kıyma konularak yapılan, yoğurt ve yağla servis edilen meşhur yemek) gelir. \"Kayseri pastırması\" ve \"Kayseri sucuğu\" dünyaca ünlüdür. \"Yağlama\" (etli, yoğurtlu, domates soslu kat kat hamur), \"köfteli yahni\", \"kuzu tandır\", \"etli ekmek\", \"sac kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"içli köfte\", \"mercimek köftesi\", \"kuru fasulye\", \"katmer\", \"gözleme\" yöresel lezzetlerdendir. Tatlı olarak \"Kayseri baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Kayseri lokumu\" ve \"burma kadayıf\" öne çıkar. Kayseri\'ye özgü \"mantı\", \"pastırma\" ve \"sucuk\" mutlaka tadılmalıdır.', 'Kayseri\'de en önemli etkinlik, her yıl şubat ayında düzenlenen Uluslararası Erciyes Kayak Festivali\'dir. Festivalde kayak yarışmaları, kar konserleri, kış sporları gösterileri ve eğlenceler yapılır. Ayrıca Uluslararası Kayseri Mantı Festivali (ekim), Kayseri Kültür ve Sanat Festivali (eylül), Kültepe Kültür ve Turizm Festivali (ağustos), Sultan Sazlığı Kuş Cenneti Festivali (nisan) ve Soğanlı Kültür ve Sanat Festivali (temmuz) düzenlenmektedir.', 'Kayseri\'yi ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, Erciyes Dağı\'nı ve doğa yürüyüşlerini keşfetmek için idealdir. Yaz aylarında sıcaklık 30-35 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşer, ancak Erciyes Kayak Merkezi için kış ayları (aralık-şubat) idealdir.', 'Kayseri\'ye hava yoluyla Kayseri Erkilet Havalimanı (ASR) ile ulaşılır. Havalimanı şehir merkezine 5 km uzaklıkta olup havaş otobüsleri, belediye otobüsleri ve taksi ile ulaşım sağlanır. Kayseri\'ye şehirlerarası otobüs terminalinden (Kayseri Otogarı) Ankara, İstanbul, İzmir, Adana, Mersin, Antalya, Konya, Sivas, Malatya, Elazığ, Diyarbakır, Gaziantep, Nevşehir, Aksaray, Niğde, Kırşehir, Yozgat, Tokat gibi birçok ile direkt otobüs seferleri vardır. Kayseri, Yüksek Hızlı Tren (YHT) hattı ile Ankara, Sivas ve Kırıkkale\'ye bağlıdır. Kayseri Tren Garı şehir merkezindedir. Şehir içi ulaşımda tramvay, minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Erciyes Kayak Merkezi, Kültepe-Kaniş Karumu, Soğanlı Vadisi, Koramaz Vadisi, Sultan Sazlığı ve diğer ilçelere minibüslerle ulaşım vardır. Erciyes Dağı, Kapadokya\'nın diğer bölgeleri (Ürgüp, Göreme, Avanos) ve tarihi alanlara gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Kayseri, tarihi boyunca Hititler, Asurlular, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, İlhanlılar, Eretna Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kapadokya bölgesinin önemli merkezlerinden biri olan Kayseri, Roma döneminde \"Caesarea\" adıyla anılmıştır. MÖ 2000 yıllarında Kültepe\'de kurulan Kaniş Karumu, Anadolu\'nun bilinen en eski yazılı belgelerine ev sahipliği yapmıştır. Selçuklu döneminde Kayseri, Anadolu\'nun en önemli ticaret ve kültür merkezlerinden biri haline gelmiştir. Bu dönemde inşa edilen Sahabiye Medresesi, Hunat Hatun Külliyesi ve Çifte Medrese gibi eserler günümüze ulaşmıştır. 1515 yılında Osmanlı topraklarına katılan Kayseri, Osmanlı döneminde sancak statüsünde yönetilmiştir. Cumhuriyet döneminde il statüsü kazanan Kayseri, günümüzde pastırması, sucuğu, mantısı ve Erciyes Dağı ile ünlü bir İç Anadolu ilidir.', 'Kayseri', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(48, 'Kırıkkale', 'İç Anadolu', 'kirikkale.jpg', 'Sanayi şehri.', 'Kırıkkale\'nin en önemli simgesi, Türkiye\'nin savunma sanayiinin kalbi olan MKE Kırıkkale Fabrikaları\'dır. Fabrikaların geçmişi 1920\'li yıllara uzanır ve ürettiği silah, mühimmat, askeri araç gereçler ile Türk Silahlı Kuvvetleri\'ne destek vermektedir. Kırıkkale Kalesi (Hasandede Kalesi), şehir merkezinde yükselen ve tarihi Bizans dönemine kadar uzanan bir yapıdır. Hasandede Türbesi, şehrin manevi simgelerinden biridir ve her yıl birçok ziyaretçi tarafından ziyaret edilmektedir. Çeşnigir Köprüsü (Kızılırmak üzerinde, Selçuklu dönemi), Kırıkkale\'nin en önemli tarihi eserlerinden biridir. Sulakyurt, Balışeyh, Delice ve Keskin ilçelerindeki tarihi camiler, hamamlar ve kalıntılar bölgenin geçmişine ışık tutar. Kızılırmak Nehri, Kırıkkale sınırları içinden geçer ve doğa yürüyüşleri, piknik ve kuş gözlem için elverişli alanlar sunar. Kırıkkale\'de ayrıca Delice ilçesinde bulunan jeotermal kaynaklar (Ilıcak Kaplıcası) termal turizm açısından önem taşımaktadır.', 'Kırıkkale mutfağı, İç Anadolu mutfağının sade ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Kırıkkale köftesi\" gelir. \"Etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\" ve \"herle\" yöresel yemeklerdendir. \"Kırıkkale peyniri\" (tulum), \"Kırıkkale yoğurdu\" ve \"Kırıkkale balı\" meşhurdur. Tatlı olarak \"Kırıkkale baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kırıkkale lokumu\" öne çıkar. Yörede \"düğün çorbası\" ve \"kızılcık şerbeti\" de geleneksel olarak yapılmaktadır.', 'Kırıkkale\'de en önemli etkinlik, her yıl temmuz ayında düzenlenen Uluslararası Hasandede Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları ve panayır düzenlenir. Ayrıca Kırıkkale Kültür ve Sanat Festivali (eylül), Delice Kültür ve Turizm Festivali (ağustos), Keskin Kültür ve Sanat Festivali (temmuz) ve Sulakyurt Kültür Festivali (haziran) düzenlenmektedir.', 'Kırıkkale\'yi ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır. Yaz aylarında sıcaklık 30-35 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür, sıcaklık sıfırın altına düşebilir.', 'Kırıkkale\'ye hava yoluyla ulaşmak için en yakın havalimanı Ankara Esenboğa Havalimanı\'dır (80 km). Havalimanından havaş otobüsleri veya taksi ile Kırıkkale\'ye ulaşılabilir. Kırıkkale\'ye şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Kırşehir, Yozgat, Çankırı, Çorum, Samsun, Amasya, Tokat, Sivas, Kayseri, Nevşehir, Aksaray, Konya, Eskişehir, Bursa, Kocaeli, Zonguldak, Karabük, Kastamonu, Sinop, Çorum gibi illere otobüs seferleri vardır. Kırıkkale, Ankara-Kayseri demiryolu hattı üzerinde olup trenle de ulaşmak mümkündür. Kırıkkale Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Keskin, Delice, Sulakyurt, Balışeyh, Yahşihan, Karakeçili, Bahşili ilçelerine minibüslerle rahat ulaşım vardır. Kırıkkale Kalesi, Hasandede Türbesi, Çeşnigir Köprüsü, Ilıcak Kaplıcası ve Kızılırmak Nehri kenarına gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Kırıkkale, Türkiye\'nin en genç illerinden biridir. Bölge, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi medeniyetlerin egemenliğinde kalmıştır. Antik dönemde Galatya bölgesi sınırları içinde kalan Kırıkkale, uzun yıllar boyunca tarım ve hayvancılıkla geçinen küçük bir yerleşim yeri olmuştur. Cumhuriyet döneminde, özellikle 1920\'li yıllarda kurulan silah ve mühimmat fabrikaları (MKE Kırıkkale Fabrikaları) ile birlikte hızlı bir sanayileşme sürecine girmiştir. Fabrikaların çevresinde oluşan yerleşim, önce Ankara\'ya bağlı bir ilçe, 1989 yılında ise il statüsü kazanmıştır. Kırıkkale, günümüzde Türkiye\'nin savunma sanayi merkezlerinden biri olarak öne çıkmaktadır.', 'Kırıkkale', '2026-04-08 23:20:51'),
(49, 'Kırklareli', 'Marmara', 'kirklareli.jpg', 'Dupnisa Mağarası ile ünlü.', 'Kırklareli denince akla gelen ilk simge, şehrin merkezindeki Kırklareli Kalesi\'dir. Bizans döneminden kalma bu kale, surları ve burçlarıyla ziyaretçilerini geçmişe götürür. Dupnisa Mağarası (Dupnisa Caves), Türkiye\'nin en uzun mağaralarından biridir ve üç kattan oluşan sarkıt, dikit ve traverten oluşumlarıyla görülmeye değerdir. Demirköy\'de bulunan Demirköy Dökümhanesi (Fatih Dökümhanesi), Osmanlı döneminde top dökümü için kurulan tarihi bir sanayi tesisidir. Sütçüler köyündeki Sütçüler Kaya Mezarları (Kırk Kilise) ve Kıyıköy\'deki Aya Nikola Manastırı, bölgenin erken Hristiyanlık dönemine ışık tutar. İğneada Longoz Ormanları Milli Parkı, Türkiye\'nin ender sulak orman ekosistemlerinden biridir ve yürüyüş, kuş gözlem, kamp ve doğa fotoğrafçılığı için eşsiz bir alandır. Erikli Gölü, Mert Gölü, Saka Gölü ve Hamam Gölü gibi göller ziyaretçiler için popüler duraklardır. Kırklareli\'nde ayrından Vize ilçesindeki Küçük Ayasofya (Vize Meryem Ana Kilisesi) ve Poyralı\'daki antik kalıntılar tarih meraklılarını beklemektedir.', 'Kırklareli mutfağı, Trakya mutfağının zengin ve lezzetli örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"Kırklareli köftesi\" ve \"Trakya köftesi\" gelir. \"Tava ciğer\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\" yöresel yemeklerdendir. \"Kırklareli peyniri\" (tulum), \"Kırklareli yoğurdu\", \"Kırklareli balı\" ve \"Kırklareli sucuğu\" meşhurdur. Tatlı olarak \"Kırklareli baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kırklareli lokumu\" öne çıkar. Kırklareli\'ne özgü \"kırklareli hardaliyesi\" (hardal soslu et yemeği) ve \"börek çeşitleri\" de tadılmalıdır.', 'Kırklareli\'nde en önemli etkinlik, her yıl temmuz ayında düzenlenen Uluslararası Kırklareli Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, mağara gezileri, doğa yürüyüşleri ve panayır düzenlenir. Ayrıca İğneada Longoz Ormanları Doğa Festivali (haziran), Demirköy Dökümhanesi Kültür Festivali (ağustos), Vize Kültür ve Sanat Festivali (temmuz) ve Kıyıköy Kültür ve Turizm Festivali (ağustos) düzenlenmektedir.', 'Kırklareli\'ni ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, mağaraları ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, sıcak ve nemlidir. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür, sıcaklık sıfırın altına düşebilir.', 'Kırklareli\'ne hava yoluyla ulaşmak için en yakın havalimanı Tekirdağ Çorlu Havalimanı\'dır (120 km). Havalimanından havaş otobüsleri veya taksi ile Kırklareli\'ne ulaşılabilir. Ayrıca İstanbul Havalimanı (170 km) da alternatiftir. Kırklareli\'ne şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Edirne, Tekirdağ, Çanakkale, Balıkesir, Kocaeli, Sakarya, Bolu, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Amasya, Tokat, Sivas, Kayseri, Konya, Eskişehir, Bursa, Yalova, Kocaeli gibi birçok ile direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Edirne veya Tekirdağ\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Vize, Lüleburgaz, Babaeski, Demirköy, Pehlivanköy, Pınarhisar, Kofçaz, Üsküp, Kırklareli merkez ilçelere minibüslerle rahat ulaşım vardır. Dupnisa Mağarası, İğneada Longoz Ormanları, Demirköy Dökümhanesi, Kırklareli Kalesi, Vize Küçük Ayasofyası, Kıyıköy Aya Nikola Manastırı gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Kırklareli, tarihi boyunca Traklar, Persler, Romalılar, Bizanslılar, Bulgarlar ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Trakya bölgesinin önemli merkezlerinden biri olan Kırklareli, Roma döneminde \"Saladya\" adıyla anılmıştır. Bizans döneminde ise \"Kırk Kilise\" olarak bilinen şehir, adını çok sayıdaki kiliseden almıştır. 1362 yılında I. Murad döneminde Osmanlı topraklarına katılan Kırklareli, Osmanlı döneminde Kırk Kilise Sancağı olarak yönetilmiştir. 19. yüzyılda Rus işgaline uğrayan şehir, Kurtuluş Savaşı\'nda Yunan işgaline direnmiş ve 1922 yılında düşmandan temizlenmiştir. Cumhuriyet döneminde il statüsü kazanan Kırklareli, adını \"Kırk Kilise\"den alarak \"Kırklareli\" olarak değiştirmiştir. Günümüzde Kırklareli, tarihi dokusu, doğal güzellikleri, mağaraları ve yöresel lezzetleriyle öne çıkan bir Marmara ilidir.', 'Kırklareli', '2026-04-08 23:20:51'),
(50, 'Kırşehir', 'İç Anadolu', 'kirsehir.jpg', 'Cacabey Medresesi ile ünlü.', 'Kırşehir denince akla gelen ilk simge, Ahi Evran\'ın türbesinin bulunduğu Ahi Evran Külliyesi\'dir. Ahi Evran, Ahi teşkilatının kurucusu olarak Türk esnaf ve zanaatkarlık geleneğinin sembol ismidir. Külliyede cami, türbe, hamam ve çarşı bulunmaktadır. Cacabey Camii ve Medresesi (1272), Selçuklu döneminde astronomi merkezi olarak kullanılmış, dönemin rasathanesi işlevini görmüştür. Kırşehir Kalesi, şehir merkezinde yükselen ve Bizans ile Selçuklu dönemlerinden izler taşıyan bir yapıdır. Neşet Ertaş Türbesi, ünlü Türk halk ozanı Neşet Ertaş\'ın anısına yapılmıştır ve her yıl binlerce hayranı tarafından ziyaret edilmektedir. Kırşehir Müzesi, bölgede bulunan arkeolojik eserler, etnografik eserler ve Ahi Evran\'a ait eşyaları sergilemektedir. Japonya ile Kırşehir arasında kültür köprüsü kuran Japon Parkı (Mucur), Japon mimarisine uygun olarak inşa edilmiş bahçeleri ve göletleriyle ilginç bir duraktır. Mucur Yeraltı Şehri, Kapadokya bölgesinin kuzeyindeki en önemli yeraltı yerleşimlerinden biridir. Kırşehir, ayrıca Türk halk müziğinin önemli merkezlerinden biri olarak bağlama ve türkü geleneğiyle ünlüdür.', 'Kırşehir mutfağı, İç Anadolu mutfağının zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Kırşehir köftesi\" gelir. \"Kırşehir tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\" ve \"herle\" yöresel yemeklerdendir. \"Kırşehir peyniri\" (tulum), \"Kırşehir yoğurdu\" ve \"Kırşehir balı\" meşhurdur. Tatlı olarak \"Kırşehir baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kırşehir lokumu\" öne çıkar. Kırşehir\'e özgü \"kıymalı erişte\" ve \"bulgur aşı\" da tadılmalıdır.', 'Kırşehir\'de en önemli etkinlik, her yıl ekim ayında düzenlenen Uluslararası Ahi Evran Kültür ve Sanat Festivali\'dir. Festivalde Ahi Evran\'ı anma törenleri, konserler, halk oyunları gösterileri, yöresel lezzet tadımları, el sanatları sergileri ve panayır düzenlenir. Ayrıca Uluslararası Neşet Ertaş Türkü ve Kültür Festivali (eylül), Kırşehir Kültür ve Sanat Festivali (ağustos), Mucur Yeraltı Şehri Kültür Festivali (temmuz) ve Cacabey Gökbilim Festivali (mayıs) düzenlenmektedir.', 'Kırşehir\'i ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, türbeleri ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 30-35 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür, sıcaklık sıfırın altına düşebilir.', 'Kırşehir\'e hava yoluyla ulaşmak için en yakın havalimanı Nevşehir Kapadokya Havalimanı\'dır (90 km) veya Kayseri Erkilet Havalimanı (140 km). Havalimanlarından havaş otobüsleri veya taksi ile Kırşehir\'e ulaşılabilir. Kırşehir\'e şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Kayseri, Nevşehir, Aksaray, Konya, Yozgat, Çorum, Sivas, Malatya, Elazığ, Diyarbakır, Gaziantep, Adana, Mersin, Kırıkkale, Kırklareli, Bursa, Eskişehir, Kocaeli, Sakarya, Bolu, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Amasya, Tokat gibi birçok ile direkt otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Kayseri veya Kırıkkale\'dedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Mucur, Kaman, Akpınar, Akçakent, Boztepe, Çiçekdağı ilçelerine minibüslerle rahat ulaşım vardır. Ahi Evran Külliyesi, Cacabey Camii, Neşet Ertaş Türbesi, Kırşehir Kalesi, Japon Parkı, Mucur Yeraltı Şehri, Kırşehir Müzesi gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Kırşehir, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Danişmentliler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kapadokya bölgesinin kuzeybatısında yer alan Kırşehir, Roma döneminde \"Mokissos\" adıyla anılmıştır. 11. yüzyılda Malazgirt Meydan Muharebesi\'nden sonra Türklerin eline geçen bölge, Selçuklu döneminde önemli bir kültür ve tasavvuf merkezi haline gelmiştir. 13. yüzyılda yaşamış olan büyük Türk mutasavvıfı Ahi Evran, Kırşehir\'de Ahi teşkilatını kurmuş ve şehir Ahi kültürünün merkezi olmuştur. Osmanlı döneminde Kırşehir Sancağı olarak yönetilen şehir, 1924 yılında il statüsü kazanmış, 1953 yılında kısa süreliğine Nevşehir\'e bağlanmışsa da 1957\'de tekrar il olmuştur. Kırşehir, Ahi Evran, Cacabey ve Neşet Ertaş gibi önemli şahsiyetleri yetiştirmiş, Türk kültür ve sanat hayatına büyük katkılar sunmuş bir ildir.', 'Kırşehir', '2026-04-08 23:20:51'),
(51, 'Kilis', 'Güneydoğu Anadolu', 'kilis.jpg', 'Ravanda Kalesi ile ünlü.', 'Kilis denince akla gelen ilk simge, şehir merkezindeki Kilis Kalesi\'dir. Memluklular döneminde yapılan bu kale, surları ve burçlarıyla dikkat çeker. Oylum Höyüğü, Kilis\'in en önemli arkeolojik alanıdır; yapılan kazılarda Hitit, Asur, Roma ve Bizans dönemlerine ait eserler bulunmuştur. Kilis Ulu Camii (1290), Memluklu döneminden kalma taş işçiliğiyle dikkat çeken önemli bir eserdir. Çınarlı Cami, Murat Ağa Camii ve Hasan Ağa Camii diğer tarihi camilerdir. Akpınar Köyü\'ndeki Akpınar Antik Kenti (Kyrrhos) ve Ravanda Kalesi (Sarıtaş) tarih meraklıları için ilgi çekicidir. Kilis Müzesi, bölgede bulunan mozaikler, heykeller, sikke koleksiyonu ve etnografik eserleri sergilemektedir. Kilis, Türkiye\'nin en önemli zeytin ve zeytinyağı üretim merkezlerinden biridir. Kilis zeytini (Kilis yağlık zeytini) ve Kilis zeytinyağı dünyaca ünlüdür. Şehirdeki zeytin bahçeleri ve zeytinyağı fabrikaları ziyaret edilebilir. Kilis, ayrıca Suriye sınırındaki konumu nedeniyle Öncüpınar Sınır Kapısı\'na ev sahipliği yapmaktadır.', 'Kilis mutfağı, Güneydoğu Anadolu mutfağının zengin ve baharatlı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Kilis tava\" (etli, patlıcanlı, biberli güveç) gelir. \"Kilis köftesi\", \"içli köfte\", \"oruk\", \"lahmacun\", \"çiğ köfte\" (etli), \"kuzu tandır\", \"etli ekmek\", \"yaprak sarma\", \"dolma\", \"mercimek köftesi\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\" yöresel yemeklerdendir. \"Kilis peyniri\", \"Kilis yoğurdu\", \"Kilis balı\" ve \"Kilis zeytini\" meşhurdur. Tatlı olarak \"Kilis baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kilis lokumu\" öne çıkar. Kilis\'e özgü \"katıklı ekmek\", \"bulgur pilavı\" ve \"zeytinyağlı enginar\" da tadılmalıdır.\r\n\r\n', 'Kilis\'te en önemli etkinlik, her yıl eylül ayında düzenlenen Uluslararası Kilis Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, zeytin ve zeytinyağı tadımı, panayır ve sergiler düzenlenir. Ayrıca Uluslararası Kilis Zeytin ve Zeytinyağı Festivali (kasım), Kilis Kültür ve Turizm Festivali (ağustos) ve Oylum Höyüğü Kültür ve Arkeoloji Festivali (mayıs) düzenlenmektedir.', 'Kilis\'i ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır. Yaz aylarında sıcaklık 35-40 dereceye ulaşabilir, çok sıcak ve kuraktır. Kışlar ılımandır, sıcaklık genelde 5-12 derece arasındadır, yağışlı olabilir. Kilis\'i ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Kilis\'e hava yoluyla ulaşmak için en yakın havalimanı Gaziantep Havalimanı\'dır (65 km). Havalimanından havaş otobüsleri veya taksi ile Kilis\'e ulaşılabilir. Kilis\'e şehirlerarası otobüs terminalinden Gaziantep, Ankara, İstanbul, İzmir, Adana, Mersin, Konya, Kayseri, Şanlıurfa, Diyarbakır, Malatya, Elazığ, Batman, Siirt, Mardin, Kahramanmaraş, Hatay, Osmaniye, Adıyaman gibi illere otobüs seferleri vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Gaziantep\'dedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Elbeyli, Musabeyli, Polateli ilçelerine minibüslerle rahat ulaşım vardır. Kilis Kalesi, Oylum Höyüğü, Kilis Ulu Camii, Kilis Müzesi, Akpınar Antik Kenti, Ravanda Kalesi, zeytin bahçeleri ve zeytinyağı fabrikaları gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir. Öncüpınar Sınır Kapısı\'na gitmek için de araç veya taksi kullanılır.', 'Kilis, tarihi boyunca Hititler, Asurlular, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Memluklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde önemli bir ticaret merkezi olan Kilis, stratejik konumu nedeniyle sık sık el değiştirmiştir. 1516 yılında Mercidabık Meydan Muharebesi\'nden sonra Yavuz Sultan Selim tarafından Osmanlı topraklarına katılmıştır. Osmanlı döneminde Halep\'e bağlı bir sancak olarak yönetilen Kilis, Cumhuriyet döneminde önce Gaziantep\'e bağlanmış, 1995 yılında il statüsü kazanarak Türkiye\'nin en genç illerinden biri olmuştur. Kilis, Türkiye\'nin Suriye sınırında yer alması nedeniyle tarih boyunca kültürel etkileşimlerin yoğun yaşandığı bir bölge olmuştur. Günümüzde zeytini, zeytinyağı ve yöresel lezzetleriyle öne çıkan bir Güneydoğu Anadolu ilidir.', 'Kilis', '2026-04-08 23:20:51'),
(52, 'Kocaeli', 'Marmara', 'kocaeli.jpg', 'Seka kağıt müzesi ile ünlü.', 'Kocaeli denince akla gelen ilk simge, Osmanlı döneminden kalma Tarihi İzmit Saat Kulesi\'dir (1901). İzmit\'in simgesi haline gelen bu kule, şehrin merkezinde yükselmektedir. İzmit Kalesi (Akçakoca Kalesi), Bizans döneminden kalma surları ve manzarasıyla ziyaretçilerini bekler. Seka Park (Eski Kağıt Fabrikası), restore edilerek park ve kültür merkezine dönüştürülmüş, İzmit Körfezi manzarası ve yürüyüş yollarıyla popüler bir alandır. Gayret Gemi Müzesi, Türk denizcilik tarihine ışık tutan önemli bir müzedir. Kartepe Kayak Merkezi, İstanbul ve çevresine yakınlığıyla kış sporları için tercih edilen bir merkezdir. Maşukiye (Kartepe), şelaleleri, yayla evleri, restoranları (alabalık tesisleri) ve doğa yürüyüşleriyle ünlüdür. Ballıkayalar Tabiat Parkı (Kartepe), kaya tırmanışı, doğa yürüyüşü, kamp ve şelaleleriyle doğa sporları merkezidir. Kerpe Plajı (Kandıra), Kefken Adası (Kandıra), Sarısu Plajı ve Altınkemer Plajı yaz aylarında yoğun ilgi gören plajlardır. Hereke Kalesi ve Hereke Halı Fabrikası (Osmanlı dönemi Hereke halıları dünyaca ünlüdür) tarih ve kültür meraklıları için önemli duraklardır. Kocaeli Arkeoloji Müzesi, İzmit\'te bulunan eserlerin sergilendiği önemli bir müzedir. Kartepe yaylaları, Sapanca Gölü\'nün Kocaeli kıyıları ve Karamürsel ilçesi de görülmeye değerdir.', 'Kocaeli mutfağı, Marmara ve Karadeniz mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Kocaeli köftesi\" ve \"İzmit köftesi\" gelir. \"Pişmaniye\" (Kocaeli\'nin dünyaca ünlü tatlısı, ipeksi kıvamda şeker ve un helvası) mutlaka tadılmalıdır. \"Kandıra sucuğu\", \"Kandıra pastırması\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"mıhlama\" (kuymak), \"karalahana çorbası\" yöresel yemeklerdendir. \"Kocaeli peyniri\", \"Kocaeli yoğurdu\", \"Kocaeli balı\" ve \"Kocaeli zeytini\" meşhurdur. Tatlı olarak \"pişmaniye\" dışında \"Kocaeli baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kocaeli lokumu\" öne çıkar. Kocaeli\'ne özgü \"ızgara hamsi\" ve \"deniz ürünleri\" de tadılmalıdır.', 'Kocaeli\'nde en önemli etkinlik, her yıl ağustos ayında düzenlenen Uluslararası Kocaeli Kültür ve Sanat Festivali\'dir (Kocaeli Fest). Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, el sanatları sergileri, panayır, kortej ve deniz yarışları düzenlenir. Ayrıca Uluslararası Kartepe Kayak Festivali (şubat), Kandıra Kültür ve Turizm Festivali (temmuz), Karamürsel Kiraz Festivali (haziran), Gölcük Kültür ve Sanat Festivali (eylül), Hereke Halı Festivali (ekim) ve Maşukiye Doğa Sporları Festivali (mayıs) düzenlenmektedir.', 'Kocaeli\'ni ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, yaylaları, mağaraları ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, nem oranı yüksektir, ancak Kerpe, Kefken ve Sarısu gibi plajlar için yaz ayları tercih edilir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 3-12 derece arasındadır, zaman zaman kar yağışı görülür.', 'Kocaeli\'ne hava yoluyla ulaşmak için en yakın havalimanı İstanbul Sabiha Gökçen Havalimanı\'dır (45 km). Havalimanından havaş otobüsleri, belediye otobüsleri, minibüs ve taksi ile Kocaeli\'ne ulaşılabilir. Kocaeli\'ne şehirlerarası otobüs terminalinden (İzmit Otogarı) İstanbul, Ankara, İzmir, Bursa, Eskişehir, Konya, Kayseri, Sivas, Erzincan, Erzurum, Kars, Ardahan, Artvin, Trabzon, Rize, Samsun, Ordu, Giresun, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli ilçeleri, Yalova, Bilecik, Kütahya, Afyonkarahisar, Denizli, Antalya, Adana, Mersin, Gaziantep, Şanlıurfa, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ağrı, Ardahan, Kars gibi birçok ile direkt otobüs seferleri vardır. Kocaeli, Yüksek Hızlı Tren (YHT) hattı üzerinde olup İstanbul, Ankara, Eskişehir, Konya, Karaman, Sivas, Bursa (YHT aktarmalı), Gebze, Pendik, Bostancı, Söğütlüçeşme, Halkalı gibi yerlere hızlı tren bağlantısı vardır. Kocaeli Tren Garı (İzmit Garı) şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri, taksi ve tramvay (Akçaray) kullanılır. İzmit, Gölcük, Karamürsel, Kandıra, Kartepe, Körfez, Derince, Başiskele, Çayırova, Dilovası, Darıca, Gebze ilçelerine minibüslerle rahat ulaşım vardır. Kartepe Kayak Merkezi, Maşukiye, Ballıkayalar Tabiat Parkı, Kerpe Plajı, Kefken Adası, İzmit Kalesi, Seka Park, Gayret Gemi Müzesi, Hereke Kalesi, Kocaeli Arkeoloji Müzesi gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n\r\n', 'Kocaeli, tarihi boyunca Bitinler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Bitinya bölgesinin önemli merkezlerinden biri olan Kocaeli, Roma döneminde \"Nicomedia\" (İzmit) adıyla Doğu Roma\'nın başkenti olmuştur. 1337 yılında Orhan Gazi tarafından Osmanlı topraklarına katılan Kocaeli, Osmanlı döneminde Kocaeli Sancağı olarak yönetilmiştir. Cumhuriyet döneminde il statüsü kazanan Kocaeli, günümüzde Türkiye\'nin en önemli sanayi merkezlerinden biridir. Otomotiv, kimya, metal, kağıt ve tekstil sektörlerinde Türkiye\'nin üretim üssü konumundadır. Aynı zamanda İzmit Körfezi, yaylaları, plajları ve tarihi yapılarıyla da dikkat çeken bir Marmara ilidir.', 'Kocaeli', '2026-04-08 23:20:51'),
(53, 'Konya', 'İç Anadolu', 'konya.jpg', 'Mevlana şehri.', 'Konya denince akla gelen ilk simge, Mevlana Celaleddin-i Rumi\'nin türbesinin bulunduğu Mevlana Külliyesi ve Müzesi\'dir. Yeşil türbesi, semahane, dergah, cami, matbah-ı şerif (mutfak) ve eserleriyle dünyanın dört bir yanından ziyaretçi çeken manevi bir merkezdir. Konya\'nın simgesi haline gelmiş olan İnce Minareli Medrese (Taş ve Ahşap Eserler Müzesi), Selçuklu döneminin taş işçiliğinin en güzel örneklerinden birini sergiler. Sırçalı Medrese, Karatay Medresesi (Çini Eserler Müzesi, Selçuklu çinileriyle ünlü) ve Sahib-i Ata Külliyesi diğer önemli Selçuklu eserleridir. Alaeddin Camii (Alaeddin Tepesi), Selçuklu sultanlarının türbelerinin bulunduğu Konya\'nın en büyük ve en eski camilerindendir. Aziziye Camii, Şems-i Tebrizi Camii ve Türbesi, İplikçi Camii, Konya Kalesi (Selçuklu surları) ve Konya Arkeoloji Müzesi de görülmesi gereken yerler arasındadır. Konya\'da modern dönemde inşa edilen ve Selçuklu mimarisinden esinlenen Meram Tarihi Bağları (Meram Dereboyu), Konya Tropikal Kelebek Bahçesi (Türkiye\'nin en büyük kelebek bahçesi), Konya Bilim Merkezi, Japon Parkı, Sille (tarihi Rum mahallesi, Sille Barajı, Aya Eleni Kilisesi, Sille evleri) ve Tuz Gölü (Konya sınırları içinde kalan kısmı) popüler gezilecek yerlerdendir. Çatalhöyük (Neolitik dönem, UNESCO Dünya Mirası Listesi), Kilistra Antik Kenti, İvriz Kaya Kabartması, Beyşehir Gölü (Türkiye\'nin en büyük tatlı su gölü) ve Beyşehir Eşrefoğlu Camii (ahşap direkli cami, UNESCO Dünya Mirası Geçici Listesi) Konya sınırları içindeki diğer önemli tarihi ve doğal güzelliklerdir. Konya, ayrıca etli ekmeği ve Mevlana\'sıyla tüm dünyada tanınmaktadır.', 'Konya mutfağı, Selçuklu ve Osmanlı mutfak kültürünün izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Konya etli ekmek\" (ince uzun hamur üzerine kıyma, biber, domates, maydanoz konularak taş fırında pişirilir) gelir. \"Fırın kebabı\", \"bamya çorbası\", \"tirit\", \"keşkek\", \"okra çorbası\", \"arabaşı çorbası\", \"biber dolması\", \"patlıcan dolması\", \"yaprak sarma\", \"mercimek köftesi\", \"sac arası\", \"katmer\", \"gözleme\", \"Konya mantısı\", \"Konya pilavı\", \"Konya peyniri\", \"Konya yoğurdu\", \"Konya balı\" yöresel lezzetlerdendir. Tatlı olarak \"Konya baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Konya lokumu\" öne çıkar. Konya\'ya özgü \"bici bici\" (şerbetli nişasta tatlısı) ve \"şekerpare\" de mutlaka tadılmalıdır.', 'Konya\'da en önemli etkinlik, her yıl 7-17 Aralık tarihleri arasında düzenlenen Uluslararası Mevlana\'nın Anma Törenleri (Şeb-i Arus)dir. Mevlana\'nın vuslat yıldönümü olan bu törenlerde sema gösterileri, konserler, paneller, şiir dinletileri ve Mevlana felsefesi üzerine konuşmalar yapılır. Ayrıca Uluslararası Konya Kültür ve Sanat Festivali (mayıs), Konya Etli Ekmek Festivali (eylül), Beyşehir Gölü Kültür ve Turizm Festivali (ağustos), Sille Kültür ve Sanat Festivali (temmuz), Çatalhöyük Arkeoloji Festivali (haziran) ve Tuz Gölü Doğa Sporları Festivali (eylül) düzenlenmektedir.', 'Konya\'yı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, camileri, müzeleri ve Mevlana Külliyesi\'ni gezmek için idealdir. Yaz aylarında sıcaklık 30-35 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşebilir, ancak Mevlana\'nın ölüm yıldönümü olan 17 Aralık\'ta düzenlenen Şeb-i Arus törenleri için kış ayları da tercih edilmektedir.', 'Konya\'ya hava yoluyla Konya Havalimanı (KYA) ile ulaşılır. Havalimanı şehir merkezine 18 km uzaklıkta olup havaş otobüsleri, belediye otobüsleri ve taksi ile ulaşım sağlanır. Konya\'ya şehirlerarası otobüs terminalinden (Konya Otogarı) Ankara, İstanbul, İzmir, Antalya, Adana, Mersin, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Gaziantep, Şanlıurfa, Karaman, Aksaray, Nevşehir, Niğde, Kırşehir, Yozgat, Çorum, Amasya, Samsun, Tokat, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Artvin, Rize, Trabzon, Giresun, Ordu, Samsun, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Burdur, Isparta, Uşak, Manisa, Balıkesir, Bilecik, Bursa, Yalova, Bursa, Bilecik, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Amasya, Tokat, Sivas, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Artvin, Rize, Trabzon, Giresun, Ordu, Samsun gibi birçok ile direkt otobüs seferleri vardır. Konya, Yüksek Hızlı Tren (YHT) hattı üzerinde olup Ankara, Eskişehir, İstanbul, Karaman gibi illere hızlı tren bağlantısı vardır. Konya Tren Garı şehir merkezindedir. Şehir içi ulaşımda tramvay (Konya Tramvay Ağı), minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Meram, Karatay, Selçuklu, Beyşehir, Akşehir, Ereğli, Karapınar, Cihanbeyli, Çumra, Ilgın, Kadınhanı, Sarayönü, Seydişehir, Hadim, Taşkent, Hüyük, Doğanhisar, Akören, Altınekin, Bozkır, Derbent, Emirgazi, Güneysınır, Halkapınar, Tuzlukçu, Yalıhüyük, Yunak, Ahırlı, Çeltik, Derebucak, Hüyük, Ilgın, Kadınhanı, Karapınar, Sarayönü, Seydişehir, Taşkent, Tuzlukçu, Yalıhüyük, Yunak gibi ilçelere minibüslerle rahat ulaşım vardır. Mevlana Müzesi, Alaeddin Tepesi, Karatay Medresesi, İnce Minareli Medrese, Sille, Meram Bağları, Konya Tropikal Kelebek Bahçesi, Konya Bilim Merkezi, Çatalhöyük, Beyşehir Gölü, Tuz Gölü, Kilistra Antik Kenti gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.\r\n\r\n', 'Konya, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Iconium\" adıyla anılan şehir, Roma ve Bizans dönemlerinde önemli bir Hristiyanlık merkezi olmuştur. 1071 yılında Malazgirt Meydan Muharebesi\'nden sonra Kutalmışoğlu Süleyman Şah tarafından fethedilen Konya, 1097 ile 1243 yılları arasında Anadolu Selçuklu Devleti\'nin başkenti olmuştur. Selçuklu döneminde Konya, Anadolu\'nun en önemli siyasi, kültürel ve dini merkezi haline gelmiştir. Bu dönemde yaşamış olan büyük Türk mutasavvıfı Mevlana Celaleddin-i Rumi, Konya\'yı dünyaca ünlü bir tasavvuf merkezi yapmıştır. 1467 yılında Fatih Sultan Mehmet tarafından Osmanlı topraklarına katılan Konya, Osmanlı döneminde Karaman Eyaleti\'nin önemli bir sancağı olmuştur. Cumhuriyet döneminde il statüsünü koruyan Konya, günümüzde Türkiye\'nin yüzölçümü bakımından en büyük ili olup, tarım (tahıl), sanayi ve dini turizmle öne çıkmaktadır.', 'Konya', '2026-04-08 23:20:51'),
(54, 'Kütahya', 'Ege', 'kutahya.jpg', 'Çiniciliği ile ünlü.', 'Kütahya denince akla gelen ilk simge, dünyaca ünlü Kütahya çinileri ve seramikleridir. Kütahya Çini Müzesi, Çinili Camii, Ulu Cami ve Kütahya\'nın çarşılarında çini yapım atölyeleri, çinileri yakından görmek ve alışveriş yapmak için idealdir. Kütahya Kalesi, şehir merkezinde yükselen ve Bizans, Germiyanoğulları ve Osmanlı dönemlerinden izler taşıyan surları, iç kalesi ve manzarasıyla dikkat çeker. Kütahya\'nın simgesi haline gelmiş olan Çinili Camii (Kurşunlu Camii, 1377), Germiyanoğulları döneminden kalma çinilerle bezeli önemli bir eserdir. Ulu Cami (1327), Tacettin Cami, Kütahya Saat Kulesi (1904), Zafer Müzesi (Kurtuluş Savaşı\'nda karargah olarak kullanılan bina) ve Kütahya Müzesi (arkeolojik ve etnografik eserler, çini koleksiyonu) diğer önemli duraklardır. Aizanoi Antik Kenti (Çavdarhisar), Zeus Tapınağı, tiyatrosu, stadyumu, hamamları ve köprüsüyle UNESCO Dünya Mirası Geçici Listesi\'ndedir. Yoncalı Kaplıcası (termal su, fizik tedavi), Ilıca Kaplıcası, Harlek Kaplıcası ve Hekim Sinan Kaplıcası termal turizm için popüler merkezlerdir. Dominiçe Yaylası, Şaphane Yaylası ve Murat Dağı doğa yürüyüşleri, kamp ve kış sporları için idealdir. Kütahya, ayrıca lületaşı işlemeciliği (tesbih, kolye, küpe, süs eşyası) ve Germiyan kültürüyle de ünlüdür.', 'Kütahya mutfağı, Ege ve İç Anadolu mutfaklarının izlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Kütahya köftesi\" ve \"Germiyan köftesi\" gelir. \"Kütahya tavası\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"banduma\", \"cızlama\", \"cibre\", \"kaygana\", \"höşmerim\" yöresel yemeklerdendir. \"Kütahya peyniri\" (tulum), \"Kütahya yoğurdu\", \"Kütahya balı\" ve \"Kütahya sucuğu\" meşhurdur. Tatlı olarak \"Kütahya baklavası\", \"kadayıf\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Kütahya lokumu\" öne çıkar. Kütahya\'ya özgü \"baş üstü pilavı\", \"işkembeli çorba\" ve \"kızılcık şerbeti\" de tadılmalıdır.', 'Kütahya\'da en önemli etkinlik, her yıl ağustos ayında düzenlenen Uluslararası Kütahya Çini ve Seramik Festivali\'dir. Festivalde çini yapım atölyeleri, çini sergileri, seramik yarışmaları, konserler, halk oyunları gösterileri, yöresel lezzet tadımları ve panayır düzenlenir. Ayrıca Uluslararası Kütahya Kültür ve Sanat Festivali (eylül), Aizanoi Antik Kenti Kültür ve Sanat Festivali (temmuz), Yoncalı Termal Turizm ve Kültür Festivali (şubat), Dominiçe Yaylası Kültür ve Doğa Festivali (temmuz) ve Kütahya Lületaşı Festivali (ekim) düzenlenmektedir.', 'Kütahya\'yı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, çini müzelerini ve termal kaplıcaları gezmek için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve yağışlıdır, zaman zaman kar yağışı görülür, sıcaklık sıfırın altına düşebilir, ancak kış aylarında termal kaplıcalar (Yoncalı, Ilıca) daha keyiflidir.', 'Kütahya\'ya hava yoluyla ulaşmak için en yakın havalimanı Zafer Havalimanı (Kütahya-Zafer Havalimanı, 40 km) kullanılır. Havalimanından havaş otobüsleri ve taksi ile Kütahya\'ya ulaşılır. Ayrıca Eskişehir Hasan Polatkan Havalimanı (75 km) da alternatiftir. Kütahya\'ya şehirlerarası otobüs terminalinden (Kütahya Otogarı) İstanbul, Ankara, İzmir, Bursa, Eskişehir, Konya, Afyonkarahisar, Denizli, Uşak, Manisa, Balıkesir, Bilecik, Bursa, Yalova, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Amasya, Tokat, Sivas, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Artvin, Rize, Trabzon, Giresun, Ordu, Samsun, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Bursa, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Amasya, Tokat, Sivas, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Artvin, Rize, Trabzon, Giresun, Ordu, Samsun gibi birçok ile direkt otobüs seferleri vardır. Kütahya, demiryolu hattı üzerinde olup Eskişehir, Ankara, İstanbul, Afyonkarahisar, Denizli, İzmir, Konya, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Batman, Kurtalan, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Erzurum, Erzincan, Sivas, Kayseri, Konya, Afyonkarahisar, Denizli, İzmir, Manisa, Balıkesir, Bursa, Bilecik, Eskişehir, Ankara, İstanbul gibi yerlere tren bağlantısı vardır. Kütahya Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Merkez ilçeler, Tavşanlı, Simav, Gediz, Emet, Altıntaş, Çavdarhisar, Hisarcık, Dumlupınar, Pazarlar, Şaphane, Aslanapa, Domaniç ilçelerine minibüslerle rahat ulaşım vardır. Kütahya Kalesi, Çinili Camii, Kütahya Müzesi, Aizanoi Antik Kenti, Yoncalı Kaplıcası, Dominiçe Yaylası, Murat Dağı, çini atölyeleri, lületaşı atölyeleri gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Kütahya, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Germiyanoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Frigya bölgesinin önemli merkezlerinden biri olan Kütahya, Roma ve Bizans dönemlerinde \"Cotiaeum\" adıyla anılmıştır. 13. yüzyılda Germiyanoğulları Beyliği\'nin başkenti olan şehir, 1429 yılında Osmanlı topraklarına katılmıştır. Osmanlı döneminde Kütahya, Anadolu\'daki önemli çini ve seramik üretim merkezlerinden biri haline gelmiştir. Kütahya çinileri, Osmanlı saraylarını, camileri ve yapıları süslemiş, dünyaca ün kazanmıştır. Kurtuluş Savaşı\'nda Yunan işgaline uğrayan Kütahya, 30 Ağustos 1922\'de kurtarılmıştır. Cumhuriyet döneminde il statüsünü koruyan Kütahya, günümüzde çiniciliği, termal kaynakları (Yoncalı Kaplıcası) ve lületaşı işlemeciliğiyle öne çıkan bir Ege ilidir.', 'Kütahya', '2026-04-08 23:20:51'),
(55, 'Malatya', 'Doğu Anadolu', 'malatya.jpg', 'Kayısısı ile ünlü.', 'Malatya denince akla gelen ilk simge, dünyaca ünlü Malatya kayısısıdır. Malatya, dünya kuru kayısı üretiminin yaklaşık yüzde 80-85\'ini karşılamaktadır. Şehirdeki kayısı bahçeleri, kayısı işleme tesisleri ve kayısı pazarları ziyaret edilebilir. Malatya\'nın en önemli tarihi eseri, UNESCO Dünya Mirası Listesi\'ndeki Arslantepe Höyüğü\'dür. Bu höyükte yapılan kazılarda Hitit dönemine ait saray kalıntıları, heykeller, kabartmalar ve dünyanın ilk kılıçları bulunmuştur. Malatya Kalesi (Battalgazi Kalesi), şehir merkezinde yükselen ve Bizans, Selçuklu ve Osmanlı dönemlerinden izler taşıyan surları ve manzarasıyla dikkat çeker. Battalgazi Ulu Cami (1224), Selçuklu döneminden kalma taş işçiliği ve çinileriyle önemli bir eserdir. Silahtar Mustafa Paşa Kervansarayı, Yeni Cami, Hacı Yusuf Taş Cami, Şire Pazarı, Malatya Müzesi (Arslantepe eserleri, kayısı tarihi) ve Malatya Parkı diğer gezilecek yerlerdendir. Levent Vadisi (Doğanşehir), Günpınar Şelalesi (Hekimhan), Tohma Kanyonu, Yamadağı, Kubbe Dağı, Beydağı, Sultansuyu Mesire Alanı, Yeşilyurt ilçesindeki tarihi evler ve Akçadağ ilçesindeki termal kaplıcalar doğa ve tarih severler için ilgi çekicidir. Malatya, ayrıca kayısısı, kayısılı ürünleri (kayısılı baklava, kayısılı çikolata, kayısılı lokum), Malatya işi (el dokuması ipek halı) ve yöresel kıyafetleriyle de ünlüdür.', 'Malatya mutfağı, Doğu Anadolu mutfağının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Malatya kayısısı\" (dünyaca ünlü, güneşte kurutulmuş, tatlı, aromatik) gelir. \"Malatya köftesi\", \"Malatya tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"içli köfte\", \"mercimek köftesi\", \"analı kızlı\" (etli, bulgurlu, nohutlu, yoğurtlu yemek), \"bulgur aşı\" yöresel yemeklerdendir. \"Malatya peyniri\" (tulum), \"Malatya yoğurdu\", \"Malatya balı\" ve \"Malatya sucuğu\" meşhurdur. Tatlı olarak \"Malatya baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Malatya lokumu\", \"kayısı tatlısı\", \"kayısı hoşafı\", \"kayısı reçeli\", \"kayısı marmelatı\", \"kayısı pestili\", \"kayısı kömesi\" öne çıkar.', 'Malatya\'da en önemli etkinlik, her yıl temmuz ayında düzenlenen Uluslararası Malatya Kayısı Festivali\'dir. Festivalde kayısı hasadı, kayısı yarışmaları, kayısı tadımı, kayısılı ürünler sergisi, konserler, halk oyunları gösterileri, yöresel lezzet tadımları, panayır, sergiler ve paneller düzenlenir. Ayrıca Uluslararası Malatya Kültür ve Sanat Festivali (eylül), Arslantepe Kültür ve Arkeoloji Festivali (ağustos), Levent Vadisi Doğa Sporları Festivali (mayıs), Battalgazi Kültür ve Sanat Festivali (haziran) ve Yeşilyurt Kültür ve Sanat Festivali (temmuz) düzenlenmektedir.', 'Malatya\'yı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; tarihi yapıları, kayısı bahçelerini ve doğayı gezmek için idealdir. Kayısı hasadı haziran-temmuz aylarında yapılır. Yaz aylarında sıcaklık 35-38 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşebilir. Malatya\'yı ziyaret etmek için en uygun zaman nisan-mayıs ve eylül-ekim aylarıdır.', 'Malatya\'ya hava yoluyla Malatya Erhaç Havalimanı (MLX) ile ulaşılır. Havalimanı şehir merkezine 34 km uzaklıkta olup havaş otobüsleri, belediye otobüsleri ve taksi ile ulaşım sağlanır. Malatya\'ya şehirlerarası otobüs terminalinden (Malatya Otogarı) Ankara, İstanbul, İzmir, Bursa, Konya, Kayseri, Sivas, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Artvin, Rize, Trabzon, Giresun, Ordu, Samsun, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Adana, Mersin, Gaziantep, Şanlıurfa, Diyarbakır, Elazığ, Tunceli, Bingöl, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Erzurum, Erzincan, Sivas, Kayseri, Konya, Aksaray, Nevşehir, Niğde, Kırşehir, Yozgat, Çorum, Amasya, Tokat, Ordu, Giresun, Trabzon, Rize, Artvin gibi birçok ile direkt otobüs seferleri vardır. Malatya, Doğu Ekspresi\'nin güzergahında olup trenle Ankara, Kayseri, Sivas, Erzincan, Erzurum, Kars, Elazığ, Diyarbakır, Batman, Kurtalan, Muş, Bitlis, Van, Tatvan gibi yerlere tren bağlantısı vardır. Malatya Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Battalgazi, Yeşilyurt, Akçadağ, Doğanşehir, Darende, Hekimhan, Arguvan, Kale, Yazıhan, Kuluncak, Pütürge, Arapgir ilçelerine minibüslerle rahat ulaşım vardır. Arslantepe Höyüğü, Malatya Kalesi, Battalgazi Ulu Cami, Silahtar Mustafa Paşa Kervansarayı, Malatya Müzesi, Levent Vadisi, Günpınar Şelalesi, Tohma Kanyonu, Yamadağı, Kubbe Dağı, Beydağı, Sultansuyu Mesire Alanı, Yeşilyurt Evleri, Akçadağ Kaplıcaları, kayısı bahçeleri gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Malatya, tarihi boyunca Hititler, Asurlular, Urartular, Medler, Persler, Romalılar, Bizanslılar, Selçuklular, Danişmentliler, Anadolu Selçukluları, Beylikler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Melid\" veya \"Malitija\" adıyla anılan şehir, Hitit İmparatorluğu\'nun önemli merkezlerinden biri olmuştur. Arslantepe Höyüğü, MÖ 5000 yıllarına uzanan geçmişiyle bölgenin en eski yerleşimlerinden biridir ve UNESCO Dünya Mirası Listesi\'ndedir. Roma döneminde \"Melitene\" adıyla önemli bir askeri merkez haline gelen Malatya, Bizans döneminde de stratejik önemini korumuştur. 11. yüzyılda Malazgirt Meydan Muharebesi\'nden sonra Türklerin eline geçen bölge, 12. yüzyılda Danişmentliler, ardından Selçuklular ve 14. yüzyılda Beylikler döneminde yaşamış, 1515 yılında Yavuz Sultan Selim tarafından Osmanlı topraklarına katılmıştır. Cumhuriyet döneminde il statüsü kazanan Malatya, günümüzde kayısısı ile dünyaca ünlü, tarım ve sanayisi gelişmiş bir Doğu Anadolu ilidir.', 'Malatya', '2026-04-08 23:20:51'),
(56, 'Manisa', 'Ege', 'manisa.jpg', 'Mesir Macunu ile ünlü.', 'Manisa denince akla gelen ilk simge, her yıl mart ayında düzenlenen ve binlerce kişinin katıldığı Mesir Macunu Festivali\'dir. Osmanlı döneminden kalan bu gelenekte, Sultan Camii\'nden halka mesir macunu saçılır. Manisa\'nın simgesi haline gelmiş olan Spil Dağı Milli Parkı, eşsiz doğası, yürüyüş parkurları, kamp alanları, yaban hayatı ve efsanevi Niobe (Ağlayan Kaya) anıtıyla ünlüdür. Manisa Kalesi, şehir merkezinde yükselen ve Bizans, Saruhanoğulları ve Osmanlı dönemlerinden izler taşıyan surları ve manzarasıyla dikkat çeker. Sultan Camii (Hafsa Sultan Camii, 1522), Kanuni Sultan Süleyman\'ın annesi Hafsa Sultan tarafından yaptırılmış, Osmanlı mimarisinin önemli eserlerindendir. Muradiye Camii (1586), Mimar Sinan\'ın eseri olup çinileri ve mimarisiyle görülmeye değerdir. Çağlayan Hamamı, Saruhan Bey Camii (1330), Ulu Cami, Kurşunlu Han, İvaz Paşa Camii, Manisa Müzesi (arkeolojik ve etnografik eserler, mesir macunu tarihi) ve Niobe (Ağlayan Kaya) Anıtı şehrin önemli duraklarıdır. Kula Evleri ve Kula Peribacaları (Kula Volkanik Jeoparkı, UNESCO Küresel Jeopark Ağı\'nda), Salihli ilçesindeki Sart Antik Kenti (Lidya\'nın başkenti Sart, Kral Yolu, Artemis Tapınağı, tiyatro, hamam, sinagog kalıntıları), Alaşehir ilçesindeki Philadelphia Antik Kenti (Bizans dönemi, kilise kalıntıları) ve Akhisar ilçesindeki Thyateira Antik Kenti (Roma dönemi) tarih meraklıları için önemli alanlardır. Manisa, ayrıca Sultaniye çekirdeksiz üzümü, kuru üzümü, mesir macunu, Manisa işi (el dokuması) ve Manisa kumaşıyla da ünlüdür.', 'Manisa mutfağı, Ege mutfağının zengin ve sağlıklı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Manisa mesir macunu\" (41 çeşit baharat ve bitkiden yapılan, Osmanlı döneminden kalma geleneksel macun) gelir. \"Manisa köftesi\", \"Manisa kebabı\", \"tava ciğer\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"zeytinyağlı pırasa\", \"zeytinyağlı kereviz\", \"ot kavurması\" yöresel yemeklerdendir. \"Manisa peyniri\" (tulum), \"Manisa yoğurdu\", \"Manisa balı\", \"Manisa zeytini\", \"Manisa üzümü\" (Sultaniye çekirdeksiz üzüm) meşhurdur. Tatlı olarak \"Manisa baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Manisa lokumu\", \"mesir macunu\" öne çıkar. Manisa\'ya özgü \"sızgıt böreği\" ve \"çalkama\" da tadılmalıdır.', 'Manisa\'da en önemli etkinlik, her yıl mart ayında düzenlenen Uluslararası Manisa Mesir Macunu Festivali\'dir. Festivalde Sultan Camii\'nden mesir macunu saçılması, konserler, halk oyunları gösterileri, yöresel lezzet tadımları, panayır ve sergiler düzenlenir. Ayrıca Uluslararası Manisa Kültür ve Sanat Festivali (eylül), Spil Dağı Doğa ve Kültür Festivali (haziran), Kula Kültür ve Turizm Festivali (ağustos), Salihli Sart Antik Kenti Kültür ve Sanat Festivali (temmuz), Alaşehir Kültür ve Turizm Festivali (eylül) ve Akhisar Kültür ve Sanat Festivali (ekim) düzenlenmektedir.', 'Manisa\'yı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; tarihi yapıları, Spil Dağı\'nı ve doğa yürüyüşlerini keşfetmek için idealdir. Mesir macunu festivali mart ayında düzenlenir. Yaz aylarında sıcaklık 30-36 dereceye ulaşabilir, sıcak ve kuraktır. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 5-15 derece arasındadır, zaman zaman kar yağışı görülür (Spil Dağı\'nda).', 'Manisa\'ya hava yoluyla en yakın havalimanı İzmir Adnan Menderes Havalimanı\'dır (60 km). Havalimanından havaş otobüsleri veya taksi ile Manisa\'ya ulaşılır. Manisa\'ya şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Balıkesir, Denizli, Uşak, Kütahya, Afyonkarahisar, Konya, Kayseri gibi büyük illere direkt otobüs seferleri vardır. Demiryolu bağlantısı vardır; Manisa Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Merkez ilçeler, Salihli, Akhisar, Turgutlu, Alaşehir, Kula, Soma, Demirci, Gördes, Köprübaşı, Saruhanlı, Kırkağaç, Selendi, Ahmetli, Gölmarmara, Şehzadeler, Yunusemre ilçelerine minibüslerle ulaşım vardır. Spil Dağı, Sart Antik Kenti, Kula Peribacaları, Manisa Kalesi, Sultan Camii, Muradiye Camii gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Manisa, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Saruhanoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Lidya bölgesinin önemli merkezlerinden biri olan Manisa, Roma döneminde \"Magnesia ad Sipylum\" adıyla anılmıştır. 1313 yılında Saruhanoğulları Beyliği\'nin başkenti olan şehir, 1390 yılında Yıldırım Bayezid tarafından Osmanlı topraklarına katılmıştır. Osmanlı döneminde Manisa, şehzadelerin eğitim gördüğü önemli bir sancak merkezi olmuştur. Fatih Sultan Mehmet, Kanuni Sultan Süleyman, II. Selim, III. Murad gibi birçok padişah şehzadelik yıllarını Manisa\'da geçirmiştir. Bu nedenle Manisa, \"Şehzadeler Şehri\" olarak anılmaktadır. Kurtuluş Savaşı\'nda Yunan işgaline uğrayan Manisa, 8 Eylül 1922\'de kurtarılmıştır. Cumhuriyet döneminde il statüsünü koruyan Manisa, günümüzde üzümü (Sultaniye üzümü), mesir macunu, tarım ve sanayisiyle öne çıkan bir Ege ilidir.', 'Manisa', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(57, 'Muğla', 'Ege', 'mugla.jpg', 'Mavi yolculuğun kalbi.', 'Muğla denince akla gelen ilk yerler, dünyaca ünlü turistik ilçeleridir. Bodrum (Bodrum Kalesi, Antik Tiyatro, Halikarnas Mozolesi, Bodrum Plajları, Yalıkavak, Türkbükü, Gümüşlük), Marmaris (Marmaris Kalesi, Marmaris Plajları, İçmeler Turunç, Selimiye, Bozburun), Fethiye (Ölüdeniz (mavi bayraklı plaj, yamaç paraşütü), Kelebekler Vadisi, Saklıkent Kanyonu, Kayaköy (hayalet köy), Fethiye Plajları, Çalış Plajı), Dalyan (Dalyan Plajı (Caretta caretta), İztuzu Plajı, Dalyan Kanalı, Kaunos Antik Kenti, Kaya Mezarları), Köyceğiz (Köyceğiz Gölü, Sultaniye Kaplıcaları), Datça (Datça Plajları, Knidos Antik Kenti, Palamutbükü), Milas (Milas Müzesi, Beçin Kalesi, Labranda Antik Kenti), Ortaca (Sarıgerme Plajı), Ula (Akyaka Plajı, Azmak Deresi), Seydikemer (Tlos Antik Kenti, Yaka Park, Girmeler Mağarası) Muğla\'nın en önemli turistik merkezleridir. Muğla şehir merkezinde ise Muğla Evleri (tarihi konaklar), Kurşunlu Cami, Vakıflar Hamamı, Muğla Arkeoloji Müzesi ve Muğla\'nın dar sokakları gezilmeye değerdir.', 'Muğla mutfağı, Ege ve Akdeniz mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Muğla köftesi\" gelir. \"Çökertme kebabı\", \"tava ciğer\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"ot kavurması\", \"deniz börülcesi\", \"söğüş\", \"çılbır\", \"mıhlama\" yöresel yemeklerdendir. \"Muğla peyniri\", \"Muğla yoğurdu\", \"Muğla balı\", \"Muğla zeytini\", \"Muğla zeytinyağı\", \"Muğla portakalı\", \"Muğla mandalini\", \"Muğla çam balı\" meşhurdur. Tatlı olarak \"Muğla baklavası\", \"kadayıf\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Muğla lokumu\" öne çıkar.', 'Muğla\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Bodrum Bale Festivali (yaz aylarında, Bodrum Kalesi\'nde), Uluslararası Bodrum Müzik Festivali (yaz aylarında), Uluslararası Marmaris Yat ve Kültür Festivali (mayıs), Uluslararası Ölüdeniz Hava Oyunları Festivali (ekim, yamaç paraşütü), Uluslararası Dalyan Caretta Caretta Festivali (yaz aylarında), Uluslararası Datça Knidos Kültür ve Sanat Festivali (ağustos), Muğla Kültür ve Sanat Festivali (eylül) ve Köyceğiz Sultaniye Kaplıca Festivali (temmuz).', 'Muğla\'yı ziyaret etmek için en iyi zaman ilkbahar, yaz ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, kalabalık daha azdır. Yaz aylarında (haziran-eylül) sıcaklık 30-38 dereceye ulaşır, deniz suyu sıcaklığı yüzmek için idealdir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 8-15 derece arasındadır. Muğla\'yı ziyaret etmek için en uygun zaman mayıs-eylül aylarıdır.', 'Muğla\'ya hava yoluyla Dalaman Havalimanı (DLM) (Muğla merkeze 90 km, Marmaris, Fethiye, Dalyan, Köyceğiz yakın) veya Milas-Bodrum Havalimanı (BJV) (Bodrum\'a 20 km, Muğla merkeze 80 km) ile ulaşılır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Antalya, Denizli, Aydın, Manisa, Balıkesir, Bursa, Konya, Kayseri, Adana, Mersin, Gaziantep, Diyarbakır gibi büyük illere seferler vardır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Bodrum, Marmaris, Fethiye, Köyceğiz, Dalyan, Datça, Milas, Ortaca, Ula, Seydikemer ilçelerine minibüslerle rahat ulaşım vardır. Plajlar, antik kentler, koylar ve turistik bölgelere araç kiralamak en iyi seçenektir.', 'Muğla, tarihi boyunca Karyalılar, Likyalılar, Dorlar, Persler, Romalılar, Bizanslılar, Menteşeoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Karya bölgesinin önemli merkezlerinden biri olan Muğla, Roma döneminde \"Mobolla\" adıyla anılmıştır. 13. yüzyılda Menteşeoğulları Beyliği\'nin yönetimine giren şehir, 1425 yılında II. Murad tarafından Osmanlı topraklarına katılmıştır. Osmanlı döneminde Muğla Sancağı olarak yönetilen şehir, Cumhuriyet döneminde il statüsü kazanmıştır. Muğla, günümüzde Türkiye\'nin en önemli turizm merkezlerine ev sahipliği yapmaktadır. Bodrum, Marmaris, Fethiye, Köyceğiz, Dalyan, Ölüdeniz, Datça gibi dünyaca ünlü tatil beldeleri Muğla sınırları içindedir.', 'Muğla', '2026-04-08 23:20:51'),
(58, 'Muş', 'Doğu Anadolu', 'mus.jpg', 'Muş ovası ile ünlü.', 'Muş denince akla gelen ilk yer, 1071 yılında Sultan Alp Arslan ile Bizans İmparatoru Romanos Diogenes arasında yapılan ve Anadolu\'nun kapılarını Türklere açan Malazgirt Meydan Muharebesi\'nin gerçekleştiği Malazgirt ilçesidir. Malazgirt\'te bulunan Malazgirt Kalesi ve Malazgirt Zaferi Anıtı mutlaka görülmelidir. Muş Kalesi, şehir merkezinde yükselen ve tarihi Urartu, Roma ve Osmanlı dönemlerinden izler taşıyan bir yapıdır. Muş Müzesi, bölgede bulunan arkeolojik eserler, Urartu dönemi objeleri ve etnografik eserleri sergilemektedir. Ulu Cami (Muş Ulu Cami, 12. yüzyıl), Alaeddin Bey Cami, Hacı Şeref Camii, Yıldızlı Han (tarihi kervansaray) ve Murat Paşa Külliyesi şehrin diğer önemli tarihi eserleridir. Muş Ovası, Türkiye\'nin en büyük ovalarından biridir ve tarım ürünleri (tahıl, şeker pancarı) ile ünlüdür. Hamurpet Gölü (Kaz Gölü), doğal güzelliği, kuş gözlem ve piknik alanı olarak ziyaretçileri bekler. Muş, ayrıca yaylaları (Kıyı Yaylası, Ziyaret Yaylası, Yıldızlı Yaylası) ile de doğa severler için ilgi çekicidir.', 'Muş mutfağı, Doğu Anadolu mutfağının zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Muş köftesi\" gelir. \"Etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"içli köfte\", \"mercimek köftesi\", \"keledoş\", \"ayran aşı\", \"bulgur pilavı\", \"Muş peyniri\" (tulum), \"Muş yoğurdu\", \"Muş balı\" yöresel lezzetlerdendir. Tatlı olarak \"Muş baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\" ve \"Muş lokumu\" öne çıkar.', 'Muş\'ta en önemli etkinlik, her yıl ağustos ayında düzenlenen Uluslararası Malazgirt Zaferi Kutlamaları ve Kültür Festivali\'dir. Festivalde Malazgirt Zaferi anma törenleri, konserler, halk oyunları gösterileri, yöresel lezzet tadımları, at yarışları, okçuluk gösterileri, tarihi canlandırmalar ve panayır düzenlenir. Ayrıca Uluslararası Muş Kültür ve Sanat Festivali (eylül), Hamurpet Gölü Kültür ve Doğa Festivali (temmuz), Muş Yayla Şenlikleri (yaz aylarında) ve Malazgirt Kültür ve Sanat Festivali (ağustos) düzenlenmektedir.', 'Muş\'u ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-30 derece arasındadır; tarihi yapıları, kaleleri ve yaylaları gezmek için idealdir. Kışlar çok sert ve karlıdır; sıcaklık -20 derecenin altına düşebilir, aralık-şubat aylarında seyahat önerilmez. İlkbahar ve sonbahar serin ve yağışlıdır.', 'Muş\'a hava yoluyla Muş Havalimanı (MSR) ile ulaşılır. Havalimanı şehir merkezine 18 km uzaklıktadır. Şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Bursa, Diyarbakır, Van, Erzurum, Elazığ, Malatya, Bingöl, Bitlis, Batman, Siirt, Mardin, Ağrı, Kars, Ardahan, Iğdır, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Şanlıurfa, Adıyaman, Kahramanmaraş, Hatay gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Elazığ veya Batman\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Malazgirt, Varto, Bulanık, Korkut, Hasköy ilçelerine minibüslerle ulaşım vardır. Malazgirt Zafer Anıtı, Muş Kalesi, Hamurpet Gölü, Ulu Cami, yaylalar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir.', 'Muş, tarihi boyunca Hurriler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, İlhanlılar, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Muş\" adıyla anılan şehir, Malazgirt Meydan Muharebesi\'ne (1071) ev sahipliği yapmasıyla Türk tarihi açısından büyük öneme sahiptir. Malazgirt Zaferi\'nden sonra Türklerin eline geçen bölge, 16. yüzyılda Osmanlı topraklarına katılmıştır. Osmanlı döneminde Erzurum Eyaleti\'ne bağlı bir sancak olarak yönetilen Muş, Cumhuriyet döneminde il statüsü kazanmıştır. Muş, günümüzde tarım ve hayvancılığın öne çıktığı, doğal güzellikleri ve tarihi yapılarıyla Doğu Anadolu\'nun önemli illerinden biridir.', 'Muş', '2026-04-08 23:20:51'),
(59, 'Mardin', 'Güneydoğu Anadolu', 'mardin.jpg', 'Taş evleri ile ünlü.', 'Mardin denince akla gelen ilk simge, şehre hakim tepede bulunan Mardin Kalesi\'dir. Artuklu döneminden kalma bu kale, surları ve manzarasıyla Mardin\'in en önemli yapılarından biridir. Kale içinde yer alan Artuklu Sarayı kalıntıları da görülmeye değerdir. Ulu Cami (Mardin Ulu Cami, 1176), Artuklu dönemine ait taş işçiliği ve minaresiyle dikkat çeker. Zinciriye Medresesi (1385), Mardin\'in simgelerinden biri olup, taç kapısı, kubbesi ve manzarasıyla ünlüdür. Kasımiye Medresesi (15. yüzyıl), eğitim kurumu olarak inşa edilmiş, avlusu ve havuzuyla huzur veren bir yapıdır. Mardin Müzesi (eski patriklik binası), arkeolojik eserler, etnografik eserler ve bölgenin tarihini yansıtan objeleri sergiler. Deyrulzafaran Manastırı (Mor Hananyo Manastırı, 5. yüzyıl), Süryani Kadim Kilisesi\'ne ait olan bu manastır, Mardin\'in 5 km doğusunda yer alır ve Süryani Hristiyanlığının en önemli merkezlerinden biridir. Mor Behnam (Kırklar) Kilisesi, Meryem Ana Kilisesi, Mor Hırmız Kilisesi ve Mor Simuni Kilisesi şehrin diğer önemli Süryani kiliseleridir. Mardin Evleri (taş evler, dar sokaklar, kemerli kapılar, avlular, taş işlemeciliği), şehrin dar sokaklarında yürümek ve bu eşsiz mimariyi keşfetmek unutulmazdır. Mardin Çarşısı (Saraçlar Çarşısı, Bakırcılar Çarşısı, Tellallar Çarşısı, Terziler Çarşısı) yöresel ürünler, gümüş işlemeciliği, bakır işlemeciliği, telkari ve Süryani şarabı almak için idealdir. Mardin\'in ilçeleri Midyat (Midyat Evleri, Mor Gabriel Manastırı (dünyanın en eski Süryani manastırı), Midyat Müzesi, Midyat Çarşısı), Nusaybin (Mor Yakup Kilisesi, Zeynel Abidin Camii ve Türbesi), Dargeçit, Derik, Kızıltepe, Ömerli, Savur, Yeşilli de tarihi ve kültürel zenginlikler barındırır. Mardin, ayrıca telkari işlemeciliği (gümüş tel ile yapılan süs eşyaları, takı), Süryani şarabı, badem şekeri, sabun ve yöresel el sanatlarıyla da ünlüdür.', 'Mardin mutfağı, Güneydoğu Anadolu ve Mezopotamya mutfaklarının zengin ve baharatlı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Mardin tava\" (etli, patlıcanlı, biberli güveç) gelir. \"İçli köfte\", \"oruk\", \"kibbe\", \"lahmacun\", \"çiğ köfte\" (etli), \"kuzu tandır\", \"etli ekmek\", \"yaprak sarma\", \"dolma\", \"mercimek köftesi\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"Mardin peyniri\", \"Mardin yoğurdu\", \"Mardin balı\", \"Mardin üzümü\", \"Mardin pekmezi\", \"Mardin bademi\", \"Mardin fıstığı\", \"Mardin inciri\", \"Mardin narı\" yöresel lezzetlerdendir. Tatlı olarak \"Mardin baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Mardin lokumu\", \"Mardin sucuğu\" ve \"Mardin şekeri\" öne çıkar.', 'Mardin\'de en önemli etkinlik, her yıl mayıs veya eylül ayında düzenlenen Uluslararası Mardin Film Festivali\'dir. Festivalde Mardin\'in tarihi mekanlarında film gösterimleri, paneller, atölyeler ve sergiler düzenlenir. Ayrıca Uluslararası Mardin Kültür ve Sanat Festivali (eylül), Uluslararası Midyat Kültür ve Sanat Festivali (ağustos), Deyrulzafaran Manastırı Kültür ve İnanç Turizmi Festivali (haziran), Mor Gabriel Manastırı Kültür ve Sanat Festivali (temmuz), Mardin Telkari Festivali (ekim) ve Mardin Badem Şekeri Festivali (nisan) düzenlenmektedir.\r\n\r\n', 'Mardin\'i ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; tarihi taş evleri, dar sokakları ve manastırları gezmek için idealdir. Yaz aylarında sıcaklık 38-42 dereceye ulaşabilir, çok sıcak ve kuraktır. Kışlar soğuktur, sıcaklık genelde 0-10 derece arasındadır, yağışlı ve zaman zaman karlıdır.', 'Mardin\'e hava yoluyla Mardin Havalimanı (MQM) ile ulaşılır. Havalimanı şehir merkezine 20 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Adana, Mersin, Gaziantep, Şanlıurfa, Diyarbakır, Batman, Siirt, Şırnak, Hakkari, Van, Muş, Bitlis, Elazığ, Malatya, Kayseri, Konya, Antalya, Denizli, Manisa, Balıkesir, Bursa, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Amasya, Tokat, Sivas, Erzincan, Erzurum, Kars, Ardahan, Iğdır, Ağrı gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Diyarbakır veya Batman\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Midyat, Nusaybin, Kızıltepe, Derik, Dargeçit, Mazıdağı, Savur, Ömerli, Yeşilli ilçelerine minibüslerle ulaşım vardır. Mardin Kalesi, Ulu Cami, Zinciriye Medresesi, Kasımiye Medresesi, Mardin Müzesi, Deyrulzafaran Manastırı, Midyat, Mor Gabriel Manastırı, Mardin Evleri, dar sokaklar, çarşılar gibi yerlere gitmek için araç kiralamak veya turları tercih etmek önerilir. Mardin\'in dar ve yokuşlu sokaklarında yürüyüş yapılırken rahat ayakkabı giyilmesi önerilir.', 'Mardin, tarihi boyunca Sümerler, Akadlar, Babilliler, Asurlular, Hurriler, Hititler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Artuklular, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Şehir, adını Süryanice \"Merdö\" (kale) kelimesinden almıştır. Mardin Kalesi\'nin eteklerine kurulan şehir, tarih boyunca önemli bir ticaret ve kültür merkezi olmuştur. Artuklu döneminde (12-15. yüzyıl) Mardin, bilim, sanat ve mimarinin altın çağını yaşamıştır. 1517 yılında Yavuz Sultan Selim tarafından Osmanlı topraklarına katılan Mardin, Cumhuriyet döneminde il statüsü kazanmıştır. Mardin, tarihi taş evleri, dar sokakları, camileri, kiliseleri, manastırları ve eşsiz mimarisiyle adeta bir açık hava müzesidir.', 'Mardin', '2026-04-08 23:20:51'),
(60, 'Mersin', 'Akdeniz', 'mersin.jpg', 'Kızkalesi ile ünlü.', 'Mersin denince akla gelen ilk simge, Mersin\'in en önemli tarihi eserlerinden biri olan Kız Kalesi\'dir (Maiden\'s Castle). Denizin içinde, kıyıdan 200 metre açıkta yer alan bu kale, Bizans ve Kilikya Ermeni Krallığı döneminden kalma olup, tekne turlarıyla ziyaret edilmektedir. Tarsus ilçesi, tarihi ve kültürel zenginlikleriyle öne çıkar: Tarsus Şelalesi (Tarsus Çağlayanı), Kleopatra Kapısı, St. Paul Anıt Müzesi (Aziz Pavlus\'un evi ve kuyusu), Eski Cami (Tarsus Ulu Cami, 16. yüzyıl), Kırkkaşık Bedesteni, Tarsus Müzesi (arkeolojik eserler, mozaikler) ve Roma dönemi yolu (Via Julia) görülmelidir. Silifke ilçesi, Silifke Kalesi, Silifke Ulu Cami, Taş Köprü (Roma dönemi), Aya Tekla (Azize Thekla) Mağara Kilisesi, Narlıkuyu Mozaik Müzesi, Heaven & Hell (Cennet-Cehennem Obruğu) ve Astım Mağarası ile ünlüdür. Anamur ilçesi, Anamurium Antik Kenti, Mamure Kalesi (Türkiye\'nin en iyi korunmuş kalesi) ve Anamur Plajı ile dikkat çeker. Erdemli ilçesinde Kanlıdivane (Kanytelis) Antik Kenti, Corycus (Kızkalesi) Antik Kenti, Adamkayalar (kaya kabartmaları) ve Elaiussa Sebaste Antik Kenti bulunur. Mezitli ilçesinde Soloi-Pompeiopolis Antik Kenti ve Mersin Marina yer alır. Mut ilçesi, Mut Kalesi, Alahan Manastırı (UNESCO Dünya Mirası Geçici Listesi) ve Mut Yaylaları ile ünlüdür. Mersin Arkeoloji Müzesi (bölgede bulunan eserler, mozaikler, heykeller) ve Mersin Deniz Müzesi de görülmeye değerdir. Mersin, ayrıca narenciye bahçeleri (portakal, limon, mandalin, greyfurt), çilek tarlaları (Silifke çileği) ve muz bahçeleri (Anamur muzu) ile ünlüdür. Mersin\'de kış aylarında Göksu Deltası kuş cenneti ve Caretta caretta gözlemi yapılabilir.', 'Mersin mutfağı, Akdeniz mutfağının zengin ve lezzetli örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"Mersin tantunisi\" (ince yufka arası kıyma, soğan, maydanoz, sumak, limon, nar ekşisi) gelir. \"Mersin kebabı\", \"ciğer kebabı\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"deniz ürünleri\" (çipura, levrek, barbunya, kalamar, karides, ahtapot, midye), \"humus\", \"babağannuş\", \"muhammara\", \"kısır\", \"acılı ezme\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"ot kavurması\", \"batırık\", \"çalkama\", \"Mersin yoğurdu\", \"Mersin peyniri\", \"Mersin balı\", \"Mersin portakalı\", \"Mersin limonu\", \"Mersin mandalini\" yöresel lezzetlerdendir. Tatlı olarak \"Mersin baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Mersin lokumu\", \"cezerye\" (havuç, ceviz, hindistan cevizi, şeker, Mersin\'e özgü tatlı) ve \"kar helvası\" öne çıkar.', 'Mersin\'de birçok festival düzenlenmektedir. En önemlileri Uluslararası Mersin Müzik Festivali (ekim ayında), Uluslararası Mersin Turizm ve Kültür Festivali (mayıs), Uluslararası Tarsus Kültür ve Sanat Festivali (eylül), Uluslararası Silifke Kültür ve Sanat Festivali (ağustos), Uluslararası Anamur Muz Festivali (ekim), Uluslararası Mut Alahan Manastırı Kültür ve Sanat Festivali (temmuz), Uluslararası Kızkalesi Kültür ve Sanat Festivali (ağustos) ve Mersin Cezerye Festivali (kasım).', 'Mersin\'i ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 20-30 derece arasındadır; tarihi yapıları, plajları ve doğa yürüyüşleri için idealdir. Yaz aylarında (haziran-eylül) sıcaklık 35-40 dereceye ulaşabilir, nem oranı yüksektir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 10-18 derece arasındadır.', 'Mersin\'e hava yoluyla Adana Şakirpaşa Havalimanı (70 km) veya Çukurova Uluslararası Havalimanı (yeni) ile ulaşılır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Adana, Antalya, Gaziantep, Konya, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Şanlıurfa, Hatay, Osmaniye, Kahramanmaraş, Niğde, Nevşehir, Aksaray, Karaman, Kırıkkale, Yozgat, Çorum, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır gibi büyük illere seferler vardır. Mersin, demiryolu hattı üzerinde olup Adana, Ankara, Kayseri, Sivas, Malatya, Elazığ, Diyarbakır, Batman, Kurtalan, Gaziantep, İskenderun, Toprakkale gibi yerlere tren bağlantısı vardır. Mersin Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri, taksi ve deniz otobüsü (Mersin-Taşucu hattı) kullanılır. Tarsus, Silifke, Anamur, Erdemli, Mezitli, Mut, Bozyazı, Aydıncık, Çamlıyayla, Gülnar ilçelerine minibüslerle ulaşım vardır. Kız Kalesi, Tarsus Şelalesi, Silifke Kalesi, Mamure Kalesi, Kanlıdivane, Soloi-Pompeiopolis, Heaven & Hell, Cennet-Cehennem Obruğu, Alahan Manastırı gibi yerlere araç kiralamak veya turları tercif etmek önerilir.', 'Mersin, tarihi boyunca Hititler, Asurlular, Persler, Romalılar, Bizanslılar, Selçuklular, Memluklular, Karamanoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kilikya bölgesinin önemli liman kentlerinden biri olan Mersin, Roma döneminde \"Zephyrium\" adıyla anılmıştır. 19. yüzyılda pamuk ve tahıl ticaretinin gelişmesiyle birlikte hızla büyüyen Mersin, 1888 yılında Adana\'ya bağlı bir ilçe, 1924 yılında ise il statüsü kazanmıştır. Günümüzde Mersin, Türkiye\'nin en önemli liman kentlerinden biri olup, Akdeniz Bölgesi\'nin ticaret, sanayi ve turizm merkezlerindendir. Tarsus ilçesi, Aziz Pavlus\'un doğum yeri olması nedeniyle Hristiyanlık tarihi açısından büyük öneme sahiptir.', 'Mersin', '2026-04-08 23:20:51'),
(61, 'Nevşehir', 'İç Anadolu', 'nevsehir.jpg', 'Kapadokya ile ünlü.', 'Nevşehir denince akla gelen ilk simge, Kapadokya\'nın simgesi haline gelmiş Peribacaları\'dır (Ürgüp, Göreme, Uçhisar, Avanos, İbrahimpaşa köyleri). Bu eşsiz kaya oluşumları, volkanik tüflerin erozyonuyla oluşmuş ve dünyanın en ilginç doğal oluşumları arasında yer almaktadır. Göreme Açık Hava Müzesi (UNESCO Dünya Mirası Listesi), kayalara oyulmuş kiliseleri, şapelleri, yemekhaneleri ve freskleriyle erken Hristiyanlık dönemine ışık tutar. Kaymaklı Yeraltı Şehri ve Derinkuyu Yeraltı Şehri (Türkiye\'nin en büyük yeraltı şehirleri), 8 katlı, 85 metre derinliğinde, mutfaklar, şarap mahzenleri, ahırlar, kiliseler, havalandırma bacaları ve su kuyularıyla etkileyicidir. Ürgüp ilçesi (Ürgüp Evleri (tarihi taş evler), Ürgüp Kalesi (Temenni Tepesi), Ürgüp Şarap Mahzenleri, Peribacaları), Göreme ilçesi (Göreme Açık Hava Müzesi, Göreme Kalesi, Göreme Panaroması), Uçhisar ilçesi (Uçhisar Kalesi (bölgenin en yüksek noktası, manzara), Peribacaları, Güvercinlik Vadisi), Avanos ilçesi (Kızılırmak Nehri, çömlekçilik atölyeleri, Avanos Çarşısı, El Sanatları), Çavuşin (Çavuşin Kilisesi), Ortahisar (Ortahisar Kalesi), Ihlara Vadisi (Güzelyurt, Aksaray sınırında, 14 km uzunluğunda vadi, kaya kiliseleri, yürüyüş parkuru, manzara), Zelve Açık Hava Müzesi (Peribacaları, kaya oyma kiliseler, evler), Paşabağları (Rahipler Vadisi, peribacaları), Devrent Vadisi (Hayal Vadisi, hayvan şeklinde peribacaları), Kızılçukur Vadisi, Güllüdere Vadisi, Akvadi, Kızılırmak Nehri, Hacı Bektaş-ı Veli Müzesi (Hacıbektaş ilçesi, Hacı Bektaş-ı Veli\'nin türbesi, dergah, müze) ve Nevşehir Kalesi şehrin önemli duraklarıdır. Nevşehir, ayrıca el dokuması halıları (Kapadokya halıları), çömlekçiliği (Avanos), onyx taşı işlemeciliği ve şarapçılığı (Kapadokya şarapları) ile de ünlüdür.', 'Nevşehir mutfağı, Kapadokya ve İç Anadolu mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Nevşehir testi kebabı\" (et, sebze, baharat, testide pişirilir) gelir. \"Nevşehir köftesi\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"Nevşehir peyniri\" (tulum), \"Nevşehir yoğurdu\", \"Nevşehir balı\", \"Nevşehir patatesi\" (bölgede yetişen meşhur patates), \"Nevşehir üzümü\", \"Nevşehir elması\", \"Nevşehir kayısısı\" yöresel lezzetlerdendir. Tatlı olarak \"Nevşehir baklavası\", \"kadayıf\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Nevşehir lokumu\" öne çıkar.', 'Nevşehir\'de birçok festival düzenlenmektedir. En önemlileri Uluslararası Kapadokya Kültür ve Sanat Festivali (ağustos-eylül, Göreme Açık Hava Müzesi, peribacaları arasında konserler, sergiler), Uluslararası Nevşehir Testi Kebabı Festivali (eylül), Uluslararası Hacı Bektaş-ı Veli Anma Törenleri (ağustos, Hacıbektaş ilçesinde), Uluslararası Avanos Çömlekçilik Festivali (temmuz), Uluslararası Ürgüp Şarap Festivali (ekim), Uluslararası Ihlara Vadisi Kültür ve Doğa Festivali (mayıs), Nevşehir Kültür ve Sanat Festivali (haziran) ve Nevşehir Balon Festivali (ağustos).', 'Nevşehir\'i ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; peribacaları, yeraltı şehirleri ve kaya kiliselerini gezmek için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, sıcak ve kuraktır. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşer; kış aylarında Kapadokya\'nın karla kaplı peri bacaları ayrı bir güzellik sunar.', 'Nevşehir\'e hava yoluyla Nevşehir Kapadokya Havalimanı (NAV) (30 km) veya Kayseri Erkilet Havalimanı (ASR) (75 km) ile ulaşılır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Kayseri, Konya, Aksaray, Niğde, Kırşehir, Yozgat, Çorum, Samsun, Amasya, Tokat, Sivas, Malatya, Elazığ, Diyarbakır, Gaziantep, Adana, Mersin, Antalya, Denizli, Manisa, Balıkesir, Bursa, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Kayseri veya Kırşehir\'dedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ürgüp, Göreme, Uçhisar, Avanos, Hacıbektaş, Derinkuyu, Kaymaklı, Gülşehir, Kozaklı, Acıgöl, Çardak ilçelerine minibüslerle ulaşım vardır. Peribacaları, Göreme Açık Hava Müzesi, Kaymaklı Yeraltı Şehri, Derinkuyu Yeraltı Şehri, Ürgüp, Uçhisar Kalesi, Avanos, Ihlara Vadisi, Hacı Bektaş-ı Veli Müzesi gibi yerlere araç kiralamak veya turları tercih etmek önerilir. Kapadokya\'da sıcak hava balon turu yapmak da unutulmaması gereken bir deneyimdir.', 'Nevşehir, tarihi boyunca Hititler, Asurlular, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi Kapadokya\'nın kalbi olarak bilinir. Antik dönemde \"Nyssa\" adıyla anılan şehir, erken Hristiyanlık döneminde önemli bir sığınak ve keşiş merkezi olmuştur. 18. yüzyılda Nevşehirli Damat İbrahim Paşa (Lale Devri sadrazamı) tarafından imar edilen şehir, günümüzdeki adını almıştır. Cumhuriyet döneminde il statüsü kazanan Nevşehir, günümüzde Kapadokya bölgesinin en önemli turizm merkezlerinden biridir. Peribacaları, yeraltı şehirleri, kaya kiliseleri ve peri masalı gibi doğal oluşumlarıyla dünyaca ünlüdür.', 'Nevşehir', '2026-04-08 23:20:51'),
(62, 'Niğde', 'İç Anadolu', 'nigde.jpg', 'Aladağlar ile ünlü.', 'Niğde denince akla gelen ilk simge, şehir merkezinde yükselen Niğde Kalesi\'dir. Selçuklu ve Osmanlı dönemlerinden izler taşıyan bu kale, surları ve manzarasıyla dikkat çeker. Alaeddin Camii (1223), Selçuklu dönemine ait taş işçiliği ve çinileriyle önemli bir eserdir. Sungur Bey Camii (1335), Ak Medrese (1410, günümüzde Niğde Müzesi), Hüdavend Hatun Türbesi (1312), Gündoğdu Türbesi ve Niğde Müzesi (arkeolojik ve etnografik eserler, Roma ve Bizans dönemi mozaikleri, Hitit eserleri) şehrin önemli tarihi duraklarıdır. Gümüşler Manastırı (Gümüşler ilçesi, 10-11. yüzyıl, Bizans dönemi, kaya oyma kilise, yemekhane, şarap mahzeni, freskler (dünyaca ünlü \"Gülen Meryem\" freski)), Eski Gümüşler Yeraltı Şehri (Kapadokya bölgesindeki önemli yeraltı şehirlerinden biri) mutlaka görülmelidir. Çiftehan Kaplıcaları (termal su, fizik tedavi), Aladağlar Milli Parkı (Niğde\'nin doğusunda, doğa yürüyüşleri, kamp, dağcılık, kış sporları, manzara), Bolkar Dağları, Karanfilli Dere, Çukurbağ Köyü (tarihi taş evler), Fertek Köyü (tarihi Rum evleri, kilise kalıntıları) ve Kemerhisar (antik Tyana kenti, Roma su kemerleri, köprü, havuz) doğa ve tarih severler için ilgi çekicidir. Niğde, ayrıca elması (Niğde elması, Türkiye\'nin en kaliteli elmalarından), patatesi ve ceviziyle de ünlüdür.', 'Niğde mutfağı, İç Anadolu mutfağının zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Niğde köftesi\" gelir. \"Niğde tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"Niğde peyniri\" (tulum), \"Niğde yoğurdu\", \"Niğde balı\", \"Niğde elması\", \"Niğde patatesi\", \"Niğde üzümü\", \"Niğde cevizi\", \"Niğde bademi\" yöresel lezzetlerdendir. Tatlı olarak \"Niğde baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Niğde lokumu\", \"Niğde elma tatlısı\" ve \"Niğde pestili\" öne çıkar.', 'Niğde\'de en önemli etkinlik, her yıl ağustos ayında düzenlenen Uluslararası Niğde Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, elma ve patates yarışmaları, panayır ve sergiler düzenlenir. Ayrıca Uluslararası Aladağlar Doğa Sporları Festivali (temmuz), Gümüşler Manastırı Kültür ve Sanat Festivali (eylül), Niğde Elma Festivali (ekim), Çiftehan Kaplıca ve Termal Turizm Festivali (nisan) ve Niğde Yayla Şenlikleri (yaz aylarında) düzenlenmektedir.', 'Niğde\'yi ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, kaleleri, yeraltı şehirlerini ve Aladağları gezmek için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşebilir.', 'Niğde\'ye hava yoluyla en yakın havalimanı Nevşehir Kapadokya Havalimanı (130 km) veya Kayseri Erkilet Havalimanı (140 km) kullanılır. Şehirlerarası otobüs terminalinden Ankara, İstanbul, İzmir, Bursa, Kayseri, Konya, Aksaray, Nevşehir, Adana, Mersin, Antalya, Gaziantep gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Bor, Çamardı, Ulukışla, Altunhisar, Çiftlik ilçelerine minibüslerle ulaşım vardır. Aladağlar, Gümüşler Manastırı, Niğde Kalesi, Çiftehan Kaplıcaları gibi yerlere araç kiralamak önerilir.', 'Niğde, tarihi boyunca Hititler, Asurlular, Frigler, Kimmerler, Persler, Romalılar, Bizanslılar, Selçuklular, Karamanoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kapadokya bölgesinin güneyinde yer alan Niğde, Roma döneminde \"Nakida\" adıyla anılmıştır. Selçuklu döneminde önemli bir ticaret merkezi haline gelen şehir, bu dönemde inşa edilen Alaeddin Camii, Sungur Bey Camii ve Ak Medrese gibi eserlerle donatılmıştır. 1470 yılında Fatih Sultan Mehmet tarafından Osmanlı topraklarına katılan Niğde, Cumhuriyet döneminde il statüsü kazanmıştır. Niğde, günümüzde tarihi yapıları, yeraltı şehirleri, doğal güzellikleri ve elmalarıyla öne çıkan bir İç Anadolu ilidir.', 'Niğde', '2026-04-08 23:20:51'),
(63, 'Ordu', 'Karadeniz', 'ordu.jpg', 'Fındığı ile ünlü.', 'Ordu denince akla gelen ilk simge, Boztepe\'dir. Ordu merkeze hakim bu tepeden şehir ve Karadeniz manzarası izlenebilir, teleferikle çıkılır. Ordu\'nun yaylaları, özellikle Keyfalan Yaylası, Çambaşı Yaylası, Perşembe Yaylası, Aybastı Yaylası (Korgan Yaylası), Çambaşı Yaylası\'nda kış sporları (Çambaşı Kayak Merkezi) ve doğa yürüyüşleri yapılabilir. Ordu Kalesi (Bayramlı Köyü), Bizans ve Pontus döneminden kalma surları ve manzarasıyla dikkat çeker. Taşbaşı Kültür Merkezi (eski kilise), Paşaoğlu Konağı, Etnografya Müzesi, Ordu Müzesi (arkeolojik ve etnografik eserler) tarih meraklıları için önemli duraklardır. Ünye ilçesi (Ünye Kalesı, Ünye Plajı, Çakırtepe, Ünye Evleri), Fatsa ilçesi (Fatsa Kalesi, Fatsa Plajı, Yalıköy, Bolaman Kalesi), Perşembe ilçesi (Perşembe Plajı, Yason Burnu (Yason Kilisesi, deniz feneri, manzara), Aybastı ilçesi (Aybastı Yaylası, Perşembe Yaylası), Gölköy ilçesi (Ulubey Yaylası), Korgan ilçesi (Korgan Yaylası), Kumru ilçesi (Kumru Yaylası), Mesudiye ilçesi (Mesudiye Yaylaları), Ulubey ilçesi (Ulubey Kanyonu, doğa yürüyüşleri, kamp), Çatalpınar ilçesi (Çatalpınar Şelalesi) ve Kabataş ilçesi (Kabataş Yaylası) doğa ve tarih severler için ilgi çekicidir. Ordu, ayrıca fındık bahçeleri (fındık hasadı ağustos-eylül aylarında), fındık kırma tesisleri ve Ordu fındığıyla ünlüdür.', 'Ordu mutfağı, Karadeniz mutfağının zengin ve lezzetli örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"Ordu fındığı\" (dünyaca ünlü, yağlı fındık, Ordu fındığı) gelir. \"Ordu köftesi\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"çiroz\" (tuzlanmış hamsi), \"Ordu peyniri\", \"Ordu yoğurdu\", \"Ordu balı\", \"Ordu elması\", \"Ordu kirazı\", \"Ordu üzümü\" yöresel lezzetlerdendir. Tatlı olarak \"Ordu baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Ordu lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı helva\", \"fındıklı dondurma\" ve \"kestane şekeri\" öne çıkar.', 'Ordu\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Ordu Kültür ve Sanat Festivali (ağustos), Uluslararası Keyfalan Yaylası Kültür ve Turizm Festivali (temmuz), Uluslararası Çambaşı Yaylası Kış Sporları Festivali (şubat), Ordu Fındık Festivali (eylül), Ünye Kültür ve Sanat Festivali (temmuz), Fatsa Kültür ve Sanat Festivali (ağustos), Perşembe Yason Burnu Kültür ve Turizm Festivali (haziran), Aybastı Yayla Şenliği (temmuz), Ulubey Kanyonu Doğa Sporları Festivali (mayıs) ve Ordu Turizm ve Lezzet Festivali (ekim).', 'Ordu\'yu ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; yaylalar yeşildir, doğa yürüyüşleri, yayla şenlikleri ve fındık bahçeleri için idealdir. Sonbahar aylarında yaprakların renklendiği dönem de güzeldir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 3-10 derece arasındadır, zaman zaman kar yağışı görülür (yüksek yaylalarda).', 'Ordu\'ya hava yoluyla Ordu-Giresun Havalimanı (OGU) ile ulaşılır. Havalimanı şehir merkezine 20 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Samsun, Trabzon, Rize, Giresun, Gümüşhane, Bayburt, Erzurum, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Erzincan, Tokat, Amasya, Çorum, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ünye, Fatsa, Perşembe, Aybastı, Gölköy, Korgan, Kumru, Mesudiye, Ulubey, Çatalpınar, Kabataş, İkizce, Akkuş ilçelerine minibüslerle ulaşım vardır. Boztepe (teleferik), Keyfalan Yaylası, Çambaşı Yaylası, Ordu Kalesi, Taşbaşı Kültür Merkezi, Yason Burnu, Ulubey Kanyonu, fındık bahçeleri gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Ordu, tarihi boyunca Kolhitler, Kimmerler, İskitler, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Pontus bölgesinin önemli merkezlerinden biri olan Ordu, Roma döneminde \"Cotyora\" adıyla anılmıştır. 13. yüzyılda Selçukluların eline geçen bölge, 15. yüzyılda Osmanlı topraklarına katılmıştır. Cumhuriyet döneminde il statüsü kazanan Ordu, günümüzde fındığı, yaylaları, tarihi yapıları ve doğal güzellikleriyle öne çıkan bir Karadeniz ilidir. Ordu, Türkiye\'nin en önemli fındık üretim merkezlerinden biridir.', 'Ordu', '2026-04-08 23:20:51'),
(64, 'Osmaniye', 'Akdeniz', 'osmaniye.jpg', 'Karatepe ile ünlü.', 'Osmaniye denince akla gelen ilk simge, Karatepe-Aslantaş Açık Hava Müzesi\'dir (Kadirli ilçesi). UNESCO Dünya Mirası Geçici Listesi\'nde yer alan bu alan, Geç Hitit dönemine ait açık hava tapınağı, kaya kabartmaları, aslan ve sfenks heykelleri, fenike alfabesiyle yazılmış tabletleriyle büyük öneme sahiptir. Osmaniye Kalesi (Kale-i Marvan), şehir merkezinde yükselen ve tarihi Bizans, Memluklu ve Osmanlı dönemlerinden izler taşıyan bir yapıdır. Toprakkale (Tarihi Toprakkale Kalesi), Osmaniye\'nin Toprakkale ilçesinde yer alır. Haruniye Kaplıcaları (Düziçi ilçesi, termal su, şifalı su, antik dönemden beri kullanılan kaplıcalar), Yarpuz Kaplıcaları, Zorkun Yaylası (Düziçi ilçesi, doğa yürüyüşleri, kamp, yayla şenlikleri), Cebel-i Bereket (Nur Dağları), Aslantaş Barajı (doğa, piknik), Altıngözü Mesire Alanı, Akçalar Şelalesi ve Savranda Kalesi doğa ve tarih severler için ilgi çekicidir. Kadirli ilçesi (Kadirli Ulu Cami (Kadirli Ulu Camii, 14. yüzyıl), Kadirli Kalesi, Kadirli Müzesi), Düziçi ilçesi (Haruniye Kaplıcaları, Zorkun Yaylası, Amanos Dağları), Bahçe ilçesi (Bahçe Kalesi, Bahçe Yaylaları), Sumbas ilçesi (Sumbas Şelalesi), Toprakkale ilçesi (Toprakkale Kalesi), Hasanbeyli ilçesi, Osmaniye\'nin diğer önemli ilçeleridir. Osmaniye, ayrıca yer fıstığı (Osmaniye yer fıstığı, Türkiye\'nin en kaliteli yer fıstığı), susam, tahin, pekmez, Osmaniye işi (el dokuması), halıcılık ve bakır işlemeciliğiyle de ünlüdür.', 'Osmaniye mutfağı, Akdeniz ve Çukurova mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Osmaniye köftesi\" gelir. \"Osmaniye tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"içli köfte\", \"mercimek köftesi\", \"humus\", \"babağannuş\", \"muhammara\", \"kısır\", \"acılı ezme\", \"zeytinyağlı enginar\", \"zeytinyağlı taze fasulye\", \"Osmaniye peyniri\", \"Osmaniye yoğurdu\", \"Osmaniye balı\", \"Osmaniye yer fıstığı\", \"Osmaniye susamı\", \"Osmaniye tahini\", \"Osmaniye pekmezi\" yöresel lezzetlerdendir. Tatlı olarak \"Osmaniye baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Osmaniye lokumu\", \"tahinli sarma\" ve \"susamlı çörek\" öne çıkar.', 'Osmaniye\'de en önemli etkinlik, her yıl temmuz ayında düzenlenen Uluslararası Osmaniye Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, yer fıstığı yarışmaları, el sanatları sergileri, panayır, kortej ve doğa yürüyüşleri düzenlenir. Ayrıca Uluslararası Karatepe-Aslantaş Kültür ve Sanat Festivali (eylül), Haruniye Kaplıca ve Termal Turizm Festivali (nisan), Zorkun Yaylası Kültür ve Doğa Festivali (temmuz), Kadirli Kültür ve Sanat Festivali (ağustos) ve Osmaniye Yer Fıstığı Festivali (ekim) düzenlenmektedir.', 'Osmaniye\'yi ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; tarihi yapıları, kaleleri ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 35-40 dereceye ulaşabilir, sıcak ve nemlidir. Kışlar ılımandır, sıcaklık genelde 8-15 derece arasındadır, yağışlı olabilir.', 'Osmaniye\'ye hava yoluyla Adana Şakirpaşa Havalimanı (100 km) veya Hatay Havalimanı (80 km) kullanılır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Adana, Mersin, Gaziantep, Hatay, Kahramanmaraş, Niğde, Kayseri, Konya, Aksaray, Nevşehir, Kırşehir, Yozgat, Çorum, Samsun, Tokat, Sivas, Malatya, Elazığ, Diyarbakır, Şanlıurfa, Mardin, Batman, Siirt, Hakkari, Van, Muş, Bitlis, Ağrı, Kars, Erzurum, Erzincan, Trabzon, Rize, Artvin, Giresun, Ordu, Samsun, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı vardır (Osmaniye Tren Garı). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kadirli, Düziçi, Bahçe, Toprakkale, Sumbas, Hasanbeyli ilçelerine minibüslerle ulaşım vardır. Karatepe-Aslantaş Açık Hava Müzesi, Osmaniye Kalesi, Haruniye Kaplıcaları, Zorkun Yaylası, Toprakkale Kalesi gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Osmaniye, tarihi boyunca Hititler, Asurlular, Persler, Romalılar, Bizanslılar, Memluklular, Dulkadiroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kilikya bölgesinin önemli merkezlerinden biri olan Osmaniye, Roma döneminde \"Flavias\" veya \"Neronias\" adıyla anılmıştır. 1515 yılında Yavuz Sultan Selim tarafından Osmanlı topraklarına katılan bölge, Cumhuriyet döneminde önce Adana\'ya bağlanmış, 1996 yılında il statüsü kazanarak Türkiye\'nin en genç illerinden biri olmuştur. Osmaniye, günümüzde yer fıstığı, şeker pancarı, mısır, pamuk tarımı ve tarihi yapılarıyla öne çıkan bir Akdeniz ilidir.', 'Osmaniye', '2026-04-08 23:20:51'),
(65, 'Rize', 'Karadeniz', 'rize.jpg', 'Çayı ile ünlü.', 'Rize denince akla gelen ilk simge, çaydır. Rize Çay Bahçeleri (Çaykur Fabrikaları, çay üretim tesisleri, çay tadım atölyeleri, çay alışverişi) ziyaret edilebilir. Rize Kalesi, şehir merkezinde yükselen Bizans ve Osmanlı dönemlerinden izler taşıyan surları ve manzarasıyla dikkat çeker. Rize Müzesi (arkeolojik ve etnografik eserler, yöresel kıyafetler, çay tarihi), Ziraat Botanik Parkı (Rize\'nin bitki örtüsü, çay bahçeleri, manzara), Rize Çarşısı (yöresel ürünler, çay, bal, peynir, el sanatları) görülmelidir. Rize\'nin yaylaları: Ayder Yaylası (Çamlıhemşin ilçesi, Rize\'nin en ünlü yaylası, kaplıcaları (Ayder Kaplıcaları), yayla evleri, doğa yürüyüşleri, kamp, manzara), Pokut Yaylası (sisli atmosferi, manzarasıyla ünlü), Elevit Yaylası, Samistal Yaylası, Hazindağ Yaylası, Verçenik Yaylası, Anzer Yaylası (Anzer Balı ile ünlü, dünyaca ünlü Anzer balı, yayla şenlikleri), Ovit Yaylası (Rize-İkizdere arası, yüksek rakım, manzara), Sal Yaylası, Çat Yaylası, Başköy Yaylası, Zil Kale (Çamlıhemşin, 15. yüzyılda yapılan kale, manzara), Fırtına Deresi (Fırtına Vadisi, rafting, kano, doğa yürüyüşleri, kamp), Palovit Şelalesi (Çamlıhemşin, yüksekten dökülen şelale, doğa harikası), Gito Yaylası, Çiftehöyük Şelalesi, İkizdere (İkizdere ilçesi, Anzer Yaylası, Ovit Yaylası, doğa), Çamlıhemşin ilçesi (Çamlıhemşin Kalesi, Zil Kale, Fırtına Vadisi, Ayder Yaylası, yayla evleri, taş evler), Ardeşen ilçesi (Ardeşen Plajı, Ardeşen Kalesi), Pazar ilçesi (Pazar Plajı, Pazar Kalesi), Fındıklı ilçesi (Fındıklı Plajı), Güneysu ilçesi, Kalkandere ilçesi, Derepazarı ilçesi, İkizdere ilçesi (İkizdere Yaylaları), Hemşin ilçesi, Çayeli ilçesi (Çayeli Plajı, Çayeli Kalesi), İyidere ilçesi, Rize\'nin diğer önemli ilçeleridir. Rize, ayrıca Anzer balı, Rize çayı, kendir (kenevir) ürünleri (el dokuması bebek, çanta, ip), bakır işlemeciliği, ahşap işlemeciliği ve hemşin kültürüyle de ünlüdür.', 'Rize mutfağı, Karadeniz mutfağının zengin ve eşsiz lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Rize çayı\" (dünyaca ünlü, organik, demli, Rize çay bahçelerinde yetişir) gelir. \"Rize köftesi\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı, Rize usulü), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak, mısır unu, yağ, peynirle yapılan Karadeniz lezzeti), \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"laz böreği\" (kremalı baklava), \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"çiroz\" (tuzlanmış hamsi), \"kalkan balığı\", \"çinekop\", \"levrek\", \"Rize peyniri\", \"Rize yoğurdu\", \"Rize balı\", \"Rize mısırı\", \"Rize fasulyesi\", \"Rize lahanası\", \"Rize çayı\" yöresel lezzetlerdendir. Tatlı olarak \"Rize baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Rize lokumu\", \"laz böreği\", \"kaygana\" (mısır unlu omlet benzeri), \"muhlama\" ve \"kestane şekeri\" öne çıkar.', 'Rize\'de birçok festival düzenlenmektedir. En önemlileri Uluslararası Rize Kültür ve Sanat Festivali (ağustos), Uluslararası Ayder Yaylası Kültür ve Turizm Festivali (temmuz), Uluslararası Anzer Balı ve Kültür Festivali (ağustos), Rize Çay Festivali (mayıs), Uluslararası Fırtına Vadisi Rafting Festivali (haziran), Uluslararası Çamlıhemşin Kültür ve Doğa Festivali (temmuz), İkizdere Ovit Yaylası Kültür ve Doğa Festivali (ağustos), Ardeşen Kültür ve Sanat Festivali (eylül) ve Rize Yayla Şenlikleri (yaz aylarında).', 'Rize\'yi ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; yaylalar yeşildir, çay bahçeleri hasat dönemindedir (mayıs-ekim), doğa yürüyüşleri, yayla şenlikleri ve şelaleler için idealdir. Sonbahar aylarında yaprakların renklendiği dönem de güzeldir. Kışlar yağışlı ve soğuktur, sıcaklık genelde 2-8 derece arasındadır, yüksek yaylalarda kar yağışı görülür.', 'Rize\'ye hava yoluyla Trabzon Havalimanı (TZX) (70 km) kullanılır. Havalimanından havaş otobüsleri ve taksi ile Rize\'ye ulaşılır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Trabzon, Giresun, Ordu, Samsun, Artvin, Ardahan, Erzurum, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Kars, Ardahan, Artvin, Gümüşhane, Bayburt, Tokat, Amasya, Çorum, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Çamlıhemşin, Ardeşen, Pazar, Fındıklı, Güneysu, Kalkandere, Derepazarı, İkizdere, Hemşin, Çayeli, İyidere ilçelerine minibüslerle ulaşım vardır. Ayder Yaylası, Pokut Yaylası, Anzer Yaylası, Palovit Şelalesi, Fırtına Deresi, Zil Kale, Rize Kalesi, Rize Müzesi, çay bahçeleri gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Rize, tarihi boyunca Kolhitler, Kimmerler, İskitler, Persler, Romalılar, Bizanslılar, Trabzon İmparatorluğu ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Pontus bölgesinin önemli merkezlerinden biri olan Rize, Roma döneminde \"Rhizus\" adıyla anılmıştır. 1461 yılında Fatih Sultan Mehmet\'in Trabzon\'u fethetmesinin ardından Osmanlı topraklarına katılan Rize, Cumhuriyet döneminde il statüsü kazanmıştır. Rize, günümüzde Türkiye\'nin en önemli çay üretim merkezidir. Yeşilin her tonunun bulunduğu doğası, yaylaları, şelaleleri ve çay bahçeleriyle ünlüdür.', 'Rize', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(66, 'Sakarya', 'Marmara', 'sakarya.jpg', 'Sapanca Gölü ile ünlü.', 'Sakarya denince akla gelen ilk simge, Sakarya Nehri ve Sapanca Gölü\'dür. Sapanca Gölü (Sapanca ilçesi, doğal güzellik, yürüyüş yolları, bisiklet yolları, piknik alanı, balık tutma, sandal gezisi, manzara, göl kenarında restoranlar, kafeler, oteller) mutlaka görülmelidir. Sakarya\'nın plajları: Karasu Plajı (Karasu ilçesi, Karadeniz sahili, kum plaj, dalgalar), Kocaali Plajı, Kaynarca Plajı, Söğütlü Plajı, Akçay Plajı yaz aylarında yoğun ilgi görür. Sakarya\'nın yaylaları: Acelle Yaylası (Taraklı ilçesi), Keremali Yaylası (Taraklı ilçesi, manzara, doğa yürüyüşü, yayla şenlikleri), Mahmudiye Yaylası, Çamdağı Yaylası, Çiğdem Yaylası, Koca Yayla, Kırkgöz Yaylası, Çiçekli Yaylası, Karagöl Yaylası, Sakarya\'nın yaylaları doğa severler için idealdir. Sakarya\'nın şelaleleri: Kuzuluk Şelalesi (Kuzuluk Kaplıcaları yakınında), Maden Deresi Şelalesi (Kocaali), Acarlar Longozu (Karacaköy, sulak alan, yürüyüş yolları, kuş gözlem, doğa fotoğrafçılığı), Ormanya (Kartepe, doğal yaşam parkı, yürüyüş yolları, hayvanat bahçesi, piknik alanı, manzara), Kartepe (Kartepe Kayak Merkezi, kış sporları, doğa yürüyüşleri, manzara, Sapanca Gölü manzarası), Taraklı ilçesi (Taraklı Evleri (tarihi Osmanlı evleri), Taraklı Kalesi, Taraklı Müzesi, Taraklı Çarşısı (el sanatları, yöresel ürünler), Taraklı Yaylaları), Geyve ilçesi (Geyve Boğazı, Geyve Kirazı, Geyve Menderesleri), Pamukova ilçesi (Pamukova Kirazı, Pamukova Yaylaları), Hendek ilçesi (Hendek Kalesi, Hendek Yaylaları), Akyazı ilçesi (Akyazı Kalesi, Akyazı Yaylaları), Sapanca ilçesi (Sapanca Gölü, Sapanca Yaylaları, Sapanca Evleri), Serdivan ilçesi, Erenler ilçesi, Adapazarı ilçesi (Sakarya Müzesi (arkeolojik ve etnografik eserler), Sakarya Meydan Muharebesi Müzesi, Atatürk Evi Müzesi, Adapazarı Merkez), Karasu ilçesi (Karasu Plajı, Karasu Feneri, Karasu Limanı), Kocaali ilçesi (Kocaali Plajı, Kocaali Feneri), Söğütlü ilçesi, Ferizli ilçesi, Kaynarca ilçesi, Karapürçek ilçesi, Sakarya\'nın diğer önemli ilçeleridir. Sakarya, ayrıca Kuzuluk Kaplıcaları (termal su, fizik tedavi, romatizma, cilt hastalıkları) ve Sakarya\'nın el sanatları (taraklı işi (ahşap), bakır işlemeciliği, halıcılık, kilim dokumacılığı) ile de ünlüdür.', 'Sakarya mutfağı, Marmara ve Karadeniz mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Sakarya köftesi\" gelir. \"Islama köfte\" (ekmek üzerine köfte, domates sos, yoğurt, tereyağı), \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"hamsi tava\", \"hamsi buğulama\", \"Sakarya peyniri\", \"Sakarya yoğurdu\", \"Sakarya balı\", \"Sakarya fındığı\", \"Sakarya mısırı\", \"Sakarya fasulyesi\", \"Sakarya elması\", \"Sakarya kirazı\", \"Sakarya üzümü\" yöresel lezzetlerdendir. Tatlı olarak \"Sakarya baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Sakarya lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"Sakarya macunu\" ve \"Sakarya şekeri\" öne çıkar.', 'Sakarya\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Sapanca Gölü Kültür ve Sanat Festivali (ağustos), Uluslararası Sakarya Kültür ve Sanat Festivali (eylül), Uluslararası Taraklı Kültür ve Sanat Festivali (temmuz), Uluslararası Kartepe Kış Sporları Festivali (şubat), Sakarya Yayla Şenlikleri (temmuz-ağustos), Karasu Kültür ve Turizm Festivali (ağustos), Kocaali Kültür ve Turizm Festivali (temmuz), Geyve Kiraz Festivali (haziran), Pamukova Kiraz Festivali (haziran), Kuzuluk Kaplıca ve Termal Turizm Festivali (nisan), Acarlar Longozu Doğa Festivali (mayıs) ve Sakarya Ormanya Doğa Sporları Festivali (ekim).', 'Sakarya\'yı ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-30 derece arasındadır; göl, plaj, yayla, şelale ve doğa yürüyüşleri için idealdir. Sonbahar aylarında yaprakların renklendiği dönem de güzeldir. Kışlar soğuk ve yağışlıdır, sıcaklık genelde 2-10 derece arasındadır, zaman zaman kar yağışı görülür.', 'Sakarya\'ya hava yoluyla en yakın havalimanı İstanbul Sabiha Gökçen Havalimanı\'dır (130 km). Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Kocaeli, Bolu, Düzce, Zonguldak, Karabük, Bartın, Kastamonu, Sinop, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin, Erzurum, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman gibi büyük illere seferler vardır. Demiryolu bağlantısı vardır; Sakarya Tren Garı (Adapazarı Garı) ile Yüksek Hızlı Tren (YHT) ile İstanbul, Ankara, Eskişehir, Konya, Karaman, Sivas\'a bağlantı vardır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Sapanca, Karasu, Kocaali, Kaynarca, Söğütlü, Ferizli, Karapürçek, Geyve, Pamukova, Hendek, Akyazı, Taraklı, Serdivan, Erenler ilçelerine minibüslerle ulaşım vardır. Sapanca Gölü, Karasu Plajı, Taraklı Evleri, Kuzuluk Kaplıcaları, Acarlar Longozu, Kartepe, Ormanya gibi yerlere araç kiralamak önerilir.', 'Sakarya, tarihi boyunca Bitinler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Bitinya bölgesinin önemli merkezlerinden biri olan Sakarya, Roma döneminde \"Agrilion\" adıyla anılmıştır. 13. yüzyılda Selçukluların, ardından Osmanlıların egemenliğine giren bölge, Cumhuriyet döneminde il statüsü kazanmıştır. Sakarya, adını il sınırlarından geçen Sakarya Nehri\'nden almıştır. Kurtuluş Savaşı\'nda Sakarya Meydan Muharebesi (23 Ağustos - 13 Eylül 1921) bu topraklarda kazanılmıştır. Günümüzde Sakarya, Türkiye\'nin önemli sanayi merkezlerinden biri olup, otomotiv, kağıt, metal, gıda ve tekstil sektörlerinde öne çıkmaktadır.', 'Sakarya', '2026-04-08 23:20:51'),
(67, 'Samsun', 'Karadeniz', 'samsun.jpg', 'Bandırma Vapuru ile ünlü.', 'Samsun denince akla gelen ilk simge, Kurtuluş Savaşı\'nın başladığı yer olan Onur Anıtı (Atatürk Anıtı) ve Bandırma Vapuru\'nun sergilendiği Bandırma Vapuru Müzesi\'dir. Atatürk\'ün Samsun\'a çıktığı 19 Mayıs 1919\'u simgeleyen bu alan, Samsun\'un en önemli tarihi noktasıdır. Samsun\'daki diğer önemli müzeler: Gazi Müzesi (Atatürk\'ün Samsun\'da kaldığı ev), Arkeoloji ve Etnografya Müzesi (Amisos eserleri), Amazon Köyü (Amazon heykelleri, mitoloji), Amisos Tepesi (Amisos Antik Kenti kazı alanı, manzara). Samsun\'un ilçeleri: Bafra (Bafra Kalesi, Bafra Pidesi, Bafra Karpuzu, Bafra Plajı, Bafra Yaylaları, Kızılırmak Deltası Kuş Cenneti), Çarşamba (Çarşamba Ovası, Çarşamba Pidesi, Çarşamba Fasulyesi, Çarşamba Plajı, Çarşamba Yaylaları, Saklı Göl), Terme (Terme Pidesi, Terme Kaplıcaları, Terme Yaylaları), Havza (Havza Kaplıcaları, Atatürk Evi Müzesi, Havza Plajı), Ladik (Ladik Gölü, Ladik Kaplıcaları, Ladik Yaylaları), Vezirköprü (Vezirköprü Kalesi, Vezirköprü Evleri, Şahinkaya Kanyonu, Vezirköprü Yaylaları), Alaçam (Alaçam Yaylaları), Asarcık (Asarcık Yaylaları), Ayvacık, Salıpazarı, Tekkeköy, 19 Mayıs (19 Mayıs Plajı), İlkadım, Canik, Atakum ilçeleri. Samsun\'un plajları: Atakum Plajı (Mavi Bayrak plaj), Çarşamba Plajı, Terme Plajı, Bafra Plajı, Yörükler Plajı, Fener Plajı, Dikbıyık Plajı yaz aylarında yoğun ilgi görür. Samsun\'un yaylaları: Akdağ Yaylası (Ladik), Asarcık Yaylaları, Bafra Yaylaları, Çarşamba Yaylaları, Terme Yaylaları, Vezirköprü Yaylaları doğa severler için idealdir. Kızılırmak Deltası Kuş Cenneti (Bafra), Şahinkaya Kanyonu (Vezirköprü), Kızılırmak, Yeşilırmak, Ladik Gölü, Çakırlar Gölü, Tersakan Gölü, Sarıkum Gölü, Balık Gölü doğal güzelliklerdir.', 'Samsun mutfağı, Karadeniz mutfağının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Samsun pidesi\" (kıymalı, peynirli, kuşbaşılı, yumurtalı, ince hamur, uzun, kıtır) gelir. \"Bafra pidesi\", \"Terme pidesi\", \"Samsun köftesi\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"kuru fasulye\", \"sac kavurma\", \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"çiroz\", \"Samsun peyniri\", \"Samsun yoğurdu\", \"Samsun balı\", \"Samsun fındığı\", \"Samsun mısırı\", \"Samsun elması\", \"Samsun kirazı\", \"Bafra karpuzu\", \"Çarşamba fasulyesi\" yöresel lezzetlerdendir. Tatlı olarak \"Samsun baklavası\", \"kadayıf\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Samsun lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı dondurma\" öne çıkar.', 'Samsun\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Samsun Kültür ve Sanat Festivali (mayıs), 19 Mayıs Atatürk\'ü Anma ve Gençlik Festivali (19 Mayıs), Uluslararası Bafra Kültür ve Karpuz Festivali (ağustos), Uluslararası Çarşamba Kültür ve Turizm Festivali (eylül), Uluslararası Terme Kültür ve Sanat Festivali (temmuz), Uluslararası Havza Kaplıca ve Termal Turizm Festivali (haziran), Uluslararası Ladik Gölü Kültür ve Doğa Festivali (temmuz), Uluslararası Vezirköprü Şahinkaya Kanyonu Kültür ve Doğa Festivali (ağustos), Samsun Fındık Festivali (ağustos), Samsun Pide Festivali (ekim) ve Samsun Caz Festivali (eylül).', 'Samsun\'u ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; sahil, plajlar, yaylalar, doğa yürüyüşleri, Atatürk ve tarih rotaları için idealdir. Sonbahar ayları da güzeldir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 3-12 derece arasındadır, zaman zaman kar yağışı görülür.', 'Samsun\'a hava yoluyla Samsun Çarşamba Havalimanı (SZF) ile ulaşılır. Havalimanı şehir merkezine 20 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Ordu, Giresun, Trabzon, Rize, Artvin, Gümüşhane, Bayburt, Erzurum, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı vardır; Samsun Tren Garı ile Sivas, Amasya, Tokat, Kayseri, Ankara gibi illere tren bağlantısı vardır. Şehir içi ulaşımda tramvay (SAMULAŞ), minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Bafra, Çarşamba, Terme, Havza, Ladik, Vezirköprü, Alaçam, Asarcık, Ayvacık, Salıpazarı, Tekkeköy, 19 Mayıs, İlkadım, Canik, Atakum ilçelerine minibüslerle ulaşım vardır. Bandırma Vapuru Müzesi, Onur Anıtı, Gazi Müzesi, Amisos Tepesi, Atakum Plajı, Bafra Plajı, Kızılırmak Deltası, Şahinkaya Kanyonu, Ladik Gölü, Havza Kaplıcaları, Akdağ Yaylası gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Samsun, tarihi boyunca Kolhitler, Kimmerler, İskitler, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Amisos\" adıyla anılan şehir, Roma ve Bizans dönemlerinde önemli bir liman kenti olmuştur. 13. yüzyılda Selçukluların, 14. yüzyılda Osmanlıların egemenliğine giren Samsun, Cumhuriyet döneminde il statüsü kazanmıştır. Samsun, Türkiye Cumhuriyeti\'nin kurucusu Mustafa Kemal Atatürk\'ün 19 Mayıs 1919\'da Samsun\'a çıkarak Kurtuluş Savaşı\'nı başlattığı şehir olarak büyük öneme sahiptir. Günümüzde Samsun, Karadeniz Bölgesi\'nin en büyük şehri, önemli bir liman, sanayi, ticaret ve tarım merkezidir.', 'Samsun', '2026-04-08 23:20:51'),
(68, 'Siirt', 'Güneydoğu Anadolu', 'siirt.jpg', 'Siirt battaniyesi ile ünlü.', 'Siirt denince akla gelen ilk simge, Siirt Kalesi\'dir (Eski Siirt, İç Kale). Şehir merkezinde yükselen bu kale, Bizans, Artuklu ve Osmanlı dönemlerinden izler taşır. Ulu Cami (Siirt Ulu Cami, 1129), Artuklu dönemine ait taş işçiliği ve minaresiyle dikkat çeker. Büyük Cami, Mollakent Cami, Safiyye Cami, İplik Pazarı Cami, Siirt Evleri (tarihi taş evler, dar sokaklar, kemerli kapılar), Siirt Müzesi (arkeolojik ve etnografik eserler, Siirt fıstığı tarihi, el sanatları), Siirt Çarşısı (Bıttım sabunu, fıstık, yöresel el sanatları, bakır işlemeciliği) gezilecek yerlerdendir. Siirt\'in ilçeleri: Kurtalan (Kurtalan Kalesi, Kurtalan Ekspresi ile ünlü), Pervari (Pervari Yaylaları, Pervari Kalesi, Peri Mağarası), Şirvan (Şirvan Yaylaları, Şirvan Kalesi), Eruh (Eruh Yaylaları, Eruh Kalesi, Botan Çayı), Baykan (Baykan Yaylaları), Tillo (Tillo ilçesi, tarihi Tillo Evleri, İsmail Fakirullah Türbesi (Molla Halil Türbesi), Tillo Medresesi, Tillo Camii, manzara), Aydınlar (Tillo) (Aydınlar Evleri), Siirt\'in yaylaları (Pervari Yaylaları, Şirvan Yaylaları, Eruh Yaylaları, Baykan Yaylaları, doğa yürüyüşleri, yayla şenlikleri, kamp), Botan Çayı (doğa, piknik, balık tutma), Siirt fıstık bahçeleri (fıstık hasadı eylül-ekim aylarında), Bıttım sabunu atölyeleri (Tillo\'da ve Siirt merkezde, doğal sabun yapımı, Bıttım sabunu alışverişi), Tillo\'daki tarihi köprüler ve çeşmeler de görülmeye değerdir.', 'Siirt mutfağı, Güneydoğu Anadolu ve Mezopotamya mutfaklarının zengin ve baharatlı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Siirt fıstığı\" (dünyaca ünlü, iri taneli, yağlı, lezzetli) gelir. \"Siirt köftesi\", \"Büryan kebabı\" (kuzu etinin tandırda pişirilmesi, Siirt usulü), \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"perde pilavı\", \"içli köfte\", \"kibbe\", \"lahmacun\", \"çiğ köfte\" (etli), \"mercimek köftesi\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"Bıttım (melengiç) kahvesi\" (Bıttım sabunu yapımında da kullanılan melengiç meyvesinden yapılan kahve), \"Siirt peyniri\", \"Siirt yoğurdu\", \"Siirt balı\", \"Siirt üzümü\", \"Siirt pekmezi\", \"Siirt tarhanası\", \"Siirt kavutu\" yöresel lezzetlerdendir. Tatlı olarak \"Siirt baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Siirt lokumu\", \"fıstıklı baklava\", \"fıstıklı kadayıf\", \"fıstıklı dondurma\", \"fıstıklı helva\", \"fıstıklı sucuk\" öne çıkar.', 'Siirt\'te en önemli etkinlik, her yıl eylül ayında düzenlenen Uluslararası Siirt Fıstık ve Kültür Festivali\'dir. Festivalde Siirt fıstığı hasadı, fıstık kırma yarışmaları, fıstık tadımı, fıstıklı ürünler sergisi, Bıttım sabunu yapım atölyeleri, konserler, halk oyunları gösterileri, yöresel lezzet tadımları, panayır, sergiler ve paneller düzenlenir. Ayrıca Uluslararası Tillo Kültür ve Sanat Festivali (ağustos), Uluslararası Siirt Kültür ve Sanat Festivali (ekim), Pervari Yayla Şenlikleri (temmuz), Eruh Kültür ve Doğa Festivali (ağustos) ve Kurtalan Kültür ve Sanat Festivali (eylül) düzenlenmektedir.', 'Siirt\'i ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; tarihi yapıları, kaleleri ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 38-42 dereceye ulaşabilir, çok sıcak ve kuraktır. Kışlar soğuktur, sıcaklık genelde 0-10 derece arasındadır, yağışlı ve zaman zaman karlıdır.', 'Siirt\'e hava yoluyla Siirt Havalimanı (SXZ) ile ulaşılır. Havalimanı şehir merkezine 15 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Diyarbakır, Batman, Mardin, Şırnak, Hakkari, Van, Muş, Bitlis, Elazığ, Malatya, Gaziantep, Adana, Mersin, Konya, Kayseri, Sivas, Erzincan, Erzurum, Kars, Ardahan, Ağrı, Iğdır, Trabzon, Rize, Samsun, Sinop, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Batman veya Diyarbakır\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kurtalan, Pervari, Şirvan, Eruh, Baykan, Tillo (Aydınlar) ilçelerine minibüslerle ulaşım vardır. Siirt Kalesi, Ulu Cami, Tillo Evleri, İsmail Fakirullah Türbesi, Pervari Yaylaları, Botan Çayı, Siirt fıstık bahçeleri, Bıttım sabunu atölyeleri gibi yerlere araç kiralamak veya turları tercif etmek önerilir.', 'Siirt, tarihi boyunca Sümerler, Akadlar, Babilliler, Asurlular, Hurriler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Artuklular, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde \"Sert\" adıyla anılan şehir, önemli bir ticaret ve kültür merkezi olmuştur. 16. yüzyılda Osmanlı topraklarına katılan Siirt, Cumhuriyet döneminde il statüsü kazanmıştır. Siirt, günümüzde özellikle Siirt fıstığı (Siirt fıstığı, Antep fıstığından farklı, iri taneli, yağlı, lezzetli), Bıttım sabunu (melengiç yağından yapılan doğal sabun), tarihi yapıları ve yöresel el sanatlarıyla öne çıkan bir Güneydoğu Anadolu ilidir.', 'Siirt', '2026-04-08 23:20:51'),
(69, 'Sinop', 'Karadeniz', 'sinop.jpg', 'Tarihi cezaevi ile ünlü.', 'Sinop denince akla gelen ilk simge, Tarihi Sinop Cezaevi\'dir. 1887 yılında inşa edilen ve 1997 yılına kadar cezaevi olarak kullanılan bu yapı, ünlü yazar Sabahattin Ali\'nin de yattığı cezaevidir. Günümüzde müze olarak ziyaret edilebilen cezaevi, Sinop\'un en önemli turistik noktasıdır. Sinop Kalesi, şehir merkezinde yükselen Bizans, Candaroğulları ve Osmanlı dönemlerinden izler taşıyan surları, burçları ve manzarasıyla dikkat çeker. Sinop Müzesi (arkeolojik ve etnografik eserler, Sinop cezaevi tarihi, Diogenes heykeli, amphoralar, sikke koleksiyonu), Alaaddin Camii (Selçuklu dönemi, 1267), Pervane Medresesi (Selçuklu dönemi, 1263), Balatlar Kilisesi (Bizans dönemi, kazı alanı, mozaikler), Sinop Limanı, Sinop Adaları, Sinop Feneri, Sinop Plajları: Akliman Plajı (ince kum, Mavi Bayrak plaj), Karakum Plajı, Ayancık Plajı, Gerze Plajı, Türkeli Plajı, Sarıkum Plajı, İnceburun Plajı yaz aylarında yoğun ilgi görür. Sinop\'un ilçeleri: Boyabat (Boyabat Kalesi, Boyabat Evleri, Boyabat Yaylaları, Boyabat Plajı), Ayancık (Ayancık Plajı, Ayancık Yaylaları, Ayancık Fındığı), Gerze (Gerze Kalesi, Gerze Plajı, Gerze Yaylaları), Türkeli (Türkeli Plajı, Türkeli Yaylaları), Durağan (Durağan Kalesi, Durağan Yaylaları, Kızılırmak), Erfelek (Erfelek Şelaleleri, Erfelek Yaylaları), Dikmen (Dikmen Yaylaları), Saraydüzü (Saraydüzü Yaylaları). Sinop\'un yaylaları: Erfelek Yaylaları (Erfelek Şelaleleri, doğa yürüyüşleri, kamp, yayla şenlikleri), Boyabat Yaylaları, Ayancık Yaylaları, Gerze Yaylaları, Türkeli Yaylaları, Durağan Yaylaları, Dikmen Yaylaları, Saraydüzü Yaylaları doğa severler için idealdir. Erfelek Şelaleleri (Erfelek ilçesi, 18 şelaleden oluşan doğal güzellik, yürüyüş yolları, ahşap platformlar, manzara), Hamsilos Koyu (Sinop\'un doğal limanı, doğa harikası, yürüyüş, manzara), İnceburun (Türkiye\'nin en kuzey ucu, deniz feneri, manzara, rüzgar türbinleri), Sarıkum Gölü (kuş cenneti, doğa yürüyüşleri, kuş gözlem, piknik), Kızılırmak Deltası (kuş cenneti, doğa yürüyüşleri), Diogenes Heykeli (Sinop limanında, ünlü filozof Diogenes\'in heykeli).', 'Sinop mutfağı, Karadeniz mutfağının zengin ve lezzetli örneklerini taşır. Mutlaka denenmesi gerekenlerin başında \"Sinop köftesi\" gelir. \"Sinop mantısı\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"karalahana çorbası\" (mısır unlu, fasulyeli, karalahanalı), \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"hamsili börek\", \"çiroz\" (tuzlanmış hamsi), \"kalkan balığı\", \"çinekop\", \"levrek\", \"mezgit\", \"palamut\", \"lüfer\", \"kefal\", \"istavrit\", \"Sinop peyniri\", \"Sinop yoğurdu\", \"Sinop balı\", \"Sinop fındığı\", \"Sinop mısırı\", \"Sinop elması\", \"Sinop kirazı\", \"Sinop üzümü\", \"Sinop cevizi\" yöresel lezzetlerdendir. Tatlı olarak \"Sinop baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Sinop lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı helva\", \"kestane şekeri\" öne çıkar.', 'Sinop\'ta birçok festival düzenlenmektedir. En önemlileri Uluslararası Sinop Kültür ve Sanat Festivali (ağustos), Uluslararası Sinop Tarihi Cezaevi Kültür ve Sanat Festivali (eylül), Uluslararası Boyabat Kültür ve Sanat Festivali (temmuz), Uluslararası Erfelek Şelaleleri Kültür ve Doğa Festivali (mayıs), Sinop Hamsi Festivali (kasım), Sinop Diogenes Felsefe Festivali (ekim), Ayancık Kültür ve Fındık Festivali (ağustos), Gerze Kültür ve Sanat Festivali (temmuz), Durağan Kültür ve Turizm Festivali (ağustos), Sinop Yayla Şenlikleri (yaz aylarında).', 'Sinop\'u ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; plajlar, yaylalar, tarihi cezaevi ve doğa yürüyüşleri için idealdir. Sonbahar ayları da güzeldir. Kışlar yağışlı ve soğuktur, sıcaklık genelde 2-10 derece arasındadır, zaman zaman kar yağışı görülür.', 'Sinop\'a hava yoluyla Sinop Havalimanı (SIC) ile ulaşılır. Havalimanı şehir merkezine 8 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin, Gümüşhane, Bayburt, Erzurum, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Samsun\'dur. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Boyabat, Ayancık, Gerze, Türkeli, Durağan, Erfelek, Dikmen, Saraydüzü ilçelerine minibüslerle ulaşım vardır. Tarihi Sinop Cezaevi, Sinop Kalesi, Erfelek Şelaleleri, Hamsilos Koyu, İnceburun, Akliman Plajı, Boyabat Kalesi, Balatlar Kilisesi, Sinop Müzesi, yaylalar gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Sinop, tarihi boyunca Kolhitler, Kimmerler, İskitler, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Karadeniz\'in en önemli liman kentlerinden biri olan Sinop, Roma döneminde \"Sinope\" adıyla anılmıştır. MÖ 370 yılında Sinop, ünlü filozof Diogenes\'in doğum yeridir. 13. yüzyılda Selçukluların, 14. yüzyılda Candaroğulları\'nın, 1461 yılında ise Fatih Sultan Mehmet tarafından Osmanlı topraklarına katılmıştır. Cumhuriyet döneminde il statüsü kazanan Sinop, günümüzde tarihi cezaevi, doğal güzellikleri, plajları, yaylaları ve balıkçılığıyla öne çıkan bir Karadeniz ilidir.', 'Sinop', '2026-04-08 23:20:51'),
(70, 'Sivas', 'İç Anadolu', 'sivas.jpg', 'Kangal kaplıcası ile ünlü.', 'Sivas denince akla gelen ilk simge, Kangal Balıklı Kaplıca\'dır (Kangal ilçesi). Psoriasis (sedef hastalığı) başta olmak üzere birçok cilt hastalığına iyi geldiğine inanılan, içinde Kangal balıklarının (Cyprinion macrostomus) yaşadığı dünyaca ünlü bir şifalı sudur. Sivas\'ın simgesi haline gelmiş olan Çifte Minareli Medrese (1271), Selçuklu döneminin taş işçiliğinin en güzel örneklerindendir. Gök Medrese (1271, günümüzde Sivas Müzesi), Buruciye Medresesi (1271), Şifaiye Medresesi (1217, Darüşşifa), Ulu Cami (1197), Sivas Kalesi (Bizans, Selçuklu ve Osmanlı dönemlerinden izler taşır), Sivas Kongre Binası (Atatürk ve Kongre Müzesi, 4 Eylül 1919 Sivas Kongresi\'nin yapıldığı tarihi okul binası), Sivas Müzesi (arkeolojik ve etnografik eserler, Selçuklu eserleri), Etnografya Müzesi, Atatürk Evi Müzesi, Sivas Evleri (tarihi taş evler, restore edilmiş konaklar), Sivas Çarşısı (yöresel ürünler, el sanatları, bakır işlemeciliği, halıcılık) şehrin önemli duraklarıdır. Sivas\'ın ilçeleri: Kangal (Kangal Balıklı Kaplıca, Kangal köpeği (dünyaca ünlü Sivas Kangal çoban köpeği), Kangal Yaylaları), Yıldızeli (Yıldız Dağı (Yıldız Dağı Kayak Merkezi), kış sporları), Suşehri (Suşehri Yaylaları), Zara (Zara Yaylaları, Zara Evleri), Divriği (Divriği Ulu Cami ve Darüşşifası (UNESCO Dünya Mirası Listesi, 1228, Mengücek Gazi dönemi, taş işçiliğinin zirvesi, dünyanın en önemli sanat eserlerinden), Divriği Kalesi, Divriği Evleri), Gemerek, Gürün (Gürün Şelalesi, Gürün Yaylaları), Ulaş, Hafik (Hafik Gölü), İmranlı (İmranlı Yaylaları), Koyulhisar (Koyulhisar Kalesi, Koyulhisar Yaylaları), Şarkışla (Şarkışla Yaylaları, Aşıklık geleneği), Altınyayla, Doğanşar, Akıncılar, Gölova. Sivas, ayrıca Kangal köpeği, Sivas kilimi (el dokuması, yün, doğal boyalar, motifler), bakır işlemeciliği, Sivas sucuğu ve pastırmasıyla da ünlüdür.', 'Sivas mutfağı, İç Anadolu mutfağının zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Sivas köftesi\" gelir. \"Sivas tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"Sivas peyniri\", \"Sivas yoğurdu\", \"Sivas balı\", \"Sivas sucuğu\", \"Sivas pastırması\", \"Sivas elması\", \"Sivas üzümü\", \"Sivas cevizi\", \"Sivas kavunu\", \"Sivas karpuzu\" yöresel lezzetlerdendir. Tatlı olarak \"Sivas baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Sivas lokumu\", \"Sivas katmeri\" ve \"Sivas pestili\" öne çıkar.', 'Sivas\'ta birçok festival düzenlenmektedir. En önemlileri Uluslararası Sivas Kültür ve Sanat Festivali (eylül), Uluslararası Kangal Balıklı Kaplıca ve Kültür Festivali (temmuz), Uluslararası Divriği Ulu Cami ve Darüşşifası Kültür ve Sanat Festivali (ağustos), Uluslararası Sivas Kangal Köpeği Festivali (ekim), Sivas Yıldız Dağı Kış Sporları ve Kayak Festivali (şubat), Sivas Tarihi Kongre Binası ve Atatürk\'ü Anma Günleri (4 Eylül), Şarkışla Aşıklar Festivali (ağustos), Suşehri Kültür ve Sanat Festivali (temmuz) ve Sivas Yayla Şenlikleri (yaz aylarında).', 'Sivas\'ı ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; tarihi medreseleri, camileri, müzeleri, Kangal Balıklı Kaplıca ve doğa yürüyüşleri için idealdir. Sonbahar ayları da güzeldir. Kışlar çok sert ve karlıdır; sıcaklık -15 derecenin altına düşebilir, aralık-şubat aylarında seyahat önerilmez, ancak kış turizmi (kayak) için Yıldız Dağı tercih edilebilir.', 'Sivas\'a hava yoluyla Sivas Nuri Demirağ Havalimanı (VAS) ile ulaşılır. Havalimanı şehir merkezine 25 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Erzincan, Erzurum, Kars, Ardahan, Artvin, Trabzon, Rize, Giresun, Ordu, Samsun, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Sivas, Yüksek Hızlı Tren (YHT) hattı üzerinde olup Ankara, Kırıkkale, Kayseri, Yozgat, Eskişehir, İstanbul, Konya gibi illere hızlı tren bağlantısı vardır. Sivas Tren Garı şehir merkezindedir. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Kangal, Yıldızeli, Suşehri, Zara, Divriği, Gemerek, Gürün, Ulaş, Hafik, İmranlı, Koyulhisar, Şarkışla, Altınyayla, Doğanşar, Akıncılar, Gölova ilçelerine minibüslerle ulaşım vardır. Çifte Minareli Medrese, Gök Medrese, Buruciye Medresesi, Şifaiye Medresesi, Ulu Cami, Sivas Kongre Binası, Kangal Balıklı Kaplıca, Divriği Ulu Cami ve Darüşşifası, Yıldız Dağı Kayak Merkezi, Gürün Şelalesi, Hafik Gölü, yaylalar gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Sivas, tarihi boyunca Hititler, Frigler, Kimmerler, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, İlhanlılar, Eretna Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kapadokya bölgesinin kuzeyinde yer alan Sivas, Roma döneminde \"Sebastea\" adıyla anılmıştır. 1071 yılında Malazgirt Meydan Muharebesi\'nden sonra Danişmentlilerin eline geçen Sivas, 1175 yılında Selçuklular tarafından fethedilmiştir. Selçuklu döneminde Sivas, önemli bir kültür, ticaret ve sanat merkezi haline gelmiştir. Bu dönemde inşa edilen Ulu Cami, Çifte Minareli Medrese, Buruciye Medresesi, Gök Medrese, Şifaiye Medresesi gibi eserler günümüze ulaşmıştır. 1398 yılında Osmanlı topraklarına katılan Sivas, Cumhuriyet döneminde il statüsünü korumuştur. Sivas, Kurtuluş Savaşı\'nda Sivas Kongresi\'ne (4-11 Eylül 1919) ev sahipliği yapmasıyla da büyük öneme sahiptir. Günümüzde Sivas, Kangal köpeği, şifalı termal suları, tarihi medreseleri ve yöresel lezzetleriyle öne çıkan bir İç Anadolu ilidir.', 'Sivas', '2026-04-08 23:20:51'),
(71, 'Şanlıurfa', 'Güneydoğu Anadolu', 'sanliurfa.jpg', 'Peygamberler şehri.', 'Şanlıurfa denince akla gelen ilk simge, Hz. İbrahim\'in doğduğu ve ateşe atıldığı yer olarak kabul edilen Balıklıgöl ve Hz. İbrahim Makamı\'dır. Balıklıgöl\'deki kutsal havuzda yaşayan balıklar (sazan balığı) ve çevresindeki camiler, medreseler (Rızvaniye Camii, Halil-ür Rahman Camii), Hz. İbrahim\'in makamı, Mevlid-i Halil Camii (Halil-ür Rahman Camii), Dergah Camii, Yeni Camii, Ayn-ı Zeliha Gölü, Hz. Eyyüb Makamı (Eyyüp Nebi) şehrin en önemli inanç turizmi merkezleridir. Şanlıurfa Kalesi (Urfa Kalesi), şehir merkezinde yükselen Bizans ve Osmanlı dönemlerinden izler taşıyan surları, sütunları, manzarası ve kalenin içindeki Nevali Çori (Neolitik dönem) kalıntılarıyla dikkat çeker. Balıklıgöl\'ün hemen yanındaki tarihi Urfa Evleri (Sit Alanı, dar sokaklar, taş evler, kemerli kapılar, avlular), Gümrük Hanı (tarihi kervansaray), Sipahi Çarşısı, Bakırcılar Çarşısı, Kazaz Çarşısı, Tarihi Urfa Çarşıları (Bedesten, Hüseyniye Çarşısı, Saraçlar Çarşısı, Kazzaz Çarşısı, Uzun Çarşı), Urfa Müzesi (Şanlıurfa Müzesi, arkeolojik ve etnografik eserler, Balıklıgöl mozaiği, Haleplibahçe mozaikleri, Nevali Çori eserleri, Göbeklitepe eserleri, yöresel kıyafetler, el sanatları), Göbeklitepe (Şanlıurfa\'nın 18 km kuzeydoğusunda, UNESCO Dünya Mirası Listesi, dünyanın bilinen en eski tapınak merkezi, MÖ 9600-8000 yıllarına ait, dikilitaşlar, kabartmalar, T şeklinde sütunlar), Harran ilçesi (Harran Evleri (kümbet evler, konik kubbeli taş evler), Harran Ulu Cami (Harran Camii, 8. yüzyıl), Harran Kalesi (tarihi kale), Harran Antik Kenti, Harran Ovası, El Başak Müzesi, İslam dünyasının ilk üniversitesi kalıntıları), Halfeti ilçesi (Halfeti Evleri (taş evler), Halfeti Kalesı, Halfeti Rumkale (Rumkale), Halfeti\'de tekne turları, su altında kalan tarihi evler, sular altındaki cami minaresi, karadut (Halfeti karadutu), yöresel lezzetler), Siverek (Siverek Kalesi), Viranşehir (Viranşehir Kalesi), Suruç (Suruç Kalesi, Hz. Eyyüb Makamı (Eyyüp Nebi)), Birecik (Birecik Kalesi, Birecik Barajı, kelaynak kuşu (Birecik kelaynak üretme istasyonu)), Bozova, Akçakale, Ceylanpınar, Hilvan, Karaköprü, Eyyübiye, Haliliye ilçeleri. Şanlıurfa, ayrıca yöresel el sanatları (bakır işlemeciliği, sedef kakmacılığı, taş işlemeciliği, halıcılık, kilim dokumacılığı, Urfa işi, telkari), Urfa kumaşı, Urfa fes işlemeciliği, Urfa terliği, Urfa peyniri, Urfa balı, Urfa üzümü, Urfa narı, Urfa fıstığı ve Urfa şalgamıyla da ünlüdür.', 'Şanlıurfa mutfağı, Güneydoğu Anadolu mutfağının en zengin ve en ünlü mutfaklarından biridir. Mutlaka denenmesi gerekenlerin başında \"Urfa kebabı\" (kıyma, pul biber, kuyruk yağı, şişte pişirilir) gelir. \"Patlıcan kebabı\", \"ciğer kebabı\", \"soğan kebabı\", \"kuşbaşı kebabı\", \"simit kebabı\", \"Urfa tava\", \"içli köfte\", \"kibbe\", \"lahmacun\", \"çiğ köfte\" (etli, baharatlı), \"mercimek köftesi\", \"yaprak sarma\", \"dolma\", \"perde pilavı\", \"Büryan kebabı\", \"kuzu tandır\", \"etli ekmek\", \"katmer\", \"gözleme\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"Urfa peyniri\", \"Urfa yoğurdu\", \"Urfa balı\", \"Urfa üzümü\", \"Urfa fıstığı\", \"Urfa narı\", \"Urfa pekmezi\", \"Urfa tahini\", \"Urfa şalgamı\", \"Urfa ayranı\", \"Urfa bozası\" yöresel lezzetlerdendir. Tatlı olarak \"Urfa baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Urfa lokumu\", \"fıstıklı baklava\", \"fıstıklı kadayıf\", \"fıstıklı dondurma\", \"fındıklı sucuk\" öne çıkar.', 'Şanlıurfa\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Şanlıurfa Kültür ve Sanat Festivali (nisan), Uluslararası Balıklıgöl Kültür ve Sanat Festivali (haziran), Uluslararası Göbeklitepe Arkeoloji ve Kültür Festivali (eylül), Uluslararası Harran Kültür ve Turizm Festivali (ekim), Uluslararası Halfeti Kültür ve Karadut Festivali (temmuz), Uluslararası Birecik Kelaynak Kuşu Festivali (mayıs), Uluslararası Siverek Kültür ve Sanat Festivali (ağustos), Şanlıurfa Yöresel Lezzetler Festivali (eylül), Şanlıurfa El Sanatları Festivali (ekim) ve Şanlıurfa Çarşıları ve Hanları Festivali (mayıs).', 'Şanlıurfa\'yı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 18-30 derece arasındadır; Balıklıgöl, Hz. İbrahim makamı, tarihi çarşılar ve müzeler için idealdir. Yaz aylarında sıcaklık 40-45 dereceye ulaşabilir, çok sıcak ve kuraktır. Kışlar ılımandır, sıcaklık genelde 5-15 derece arasındadır, yağışlı olabilir.', 'Şanlıurfa\'ya hava yoluyla Şanlıurfa GAP Havalimanı ile ulaşılır. Havalimanı şehir merkezine 35 km uzaklıktadır. Alternatif olarak Gaziantep Havalimanı (150 km) veya Diyarbakır Havalimanı (180 km) kullanılabilir. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Adana, Mersin, Gaziantep, Diyarbakır, Mardin, Batman, Siirt, Şırnak, Hakkari, Van, Muş, Bitlis, Elazığ, Malatya, Kayseri, Konya, Antalya, Sivas, Erzincan, Erzurum, Trabzon, Samsun gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Gaziantep veya Diyarbakır\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Harran, Halfeti, Siverek, Viranşehir, Suruç, Birecik, Bozova, Akçakale, Ceylanpınar, Hilvan, Karaköprü, Eyyübiye, Haliliye ilçelerine minibüslerle ulaşım vardır. Balıklıgöl, Göbeklitepe, Harran Evleri, Halfeti Rumkale, Hz. İbrahim Makamı, Şanlıurfa Kalesi, Urfa Müzesi gibi yerlere araç kiralamak önerilir.\r\n\r\n', 'Şanlıurfa, tarihi boyunca Sümerler, Akadlar, Babilliler, Asurlular, Hurriler, Hititler, Mitanniler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, Eyyubiler, Artuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Edessa adıyla anılan şehir, erken Hristiyanlık döneminde önemli bir merkez olmuştur. Hz. İbrahim\'in doğduğu ve ateşe atıldığı yer olarak kabul edilen Şanlıurfa, İslam dünyasının önemli kutsal şehirlerinden biridir. 1516 yılında Yavuz Sultan Selim tarafından Osmanlı topraklarına katılan Şanlıurfa, Kurtuluş Savaşı\'nda Fransız işgaline karşı gösterdiği kahramanlık nedeniyle 1984 yılında TBMM tarafından \"Şanlı\" unvanı verilmiş ve şehrin adı \"Şanlıurfa\" olmuştur. Günümüzde Şanlıurfa, Balıklıgöl\'ü, Hz. İbrahim makamı, tarihi çarşıları, yöresel yemekleri ve el sanatlarıyla öne çıkan bir Güneydoğu Anadolu ilidir.', 'Şanlıurfa', '2026-04-08 23:20:51'),
(72, 'Şırnak', 'Güneydoğu Anadolu', 'sirnak.jpg', 'Cudi Dağı ile ünlü.', 'Şırnak denince akla gelen ilk yer, Cizre ilçesidir. Cizre, tarihi ve kültürel zenginlikleriyle öne çıkar: Cizre Kalesi (Memlu Kalesi, İç Kale, dış kale, surlar, manzara), Hz. Nuh Türbesi (Cizre\'de olduğuna inanılan Hz. Nuh\'un türbesi), İsmail Ebul-iz El Cezeri Türbesi (El Cezeri, dünyanın ilk robot bilimci, 12. yüzyıl), Ulu Cami (Cizre Ulu Cami, 14. yüzyıl), Molla Hasan Cami, Meryem Ana Kilisesi (Süryani kilisesi), Cizre Müzesi (arkeolojik ve etnografik eserler), Cizre Çarşısı, Dicle Nehri (Cizre\'den geçer, Dicle Köprüsü (Cizre Köprüsü), manzara, balıkçılık). Şırnak merkezde Şırnak Kalesi (Kale-i Şırnak), Şırnak Ulu Cami, Şırnak Evleri (tarihi taş evler), Şırnak Müzesi, Şırnak Çarşısı gezilebilir. Gabar Dağı (Şırnak\'ın güneyinde, doğa yürüyüşleri, kamp, manzara, Gabar Dağı efsaneleri, Gabar petrol kuyuları), Bestler Deresi, Hezan Vadisi, Serapel Deresi, Çağlayan Şelalesi (Kasrik), Beytüşşebap ilçesi (Beytüşşebap Kalesi, Beytüşşebap Yaylaları, Beytüşşebap Vadisi, doğa yürüyüşleri, yayla şenlikleri, kamp), Uludere ilçesi (Uludere Kalesi, Uludere Yaylaları), İdil ilçesi (İdil Kalesi, İdil Yaylaları), Silopi ilçesi (Silopi Kalesi, Habur Sınır Kapısı (Irak sınırı), Silopi Yaylaları), Güçlükonak ilçesi (Güçlükonak Yaylaları) doğa ve tarih severler için ilgi çekicidir.', 'Şırnak mutfağı, Güneydoğu Anadolu mutfağının zengin ve baharatlı lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Şırnak köftesi\" gelir. \"Cizre tava\", \"Büryan kebabı\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"perde pilavı\", \"içli köfte\", \"kibbe\", \"lahmacun\", \"çiğ köfte\", \"mercimek köftesi\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"Şırnak peyniri\", \"Şırnak yoğurdu\", \"Şırnak balı\", \"Cizre üzümü\", \"Cizre narı\", \"Şırnak pekmezi\", \"Şırnak tarhanası\" yöresel lezzetlerdendir. Tatlı olarak \"Şırnak baklavası\", \"kadayıf\", \"künefe\", \"un helvası\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Şırnak lokumu\", \"Cizre burma kadayıf\" öne çıkar.', 'Şırnak\'ta en önemli etkinlik, her yıl eylül ayında düzenlenen Uluslararası Cizre Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, panayır, sergiler, paneller ve El Cezeri anma törenleri düzenlenir. Ayrıca Uluslararası Şırnak Kültür ve Sanat Festivali (ağustos), Uluslararası Beytüşşebap Yayla ve Kültür Festivali (temmuz), Uluslararası İdil Kültür ve Sanat Festivali (eylül), Uluslararası Silopi Kültür ve Turizm Festivali (ağustos) ve Şırnak Yayla Şenlikleri (yaz aylarında) düzenlenmektedir.', 'Şırnak\'ı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; tarihi yapıları, kaleleri, köprüleri ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 38-42 dereceye ulaşabilir, çok sıcak ve kuraktır. Kışlar soğuktur, sıcaklık genelde 0-10 derece arasındadır, yağışlı ve zaman zaman karlıdır.', 'Şırnak\'a hava yoluyla Şırnak Şerafettin Elçi Havalimanı (NKT) ile ulaşılır. Havalimanı şehir merkezine 60 km (Cizre ilçesinde), Şırnak merkeze 80 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Diyarbakır, Mardin, Batman, Siirt, Hakkari, Van, Muş, Bitlis, Elazığ, Malatya, Gaziantep, Adana, Mersin, Konya, Kayseri, Sivas, Erzincan, Erzurum, Trabzon, Samsun gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Batman veya Diyarbakır\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Cizre, Silopi, İdil, Uludere, Beytüşşebap, Güçlükonak ilçelerine minibüslerle ulaşım vardır. Cizre Kalesi, Hz. Nuh Türbesi, El Cezeri Türbesi, Dicle Nehri, Cizre Müzesi, Şırnak Kalesi, Gabar Dağı, Beytüşşebap Yaylaları, Habur Sınır Kapısı gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Şırnak, tarihi boyunca Asurlular, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi İpek Yolu üzerinde önemli bir durak olmuştur. 16. yüzyılda Osmanlı topraklarına katılan Şırnak, Cumhuriyet döneminde önce Siirt\'e bağlı bir ilçe iken 1990 yılında il statüsü kazanarak Türkiye\'nin en genç illerinden biri olmuştur. Şırnak, günümüzde Cizre ilçesinin tarihi ve kültürel önemi, Gabar Dağı, tüpraş (petrol rafinerisi) ve sınır ticaretiyle öne çıkan bir Güneydoğu Anadolu ilidir.', 'Şırnak', '2026-04-08 23:20:51'),
(73, 'Tekirdağ', 'Marmara', 'tekirdag.jpg', 'Şarköy plajları ile ünlü.', 'Tekirdağ denince akla gelen ilk simge, Tekirdağ Kalesi\'dir (Tarihi Tekirdağ Kalesi, surlar, burçlar, manzara). Rakoczi Müzesi (Macaristan Milli Kahramanı II. Ferenc Rakoczi\'nin 1720-1735 yılları arasında sürgünde kaldığı ev, müze), Tekirdağ Arkeoloji ve Etnografya Müzesi (arkeolojik eserler, Trakya eserleri, etnografik eserler, yöresel kıyafetler, el sanatları), Namık Kemal Evi Müzesi (vatan şairi Namık Kemal\'in doğduğu ev, müze), Tekirdağ Saat Kulesi (1890), Tekirdağ Limanı, Tekirdağ Sahil Şeridi (yürüyüş yolu, bisiklet yolu, çay bahçeleri, restoranlar, manzara), Tekirdağ Plajları (Marmara Ereğlisi Plajı, Şarköy Plajı, Mürefte Plajı, Kumbağ Plajı, Yeniçiftlik Plajı, Uçmakdere Plajı, sahil şeridi, kumsal, deniz). Tekirdağ\'ın ilçeleri: Şarköy (Şarköy Plajı, Şarköy Şarapları (Bağcılık, şarap evleri, şarap tadımı), Şarköy Kalesi, Şarköy Evleri), Mürefte (Mürefte Şarapları, Mürefte Plajı, Mürefte Kalesi), Marmara Ereğlisi (Marmara Ereğlisi Plajı, Marmara Ereğlisi Kalesi, Marmara Ereğlisi Limanı), Hayrabolu (Hayrabolu Evleri, Hayrabolu Kalesi), Çorlu (Çorlu Sanayi, Çorlu Pidesi, Çorlu Köftesi), Malkara (Malkara Peyniri, Malkara Evleri), Saray (Saray Köftesi, Saray Yaylaları), Kapaklı, Muratlı, Süleymanpaşa (merkez ilçe). Tekirdağ, ayrıca Tekirdağ köftesi, Tekirdağ şarabı (Şarköy, Mürefte bağları), Tekirdağ zeytini, Tekirdağ ayçiçeği tarlaları (yaz aylarında sarı renkli manzara), Tekirdağ el sanatları (bakır işlemeciliği, halıcılık, kilim dokumacılığı) ile de ünlüdür.', 'Tekirdağ mutfağı, Trakya mutfağının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Tekirdağ köftesi\" (kıyma, tuz, baharat, özel yuvarlak şekil, ızgarada pişirilir) gelir. \"Tekirdağ tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"Tekirdağ peyniri\", \"Tekirdağ yoğurdu\", \"Tekirdağ balı\", \"Tekirdağ zeytini\", \"Tekirdağ zeytinyağı\", \"Tekirdağ şarabı\" (Kırmızı, beyaz, bölgenin ünlü şarapları), \"deniz ürünleri\" (çipura, levrek, barbunya, kalamar, karides, midye), \"Tekirdağ simidi\", \"Tekirdağ pidesi\", \"Tekirdağ böreği\" yöresel lezzetlerdendir. Tatlı olarak \"Tekirdağ baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Tekirdağ lokumu\", \"Tekirdağ şekerparesi\", \"Tekirdağ tulumbası\" öne çıkar.', 'Tekirdağ\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Tekirdağ Kültür ve Sanat Festivali (eylül), Uluslararası Tekirdağ Köftesi Festivali (ekim), Uluslararası Şarköy Bağ Bozumu ve Şarap Festivali (eylül), Uluslararası Kumbağ Plajı Festivali (temmuz), Uluslararası Marmara Ereğlisi Kültür ve Turizm Festivali (ağustos), Uluslararası Hayrabolu Kültür ve Sanat Festivali (temmuz), Tekirdağ Namık Kemal Kültür ve Sanat Günleri (aralık), Rakoczi Kültür ve Sanat Festivali (mayıs) ve Tekirdağ Yürüyüş ve Bisiklet Festivali (nisan).', 'Tekirdağ\'ı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; sahil şeridi, yürüyüş yolları, müzeler ve doğa için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, sıcak ve nemlidir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 3-12 derece arasındadır.', 'Tekirdağ\'a hava yoluyla Tekirdağ Çorlu Havalimanı (TEQ) ile ulaşılır. Havalimanı şehir merkezine 50 km (Çorlu ilçesinde) uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Edirne, Kırklareli, Çanakkale, Balıkesir, Manisa, Denizli, Antalya, Adana, Mersin, Gaziantep, Diyarbakır, Samsun, Trabzon, Erzurum, Kayseri, Konya, Eskişehir, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin gibi büyük illere seferler vardır. Demiryolu bağlantısı vardır (Tekirdağ Tren Garı). Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Çorlu, Çerkezköy, Kapaklı, Saray, Malkara, Hayrabolu, Muratlı, Marmara Ereğlisi, Şarköy, Süleymanpaşa ilçelerine minibüslerle ulaşım vardır. Rakoczi Müzesi, Namık Kemal Evi Müzesi, Tekirdağ Kalesi, Tekirdağ Müzesi, Kumbağ Plajı, Şarköy Plajı, Marmara Ereğlisi Plajı, Şarköy Şarap Evleri gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Tekirdağ, tarihi boyunca Traklar, Persler, Romalılar, Bizanslılar ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Trakya bölgesinin önemli merkezlerinden biri olan Tekirdağ, Roma döneminde \"Bisanthe\" adıyla anılmıştır. 14. yüzyılda Osmanlı topraklarına katılan şehir, Cumhuriyet döneminde il statüsü kazanmıştır. Tekirdağ, günümüzde özellikle Tekirdağ köftesi, Rakoczi Müzesi (Macar Prensi Rakoczi\'nin sürgün evi), şarapları, ayçiçeği tarlaları ve deniz ürünleriyle ünlü bir Marmara ilidir.', 'Tekirdağ', '2026-04-08 23:20:51');
INSERT INTO `cities` (`id`, `name`, `region`, `image`, `description`, `famous_for`, `cuisine`, `festivals`, `best_time`, `transportation`, `history`, `location`, `created_at`) VALUES
(74, 'Tokat', 'Karadeniz', 'tokat.jpg', 'Ballıca Mağarası ile ünlü.', 'Tokat denince akla gelen ilk simge, Tokat Kalesi\'dir. Şehir merkezinde yükselen bu kale, Bizans, Danişmentli, Selçuklu ve Osmanlı dönemlerinden izler taşıyan surları, burçları, iç kalesi ve manzarasıyla dikkat çeker. Tokat Müzesi (arkeolojik ve etnografik eserler, Komana Pontika kazı eserleri, yazmacılık, bakır işlemeciliği), Gök Medrese (Selçuklu dönemi, 1270, taş işçiliği), Ulu Cami (Tokat Ulu Cami, 12. yüzyıl), Ali Paşa Cami (16. yüzyıl), Hatuniye Cami, Sulusokak Evleri (tarihi Tokat evleri, restore edilmiş konaklar, dar sokaklar), Tokat Çarşısı (bakırcılar çarşısı, yazmacılar çarşısı, el sanatları, yöresel ürünler), Taşhan (tarihi kervansaray), Deveciler Hanı, Latifoğlu Konağı (tarihi konak, müze), Ballıca Mağarası (Pazar ilçesi, dünyanın en büyük mağaralarından biri, sarkıt ve dikitler, traverten havuzları, doğa harikası), Kaz Gölü (doğal göl, kuş cenneti, piknik, manzara), Niksar ilçesi (Niksar Kalesi (Danişmentli dönemi), Niksar Ulu Cami (12. yüzyıl), Niksar Müzesi, Niksar Çarşısı, Niksar Yaylaları, Niksar Kaplıcaları (termal su)), Turhal ilçesi (Turhal Kalesi, Turhal Kaplıcaları), Erbaa ilçesi (Erbaa Kaplıcaları, Erbaa Yaylaları), Zile ilçesi (Zile Kalesi (Büyük İskender dönemi, Kral Kaya Mezarları), Zile Müzesi, Zile Çarşısı, Zile Yaylaları), Reşadiye ilçesi (Reşadiye Yaylaları, Reşadiye Kaplıcaları), Almus ilçesi (Almus Baraj Gölü, Almus Yaylaları, Almus Şelalesi), Pazar ilçesi (Ballıca Mağarası), Başçiftlik, Sulusaray, Artova, Yeşilyurt ilçeleri.', 'Tokat mutfağı, Karadeniz ve İç Anadolu mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Tokat kebabı\" (et, patates, domates, biber, özel taş fırında pişirilir) gelir. \"Tokat köftesi\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"Tokat peyniri\", \"Tokat yoğurdu\", \"Tokat balı\", \"Tokat üzümü\", \"Tokat elması\", \"Tokat cevizi\", \"Tokat kirazı\" yöresel lezzetlerdendir. Tatlı olarak \"Tokat baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Tokat lokumu\", \"Tokat bezmesi\" (pekmez, ceviz, üzüm, Tokat\'a özgü tatlı) ve \"Tokat sucuğu\" öne çıkar.', 'Tokat\'ta birçok festival düzenlenmektedir. En önemlileri Uluslararası Tokat Kültür ve Sanat Festivali (eylül), Uluslararası Ballıca Mağarası Kültür ve Turizm Festivali (ağustos), Uluslararası Niksar Kültür ve Sanat Festivali (temmuz), Uluslararası Zile Kültür ve Turizm Festivali (ağustos), Uluslararası Almus Baraj Gölü ve Doğa Festivali (haziran), Tokat Bezmesi Festivali (ekim), Tokat Yayla Şenlikleri (yaz aylarında) ve Tokat Bakır ve Yazmacılık Festivali (eylül).', 'Tokat\'ı ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; tarihi yapıları, yaylaları, kaplıcaları ve doğa yürüyüşleri için idealdir. Sonbahar ayları da güzeldir. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşebilir.', 'Tokat\'a hava yoluyla Tokat Havalimanı (TJK) ile ulaşılır. Havalimanı şehir merkezine 20 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Samsun, Amasya, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Erzincan, Erzurum, Trabzon, Giresun, Ordu, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Sivas veya Amasya\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Niksar, Erbaa, Turhal, Zile, Reşadiye, Almus, Pazar, Başçiftlik, Sulusaray, Artova, Yeşilyurt ilçelerine minibüslerle ulaşım vardır. Tokat Kalesi, Ballıca Mağarası, Kaz Gölü, Gök Medrese, Tokat Müzesi, Sulusokak Evleri, Niksar Kalesi, Zile Kalesi, Almus Baraj Gölü, Reşadiye Yaylaları, Erbaa Kaplıcaları, Turhal Kaplıcaları, Niksar Kaplıcaları gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Tokat, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, İlhanlılar, Eretna Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kapadokya bölgesinin kuzeyinde yer alan Tokat, Roma döneminde \"Comana Pontica\" adıyla anılmıştır. 11. yüzyılda Malazgirt Meydan Muharebesi\'nden sonra Danişmentlilerin eline geçen Tokat, 12. yüzyılda Selçuklular, 14. yüzyılda Eretna Beyliği ve 15. yüzyılda Osmanlı topraklarına katılmıştır. Cumhuriyet döneminde il statüsü kazanan Tokat, günümüzde tarihi konakları, doğal güzellikleri, yöresel el sanatları (bakır işlemeciliği, yazmacılık) ve ünlü Tokat bezmesiyle öne çıkan bir Karadeniz ilidir.', 'Tokat', '2026-04-08 23:20:51'),
(75, 'Trabzon', 'Karadeniz', 'trabzon.jpg', 'Yeşilin maviyle buluştuğu şehir.', 'Trabzon denince akla gelen ilk simge, dünyaca ünlü Sümela Manastırı\'dır (Maçka ilçesi, 4. yüzyıl, Bizans dönemi, kaya oyma manastır, Meryem Ana Kilisesi, şapeller, keşiş odaları, kütüphane, kutsal su kaynağı, freskler, manzara, orman içinde). Trabzon\'un simgesi haline gelmiş diğer yerler: Uzungöl (Çaykara ilçesi, krater gölü, doğa harikası, yürüyüş yolları, çay bahçeleri, restoranlar, oteller, manzara), Ayasofya Müzesi (13. yüzyıl, Trabzon İmparatorluğu dönemi, kilise, freskler, manzara), Atatürk Köşkü (Trabzon\'un Soğuksu semtinde, Atatürk\'ün Trabzon\'da kaldığı köşk, müze, bahçe, manzara), Trabzon Kalesi (İç Kale, Orta Hisar, Aşağı Hisar, Bizans, Trabzon İmparatorluğu ve Osmanlı dönemlerinden izler taşır, surlar, burçlar, manzara), Trabzon Meydanı (Atatürk Alanı, Merkez, saat kulesi, çarşılar, camiler, restoranlar, kafeler), Gülbahar Hatun Camii (16. yüzyıl, Osmanlı), İskender Paşa Camii, Çarşı Camii, Trabzon Müzesi (Kostaki Konağı, arkeolojik ve etnografik eserler), Trabzon Akvaryumu, Boztepe (Trabzon manzarası, teleferik, çay bahçeleri, manzara), Çal Mağarası (Düzköy ilçesi, doğal mağara, sarkıt ve dikitler), Hıdırnebi Yaylası, Sera Gölü (Yomra ilçesi, doğal göl, piknik, restoranlar), Altındere Vadisi Milli Parkı (Maçka ilçesi, Sümela Manastırı\'nın içinde bulunduğu milli park, doğa yürüyüşleri, kamp), Vazelon Manastırı (Maçka ilçesi, 4. yüzyıl, kaya oyma manastır), Kuştul Manastırı (Maçka ilçesi), Kaymaklı Manastırı (Trabzon merkez). Trabzon\'un ilçeleri: Maçka (Sümela Manastırı, Altındere Vadisi, Maçka Yaylaları), Çaykara (Uzungöl, Çaykara Yaylaları, Demirkapı Yaylası, Haldizen Yaylası), Akçaabat (Akçaabat Köftesi, Akçaabat Plajı, Akçaabat Yaylaları), Of (Of Yaylaları, Of Peyniri, Of Çayı), Sürmene (Sürmene Bıçağı (dünyaca ünlü Sürmene bıçağı), Sürmene Yaylaları), Araklı (Araklı Plajı, Araklı Yaylaları), Arsin (Arsin Plajı, Arsin Yaylaları), Beşikdüzü, Şalpazarı (Şalpazarı Yaylaları), Tonya (Tonya Tereyağı, Tonya Peyniri, Tonya Yaylaları), Düzköy (Düzköy Yaylaları, Çal Mağarası, Sera Gölü), Vakfıkebir (Vakfıkebir Ekmeği, Vakfıkebir Yaylaları), Çarşıbaşı, Yomra (Yomra Plajı, Sera Gölü), Köprübaşı, Dernekpazarı, Hayrat. Trabzon, ayrıca Sürmene bıçağı (el yapımı, çelik, dünyaca ünlü), Trabzon iğne oyası, Trabzon bezi, bakır işlemeciliği, Trabzon fındığı, Trabzon tereyağı, Tonya tereyağı, Akçaabat köftesi, Vakfıkebir ekmeği, Of peyniri, Trabzon el sanatları ile de ünlüdür.', 'Trabzon mutfağı, Karadeniz mutfağının en zengin ve en ünlü lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Trabzon pidesi\" (etli, peynirli, yumurtalı, kuşbaşılı, kıtır, uzun) gelir. \"Trabzon köftesi\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"hamsili börek\", \"çiroz\" (tuzlanmış hamsi), \"Trabzon peyniri\" (tulum peyniri, minci peynir), \"Trabzon yoğurdu\", \"Trabzon balı\", \"Trabzon fındığı\", \"Trabzon mısırı\", \"Trabzon elması\", \"Trabzon kirazı\", \"Trabzon üzümü\", \"Trabzon çayı\" (çay bahçeleri, Rize sınırında) yöresel lezzetlerdendir. Tatlı olarak \"Trabzon baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Trabzon lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı helva\", \"fındıklı dondurma\", \"kestane şekeri\" ve \"sütlü kadayıf\" öne çıkar.', 'Trabzon\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Sümela Kültür ve Sanat Festivali (ağustos), Uluslararası Uzungöl Kültür ve Doğa Festivali (temmuz), Uluslararası Akçaabat Kültür ve Sanat Festivali (eylül), Uluslararası Of Kültür ve Sanat Festivali (ağustos), Uluslararası Sürmene Bıçağı Festivali (ekim), Uluslararası Vakfıkebir Ekmek Festivali (ağustos), Trabzon Kültür ve Sanat Festivali (mayıs), Trabzon Yayla Şenlikleri (yaz aylarında) ve Trabzon Hamsi Festivali (kasım).', 'Trabzon\'u ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; Sümela Manastırı, Uzungöl, yaylalar, şelaleler ve doğa yürüyüşleri için idealdir. Sonbahar ayları da güzeldir. Kışlar yağışlı ve soğuktur, sıcaklık genelde 2-10 derece arasındadır, zaman zaman kar yağışı görülür.', 'Trabzon\'a hava yoluyla Trabzon Havalimanı (TZX) ile ulaşılır. Havalimanı şehir merkezine 5 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Samsun, Ordu, Giresun, Rize, Artvin, Gümüşhane, Bayburt, Erzurum, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Sinop, Kastamonu, Zonguldak, Karabük, Bolu, Düzce, Sakarya, Kocaeli, Bursa, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Samsun veya Erzincan\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri, taksi ve teleferik (Boztepe Teleferiği) kullanılır. Maçka, Çaykara, Akçaabat, Of, Sürmene, Araklı, Arsin, Beşikdüzü, Şalpazarı, Tonya, Düzköy, Vakfıkebir, Çarşıbaşı, Yomra, Köprübaşı, Dernekpazarı, Hayrat ilçelerine minibüslerle ulaşım vardır. Sümela Manastırı, Uzungöl, Ayasofya Müzesi, Atatürk Köşkü, Trabzon Kalesi, Boztepe, Çal Mağarası, Hıdırnebi Yaylası, Sera Gölü, Altındere Vadisi Milli Parkı, Vazelon Manastırı, Kuştul Manastırı, yaylalar, plajlar gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Trabzon, tarihi boyunca Kolhitler, Kimmerler, İskitler, Persler, Romalılar, Bizanslılar, Trabzon İmparatorluğu (Pontus Rum İmparatorluğu) ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Karadeniz\'in en önemli liman kentlerinden biri olan Trabzon, Roma döneminde \"Trapezus\" adıyla anılmıştır. 1204 yılında İstanbul\'da Latin işgalinin başlamasıyla birlikte Trabzon\'da bağımsız bir Rum devleti olan Trabzon İmparatorluğu kurulmuş ve bu devlet 1461 yılına kadar varlığını sürdürmüştür. 1461 yılında Fatih Sultan Mehmet tarafından Osmanlı topraklarına katılan Trabzon, Cumhuriyet döneminde il statüsünü korumuştur. Trabzon, günümüzde Sümela Manastırı, Uzungöl, Ayasofya Müzesi, Atatürk Köşkü, tarihi meydanı ve yöresel lezzetleriyle öne çıkan önemli bir Karadeniz ilidir.', 'Trabzon', '2026-04-08 23:20:51'),
(76, 'Tunceli', 'Doğu Anadolu', 'Tunceli.jpg', 'Munzur Vadisi ile ünlü.', 'Tunceli denince akla gelen ilk simge, Munzur Vadisi Milli Parkı\'dır. Türkiye\'nin en büyük milli parklarından biri olan Munzur Vadisi, Munzur Dağları, Mercan Dağları, Munzur Çayı, Mercan Çayı, şelaleler, doğal güzellikler, yürüyüş parkurları, kamp alanları, yaban hayatı (ayı, kurt, yaban keçisi, kartal, alabalık), doğa fotoğrafçılığı, kuş gözlem, rafting (Munzur Çayı), kano, dağcılık, kaya tırmanışı, kamp, doğa yürüyüşleri için eşsiz bir alandır. Tunceli Kalesi (Kalan Kalesi), şehir merkezinde yükselen tarihi kale kalıntıları, manzara. Pertek Kalesi (Pertek ilçesi, Keban Baraj Gölü kenarında, kale, manzara). Çemişgezek Kalesi (Çemişgezek ilçesi), Mazgirt Kalesi (Mazgirt ilçesi). Tunceli Müzesi (arkeolojik ve etnografik eserler, yöresel kıyafetler, el sanatları). Munzur Şelalesi, Mercan Şelalesi, Pülümür Şelalesi, Ovacık Şelalesi. Tunceli\'nin ilçeleri: Ovacık (Ovacık Yaylaları, Munzur Vadisi, şelaleler), Hozat (Hozat Kalesi, Hozat Yaylaları, Hozat Müzesi), Pertek (Pertek Kalesi, Keban Baraj Gölü, Pertek Adası, Pertek Yaylaları), Mazgirt (Mazgirt Kalesi, Mazgirt Yaylaları), Çemişgezek (Çemişgezek Kalesi, Çemişgezek Evleri, Keban Baraj Gölü), Pülümür (Pülümür Yaylaları, Pülümür Şelalesi, Pülümür Vadisi), Nazımiye (Nazımiye Yaylaları). Tunceli\'nin yaylaları: Ovacık Yaylaları, Hozat Yaylaları, Mazgirt Yaylaları, Pülümür Yaylaları, Nazımiye Yaylaları, Pertek Yaylaları (yayla evleri, yayla şenlikleri, doğa yürüyüşleri, kamp, yayla manzaraları). Keban Baraj Gölü (Tunceli\'nin Pertek, Çemişgezek ilçelerinde, baraj gölü, doğa, balıkçılık, tekne turları, manzara). Munzur Çayı (rafting, kano, alabalık tutma). Tunceli, ayrıca doğal alabalık (Munzur alabalığı), yayla balı, Munzur suyu, el dokuması halı ve kilimleri, bakır işlemeciliği, keçecilik ile de ünlüdür.', 'Tunceli mutfağı, Doğu Anadolu ve Dersim mutfaklarının zengin ve doğal lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Tunceli köftesi\" gelir. \"Etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"keledoş\", \"ayran aşı\", \"Tunceli peyniri\", \"Tunceli yoğurdu\", \"Tunceli balı\" (Munzur balı, yayla balı), \"Tunceli üzümü\", \"Tunceli cevizi\", \"Tunceli dutu\", \"Tunceli pekmezi\", \"Tunceli tarhanası\" yöresel lezzetlerdendir. Tatlı olarak \"Tunceli baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Tunceli lokumu\", \"dut pekmezi\" ve \"cevizli pestil\" öne çıkar.', 'Tunceli\'de en önemli etkinlik, her yıl temmuz ayında düzenlenen Uluslararası Munzur Vadisi Kültür ve Doğa Festivali\'dir. Festivalde Munzur Vadisi\'nde doğa yürüyüşleri, kamp, rafting, dağcılık, kaya tırmanışı, konserler, halk oyunları gösterileri, yöresel lezzet tadımları, panayır, sergiler ve paneller düzenlenir. Ayrıca Uluslararası Tunceli Kültür ve Sanat Festivali (ağustos), Uluslararası Ovacık Yayla ve Kültür Festivali (temmuz), Uluslararası Pertek Kalesi ve Kültür Festivali (eylül), Uluslararası Hozat Kültür ve Sanat Festivali (ağustos), Uluslararası Pülümür Yayla ve Kültür Festivali (ağustos), Tunceli Yayla Şenlikleri (yaz aylarında) ve Munzur Çayı Rafting Festivali (haziran).', 'Tunceli\'yi ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-30 derece arasındadır; Munzur Vadisi, Mercan Dağları, yaylalar, doğa yürüyüşleri ve kamp için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -15 derecenin altına düşebilir, aralık-şubat aylarında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez.', 'Tunceli\'ye hava yoluyla en yakın havalimanı Elazığ Havalimanı (EZS) (120 km) veya Erzincan Havalimanı (ERC) (140 km) kullanılır. Havalimanlarından havaş otobüsleri veya taksi ile Tunceli\'ye ulaşılır. Tunceli\'ye şehirlerarası otobüs terminalinden Elazığ, Erzincan, İstanbul, Ankara, İzmir, Bursa, Malatya, Diyarbakır, Gaziantep, Adana, Mersin, Konya, Kayseri, Sivas, Erzurum, Trabzon, Samsun gibi büyük illere aktarmalı seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Elazığ veya Erzincan\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Pertek, Hozat, Ovacık, Mazgirt, Çemişgezek, Pülümür, Nazımiye ilçelerine minibüslerle ulaşım vardır. Munzur Vadisi Milli Parkı, Mercan Dağları, Munzur Şelalesi, Mercan Şelalesi, Pülümür Şelalesi, Ovacık Yaylaları, Pertek Kalesi, Çemişgezek Kalesi, Tunceli Kalesi, Keban Baraj Gölü, Munzur Çayı, yaylalar gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Tunceli, tarihi boyunca Hurriler, Urartular, Medler, Persler, Romalılar, Bizanslılar, Emeviler, Abbasiler, Selçuklular, İlhanlılar, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Bölge, tarihi boyunca stratejik konumu nedeniyle sık sık el değiştirmiştir. 16. yüzyılda Osmanlı topraklarına katılan Tunceli, Cumhuriyet döneminde il statüsü kazanmıştır. Tunceli, günümüzde Munzur Vadisi Milli Parkı, Mercan Dağları, yaylaları, doğal güzellikleri ve yöresel kültürüyle öne çıkan bir Doğu Anadolu ilidir.', 'Tunceli', '2026-04-08 23:20:51'),
(77, 'Uşak', 'Ege', 'usak.jpg', 'Şeker fabrikası ile ünlü.', 'Uşak denince akla gelen ilk simge, Uşak Halısı\'dır. Uşak halıları, el dokuması, yün, doğal boyalar, motifler (Uşak halıları dünyaca ünlüdür). Uşak\'ta halıcılık atölyeleri, halı müzesi, halı çarşısı ziyaret edilebilir. Uşak\'ın en önemli tarihi eseri, dünyaca ünlü Karun Hazineleri\'nin sergilendiği Uşak Arkeoloji Müzesi\'dir. Lidya Kralı Karun\'a ait altın, gümüş, elektrum eserler, takılar, heykelcikler, sikke koleksiyonu bu müzede sergilenmektedir. Uşak Kalesi, şehir merkezinde yükselen Bizans ve Osmanlı dönemlerinden izler taşıyan surları ve manzarasıyla dikkat çeker. Uşak Evleri (tarihi Uşak evleri, restore edilmiş konaklar), Uşak Müzesi, Etnografya Müzesi, Atatürk Evi Müzesi, Uşak Çarşısı (bakırcılar çarşısı, halıcılar çarşısı, dericiler çarşısı, yöresel ürünler). Blaundos Antik Kenti (Ulubey ilçesi, Roma dönemi, tiyatro, sütunlu cadde, agora, surlar, kaya mezarları), Ulubey Kanyonu (Ulubey ilçesi, dünyanın en büyük ikinci kanyonu (Büyük Kanyon), doğa yürüyüşleri, kamp, manzara, cam teras). Uşak\'ın ilçeleri: Ulubey (Ulubey Kanyonu, Blaundos Antik Kenti), Eşme (Eşme Halıları, Eşme Yaylaları, Eşme Kirazı), Banaz (Banaz Yaylaları, Banaz Kaplıcaları), Sivaslı (Sivaslı Yaylaları), Karahallı, Kızılcasöğüt, Ulubey, Eşme, Banaz, Sivaslı. Uşak, ayrıca deri işlemeciliği (Uşak derisi, ayakkabı, çanta, ceket, kemer), Uşak sucuğu, Uşak pastırması, Uşak pestili, Uşak elması, Uşak kirazı ve Uşak üzümü ile de ünlüdür.', 'Uşak mutfağı, Ege ve İç Anadolu mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Uşak köftesi\" gelir. \"Uşak tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"Uşak peyniri\", \"Uşak yoğurdu\", \"Uşak balı\", \"Uşak üzümü\", \"Uşak elması\", \"Uşak cevizi\", \"Uşak bademi\" yöresel lezzetlerdendir. Tatlı olarak \"Uşak baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Uşak lokumu\", \"Uşak macunu\" ve \"Uşak şekeri\" öne çıkar.', 'Uşak\'ta en önemli etkinlik, her yıl eylül ayında düzenlenen Uluslararası Uşak Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, halıcılık sergileri, deri işlemeciliği sergileri, panayır, sergiler ve paneller düzenlenir. Ayrıca Uluslararası Ulubey Kanyonu Kültür ve Doğa Festivali (temmuz), Uluslararası Eşme Kültür ve Kiraz Festivali (haziran), Uluslararası Banaz Kültür ve Sanat Festivali (ağustos), Uşak Halı Festivali (ekim), Uşak Karun Hazineleri Festivali (nisan) ve Uşak Yayla Şenlikleri (yaz aylarında).', 'Uşak\'ı ziyaret etmek için en iyi zaman ilkbahar ve sonbahar aylarıdır. Nisan, mayıs, eylül ve ekim aylarında hava ılımandır, sıcaklık 15-25 derece arasındadır; tarihi yapıları, müzeleri, kaplıcaları ve doğa yürüyüşleri için idealdir. Yaz aylarında sıcaklık 28-33 dereceye ulaşabilir, kurak ve sıcaktır. Kışlar soğuk ve yağışlıdır, sıcaklık sıfırın altına düşebilir, zaman zaman kar yağışı görülür.', 'Uşak\'a hava yoluyla Uşak Havalimanı ile ulaşılır. Havalimanı şehir merkezine 5 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Denizli, Manisa, Kütahya, Afyonkarahisar, Eskişehir, Konya, Kayseri, Antalya, Muğla, Aydın, Balıkesir gibi büyük illere seferler vardır. Demiryolu bağlantısı vardır; Uşak Tren Garı ile İzmir, Manisa, Balıkesir, Kütahya, Eskişehir, Ankara gibi illere tren bağlantısı vardır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ulubey, Eşme, Banaz, Sivaslı, Karahallı, Kızılcasöğüt ilçelerine minibüslerle ulaşım vardır. Uşak Arkeoloji Müzesi (Karun Hazineleri), Ulubey Kanyonu, Blaundos Antik Kenti, Uşak Kalesi, Uşak Halı Atölyeleri gibi yerlere araç kiralamak önerilir.', 'Uşak, tarihi boyunca Hititler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular, Germiyanoğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Lidya bölgesinin önemli merkezlerinden biri olan Uşak, Roma döneminde \"Flavia\" adıyla anılmıştır. 14. yüzyılda Germiyanoğulları Beyliği\'nin, ardından Osmanlıların egemenliğine giren Uşak, Cumhuriyet döneminde il statüsü kazanmıştır. Uşak, günümüzde halıcılığı, deri işlemeciliği, tarihi Karun Hazineleri, şeker pancarı üretimi ve yöresel lezzetleriyle öne çıkan bir Ege ilidir.', 'Uşak', '2026-04-08 23:20:51'),
(78, 'Van', 'Doğu Anadolu', 'van.jpg', 'Van Gölü ile ünlü.', 'Van denince akla gelen ilk simge, Van Gölü (dünyanın en büyük sodalı gölü, Türkiye\'nin en büyük gölü, doğal güzellik, yüzme (sodalı su, sabunlanma hissi), balıkçılık (inci kefali), tekne turları, kuş gözlem, Van Gölü manzarası, gölün ortasında Akdamar Adası, Çarpanak Adası, Adır Adası, Kuş Adası). Akdamar Adası ve Akdamar Kilisesi (10. yüzyıl, Vaspurakan Krallığı Kralı Gagik tarafından yaptırılmış, Ermeni mimarisi, kırmızı tüf taşı, kabartmalar (Adem, Havva, Davud, Golyat, Hz. Yunus, balina), freskler, manzara, Van\'ın en önemli turistik noktası). Van Kalesi (Tuşpa, Urartu Krallığı\'nın başkenti, MÖ 9. yüzyıl, Kral Sarduri tarafından yaptırılmış, surlar, burçlar, kaya mezarları, yazıtlar, Kral Yolu, manzara (Van Gölü, Van Ovası, şehir manzarası)). Van Müzesi (Urartu eserleri, sikke koleksiyonu, Van kedisi, etnografik eserler, yöresel kıyafetler, halılar, el sanatları). Van Kedisi Evi (Van Yüzüncü Yıl Üniversitesi Kedi Evi, dünyaca ünlü Van kedisi (beyaz, mavi ve yeşil göz, tüyleri uzun, yumuşak, suyu seven, yüzebilen)). Çavuştepe (Urartu Kalesi, MÖ 8. yüzyıl, Kral II. Sarduri tarafından yaptırılmış, surlar, tapınak, depo odaları, su kanalları, manzara). Hoşap Kalesi (Güzelsu, 17. yüzyıl, Mahmudi Beyleri tarafından yaptırılmış, surlar, iç kale, kuleler, manzara). Erek Dağı (Van\'ın güneyinde, kış sporları, kayak, doğa yürüyüşleri, manzara). Van\'ın ilçeleri: Gevaş (Akdamar Adası, Gevaş Evleri, Gevaş Yaylaları), Edremit (Edremit Plajı, Edremit Yaylaları), Erciş (Erciş Kalesi, Erciş Yaylaları, Erciş Plajı, Çelebibağı), Muradiye (Muradiye Şelalesi (Bend-i Mahi Şelalesi), Muradiye Yaylaları), Özalp (Özalp Yaylaları), Başkale (Başkale Yaylaları, Başkale Kalesi), Gürpınar (Gürpınar Yaylaları), Çaldıran (Çaldıran Yaylaları, Çaldıran Savaşı Alanı (1514, Yavuz Sultan Selim ile Şah İsmail arasında)), Saray, Bahçesaray (Bahçesaray Yaylaları). Van, ayrıca Van balı (inci kefali, ilkbaharda göç dönemi, Van Gölü\'nde), Van otlu peyniri, Van otlu lor, Van kavutu, Van murtuğası, Van kahvaltısı, Van kedisi, Van el dokuması halı ve kilimleri, Van bakır işlemeciliği, Van keçeciliği ile de ünlüdür.', 'Van mutfağı, Doğu Anadolu mutfağının en zengin ve en ünlü mutfaklarından biridir. Mutlaka denenmesi gerekenlerin başında \"Van kahvaltısı\" (Van otlu peyniri, murtuğa, kavut, otlu lor, sade yağ, bal, kaymak, Van ketesi, van simidi, köy yumurtası, zeytin, ceviz, dut kurusu, pestil, sucuk, salam, domates, salatalık, biber, çay) gelir. \"Van köftesi\", \"Van tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"keledoş\", \"ayran aşı\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"Van otlu peyniri\", \"Van otlu lor\", \"Van murtuğası\", \"Van kavutu\", \"Van balı\", \"Van cevizi\", \"Van dutu\", \"Van üzümü\", \"Van elması\", \"Van karpuzu\" yöresel lezzetlerdendir. Tatlı olarak \"Van baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Van lokumu\", \"Van ketesi\" (tatlı çörek), \"Van simidi\", \"kaymaklı kadayıf\" ve \"Van dondurması\" öne çıkar.', 'Van\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Van Gölü ve Akdamar Kültür ve Sanat Festivali (ağustos), Uluslararası Van Kedisi Kültür ve Sanat Festivali (eylül), Uluslararası İnci Kefali ve Van Gölü Festivali (nisan-mayıs), Uluslararası Muradiye Şelalesi Kültür ve Doğa Festivali (temmuz), Uluslararası Erciş Kültür ve Sanat Festivali (ağustos), Uluslararası Çaldıran Kültür ve Sanat Festivali (ağustos), Van Kahvaltı Festivali (mayıs) ve Van Yayla Şenlikleri (yaz aylarında).', 'Van\'ı ziyaret etmek için en iyi zaman yaz aylarıdır (haziran-eylül). Bu dönemde hava ılımandır, sıcaklık 20-30 derece arasındadır; Van Gölü, Akdamar Adası, Van Kalesi, Çavuştepe, yaylalar ve doğa yürüyüşleri için idealdir. İlkbahar (nisan-mayıs) serin ve yağışlıdır, sonbahar (eylül-ekim) ise soğumaya başlar. Kışlar çok sert ve karlıdır; sıcaklık -15 derecenin altına düşebilir, aralık-şubat aylarında yollar zaman zaman kapanabilir, bu nedenle kış seyahati önerilmez.', 'Van\'a hava yoluyla Van Ferit Melen Havalimanı (VAN) ile ulaşılır. Havalimanı şehir merkezine 8 km uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Diyarbakır, Mardin, Batman, Siirt, Şırnak, Hakkari, Muş, Bitlis, Elazığ, Malatya, Gaziantep, Adana, Mersin, Konya, Kayseri, Sivas, Erzincan, Erzurum, Kars, Ardahan, Iğdır, Ağrı, Trabzon, Samsun gibi büyük illere seferler vardır. Van, Doğu Ekspresi\'nin güzergahında olup Ankara, Kayseri, Sivas, Erzincan, Erzurum, Kars, Iğdır, Tatvan, Bitlis, Muş, Elazığ, Malatya, Diyarbakır, Batman, Kurtalan gibi yerlere tren bağlantısı vardır. Van Tren Garı şehir merkezindedir. Van, Tatvan arasında Van Gölü feribot seferleri vardır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. İpekyolu, Tuşba, Edremit, Gevaş, Erciş, Muradiye, Özalp, Başkale, Gürpınar, Çaldıran, Saray, Bahçesaray ilçelerine minibüslerle ulaşım vardır. Van Kalesi, Akdamar Adası, Akdamar Kilisesi, Van Müzesi, Van Kedisi Evi, Çavuştepe, Hoşap Kalesi, Muradiye Şelalesi, Erek Dağı Kayak Merkezi, Erciş Plajı, Edremit Plajı, Van Gölü sahili, yaylalar gibi yerlere araç kiralamak veya turları tercif etmek önerilir.', 'Van, tarihi boyunca Urartular, Medler, Persler, Romalılar, Bizanslılar, Selçuklular, Karakoyunlular, Akkoyunlular, Safeviler ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Urartu Krallığı\'nın başkenti olan Van, MÖ 9. yüzyılda Kral Sarduri tarafından kurulmuştur. Urartu döneminde Van Kalesi, Tuşpa Başkenti, Çavuştepe, Toprakkale gibi önemli eserler inşa edilmiştir. 11. yüzyılda Selçukluların, 16. yüzyılda Osmanlıların egemenliğine giren Van, Cumhuriyet döneminde il statüsü kazanmıştır. Van, günümüzde Van Gölü, Van kedisi, Van kahvaltısı, tarihi Van Kalesi, Akdamar Adası ve Kilisesi ile ünlü bir Doğu Anadolu ilidir.', 'Van', '2026-04-08 23:20:51'),
(79, 'Yalova', 'Marmara', 'yalova.jpg', 'Termal kaynakları ile ünlü.', 'Yalova denince akla gelen ilk simge, Yalova Termal Kaplıcaları\'dır (Termal ilçesi). Roma döneminden beri kullanılan, romatizma, cilt hastalıkları, sinir sistemi, kadın hastalıklarına iyi gelen şifalı suları ile ünlüdür. Tarihi Termal Oteli (Atatürk\'ün kaldığı oda), Atatürk Köşkü (Termal\'daki tarihi köşk), Yürüyen Köşk (Atatürk\'ün ağacın dallarının kesilmemesi için köşkü raylar üzerinde kaydırdığı yer, tarihi anıt), Termal Müzesi. Yalova\'nın plajları: Çınarcık Plajı, Altınova Plajı, Kocadere Plajı, Armutlu Plajı, Esenköy Plajı, Kumla Plajı, Fıstıklı Plajı (Mavi Bayrak plajlar, ince kum, deniz). Yalova\'nın yaylaları: Erikli Yaylası, Delmece Yaylası, Soğucak Yaylası, Teşvikiye Yaylası, Sarmaşık Yaylası, Gürgen Yaylası, Işık Yaylası, Sazlık Yaylası (yayla evleri, yayla şenlikleri, doğa yürüyüşleri, kamp, manzara). Yalova\'nın ilçeleri: Çınarcık (Çınarcık Plajı, Esenköy, Erikli Yaylası, Delmece Yaylası, Ormanlı, Kocadere, Kirazlı, Teşvikiye Kaplıcaları, Sarmaşık Yaylası), Altınova (Altınova Plajı, Hersek Burnu, Hersek Lagünü (kuş cenneti), Altınova Müzesi), Termal (Yalova Termal Kaplıcaları, Tarihi Termal Oteli, Atatürk Köşkü, Yürüyen Köşk, Gökçedere), Armutlu (Armutlu Plajı, Armutlu Kaplıcaları, Armutlu Yaylaları), Çiftlikköy (Çiftlikköy Plajı, Çiftlikköy Müzesi), Altınova, Çınarcık, Termal, Armutlu, Çiftlikköy. Yalova\'da doğa yürüyüşleri ve kamp alanları: Erikli Yaylası, Delmece Yaylası, Sarmaşık Yaylası, Soğucak Yaylası, Işık Yaylası, Sazlık Yaylası, Çobankale (tarihi kale kalıntıları, manzara), Sudüşen Şelalesi, Sütüven Şelalesi, Ulupelit Parkı, Karaca Arboretumu (dünyanın dört bir yanından ağaç ve bitki türleri, botanik bahçesi, yürüyüş yolları), Yalova Kent Ormanı, Yalova Sahil Yürüyüş Yolu, Millet Bahçesi.', 'Yalova mutfağı, Marmara ve Karadeniz mutfaklarının zengin lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Yalova köftesi\" gelir. \"Etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"mıhlama\" (kuymak), \"karalahana çorbası\", \"hamsi tava\", \"Yalova peyniri\", \"Yalova yoğurdu\", \"Yalova balı\", \"Yalova kirazı\", \"Yalova elması\", \"Yalova üzümü\", \"Yalova çileği\", \"Yalova mandalini\", \"Yalova portakalı\" yöresel lezzetlerdendir. Tatlı olarak \"Yalova baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Yalova lokumu\", \"Yalova kestane şekeri\" ve \"Yalova macunu\" öne çıkar.', 'Yalova\'da birçok festival düzenlenmektedir. En önemlileri Uluslararası Yalova Kültür ve Sanat Festivali (eylül), Uluslararası Yalova Termal ve Kaplıca Festivali (nisan), Uluslararası Erikli Yaylası Kültür ve Doğa Festivali (temmuz), Uluslararası Çınarcık Kültür ve Turizm Festivali (ağustos), Uluslararası Armutlu Kültür ve Sanat Festivali (temmuz), Uluslararası Altınova Kültür ve Turizm Festivali (ağustos), Yalova Çilek Festivali (mayıs) ve Yalova Yayla Şenlikleri (yaz aylarında).', 'Yalova\'yı ziyaret etmek için en iyi zaman ilkbahar, yaz ve sonbahar aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos, eylül ve ekim aylarında hava ılımandır, sıcaklık 18-30 derece arasındadır; termal kaplıcalar, yaylalar, plajlar, doğa yürüyüşleri ve kamp için idealdir. Kışlar ılıman ve yağışlıdır, sıcaklık genelde 5-15 derece arasındadır, kış aylarında termal kaplıcalar (Yalova Termal Kaplıcaları) daha keyiflidir.', 'Yalova\'ya hava yoluyla en yakın havalimanı İstanbul Sabiha Gökçen Havalimanı (70 km) veya Bursa Yenişehir Havalimanı (50 km) kullanılır. Havalimanlarından havaş otobüsleri, belediye otobüsleri, minibüs ve taksi ile Yalova\'ya ulaşılır. Yalova\'ya İstanbul\'dan feribot seferleri vardır: Yalova-İstanbul Deniz Otobüsü (İDO, BUDO, Mavi Marmara), Yalova-Eskihisar (Eskihisar-Çınarcık feribotu), Yalova-Topçular feribotu. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli, Kocaeli, Sakarya, Bolu, Düzce, Zonguldak, Karabük, Kastamonu, Sinop, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin, Erzurum, Erzincan, Sivas, Kayseri, Konya, Adana, Mersin, Gaziantep, Diyarbakır, Malatya, Elazığ, Van, Muş, Bitlis, Batman, Siirt, Mardin, Hakkari, Iğdır, Ardahan, Kars, Ağrı gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu İzmit (Kocaeli) veya Bursa\'dadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Çınarcık, Altınova, Termal, Armutlu, Çiftlikköy ilçelerine minibüslerle ulaşım vardır. Termal Kaplıcaları, Yürüyen Köşk, Atatürk Köşkü, Karaca Arboretumu, Sudüşen Şelalesi, Sütüven Şelalesi, Erikli Yaylası, Delmece Yaylası, Sarmaşık Yaylası, Çınarcık Plajı, Armutlu Plajı, Altınova Plajı, Çobankale, Hersek Burnu, Hersek Lagünü gibi yerlere araç kiralamak veya turları tercih etmek önerilir.\r\n\r\n', 'Yalova, tarihi boyunca Bitinler, Frigler, Lidyalılar, Persler, Romalılar, Bizanslılar, Selçuklular ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Bitinya bölgesinin önemli merkezlerinden biri olan Yalova, Roma döneminde \"Pythia Therma\" (Termal sular) adıyla anılmıştır. 14. yüzyılda Osmanlı topraklarına katılan Yalova, Cumhuriyet döneminde önce İstanbul\'a bağlı bir ilçe iken 1995 yılında il statüsü kazanarak Türkiye\'nin en genç illerinden biri olmuştur. Yalova, günümüzde termal kaplıcaları, yaylaları, plajları, doğal güzellikleri ve yürüyüş parkurlarıyla öne çıkan bir Marmara ilidir.', 'Yalova', '2026-04-08 23:20:51'),
(80, 'Yozgat', 'İç Anadolu', 'yozgat.jpg', 'Çamlığı ile ünlü.', 'Yozgat denince akla gelen ilk simge, Çamlık Milli Parkı\'dır. Türkiye\'nin ilk milli parkı olan Çamlık, sarıçam ağaçları, yürüyüş parkurları, piknik alanları, kamp alanları, manzara, kuş gözlem, doğa yürüyüşleri için idealdir. Yozgat\'ın simgesi haline gelmiş olan Yozgat Saat Kulesi (1908), şehir merkezinde yükselen tarihi saat kulesidir. Yozgat Kalesi, şehir merkezinde yükselen Bizans, Danişmentli ve Osmanlı dönemlerinden izler taşıyan surları ve manzarasıyla dikkat çeker. Yozgat Müzesi (arkeolojik ve etnografik eserler, yazmacılık, bakır işlemeciliği, yöresel kıyafetler), Ulu Cami (Yozgat Ulu Cami, 18. yüzyıl, Osmanlı), Başçavuş Cami, Çapanoğlu Camii (18. yüzyıl, Osmanlı, çinileriyle ünlü), Çapanoğlu Külliyesi, Yozgat Evleri (tarihi Yozgat evleri, restore edilmiş konaklar, dar sokaklar), Yozgat Çarşısı (yazmacılar çarşısı, bakırcılar çarşısı, el sanatları, yöresel ürünler). Yozgat\'ın ilçeleri: Sorgun (Sorgun Yaylaları, Sorgun Çamlığı), Akdağmadeni (Akdağmadeni Yaylaları, Akdağmadeni Kalesi, Akdağmadeni Evleri), Sarıkaya (Sarıkaya Kaplıcaları (termal su), Sarıkaya Yaylaları), Boğazlıyan (Boğazlıyan Yaylaları), Yerköy (Yerköy Yaylaları, Yerköy Kaplıcaları), Şefaatli (Şefaatli Yaylaları), Çekerek (Çekerek Yaylaları, Çekerek Kalesi), Kadışehri, Çayıralan, Aydıncık, Sarıkaya, Saraykent, Yenifakılı. Yozgat\'ın yaylaları: Sorgun Yaylaları, Akdağmadeni Yaylaları, Boğazlıyan Yaylaları, Yerköy Yaylaları, Şefaatli Yaylaları, Çekerek Yaylaları (yayla evleri, yayla şenlikleri, doğa yürüyüşleri, kamp, yayla manzaraları). Yozgat, ayrıca yazmacılık (el yazması bez, yazma desenleri, yazma atölyeleri), bakır işlemeciliği (bakır tencere, tava, cezve, ibrik, sini), Yozgat halıcılığı, Yozgat kilim dokumacılığı, Yozgat peyniri, Yozgat balı, Yozgat elması, Yozgat üzümü, Yozgat cevizi ile de ünlüdür.', 'Yozgat mutfağı, İç Anadolu mutfağının zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Yozgat köftesi\" gelir. \"Yozgat tava\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"Yozgat peyniri\", \"Yozgat yoğurdu\", \"Yozgat balı\", \"Yozgat elması\", \"Yozgat üzümü\", \"Yozgat cevizi\", \"Yozgat kirazı\" yöresel lezzetlerdendir. Tatlı olarak \"Yozgat baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Yozgat lokumu\", \"Yozgat bezmesi\" (pekmez, ceviz, üzüm, Yozgat\'a özgü tatlı), \"Yozgat sucuğu\" ve \"Yozgat pestili\" öne çıkar.', 'Yozgat\'ta en önemli etkinlik, her yıl ağustos ayında düzenlenen Uluslararası Yozgat Çamlık Kültür ve Sanat Festivali\'dir. Festivalde konserler, halk oyunları gösterileri, yöresel lezzet tadımları, yazmacılık ve bakır işlemeciliği sergileri, panayır, sergiler ve paneller düzenlenir. Ayrıca Uluslararası Sorgun Kültür ve Sanat Festivali (temmuz), Uluslararası Akdağmadeni Kültür ve Turizm Festivali (ağustos), Uluslararası Sarıkaya Kaplıca ve Termal Turizm Festivali (haziran), Uluslararası Boğazlıyan Kültür ve Sanat Festivali (eylül), Yozgat Yayla Şenlikleri (yaz aylarında), Yozgat Bezmesi Festivali (ekim) ve Yozgat Yazmacılık Festivali (mayıs).', 'Yozgat\'ı ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 15-28 derece arasındadır; Çamlık Milli Parkı, yaylalar, tarihi yapılar ve doğa yürüyüşleri için idealdir. Sonbahar ayları da güzeldir. Kışlar soğuk ve karlıdır, sıcaklık sıfırın altına düşebilir, zaman zaman kar yağışı görülür.', 'Yozgat\'a hava yoluyla en yakın havalimanı Ankara Esenboğa Havalimanı (200 km) veya Kayseri Erkilet Havalimanı (180 km) kullanılır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Kayseri, Sivas, Konya, Kırıkkale, Kırşehir, Çorum, Amasya, Tokat, Samsun, Trabzon, Erzincan, Erzurum gibi büyük illere seferler vardır. Demiryolu bağlantısı yoktur; en yakın tren istasyonu Kayseri veya Sivas\'tadır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Sorgun, Akdağmadeni, Sarıkaya, Boğazlıyan, Yerköy, Şefaatli, Çekerek, Kadışehri, Çayıralan, Aydıncık, Saraykent, Yenifakılı ilçelerine minibüslerle ulaşım vardır. Çamlık Milli Parkı, Yozgat Saat Kulesi, Yozgat Kalesi, Yozgat Müzesi, Çapanoğlu Camii, Sarıkaya Kaplıcaları, Yerköy Kaplıcaları, Sorgun Yaylaları, Akdağmadeni Yaylaları gibi yerlere araç kiralamak önerilir.', 'Yozgat, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Danişmentliler, Selçuklular, Eretna Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Kapadokya bölgesinin kuzeyinde yer alan Yozgat, Roma döneminde \"Eusebeia\" adıyla anılmıştır. 11. yüzyılda Malazgirt Meydan Muharebesi\'nden sonra Türklerin eline geçen bölge, 14. yüzyılda Osmanlı topraklarına katılmıştır. Cumhuriyet döneminde il statüsü kazanan Yozgat, günümüzde Çamlık Milli Parkı, tarihi saat kulesi, yöresel el sanatları (yazmacılık, bakır işlemeciliği) ve ünlü Yozgat bezmesiyle öne çıkan bir İç Anadolu ilidir.', 'Yozgat', '2026-04-08 23:20:51'),
(81, 'Zonguldak', 'Karadeniz', 'zonguldak.jpg', 'Filyos ile ünlü.', 'Zonguldak denince akla gelen ilk simge, taşkömürü madenleridir. Zonguldak Maden Müzesi (maden tarihi, kömür örnekleri, madenci kıyafetleri, maden ocakları maketleri, madenci heykelleri), Üzülmez Maden Ocağı, Kozlu Maden Ocağı, Karadon Maden Ocağı, Armutçuk Maden Ocağı ziyaret edilebilir. Zonguldak\'ın plajları: Kapuz Plajı, Plaj (Uzunkum Plajı), Kozlu Plajı, Filyos Plajı, Türkali Plajı, İnağzı Plajı, Gökçebey Plajı, Çaycuma Plajı, Değirmenağzı Plajı yaz aylarında yoğun ilgi görür. Zonguldak\'ın mağaraları: Gökgöl Mağarası (sarkıt, dikit, traverten havuzları, yürüyüş yolları, aydınlatma), Cehennemağzı Mağarası (mağara içinde dere, yürüyüş yolları), Kızılelma Mağarası, Mencilis Mağarası, İkikara Mağarası. Zonguldak\'ın yaylaları: Acılık Yaylası, Işıklı Yaylası, Göldağı Yaylası, Çaycuma Yaylaları, Devrek Yaylaları, Alaplı Yaylaları (yayla evleri, yayla şenlikleri, doğa yürüyüşleri, kamp). Zonguldak\'ın ilçeleri: Filyos (Filyos Plajı, Filyos Kalesi (Ceneviz Kalesi), Filyos Limanı, Filyos Antik Kenti (Tieion, Tios), Filyos Çayı), Çaycuma (Çaycuma Plajı, Çaycuma Yaylaları, Çaycuma Kalesi), Devrek (Devrek Bastonu (dünyaca ünlü Devrek bastonu), Devrek Evleri, Devrek Yaylaları), Ereğli (Karadeniz Ereğli, Ereğli Plajı, Ereğli Kalesi (Ceneviz Kalesi), Ereğli Müzesi, Cehennemağzı Mağarası, Kızılelma Mağarası, Herakleia Pontica Antik Kenti), Alaplı (Alaplı Plajı, Alaplı Yaylaları), Gökçebey (Gökçebey Plajı, Gökçebey Yaylaları). Zonguldak, ayrıca Devrek bastonu (el yapımı, şimşir ağacı, gümüş, fildişi, sedef kakma, dünyaca ünlü), Zonguldak bezi, Zonguldak el dokuması halı ve kilimleri, Zonguldak bakır işlemeciliği, Zonguldak peyniri, Zonguldak balı, Zonguldak fındığı, Zonguldak elması, Zonguldak kirazı ile de ünlüdür.', 'Zonguldak mutfağı, Karadeniz mutfağının zengin ve doyurucu lezzetlerini taşır. Mutlaka denenmesi gerekenlerin başında \"Zonguldak köftesi\" gelir. \"Erikli et\", \"etli ekmek\", \"kavurma\", \"keşkek\", \"yaprak sarma\", \"dolma\", \"karalahana çorbası\", \"oğmaç çorbası\", \"tarhana çorbası\", \"mercimek çorbası\", \"yayla çorbası\", \"sac böreği\", \"katmer\", \"gözleme\", \"mıhlama\" (kuymak), \"kuru fasulye\", \"sac kavurma\", \"haşıl\", \"herle\", \"mısır ekmeği\", \"hamsi tava\", \"hamsi buğulama\", \"hamsili ekmek\", \"hamsili pilav\", \"çiroz\", \"Zonguldak peyniri\", \"Zonguldak yoğurdu\", \"Zonguldak balı\", \"Zonguldak fındığı\", \"Zonguldak mısırı\", \"Zonguldak elması\", \"Zonguldak kirazı\" yöresel lezzetlerdendir. Tatlı olarak \"Zonguldak baklavası\", \"kadayıf\", \"un helvası\", \"höşmerim\", \"cevizli sucuk\", \"pestil\", \"köme\", \"kabak tatlısı\", \"sütlaç\", \"güllaç\", \"Zonguldak lokumu\", \"fındıklı baklava\", \"fındıklı sütlaç\", \"fındıklı helva\" ve \"kestane şekeri\" öne çıkar.', 'Zonguldak\'ta birçok festival düzenlenmektedir. En önemlileri Uluslararası Zonguldak Kültür ve Sanat Festivali (eylül), Uluslararası Karadeniz Ereğli Kültür ve Sanat Festivali (ağustos), Uluslararası Devrek Bastonu ve Kültür Festivali (temmuz), Uluslararası Filyos Kalesi Kültür ve Sanat Festivali (ağustos), Uluslararası Çaycuma Kültür ve Sanat Festivali (temmuz), Uluslararası Alaplı Kültür ve Turizm Festivali (ağustos), Zonguldak Kömür Festivali (ekim), Zonguldak Yayla Şenlikleri (yaz aylarında) ve Zonguldak Mağara Festivali (haziran).', 'Zonguldak\'ı ziyaret etmek için en iyi zaman ilkbahar ve yaz aylarıdır. Nisan, mayıs, haziran, temmuz, ağustos ve eylül aylarında hava ılımandır, sıcaklık 18-28 derece arasındadır; plajlar, yaylalar, mağaralar, doğa yürüyüşleri ve kamp için idealdir. Sonbahar ayları da güzeldir. Kışlar yağışlı ve soğuktur, sıcaklık genelde 3-12 derece arasındadır, zaman zaman kar yağışı görülür.', 'Zonguldak\'a hava yoluyla Zonguldak Havalimanı (ONQ) ile ulaşılır. Havalimanı şehir merkezine 40 km (Çaycuma ilçesinde) uzaklıktadır. Şehirlerarası otobüs terminalinden İstanbul, Ankara, İzmir, Bursa, Karabük, Bartın, Kastamonu, Sinop, Samsun, Ordu, Giresun, Trabzon, Rize, Artvin, Bolu, Düzce, Sakarya, Kocaeli, Yalova, Bilecik, Eskişehir, Kütahya, Afyonkarahisar, Denizli, Antalya, Muğla, Aydın, İzmir, Manisa, Balıkesir, Çanakkale, Tekirdağ, Edirne, Kırklareli gibi büyük illere seferler vardır. Demiryolu bağlantısı vardır; Zonguldak Tren Garı ile Ankara, Karabük, Çankırı, Kırıkkale gibi illere tren bağlantısı vardır. Şehir içi ulaşımda minibüs, dolmuş, belediye otobüsleri ve taksi kullanılır. Ereğli, Çaycuma, Devrek, Alaplı, Gökçebey, Kilimli, Kozlu ilçelerine minibüslerle ulaşım vardır. Kapuz Plajı, Filyos Plajı, Ereğli Plajı, Gökgöl Mağarası, Cehennemağzı Mağarası, Filyos Kalesi, Ereğli Kalesi, Devrek Bastonu Atölyeleri, Zonguldak Maden Müzesi, Acılık Yaylası, Işıklı Yaylası gibi yerlere araç kiralamak veya turları tercih etmek önerilir.', 'Zonguldak, tarihi boyunca Hititler, Frigler, Kimmerler, Lidyalılar, Persler, Romalılar, Bizanslılar, Candaroğulları Beyliği ve Osmanlılar gibi birçok medeniyete ev sahipliği yapmıştır. Antik dönemde Paflagonya bölgesinin önemli merkezlerinden biri olan Zonguldak, Roma döneminde \"Hypium\" adıyla anılmıştır. 15. yüzyılda Osmanlı topraklarına katılan bölge, Cumhuriyet döneminde il statüsü kazanmıştır. Zonguldak, Türkiye\'nin en önemli kömür (taşkömürü) üretim merkezidir. 19. yüzyılda keşfedilen kömür yatakları ile birlikte hızla gelişen şehir, günümüzde maden ocakları, Filyos Limanı, plajları, mağaraları ve yaylalarıyla öne çıkan bir Karadeniz ilidir.', 'Zonguldak', '2026-04-08 23:20:51');

